// 관주(교차참조) 데이터 — sihong.pe.kr/ref 에서 자동 추출
// key: 절 주소(앱 reference 약어 체계),  value: [{r:주소, t:본문}]
window.GWANJU = {"갈2:16":[{"r":"갈3:11","t":"또 하나님 앞에서 아무나 률법으로 말미암아 의롭게 되지 못할 것이 분명하니 이는 의인이 믿음으로 살리라 하였음이니라"},{"r":"행13:39","t":"또 모세의 률법으로 너희가 의롭다 하심을 얻지 못하던 모든 일에도 이 사람을 힘입어 믿는 자마다 의롭다 하심을 얻는 이것이라"},{"r":"롬9:30","t":"그런즉 우리가 무슨 말 하리요 의를 좇지 아니한 이방인들이 의를 얻었으니 곧 믿음에서 난 의요"},{"r":"롬3:20","t":"그러므로 률법의 행위로 그의 앞에 의롭다 하심을 얻을 육체가 없나니 률법으로는 죄를 깨달음이니라"},{"r":"시143:2","t":"주의 종에게 심판을 행치 마소서 주의 목전에는 의로운 인생이 하나도 없나이다"}],"갈2:20":[{"r":"갈5:24","t":"그리스도 예수의 사람들은 육체와 함께 그 정과 욕심을 십자가에 못 박았느니라"},{"r":"갈6:14","t":"그러나 내게는 우리 주 예수 그리스도의 십자가 외에 결코 자랑할 것이 없으니 그리스도로 말미암아 세상이 나를 대하여 십자가에 못 박히고 내가 또한 세상을 대하여 그러하니라"},{"r":"롬6:6","t":"우리가 알거니와 우리 옛 사람이 예수와 함께 십자가에 못 박힌 것은 죄의 몸이 멸하여 다시는 우리가 죄에게 종노릇하지 아니하려 함이니"},{"r":"요17:23","t":"곧 내가 저희 안에 아버지께서 내 안에 계셔 저희로 온전함을 이루어 하나가 되게 하려 함은 아버지께서 나를 보내신 것과 또 나를 사랑하심 같이 저희도 사랑하신 것을 세상으로 알게 하려 함이로소이다"},{"r":"롬8:37","t":"그러나 이 모든 일에 우리를 사랑하시는 이로 말미암아 우리가 넉넉히 이기느니라"},{"r":"갈1:4","t":"그리스도께서 하나님 곧 우리 아버지의 뜻을 따라 이 악한 세대에서 우리를 건지시려고 우리 죄를 위하여 자기 몸을 드리셨으니"}],"갈2:9":[{"r":"롬1:5","t":"그로 말미암아 우리가 은혜와 사도의 직분을 받아 그 이름을 위하여 모든 이방인 중에서 믿어 순종케 하나니"},{"r":"렘1:18","t":"보라, 내가 오늘날 너로 그 온 땅과 유다 왕들과 그 족장들과 그 제사장들과 그 땅 백성 앞에 견고한 성읍, 쇠기둥, 놋 성벽이 되게 하였은즉"},{"r":"계3:12","t":"이기는 자는 내 하나님 성전에 기둥이 되게 하리니 그가 결코 다시 나가지 아니하리라 내가 하나님의 이름과 하나님의 성 곧 하늘에서 내 하나님께로부터 내려 오는 새 예루살렘의 이름과 나의 새 이름을 그이 위에 기록하리라"},{"r":"벧후3:15","t":"또 우리 주의 오래 참으심이 구원이 될 줄로 여기라 우리 사랑하는 형제 바울도 그 받은 지혜대로 너희에게 이같이 썼고"}],"갈3:26":[{"r":"갈4:5,6","t":"률법 아래 있는 자들을 속량하시고 우리로 아들의 명분을 얻게 하려 하심이라"},{"r":"요1:12","t":"영접하는 자 곧 그 이름을 믿는 자들에게는 하나님의 자녀가 되는 권세를 주셨으니"},{"r":"롬8:14~16","t":"무릇 하나님의 영으로 인도함을 받는 그들은 곧 하나님의 아들이라"}],"갈3:27":[{"r":"행8:16","t":"이는 아직 한 사람에게도 성령 내리신 일이 없고 오직 주 예수의 이름으로 세례만 받을 뿐이러라"},{"r":"롬6:3","t":"무릇 그리스도 예수와 합하여 세례를 받은 우리는 그의 죽으심과 합하여 세례 받은 줄을 알지 못하느뇨"},{"r":"롬13:14","t":"오직 주 예수 그리스도로 옷입고 정욕을 위하여 육신의 일을 도모하지 말라"}],"갈4:4":[{"r":"딤전2:6","t":"그가 모든 사람을 위하여 자기를 속전으로 주셨으니 기약이 이르면 증거할 것이라"},{"r":"막1:15","t":"가라사대 때가 찼고 하나님 나라가 가까왔으니 회개하고 복음을 믿으라  하시더라"},{"r":"딤전2:15","t":"그러나 녀자들이 만일 정절로써 믿음과 사랑과 거룩함에 거하면 그 해산함으로 구원을 얻으리라"},{"r":"창3:15","t":"내가 너로 녀자와 원수가 되게 하고 너의 후손도 녀자의 후손과 원수가 되게 하리니 녀자의 후손은 네 머리를 상하게 할 것이요 너는 그의 발꿈치를 상하게 할 것이니라 하시고"},{"r":"눅2:21,22","t":"할례할 팔일이 되매 그 이름을 예수라 하니 곧 수태하기 전에 천사의 일컬은 바러라"},{"r":"눅2:27","t":"성령의 감동으로 성전에 들어가매 마침 부모가 률법의 전례대로 행하고자 하여 그 아기 예수를 데리고 오는지라"},{"r":"빌2:7","t":"오히려 자기를 비어 종의 형체를 가져 사람들과 같이 되었고"},{"r":"요1:14","t":"말씀이 육신이 되어 우리 가운데 거하시매 우리가 그 영광을 보니 아버지의 독생자의 영광이요 은혜와 진리가 충만하더라"}],"갈4:5":[{"r":"갈3:13","t":"그리스도께서 우리를 위하여 저주를 받은 바 되사 률법의 저주에서 우리를 속량하셨으니 기록된 바 나무에 달린 자마다 저주 아래 있는 자라 하였음이라"},{"r":"갈3:26","t":"너희가 다 믿음으로 말미암아 그리스도 예수 안에서 하나님의 아들이 되었으니"},{"r":"롬8:15","t":"너희는 다시 무서워하는 종의 영을 받지 아니하였고 양자의 영을 받았으므로 아바 아버지라 부르짖느니라"}],"갈5:16":[{"r":"갈5:25","t":"만일 우리가 성령으로 살면 또한 성령으로 행할지니"},{"r":"롬8:4","t":"육신을 좇지 않고 그 영을 좇아 행하는 우리에게 률법의 요구를 이루어지게 하려 하심이니라"},{"r":"롬13:14","t":"오직 주 예수 그리스도로 옷입고 정욕을 위하여 육신의 일을 도모하지 말라"},{"r":"엡2:3","t":"전에는 우리도 다 그 가운데서 우리 육체의 욕심을 따라 지내며 육체와 마음의 원하는 것을 하여 다른 이들과 같이 본질상 진노의 자녀이었더니"}],"갈5:17":[{"r":"롬7:23","t":"내 지체 속에서 한 다른 법이 내 마음의 법과 싸워 내 지체 속에 있는 죄의 법 아래로 나를 사로잡아 오는 것을 보는도다"},{"r":"롬8:5~7","t":"육신을 좇는 자는 육신의 일을 영을 좇는 자는 영의 일을 생각하나니"},{"r":"롬7:15","t":"나의 행하는 것을 내가 알지 못하노니 곧 원하는 이것은 행하지 아니하고 도리어 미워하는 그것을 함이라"},{"r":"롬7:18,19","t":"내 속 곧 내 육신에 선한 것이 거하지 아니하는 줄을 아노니 원함은 내게 있으나 선을 행하는 것은 없노라"}],"겔18:24":[{"r":"겔3:20","t":"또 의인이 그 의에서 돌이켜 악을 행할 때에는 이미 행한 그 의는 기억할 바 아니라 내가 그 앞에 거치는 것을 두면 그가 죽을지니 이는 네가 그를 깨우치지 않음이라 그가 그 죄 중에서 죽으려니와 그 피 값은 내가 네 손에서 찾으리라"},{"r":"겔33:12,13","t":"인자야 너는 네 민족에게 이르기를 의인이 범죄하는 날에는 그 의가 구원치 못할 것이요 악이 돌이켜 그 악에서 떠나는 날에는 그 악이 그를 엎드러뜨리지 못할 것인즉 의인이 범죄하는 날에는 그 의로 인하여는 살지 못하리라"},{"r":"겔33:18","t":"만일 의인이 돌이켜 그 의에서 떠나 죄악을 지으면 그가 그 가운데서 죽을 것이고"},{"r":"벧후2:20,21","t":"만일 저희가 우리 주 되신 구주 예수 그리스도를 앎으로 세상의 더러움을 피한 후에 다시 그 중에 얽매이고 지면 그 나중 형편이 처음보다 더 심하리니"},{"r":"겔14:13","t":"인자야 가령 어느 나라가 부법하여 내게 범죄하므로 내가 손을 그 위에 펴서 그 의뢰하는 량식을 끊어 기근을 내려서 사람과 짐승을 그 나라에서 끊는다 하자"}],"겔20:13":[{"r":"겔20:21","t":"그러나 그 자손이 내게 패역하여 사람이 준행하면 그로 인하여 삶을 얻을 나의 율례를 좇지 아니하며 나의 규례를 지켜 행하지 아니하였고 나의 안식일을 더럽혔는지라 이에 내가 이르기를 내가 광야에서 내 분을 그들의 위에 쏟으며 내 노를 그들에게 이루리라 하였으나"},{"r":"겔20:21","t":"그러나 그 자손이 내게 패역하여 사람이 준행하면 그로 인하여 삶을 얻을 나의 율례를 좇지 아니하며 나의 규례를 지켜 행하지 아니하였고 나의 안식일을 더럽혔는지라 이에 내가 이르기를 내가 광야에서 내 분을 그들의 위에 쏟으며 내 노를 그들에게 이루리라 하였으나"},{"r":"겔20:24","t":"이는 그들이 나의 규례를 행치 아니하며 나의 율례를 멸시하며 내 안식일을 더럽히고 눈으로 그 열조의 우상들을 사모함이며"},{"r":"겔20:21","t":"그러나 그 자손이 내게 패역하여 사람이 준행하면 그로 인하여 삶을 얻을 나의 율례를 좇지 아니하며 나의 규례를 지켜 행하지 아니하였고 나의 안식일을 더럽혔는지라 이에 내가 이르기를 내가 광야에서 내 분을 그들의 위에 쏟으며 내 노를 그들에게 이루리라 하였으나"},{"r":"겔20:24","t":"이는 그들이 나의 규례를 행치 아니하며 나의 율례를 멸시하며 내 안식일을 더럽히고 눈으로 그 열조의 우상들을 사모함이며"},{"r":"겔22:8","t":"너는 나의 성물들을 업신여겼으며 나의 안식일을 더럽혔으며"},{"r":"겔23:38","t":"이외에도 그들이 내게 행한 것이 있나니 당일에 내 성소를 더럽히며 내 안식일을 범하였도다"}],"겔20:16":[{"r":"겔20:24","t":"이는 그들이 나의 규례를 행치 아니하며 나의 율례를 멸시하며 내 안식일을 더럽히고 눈으로 그 열조의 우상들을 사모함이며"},{"r":"민15:39","t":"이 술은 너희로 보고 여호와의 모든 계명을 기억하여 준행하고 너희로 방종케 하는 자기의 마음과 눈의 욕심을 좇지 않게 하기 위함이라"},{"r":"시78:37","t":"이는 하나님께 향하는 저희 마음이 정함이 없으며 그의 언약에 성실치 아니하였음이로다"}],"겔20:19":[{"r":"겔20:5","t":"이르기를 주 여호와의 말씀에 옛날에 내가 이스라엘을 택하고 야곱 집의 후예를 향하여 맹서하고 애굽 땅에서 그들에게 나타나서 맹서하여 이르기를 나는 여호와 너희 하나님이라 하였었노라"},{"r":"출20:2","t":"나는 너를 애굽 땅 종 되었던 집에서 인도하여 낸 너의 하나님 여호와로라"},{"r":"신5:32,33","t":"그런즉 너희 하나님 여호와께서 너희에게 명령하신 대로 너희는 삼가 행하여 좌로나 우로나 치우치지 말고"}],"겔20:20":[{"r":"렘17:22","t":"안식일에 너희 집에서 짐을 내지 말며 아무 일이든지 하지 말아서 내가 너희 열조에게 명함같이 안식일을 거룩히 할지어다"},{"r":"겔20:12","t":"또 나는 그들을 거룩하게 하는 여호와인 줄 알게 하려하여 내가 내 안식일을 주어 그들과 나 사이에 표징을 삼았었노라"},{"r":"창9:12","t":"하나님이 가라사대 내가 나와 너희와 및 너희와 함께 하는 모든 생물 사이에 영세까지 세우는 언약의 증거는 이것이라"},{"r":"창17:11","t":"너희는 양피를 베어라  이것이 나와 너희 사이의 언약의 표징이니라"}],"겔20:24":[{"r":"겔20:16","t":"그들이 마음으로 우상을 좇아 나의 규례를 업신여기며 나의 율례를 행치 아니하며 나의 안식일을 더럽혔음이니라"}],"겔36:25":[{"r":"사52:15","t":"후에는 그가 열방을 놀랠 것이며 열왕은 그를 인하여 입을 봉하리니 이는 그들이 아직 전파되지 않은 것을 볼 것이요 아직 듣지 못한 것을 깨달을 것임이라 하시니라"},{"r":"히10:22","t":"우리가 마음에 뿌림을 받아 량심의 악을 깨닫고 몸을 맑은 물로 씻었으니 참 마음과 온전한 믿음으로 하나님께 나아가자"},{"r":"렘33:8","t":"내가 그들을 내게 범한 그 모든 죄악에서 정하게 하며 그들의 내게 범하여 행한 모든 죄악을 사할 것이라"},{"r":"사4:4","t":"이는 주께서 그 심판하는 영과 소멸하는 영으로 시온의 딸들의 더러움을 씻으시며 예루살렘의 피를 그 중에서 청결케 하실 때가 됨이라"},{"r":"겔36:17","t":"인자야 이스라엘 족속이 그 고토에 거할 때에 그 행위로 그 땅을 더럽혔나니 나 보기에 그 소위가 월경 중에 있는 녀인의 불정함과 같았느니라"},{"r":"겔37:23","t":"그들이 그 우상들과 가증한 물건과 그 모든 죄악으로 스스로 더럽히지 아니하리라 내가 그들을 그 범죄한 모든 처소에서 구원하여 정결케 한즉 그들은 내 백성이 되고 나는 그들의 하나님이 되리라"}],"겔36:26":[{"r":"겔11:19,20","t":"내가 그들에게 일치한 마음을 주고 그 속에 새 신을 주며 그 몸에서 굳은 마음을 제하고 부드러운 마음을 주어서"}],"겔36:27":[{"r":"겔37:14","t":"내가 또 내 신을 너희 속에 두어 너희로 살게 하고 내가 또 너희를 너희 고토에 거하게 하리니 나 여호와가 이 일을 말하고 이룬 줄을 너희가 알리라 나 여호와의 말이니라 하셨다 하라"},{"r":"겔37:24","t":"내 조상 다윗이 그들의 왕이 되리니 그들에게 다 한 목자가 있을 것이라 그들이 내 규례를 준행하고 내 율례를 지켜 행하며"}],"겔36:36":[{"r":"시126:2","t":"그 때에 우리 입에는 웃음이 가득하고 우리 혀에는 찬양이 찼었도다 열방 중에서 말하기를 여호와께서 저희를 위하여 대사를 행하셨다 하였도다"},{"r":"겔34:29","t":"내가 그들을 위하여 유명한 종식할 땅을 일으키리니 그들이 다시는 그 땅에서 기근으로 멸망하지 아니할지며 다시는 렬국의 수치를 받지 아니할지라"},{"r":"겔17:24","t":"들의 모든 나무가 나 여호와는 높은 나무를 낮추고 낮은 나무를 높이며 푸른 나무를 말리우고 마른 나무를 무성케 하는줄 알리라 나 여호와는 말하고 이루느니라 하라"}],"겔36:37":[{"r":"겔14:3","t":"인자야  이 사람들이 자기 우상을 마음에 들이며 죄악의 거치는 것을 자기 앞에 두었으니 그들이 내게 묻기를 내가 조금인들 용납하랴"},{"r":"겔36:10","t":"내가 또 사람을 너희 위에 많게 하리니 이들은 이스라엘 온 족속이라 그들로 성읍들에 거하게 하며 빈 땅에 건축하게 하리라"},{"r":"겔34:31","t":"내 양 곧 내 초장의 양, 너희는 사람이요 나는 너희 하나님이라 나 주 여호와의 말이니라"}],"겔4:6":[{"r":"겔23:11","t":"그 아우 오홀리바가 이것을 보고도 그 형보다 음욕을 더하며 그 형의 간음함보다 그 간음이 더 심하므로 그 형보다 더 부패하여 졌느니라"}],"계12:1":[{"r":"아6:10","t":"아침빛 같이 뚜렷하고 달 같이 아름답고 해 같이 맑고 기치를 벌인 군대 같이 엄위한 녀자가 누구인가"},{"r":"시104:2","t":"주께서 옷을 입음 같이 빛을 입으시며 하늘을 휘장같이 치시며"}],"계12:15":[{"r":"사59:19","t":"서방에서 여호와의 이름을 두려워하겠고 해돋는 편에서 그 기운에 몰려 급히 흐르는 하수같이 오실 것임이로다"}],"계12:17":[{"r":"창3:15","t":"내가 너로 녀자와 원수가 되게 하고 너의 후손도 녀자의 후손과 원수가 되게 하리니 녀자의 후손은 네 머리를 상하게 할 것이요 너는 그의 발꿈치를 상하게 할 것이니라 하시고"},{"r":"계14:12","t":"성도들의 인내가 여기 있나니 저희는 하나님의 계명과 예수 믿음을 지키는 자니라"},{"r":"요일2:3","t":"우리가 그의 계명을 지키면 이로써 우리가 저를 아는 줄로 알 것이요"},{"r":"계1:2","t":"요한은 하나님의 말씀과 예수 그리스도의 증거 곧 자기의 본 것을 다 증거하였느니라"},{"r":"계6:9","t":"다섯째 인을 떼실 때에 내가 보니 하나님의 말씀과 저희의 가진 증거를 인하여 죽임을 당한 령혼들이 제단 아래 있어"},{"r":"계19:10","t":"내가 그 발 앞에 엎드려 경배하려 하니 그가 나더러 말하기를 나는 너와 및 예수의 증거를 받은 네 형제들과 같이 된 종이니 삼가 그리하지말고 오직 하나님께 경배하라 예수의 증거는 대언의 영이라 하더라"},{"r":"계11:7","t":"저희가 그 증거를 마칠 때에 무저갱으로부터 올라오는 짐승이 저희로 더불어 전쟁을 일으켜 저희를 이기고 저희를 죽일 터인즉"},{"r":"계13:7","t":"또 권세를 받아 성도들과 싸워 이기게 되고 각 족속과 백성과 방언과 나라를 다스리는 권세를 받으니"}],"계12:7":[{"r":"유1:9","t":"천사장 미가엘이 모세의 시체에 대하여 마귀와 다투어 변론할 때에 감히 훼방하는 판결을 쓰지 못하고 다만 말하되 주께서 너를 꾸짖으시기를 원하노라 하였거늘"},{"r":"마25:41","t":"또 왼편에 있는 자들에게 이르시되 저주를 받은 자들아  나를 떠나 {마귀}와 그 사자들을 위하여 예비된 영영한 불에 들어가라"}],"계12:9":[{"r":"눅10:18","t":"예수께서 이르시되 사단이 하늘로서 번개같이 떨어지는 것을 내가 보았노라"},{"r":"요12:31","t":"이제 이 세상의 심판이 이르렀으니 이 세상 임금이 쫓겨나리라"},{"r":"계20:2","t":"용을 잡으니 곧 옛 뱀이요 마귀요 사단이라 잡아 일천년 동안 결박하여"},{"r":"창3:1","t":"여호와 하나님의 지으신 들짐승 중에 뱀이 가장 간교하더라 뱀이 녀자에게 물어 가로되 하나님이 참으로 너희더러 동산 모든 나무의 실과를 먹지 말라 하시더냐"},{"r":"계20:3","t":"무저갱에 던져 잠그고 그 위에 인봉하여 천년이 차도록 다시는 만국을 미혹하지 못하게 하였다가 그 후에는 반드시 잠간 놓이리라"},{"r":"계20:10","t":"또 저희를 미혹하는 마귀가 불과 류황 못에 던지우니 거기는 그 짐승과 거짓 선지자들도 있어 세세토록 밤낮 괴로움을 받으리라"},{"r":"계13:14","t":"짐승 앞에서 받은 바 이적을 행함으로 땅에 거하는 자들을 미혹하며 땅에 거하는 자들에게 이르기를 칼에 상하였다가 살아난 짐승을 위하여 우상을 만들라 하더라"},{"r":"요8:44","t":"너희는 너희 아비 마귀에게서 났으니 너희 아비의 욕심을 너희도 행하고자 하느니라 저는 처음부터 살인한 자요 진리가 그 속에 없으므로 진리에 서지 못하고 거짓을 말할 때마다 제 것으로 말하나니 이는 저가 거짓말장이요 거짓의 아비가 되었음이니라"},{"r":"계9:1","t":"다섯째 천사가 나팔을 불매 내가 보니 하늘에서 땅에 떨어진 별 하나가 있는데 저가 무저갱의 열쇠를 받았더라"}],"계13:16":[{"r":"계7:3","t":"가로되 우리가 우리 하나님의 종들의 이마에 인치기까지 땅이나 바다나 나무나 해하지 말라 하더라"},{"r":"갈6:17","t":"이 후로는 누구든지 나를 괴롭게 말라 내가 내 몸에 예수의 흔적을 가졌노라"}],"계13:17":[{"r":"계14:11","t":"그 고난의 연기가 세세토록 올라가리로다 짐승과 그의 우상에게 경배하고 그 이름의 표를 받는 자는 누구든지 밤낮 쉼을 얻지 못하리라 하더라"},{"r":"계15:2","t":"또 내가 보니 불이 섞인 유리 바다 같은 것이 있고 짐승과 그의 우상과 그의 이름의 수를 이기고 벗어난 자들이 유리 바닷가에 서서 하나님의 거문고를 가지고"}],"계13:5":[{"r":"단7:8","t":"내가 그 뿔을 유심히 보는 중 다른 작은 뿔이 그 사이에서 나더니 먼저 뿔 중에 셋이 그 앞에 뿌리까지 뽑혔으며 이 작은 뿔에는 사람의 눈 같은 눈이 있고 또 입이 있어 큰 말을 하였느니라"},{"r":"단7:11","t":"그 때에 내가 그 큰 말하는 작은 뿔의 목소리로 인하여 주목하여 보는 사이에 짐승이 죽임을 당하고 그 시체가 상한 바 되어 붙는 불에 던진 바 되었으며"},{"r":"단7:20","t":"또 그것의 머리에는 열 뿔이 있고 그 외에 또 다른 뿔이 나오매 세 뿔이 그 앞에 빠졌으며 그 뿔에는 눈도 있고 큰 말하는 입도 있고 그 모양이 동류보다 강하여 보인 것이라"},{"r":"단11:36","t":"이 왕이 자기 뜻대로 행하며 스스로 높여 모든 신보다 크다 하며 비상한 말로 신들의 신을 대적하며 형통하기를 분노하심이 쉴 때까지 하리니 이는 그 작정된 일이 반드시 이룰 것임이니라"},{"r":"살후2:4","t":"저는 대적하는 자라 범사에 일컫는 하나님이나 숭배함을 받는 자 위에 뛰어나 자존하여 하나님 성전에 앉아 자기를 보여 하나님이라 하느니라"},{"r":"계11:2","t":"성전 밖 마당은 척량하지 말고 그냥 두라 이것을 이방인에게 주었은즉 저희가 거룩한 성을 마흔 두 달 동안 짓밟으리라"},{"r":"계12:6","t":"그 녀자가 광야로 도망하매 거기서 일천 이백 육십일 동안 저를 양육하기 위하여 하나님의 예비하신 곳이 있더라"}],"계13:7":[{"r":"계11:7","t":"저희가 그 증거를 마칠 때에 무저갱으로부터 올라오는 짐승이 저희로 더불어 전쟁을 일으켜 저희를 이기고 저희를 죽일 터인즉"},{"r":"계12:17","t":"용이 녀자에게 분노하여 돌아가서 그 녀자의 남은 자손 곧 하나님의 계명을 지키며 예수의 증거를 가진 자들로 더불어 싸우려고 바다 모래 위에 섰더라"},{"r":"단7:21","t":"내가 본즉 이 뿔이 성도들로 더불어 싸워 이기었더니"}],"계13:8":[{"r":"행2:23","t":"그가 하나님의 정하신 뜻과 미리 아신 대로 내어준 바 되었거늘 너희가 법 없는 자들의 손을 빌어 못 박아 죽였으나"},{"r":"벧전1:19,20","t":"오직 흠 없고 점 없는 어린 양 같은 그리스도의 보배로운 피로 한 것이니라"},{"r":"계5:6","t":"내가 또 보니 보좌와 네 생물과 장로들 사이에 어린 양이 섰는데 일찍 죽임을 당한 것 같더라 일곱 뿔과 일곱 눈이 있으니 이 눈은 온 땅에 보내심을 입은 하나님의 일곱 영이더라"},{"r":"계3:5","t":"이기는 자는 이와 같이 흰 옷을 입을 것이요 내가 그 이름을 생명책에서 반드시 흐리지 아니하고 그 이름을 내 아버지 앞과 그 천사들 앞에서 시인하리라"},{"r":"계3:10","t":"네가 나의 인내의 말씀을 지켰은즉 내가 또한 너를 지키어 시험의 때를 면하게 하리니 이는 장차 온 세상에 임하여 땅에 거하는 자들을 시험할 때라"}],"계14:1":[{"r":"계5:6","t":"내가 또 보니 보좌와 네 생물과 장로들 사이에 어린 양이 섰는데 일찍 죽임을 당한 것 같더라 일곱 뿔과 일곱 눈이 있으니 이 눈은 온 땅에 보내심을 입은 하나님의 일곱 영이더라"},{"r":"시2:6","t":"내가 나의 왕을 내 거룩한 산 시온에 세웠다 하시리로다"},{"r":"히12:22","t":"그러나 너희가 이른 곳은 시온산과 살아계신 하나님의 도성인 하늘의 예루살렘과 천만 천사와"},{"r":"계7:4","t":"내가 인 맞은 자의 수를 들으니 이스라엘 자손의 각 지파 중에서 인 맞은 자들이 십 사만 사천이니"},{"r":"계7:3","t":"가로되 우리가 우리 하나님의 종들의 이마에 인치기까지 땅이나 바다나 나무나 해하지 말라 하더라"},{"r":"계3:12","t":"이기는 자는 내 하나님 성전에 기둥이 되게 하리니 그가 결코 다시 나가지 아니하리라 내가 하나님의 이름과 하나님의 성 곧 하늘에서 내 하나님께로부터 내려 오는 새 예루살렘의 이름과 나의 새 이름을 그이 위에 기록하리라"}],"계14:10":[{"r":"계16:19","t":"큰 성이 세 갈래로 갈라지고 만국의 성들도 무너지니 큰 성 바벨론이 하나님 앞에 기억하신 바 되어 그의 맹렬한 진노의 포도주 잔을 받으매"},{"r":"욥21:20","t":"자기의 멸망을 자기의 눈으로 보게 하시며 전능자의 진노를 마시게 하셔야 할 것이니라"},{"r":"계18:6","t":"그가 준 그대로 그에게 주고 그의 행위대로 갑절을 갚아주고 그의 섞은 잔에도 갑절이나 섞어 그에게 주라"},{"r":"사1:22","t":"네 은은 찌끼가 되었고 너의 포도주에는 물이 섞였도다"},{"r":"계20:10","t":"또 저희를 미혹하는 마귀가 불과 류황 못에 던지우니 거기는 그 짐승과 거짓 선지자들도 있어 세세토록 밤낮 괴로움을 받으리라"}],"계14:11":[{"r":"사34:10","t":"낮에나 밤에나 꺼지지 않고 그 연기가 끊임 없이 떠오를 것이며 세세에 황무하여 그리로 지날 자가 영영히 없겠고"},{"r":"계18:18","t":"그 불붙는 연기를 보고 외쳐 가로되 이 큰 성과 같은 성이 어디 있느뇨 하며"},{"r":"계19:3","t":"두번째 가로되 할렐루야 하더니 그 연기가 세세토록 올라가더라"},{"r":"창19:28","t":"소돔과 고모라와 그 온 들을 향하여 눈을 들어 연기가 옹기점 연기같이 치밀음을 보았더라"},{"r":"계4:8","t":"네 생물이 각각 여섯 날개가 있고 그 안과 주위에 눈이 가득하더라 그들이 밤낮 쉬지 않고 이르기를 거룩하다, 거룩하다, 거룩하다, 주 하나님 곧 전능하신 이여, 전에도 계셨고 이제도 계시고 장차 오실 자라 하고"}],"계14:12":[{"r":"계13:10","t":"사로잡는 자는 사로잡힐 것이요 칼에 죽이는 자는 자기도 마땅히 칼에 죽으리니 성도들의 인내와 믿음이 여기 있느니라"},{"r":"계12:17","t":"용이 녀자에게 분노하여 돌아가서 그 녀자의 남은 자손 곧 하나님의 계명을 지키며 예수의 증거를 가진 자들로 더불어 싸우려고 바다 모래 위에 섰더라"}],"계14:9":[{"r":"계13:15","t":"저가 권세를 받아 그 짐승의 우상에게 생기를 주어 그 짐승의 우상으로 말하게 하고 또 짐승의 우상에게 경배하지 아니하는 자는 몇이든지 다 죽이게 하더라"},{"r":"계13:16","t":"저가 모든 자 곧 작은 자나 큰 자나 부자나 빈궁한 자나 자유한 자나 종들로 그 오른손에나 이마에 표를 받게 하고"}],"계17:15":[{"r":"계17:1","t":"또 일곱 대접을 가진 일곱 천사 중 하나가 와서 내게 말하여 가로되 이리 오라 많은 물 위에 앉은 큰 음녀의 받을 심판을 네게 보이리라"},{"r":"사8:7","t":"그러므로 주 내가 흉용하고 창일한 큰 하수 곧 앗수르 왕과 그의 모든 위력으로 그들 위에 덮을 것이라 그 모든 곬에 차고 모든 언덕에 넘쳐"}],"계18:2":[{"r":"계14:8","t":"또 다른 천사 곧 둘째가 그 뒤를 따라 말하되 무너졌도다, 무너졌도다 큰 성 바벨론이여 모든 나라를 그 음행으로 인하여 진노의 포도주로 먹이던 자로다 하더라"},{"r":"사13:21","t":"오직 들짐승들이 거기 엎드리고 부르짖는 짐승이 그 가옥에 충만하며 타조가 거기 깃들이며 들 양이 거기서 뛸 것이요"},{"r":"사34:14","t":"들짐승이 이리와 만나며 수염소가 그 동류를 부르며 올빼미가 거기 거하여 쉬는 처소를 삼으며"},{"r":"렘50:39","t":"그러므로 사막의 들짐승이 시랑과 함께 거기 거하겠고 타조도 그 중에 깃들일 것이요 영영히 거민이 없으며 대대에 거할 자가 없으리라"},{"r":"렘51:37","t":"바벨론이 황폐한 무더기가 되어서 시랑의 거처와 놀람과 치솟거리가 되고 거민이 없으리라"},{"r":"습2:14,15","t":"각양 짐승이 그 가운데 떼로 누울 것이며 창에서 울 것이며 문턱이 적막하리니 백향목으로 지은 것이 벗겨졌음이라"},{"r":"계16:13","t":"또 내가 보매 개구리 같은 세 더러운 영이 용의 입과 짐승의 입과 거짓 선지자의 입에서 나오니"},{"r":"사14:23","t":"내가 또 그것으로 고슴도치의 굴혈과 물웅덩이가 되게 하고 또 멸망의 비로 소제하리라 나 만군의 여호와의 말이니라"},{"r":"사34:11","t":"당아와 고슴도치가 그 땅을 차지하며 부엉이와 까마귀가 거기 거할 것이라 여호와께서 혼란의 줄과 공허의 추를 에돔에 베푸실 것인즉"}],"계1:1":[{"r":"요17:7,8","t":"지금 저희는 아버지께서 내게 주신 것이 다 아버지께로서 온 것인 줄 알았나이다"},{"r":"요8:26","t":"내가 너희를 대하여 말하고 판단할 것이 많으나 나를 보내신 이가 참되시매 내가 그에게 들은 그것을 세상에게 말하노라 하시되"},{"r":"요14:10","t":"나는 아버지 안에 있고 아버지는 내 안에 계신 것을 네가 믿지 아니하느냐  내가 너희에게 이르는 말이 스스로 하는 것이 아니라 아버지께서 내 안에 계셔 그의 일을 하시는 것이라"},{"r":"계22:6","t":"또 그가 내게 말하기를 이 말은 신실하고 참된 자라 주 곧 선지자들의 영의 하나님이 그의 종들에게 결코 속히 될 일을 보이시려고 그의 천사를 보내셨도다"},{"r":"계22:16","t":"나 예수는 교회들을 위하여 내 사자를 보내어 이것들을 너희에게 증거하게 하였노라 나는 다윗의 뿌리요 자손이니 곧 광명한 새벽별이라 하시더라"}],"계1:2":[{"r":"요19:35","t":"이를 본 자가 증거하였으니 그 증거가 참이라 저가 자기의 말하는 것이 참인 줄 알고 너희로 믿게 하려 함이니라"},{"r":"계6:9","t":"다섯째 인을 떼실 때에 내가 보니 하나님의 말씀과 저희의 가진 증거를 인하여 죽임을 당한 령혼들이 제단 아래 있어"},{"r":"계12:17","t":"용이 녀자에게 분노하여 돌아가서 그 녀자의 남은 자손 곧 하나님의 계명을 지키며 예수의 증거를 가진 자들로 더불어 싸우려고 바다 모래 위에 섰더라"},{"r":"계19:10","t":"내가 그 발 앞에 엎드려 경배하려 하니 그가 나더러 말하기를 나는 너와 및 예수의 증거를 받은 네 형제들과 같이 된 종이니 삼가 그리하지말고 오직 하나님께 경배하라 예수의 증거는 대언의 영이라 하더라"},{"r":"고전1:6","t":"그리스도의 증거가 너희 중에 견고케 되어"},{"r":"계1:11","t":"가로되 너 보는 것을 책에 써서 에베소, 서머나, 버가모, 두아디라, 사데, 빌라델비아, 라오디게아 일곱 교회에 보내라 하시기로"},{"r":"계1:19","t":"그러므로 네 본 것과 이제 있는 일과 장차 될 일을 기록하라"}],"계1:3":[{"r":"계22:7","t":"보라, 내가 속히 오리니 이 책의 예언의 말씀을 지키는 자가 복이 있으리라 하더라"},{"r":"눅11:28","t":"예수께서 가라사대 오히려 하나님의 말씀을 듣고 지키는 자가 복이 있느니라 하시니라"},{"r":"요8:51","t":"진실로 진실로 너희에게 이르노니 사람이 내 말을 지키면 죽음을 영원히 보지 아니하리라"},{"r":"요일2:3","t":"우리가 그의 계명을 지키면 이로써 우리가 저를 아는 줄로 알 것이요"},{"r":"계22:10","t":"또 내게 말하되 이 책의 예언의 말씀을 인봉하지 말라 때가 가까우니라"},{"r":"요일2:18","t":"아이들아 이것이 마지막 때라 적그리스도가 이르겠다 함을 너희가 들은 것과 같이 지금도 많은 적그리스도가 일어났으니 이러므로 우리가 마지막 때인 줄 아노라"},{"r":"롬13:11","t":"또한 너희가 이 시기를 알거니와 자다가 깰 때가 벌써 되었으니 이는 이제 우리의 구원이 처음 믿을 때보다 가까왔음이니라"}],"계1:7":[{"r":"단7:13","t":"내가 또 밤 이상 중에 보았는데 인자 같은 이가 하늘 구름을 타고 와서 옛적부터 항상 계신 자에게 나아와 그 앞에 인도되매"},{"r":"마16:27","t":"인자가 아버지의 영광으로 그 천사들과 함께 오리니 그 때에 각 사람의 행한 대로 갚으리라"},{"r":"슥12:10","t":"내가 다윗의 집과 예루살렘 거민에게 은총과 간구하는 심령을 부어 주리니 그들이 그 찌른바 그를 바라보고 그를 위하여 애통하기를 독자를 위하여 애통하듯 하며 그를 위하여 통곡하기를 장자를 위하여 통곡하듯 하리로다"},{"r":"요19:37","t":"또 다른 성경에 저희가 그 찌른 자를 보리라 하였느니라"}],"계20:1":[{"r":"계9:1","t":"다섯째 천사가 나팔을 불매 내가 보니 하늘에서 땅에 떨어진 별 하나가 있는데 저가 무저갱의 열쇠를 받았더라"},{"r":"계1:18","t":"곧 산 자라 내가 전에 죽었었노라 볼지어다 이제 세세토록 살아 있어 사망과 음부의 열쇠를 가졌노니"}],"계20:10":[{"r":"계20:3","t":"무저갱에 던져 잠그고 그 위에 인봉하여 천년이 차도록 다시는 만국을 미혹하지 못하게 하였다가 그 후에는 반드시 잠간 놓이리라"},{"r":"계20:8","t":"나와서 땅의 사방 백성 곧 곡과 마곡을 미혹하고 모아 싸움을 붙이리니 그 수가 바다 모래 같으리라"},{"r":"계19:20","t":"짐승이 잡히고 그 앞에서 이적을 행하던 거짓 선지자도 함께 잡혔으니 이는 짐승의 표를 받고 그의 우상에게 경배하던 자들을 이적으로 미혹하던 자라 이 둘이 산 채로 류황불 붙는 못에 던지우고"},{"r":"계16:13","t":"또 내가 보매 개구리 같은 세 더러운 영이 용의 입과 짐승의 입과 거짓 선지자의 입에서 나오니"}],"계20:11":[{"r":"시102:26","t":"천지는 없어지려니와 주는 영존하시겠고 그것들은 다 옷같이 낡으리니 의복같이 바꾸시면 바뀌려니와"},{"r":"계12:8","t":"이기지 못하여 다시 하늘에서 저희의 있을 곳을 얻지 못한지라"},{"r":"단2:35","t":"때에 철과 진흙과 놋과 은과 김이 다 부숴져 여름 타작 마당의 겨같이 되어 바람에 불려 간 곳이 없었고 우상을 친돌은 태산을 이루어 온 세계에 가득하였었나이다"}],"계20:12":[{"r":"단7:10","t":"불이 강처럼 흘러 그 앞에서 나오며 그에게 수종하는 자는 천천이요 그 앞에 시위한 자는 만만이며 심판을 베푸는데 책들이 펴 놓였더라"},{"r":"계3:5","t":"이기는 자는 이와 같이 흰 옷을 입을 것이요 내가 그 이름을 생명책에서 반드시 흐리지 아니하고 그 이름을 내 아버지 앞과 그 천사들 앞에서 시인하리라"},{"r":"롬14:10","t":"네가 어찌하여 네 형제를 판단하느뇨 어찌하여 네 형제를 업신여기느뇨 우리가 다 하나님의 심판대 앞에 서리라"},{"r":"고후5:10","t":"이는 우리가 다 반드시 그리스도의 심판대 앞에 드러나 각각 선악간에 그 몸으로 행한 것을 따라 받으려 함이라"},{"r":"계11:18","t":"이방들이 분노하매 주의 진노가 임하여 죽은 자를 심판하시며 종 선지자들과 성도들과 또 무론대소하고 주의 이름을 경외하는 자들에게 상 주시며 또 땅을 망하게 하는 자들을 멸망시키실 때로소이다 하더라"},{"r":"마16:27","t":"인자가 아버지의 영광으로 그 천사들과 함께 오리니 그 때에 각 사람의 행한 대로 갚으리라"}],"계20:13":[{"r":"계6:8","t":"내가 보매 청황색 말이 나오는데 그 탄 자의 이름은 사망이니 음부가 그 뒤를 따르더라 저희가 땅 사분 일의 권세를 얻어 검과 흉년과 사망과 땅의 짐승으로써 죽이더라"}],"계20:14":[{"r":"계21:4","t":"모든 눈물을 그 눈에서 씻기시매 다시 사망이 없고 애통하는 것이나 곡하는 것이나 아픈 것이 다시 있지 아니하리니 처음 것들이 다 지나갔음이러라"},{"r":"눅20:36","t":"저희는 다시 죽을 수도 없나니 이는 천사와 동등이요 복활의 자녀로서 하나님의 자녀임이니라"},{"r":"고전15:26","t":"맨 나중에 멸망 받을 원수는 사망이니라"},{"r":"계20:6","t":"이 첫째 복활에 참여하는 자들은 복이 있고 거룩하도다 둘째 사망이 그들을 다스리는 권세가 없고 도리어 그들이 하나님과 그리스도의 제사장이 되어 천년 동안 그리스도로 더불어 왕노릇하리라"}],"계20:15":[{"r":"마13:42","t":"풀무불에 던져 넣으리니 거기서 울며 이를 갊이 있으리라"},{"r":"마13:50","t":"풀무불에 던져 넣으리니 거기서 울며 이를 갊이 있으리라"}],"계20:2":[{"r":"계12:9","t":"큰 용이 내어쫓기니 옛 뱀 곧 마귀라고도 하고 사단이라고도 하는 온 천하를 꾀는 자라 땅으로 내어쫓기니 그의 사자들도 저와 함께 내어 쫓기니라"},{"r":"벧후2:4","t":"하나님이 범죄한 천사들을 용서치 아니하시고 지옥에 던져 어두운 구덩이에 두어 심판 때까지 지키게 하셨으며"},{"r":"유1:6","t":"또 자기 지위를 지키지 아니하고 자기 처소를 떠난 천사들을 큰 날의 심판까지 영원한 결박으로 흑암에 가두셨으며"}],"계20:3":[{"r":"단6:17","t":"이에 돌을 굴려다가 굴 아구를 막으매 왕이 어인과 귀인들의 인을 쳐서 봉하였으니 이는 다니엘 처치한 것을 변개함이 없게 하려 함이었더라"},{"r":"마27:66","t":"저희가 파수군과 함께 가서 돌을 인봉하고 무덤을 굳게 하니라"},{"r":"계20:8","t":"나와서 땅의 사방 백성 곧 곡과 마곡을 미혹하고 모아 싸움을 붙이리니 그 수가 바다 모래 같으리라"},{"r":"계20:10","t":"또 저희를 미혹하는 마귀가 불과 류황 못에 던지우니 거기는 그 짐승과 거짓 선지자들도 있어 세세토록 밤낮 괴로움을 받으리라"}],"계20:4":[{"r":"단7:9","t":"내가 보았는데 왕좌가 놓이고 옛적부터 항상 계신 이가 좌정하셨는데 그 옷은 희기가 눈 같고 그 머리털은 깨끗한 양의 털같고 그 보좌는 불꽃이요 그 바퀴는 붙는 불이며"},{"r":"마19:28","t":"예수께서 가라사대 내가 진실로 너희에게 이르노니 세상이 새롭게 되어 인자가 자기 영광의 보좌에 앉을 때에 나를 좇는 너희도 열 두 보좌에 앉아 이스라엘 열 두 지파를 심판하리라"},{"r":"눅22:30","t":"너희로 내 나라에 있어 내 상에서 먹고 마시며 또는 보좌에 앉아 이스라엘 열 두 지파를 다스리게 하려 하노라"},{"r":"계3:21","t":"이기는 그에게는 내가 내 보좌에 함께 앉게 하여 주기를 내가 이기고 아버지 보좌에 함께 앉은 것과 같이 하리라"},{"r":"단7:22","t":"옛적부터 항상 계신 자가 와서 지극히 높으신 자의 성도를 위하여 신원하셨고 때가 이르매 성도가 나라를 얻었더라"},{"r":"고전6:2,3(?)","t":"성도가 세상을 판단할 것을 너희가 알지 못하느냐 세상도 너희에게 판단을 받겠거든 지극히 작은 일 판단하기를 감당치 못하겠느냐"},{"r":"계6:9","t":"다섯째 인을 떼실 때에 내가 보니 하나님의 말씀과 저희의 가진 증거를 인하여 죽임을 당한 령혼들이 제단 아래 있어"},{"r":"계13:12","t":"저가 먼저 나온 짐승의 모든 권세를 그 앞에서 행하고 땅과 땅에 거하는 자들로 처음 짐승에게 경배하게 하니 곧 죽게 되었던 상처가 나은 자니라"},{"r":"계13:14~16","t":"짐승 앞에서 받은 바 이적을 행함으로 땅에 거하는 자들을 미혹하며 땅에 거하는 자들에게 이르기를 칼에 상하였다가 살아난 짐승을 위하여 우상을 만들라 하더라"},{"r":"요14:19","t":"조금 있으면 세상은 다시 나를 보지 못할 터이로되 너희는 나를 보리니 이는 내가 살았고 너희도 살겠음이라"},{"r":"딤후2:11","t":"미쁘다, 이 말이여 우리가 주와 함께 죽었으면 또한 함께 살 것이요"},{"r":"계20:6","t":"이 첫째 복활에 참여하는 자들은 복이 있고 거룩하도다 둘째 사망이 그들을 다스리는 권세가 없고 도리어 그들이 하나님과 그리스도의 제사장이 되어 천년 동안 그리스도로 더불어 왕노릇하리라"},{"r":"계5:10","t":"저희로 우리 하나님 앞에서 나라와 제사장을 삼으셨으니 저희가 땅에서 왕노릇하리로다 하더라"},{"r":"계22:1","t":"또 저가 수정같이 맑은 생명수의 강을 내게 보이니 하나님과 및 어린 양의 보좌로부터 나서"},{"r":"단7:18","t":"지극히 높으신 자의 성도들이 나라를 얻으리니 그 누림이 영원하고 영원하고 영원하리라"},{"r":"마20:21","t":"예수께서 가라사대 무엇을 원하느뇨  가로되 이 나의 두 아들을 주의 나라에서 하나는 주의 우편에 하나는 주의 좌편에 앉게 명하소서"},{"r":"마20:27","t":"너희 중에 누구든지 으뜸이 되고자 하는 자는 너희 종이 되어야 하리라"},{"r":"딤후2:12","t":"참으면 또한 함께 왕노릇 할 것이요 우리가 주를 부인하면 주도 우리를 부인하실 것이라"},{"r":"시45:16","t":"왕의 아들들이 왕의 열조를 계승할 것이라 왕이 저희로 온 세계의 군왕을 삼으리로다"}],"계20:6":[{"r":"계14:13","t":"또 내가 들으니 하늘에서 음성이 나서 가로되 기록하라 자금 이후로 주 안에서 죽는 자들은 복이 있도다 하시매 성령이 가라사대 그러하다 저희 수고를 그치고 쉬리니 이는 저희의 행한 일이 따름이라 하시더라"},{"r":"계20:14","t":"사망과 음부도 불못에 던지우니 이것은 둘째 사망 곧 불못이라"},{"r":"계2:11","t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다 이기는 자는 둘째 사망의 해를 받지 아니하리라"},{"r":"계21:8","t":"그러나 두려워하는 자들과, 믿지 아니하는 자들과, 흉악한 자들과, 살인자들과, 행음자들과, 술객들과, 우상 숭배자들과, 모든 거짓말 하는 자들은 불과 류황으로 타는 못에 참여하리니 이것이 둘째 사망이라"},{"r":"계1:6","t":"그 아버지 하나님을 위하여 우리를 나라와 제사장으로 삼으신 그에게 영광과 능력이 세세토록 있기를 원하노라 아멘"},{"r":"계20:4","t":"또 내가 보좌들을 보니 거기 앉은 자들이 있어 심판하는 권세를 받았더라 또 내가 보니 예수의 증거와 하나님의 말씀을 인하여 목 베임을 받은 자의 령혼들과 또 짐승과 그의 우상에게 경배하지도 아니하고 이마와 손에 그의 표를 받지도 아니한 자들이 살아서 그리스도로 더불어 천년 동안 왕노릇하니"}],"계20:7":[{"r":"계20:2","t":"용을 잡으니 곧 옛 뱀이요 마귀요 사단이라 잡아 일천년 동안 결박하여"}],"계20:8":[{"r":"겔38:2","t":"인자야 너는 마곡 땅에 있는 곡, 곧 로스와 메섹과 두발 왕에게로 얼굴을 향하고 그를 쳐서 예언하여"},{"r":"겔39:1","t":"그러므로 인자야 너는 곡을 쳐서 예언하여 이르기를 주 여호와의 말씀에 로스와 메섹과 두발 왕 곡아 내가 너를 대적하여"},{"r":"계20:3","t":"무저갱에 던져 잠그고 그 위에 인봉하여 천년이 차도록 다시는 만국을 미혹하지 못하게 하였다가 그 후에는 반드시 잠간 놓이리라"},{"r":"계20:10","t":"또 저희를 미혹하는 마귀가 불과 류황 못에 던지우니 거기는 그 짐승과 거짓 선지자들도 있어 세세토록 밤낮 괴로움을 받으리라"},{"r":"계16:14","t":"저희는 귀신의 영이라 이적을 행하여 온 천하 임금들에게 가서 하나님 곧 전능하신 이의 큰 날에 전쟁을 위하여 그들을 모으더라"}],"계20:9":[{"r":"사8:8","t":"흘러 유다에 들어와서 창일하고 목에까지 미치리라 임마누엘이여  그의 펴는 날개가 네 땅에 편만하리라 하셨느니라"},{"r":"겔38:9","t":"네가 올라오되 너와 네 모든 떼와 너와 함께한 많은 백성이 광풍같이 이르고 구름 같이 땅을 덮으리라"},{"r":"겔38:16","t":"구름이 땅에 덮임 같이 내 백성 이스라엘을 치러 오리라 곡아 끝날에 내가 너를 이끌어다가 내 땅을 치게 하리니 이는 내가 너로 말미암아 이방 사람의 목전에서 내 거룩함을 나타내어 그들로 다 나를 알게 하려 함이니라"},{"r":"합1:6","t":"보라, 내가 사납고 성급한 백성 곧 땅의 넓은 곳으로 다니며 자기의 소유 아닌 거할 곳들을 점령하는 갈대아 사람을 일으켰나니"},{"r":"히13:11","t":"이는 죄를 위한 짐승의 피는 대제사장이 가지고 성소에 들어가고 그 육체는 영문 밖에서 불사름이니라"},{"r":"계13:13","t":"큰 이적을 행하되 심지어 사람들 앞에서 불이 하늘로부터 땅에 내려오게 하고"},{"r":"시132:13","t":"여호와께서 시온을 택하시고 자기 거처를 삼고자 하여 이르시기를"},{"r":"계13:13","t":"큰 이적을 행하되 심지어 사람들 앞에서 불이 하늘로부터 땅에 내려오게 하고"}],"계21:3":[{"r":"레26:11,12","t":"내가 내 장막을 너희 중에 세우리니 내 마음이 너희를 싫어하지 아니할 것이며"},{"r":"요1:14","t":"말씀이 육신이 되어 우리 가운데 거하시매 우리가 그 영광을 보니 아버지의 독생자의 영광이요 은혜와 진리가 충만하더라"},{"r":"계7:15","t":"그러므로 그들이 하나님의 보좌 앞에 있고 또 그의 성전에서 밤낮 하나님을 섬기매 보좌에 앉으신 이가 그들 위에 장막을 치시리니"}],"계21:5":[{"r":"계4:2","t":"내가 곧 성령에 감동하였더니 보라 하늘에 보좌를 베풀었고 그 보좌 위에 앉으신 이가 있는데"},{"r":"계4:9","t":"그 생물들이 영광과 존귀와 감사를 보좌에 앉으사 세세토록 사시는 이에게 돌릴 때에"},{"r":"계5:1","t":"내가 보매 보좌에 앉으신 이의 오른손에 책이 있으니 안팎으로 썼고 일곱 인으로 봉하였더라"},{"r":"계20:11","t":"또 내가 크고 흰 보좌와 그 위에 앉으신 자를 보니 땅과 하늘이 그 앞에서 피하여 간 데 없더라"},{"r":"고후5:17","t":"그런즉 누구든지 그리스도 안에 있으면 새로운 피조물이라 이전 것은 지나갔으니 보라  새것이 되었도다"},{"r":"계22:6","t":"또 그가 내게 말하기를 이 말은 신실하고 참된 자라 주 곧 선지자들의 영의 하나님이 그의 종들에게 결코 속히 될 일을 보이시려고 그의 천사를 보내셨도다"},{"r":"계3:14","t":"라오디게아 교회의 사자에게 편지하기를 아멘이시요 충성되고 참된 증인이시요 하나님의 창조의 근본이신 이가 가라사대"},{"r":"계19:11","t":"또 내가 하늘이 열린 것을 보니 보라 백마와 탄 자가 있으니 그 이름은 충신과 진실이라 그가 공의로 심판하며 싸우더라"},{"r":"딤전1:15","t":"미쁘다 모든 사람이 받을 만한 이 말이여 그리스도 예수께서 죄인을 구원하시려고 세상에 임하셨다 하였도다 죄인 중에 내가 괴수니라"}],"계21:6":[{"r":"계10:6","t":"세세토록 살아계신 자 곧 하늘과 그 가운데 있는 물건이며 땅과 그 가운데 있는 물건이며 바다와 그 가운데 있는 물건을 창조하신 이를 가리켜 맹서하여 가로되 지체하지 아니하리니"},{"r":"계1:8","t":"주 하나님이 가라사대 나는 알파와 오메가라 이제도 있고 전에도 있었고 장차 올 자요 전능한 자라 하시더라"},{"r":"계22:13","t":"나는 알파의 오메가요 처음과 나중이요 시작과 끝이라"},{"r":"계22:17","t":"성령과 신부가 말씀하시기를 오라 하시는도다 듣는 자도 오라 할 것이요 목마른 자도 올 것이요 또 원하는 자는 값없이 생명수를 받으라 하시더라"},{"r":"요4:10","t":"예수께서 대답하여 가라사대 네가 만일 하나님의 선물과 또 네게 물좀 달라 하는 이가 누구인줄 알았더면 네가 그에게 구하였을 것이요 그가 생수를 네게 주었으리라"},{"r":"요7:37","t":"명절 끝날 곧 큰날에 예수께서 서서 외쳐 가라사대 누구든지 목마르거든 내게로 와서 마시라"}],"계21:7":[{"r":"계2:7","t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다 이기는 그에게는 내가 하나님의 낙원에 있는 생명나무의 과실을 주어 먹게 하리라"},{"r":"계21:3","t":"내가 들으니 보좌에서 큰 음성이 나서 가로되 보라, 하나님의 장막이 사람들과 함께 있으매 하나님이 저희와 함께 거하시리니 저희는 하나님의 백성이 되고 하나님은 친히 저희와 함께 계셔서"},{"r":"고후6:18","t":"너희에게 아버지가 되고 너희는 내게 자녀가 되리라 전능하신 주의 말씀이니라 하셨느니라"}],"계22:1":[{"r":"계21:6","t":"또 내게 말씀하시되 이루었도다 나는 알파와 오메가요 처음과 나중이라 내가 생명수 샘물로 목마른 자에게 값없이 주리니"},{"r":"겔47:1","t":"그가 나를 데리고 전 문에 이르시니 전의 전면이 동을 향하였는데 그 문지방 밑에서 물이 나와서 동으로 흐르다가 전 우편 제단 남편으로 흘러 내리더라"},{"r":"슥14:8","t":"그 날에 생수가 예루살렘에서 솟아나서 절반은 동해로, 절반은 서해로 흐를 것이라 여름에도 겨울에도 그러하리라"},{"r":"시46:4","t":"한 시내가 있어 나뉘어 흘러 하나님의 성 곧 지극히 높으신 자의 장막의 성소를 기쁘게 하도다"}],"계22:12":[{"r":"계22:7","t":"보라, 내가 속히 오리니 이 책의 예언의 말씀을 지키는 자가 복이 있으리라 하더라"},{"r":"계22:20","t":"이것들을 증거하신 이가 가라사대 내가 진실로 속히 오리라  하시거늘 아멘 주 예수여  오시옵소서"},{"r":"사40:10","t":"보라, 주 여호와께서 장차 강한 자로 임하실 것이요 친히 그 팔로 다스리실 것이라 보라, 상급이 그에게 있고 보응이 그 앞에 있으며"},{"r":"사62:11","t":"여호와께서 땅 끝까지 반포하시되 너희는 딸 시온에게 이르라 보라, 네 구원이 임하느니라 보라, 상급이 그에게 있고 보응이 그 앞에 있느니라 하셨느니라"},{"r":"마16:27","t":"인자가 아버지의 영광으로 그 천사들과 함께 오리니 그 때에 각 사람의 행한 대로 갚으리라"}],"계22:18":[{"r":"신4:2","t":"내가 너희에게 명하는 말을 너희는 가감하지 말고 내가 너희에게 명하는 너희 하나님 여호와의 명령을 지키라"},{"r":"신12:32","t":"내가 너희에게 명하는 이 모든 말을 너희는 지켜 행하고 그것에 가감하지 말지니라"},{"r":"잠30:6","t":"너는 그 말씀에 더하지 말라 그가 너를 책망하시겠고 너는 거짓말 하는 자가 될까 두려우니라"}],"계22:19":[{"r":"계22:2","t":"길 가운데로 흐르더라 강 좌우에 생명나무가 있어 열 두 가지 실과를 맺히되 달마다 그 실과를 맺히고 그 나무 잎사귀들은 만국을 소성하기 위하여 있더라"},{"r":"계22:14","t":"그 두루마기를 빠는 자들은 복이 있으니 이는 저희가 생명나무에 나아가며 문들을 통하여 성에 들어갈 권세를 얻으려 함이로다"},{"r":"계21:2","t":"또 내가 보매 거룩한 성 새 예루살렘이 하나님께로부터 하늘에서 내려오니 그 예비한 것이 신부가 남편을 위하여 단장한 것 같더라"}],"계22:2":[{"r":"계21:21","t":"그 열 두 문은 열 두 진주니 문마다 한 진주요 성의 길은 맑은 유리같은 정김이더라"},{"r":"겔47:12","t":"강 좌우 가에는 각종 먹을 실과나무가 자라서 그 잎이 시들지 아니하며 실과가 끊치지 아니하고 달마다 새 실과를 맺으리니 그 물이 성소로 말미암아 나옴이라 그 실과는 먹을만하고 그 잎사귀는 약 재료가 되리라"},{"r":"계22:14","t":"그 두루마기를 빠는 자들은 복이 있으니 이는 저희가 생명나무에 나아가며 문들을 통하여 성에 들어갈 권세를 얻으려 함이로다"},{"r":"계22:19","t":"만일 누구든지 이 책의 예언의 말씀에서 제하여 버리면 하나님이 이 책에 기록된 생명나무와 및 거룩한 성에 참여함을 제하여 버리시리라"},{"r":"계2:7","t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다 이기는 그에게는 내가 하나님의 낙원에 있는 생명나무의 과실을 주어 먹게 하리라"},{"r":"창2:9","t":"여호와 하나님이 그 땅에서 보기에 아름답고 먹기에 좋은 나무가 나게 하시니 동산 가운데에는 생명나무와 선악을 알게하는 나무도 있더라"},{"r":"계21:24","t":"만국이 그 빛 가운데로 다니고 땅의 왕들이 자기 영광을 가지고 그리로 들어오리라"}],"계3:5":[{"r":"계2:7","t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다 이기는 그에게는 내가 하나님의 낙원에 있는 생명나무의 과실을 주어 먹게 하리라"},{"r":"계13:8","t":"죽임을 당한 어린 양의 생명책에 창세 이후로 녹명되지 못하고 이 땅에 사는 자들은 다 짐승에게 경배하리라"},{"r":"계17:8","t":"네가 본 짐승은 전에 있었다가 시방 없으나 장차 무저갱으로부터 올라와 멸망으로 들어갈 자니 땅에 거하는 자들로서 창세 이후로 생명책에 녹명되지 못한 자들이 이전에 있었다가 시방 없으나 장차 나올 짐승을 보고 기이히 여기리라"},{"r":"계20:12","t":"또 내가 보니 죽은 자들이 무론대소하고 그 보좌 앞에 섰는데 책들이 펴 있고 또 다른 책이 펴졌으니 곧 생명책이라 죽은 자들이 자기 행위를 따라 책들에 기록된 대로 심판을 받으니"},{"r":"계20:15","t":"누구든지 생명책에 기록되지 못한 자는 불못에 던지우더라"},{"r":"계21:27","t":"무엇이든지 속된 것이나 가증한 일 또는 거짓말하는 자는 결코 그리로 들어오지 못하되 오직 어린 양의 생명책에 기록된 자들 뿐이라"},{"r":"빌4:3","t":"또 참으로 나와 멍에를 같이 한 자 네게 구하노니 복음에 나와 함께 힘쓰던 저 부녀들을 돕고 또한 글레멘드와 그 위에 나의 동역자들을 도우라 그 이름들이 생명책에 있느니라"},{"r":"출32:32","t":"그러나 합의하시면 이제 그들의 죄를 사하시옵소서  그렇지 않사오면 원컨대 주의 기록하신 책에서 내 이름을 지워 버려주옵소서"},{"r":"마10:32","t":"누구든지 사람 앞에서 나를 시인하면 나도 하늘에 계신 내 아버지 앞에서 저를 시인할 것이요"},{"r":"눅12:8","t":"내가 또한 너희에게 말하노니 누구든지 사람 앞에서 나를 시인하면 인자도 하나님의 사자들 앞에서 저를 시인할 것이요"}],"계4:5":[{"r":"계8:5","t":"천사가 향로를 가지고 단 위의 불을 담아다가 땅에 쏟으매 뢰성과 음성과 번개와 지진이 나더라"},{"r":"계11:19","t":"이에 하늘에 있는 하나님의 성전이 열리니 성전 안에 하나님의 언약궤가 보이며 또 번개와 음성들과 뢰성과 지진과 큰 우박이 있더라"},{"r":"계16:18","t":"번개와 음성들과 뢰성이 있고 또 지진이 있어 어찌 큰지 사람이 땅에 있어 옴으로 이같이 큰 지진이 없었더라"},{"r":"출19:16","t":"제 삼일 아침에 우뢰와 번개와 빽빽한 구름이 산 위에 있고 나팔소리가 심히 크니 진중 모든 백성이 다 떨더라"},{"r":"슥4:2","t":"그가 내게 묻되 네가 무엇을 보느냐 내가 대답하되 내가 보니 순김 등대가 있는데 그 꼭대기에 주발 같은 것이 있고 또 그 등대에 일곱 등잔이 있으며 그 등대 꼭대기 등잔에는 일곱 관이 있고"},{"r":"계1:4","t":"요한은 아시아에 있는 일곱 교회에 편지하노니 이제도 계시고 전에도 계시고 장차 오실 이와 그 보좌 앞에 일곱 영과"}],"계6:14":[{"r":"계20:11","t":"또 내가 크고 흰 보좌와 그 위에 앉으신 자를 보니 땅과 하늘이 그 앞에서 피하여 간 데 없더라"},{"r":"계21:1","t":"또 내가 새 하늘과 새 땅을 보니 처음 하늘과 처음 땅이 없어졌고 바다도 다시 있지 않더라"},{"r":"계16:20","t":"각 섬도 없어지고 산악도 간데 없더라"},{"r":"사54:10","t":"산들은 떠나며 작은 산들은 옮길지라도 나의 인자는 네게서 떠나지 아니하며 화평케 하는 나의 언약은 옮기지 아니하리라 너를 긍휼히 여기는 여호와의 말이니라"},{"r":"렘4:24","t":"내가 산들을 본즉 다 진동하며 작은 산들도 요동하며"},{"r":"겔38:20","t":"바다의 고기들과 공중의 새들과 들의 짐승들과 땅에 기는 모든 벌레와 지면에 있는 모든 사람이 내 앞에서 떨 것이며 모든 산이 무너지며 절벽이 떨어지며 모든 성벽이 땅에 무너지리라"},{"r":"나1:5","t":"그로 인하여 산들이 진동하며 작은 산들이 녹고 그의 앞에서는 땅 곧 세계와 그 가운데 거하는 자들이 솟아 오르는도다"}],"계6:15":[{"r":"사2:19","t":"사람들이 암혈과 토굴로 들어가서 여호와께서 일어나사 땅을 진동시키는 그의 위엄과 그 광대하심의 영광을 피할 것이라"},{"r":"사2:21","t":"암혈과 험악한 바위틈에 들어가서 여호와께서 일어나사 땅을 진동시키시는 그의 위엄과 그 광대하심의 영광을 피하리라"}],"계6:16":[{"r":"호10:8","t":"이스라엘의 죄된 아웬의 산당은 패괴되어 가시와 찔레가 그 단 위에 날것이니 그 때에 저희가 산더러 우리를 가리우라 할 것이요 작은 산더러 우리 위에 무너지라 하리라"},{"r":"눅23:30","t":"그 때에 사람이 산들을 대하여 우리 위에 무너지라 하며 작은 산들을 대하여 우리를 덮으라 하리라"},{"r":"계4:2","t":"내가 곧 성령에 감동하였더니 보라 하늘에 보좌를 베풀었고 그 보좌 위에 앉으신 이가 있는데"}],"계6:17":[{"r":"렘30:7","t":"슬프다 그 날이여  비할데 없이 크니 이는 야곱의 환난의 때가 됨이로다마는 그가 이에서 구하여 냄을 얻으리로다"},{"r":"욜2:11","t":"여호와께서 그 군대 앞에서 소리를 발하시고 그 진은 심히 크고 그 명령을 행하는 자는 강하니 여호와의 날이 크고 심히 두렵도다 당할 자가 누구이랴"},{"r":"욜2:31","t":"여호와의 크고 두려운 날이 이르기 전에 해가 어두워지고 달이 핏빛 같이 변하려니와"},{"r":"습1:14","t":"여호와의 큰 날이 가깝도다 가깝고도 심히 빠르도다 여호와의 날의 소리로다 용사가 거기서 심히 애곡하는도다"},{"r":"스9:15","t":"이스라엘 하나님 여호와여  주는 의롭도소이다 우리가 남아 피한 것이 오늘날과 같사옵거늘 도리어 주께 범죄하였사오니 이로 인하여 주 앞에 한 사람도 감히 서지 못하겠나이다"},{"r":"시76:7","t":"주 곧 주는 경외할 자시니 주께서 한번 노하실 때에 누가 주의 목전에 서리이까"},{"r":"말3:2","t":"그의 임하는 날을 누가 능히 당하며 그의 나타나는 때에 누가 능히 서리요 그는 김을 연단하는 자의 불과 표백하는 자의 잿물과 같을 것이라"},{"r":"눅21:36","t":"이러므로 너희는 장차 올 이 모든 일을 능히 피하고 인자 앞에 서도록 항상 기도하며 깨어 있으라  하시니라"}],"계7:1":[{"r":"렘49:36","t":"하늘의 사방에서부터 사방 바람을 엘람에 이르게 하여 그들을 사방으로 흩으리니 엘람에서 쫓겨난 자의 이르지 아니하는 나라가 없으리라"},{"r":"단7:2","t":"다니엘이 진술하여 가로되 내가 밤에 이상을 보았는데 하늘의 네 바람이 큰 바다로 몰려 불더니"},{"r":"계7:3","t":"가로되 우리가 우리 하나님의 종들의 이마에 인치기까지 땅이나 바다나 나무나 해하지 말라 하더라"}],"계7:2":[{"r":"계9:4","t":"저희에게 이르시되 땅의 풀이나 푸른 것이나 각종 수목은 해하지 말고 오직 이마에 하나님의 인 맞지 아니한 사람들만 해하라 하시더라"},{"r":"계16:12","t":"또 여섯째가 그 대접을 큰 강 유브라데에 쏟으매 강물이 말라서 동방에서 오는 왕들의 길이 예비되더라"}],"계7:3":[{"r":"계14:1","t":"또 내가 보니 어린 양이 시온 산에 섰고 그와 함께 십 사만 사천이 섰는데 그 이마에 어린 양의 이름과 그 아버지의 이름을 쓴 것이 있도다"},{"r":"계22:4","t":"그의 얼굴을 볼 터이요 그의 이름도 저희 이마에 있으리라"},{"r":"겔9:4","t":"이르시되 너는 예루살렘 성읍 중에 순행하여 그 가운데서 행하는 모든 가증한 일로 인하여 탄식하며 우는 자의 이마에 표하라 하시고"},{"r":"계13:16","t":"저가 모든 자 곧 작은 자나 큰 자나 부자나 빈궁한 자나 자유한 자나 종들로 그 오른손에나 이마에 표를 받게 하고"},{"r":"겔3:8,9","t":"내가 그들의 얼굴을 대하도록 네 얼굴을 굳게 하였고 그들의 이마를 대하도록 네 이마를 굳게 하였으되"},{"r":"계6:6","t":"내가 네 생물 사이로서 나는 듯하는 음성을 들으니 가로되 한 데나리온에 밀 한 되요 한 데나리온에 보리 석 되로다 또 감람유와 포도주는 해치 말라 하더라"},{"r":"계9:4","t":"저희에게 이르시되 땅의 풀이나 푸른 것이나 각종 수목은 해하지 말고 오직 이마에 하나님의 인 맞지 아니한 사람들만 해하라 하시더라"}],"계7:4":[{"r":"계9:16","t":"마병대의 수는 이만만이니 내가 그들의 수를 들었노라"}],"계8:3":[{"r":"암9:1","t":"내가 보니 주께서 단 곁에 서서 이르시되 기둥 머리를 쳐서 문지방이 움직이게 하며 그것으로 부숴져서 무리의 머리에 떨어지게 하라 내가 그 남은 자를 칼로 살륙하리니 그 중에서 하나도 도망하지 못하며 그 중에서 하나도 피하지 못하리라"},{"r":"계5:8","t":"책을 취하시매 네 생물과 이십 사 장로들이 어린 양 앞에 엎드려 각각 거문고와 향이 가득한 김대접을 가졌으니 이 향은 성도의 기도들이라"},{"r":"계9:13","t":"여섯째 천사가 나팔을 불매 내가 들으니 하나님 앞 김단 네 뿔에서 한 음성이 나서"},{"r":"출30:1","t":"너는 분향할 단을 만들지니 곧 조각목으로 만들되"},{"r":"출30:3","t":"단 상면과 전후 좌우면과 뿔을 정김으로 싸고 주위에 김테를 두를지며"}],"계8:4":[{"r":"시141:2","t":"나의 기도가 주의 앞에 분향함과 같이 되며 나의 손드는 것이 저녁 제사같이 되게 하소서"}],"고전10:11":[{"r":"롬13:11","t":"또한 너희가 이 시기를 알거니와 자다가 깰 때가 벌써 되었으니 이는 이제 우리의 구원이 처음 믿을 때보다 가까왔음이니라"},{"r":"롬4:23","t":"저에게 의로 여기셨다 기록된 것은 아브라함만 위한 것이 아니요"}],"고전10:31":[{"r":"골3:17","t":"또 무엇을 하든지 말에나 일에나 다 주 예수의 이름으로 하고 그를 힘입어 하나님 아버지께 감사하라"},{"r":"벧전4:11","t":"만일 누가 말하려면 하나님의 말씀을 하는 것같이 하고 누가 봉사하려면 하나님의 공급하시는 힘으로 하는 것같이 하라 이는 범사에 예수 그리스도로 말미암아 하나님이 영광을 받으시게 하려 함이니 그에게 영광과 권능이 세세에 무궁토록 있느니라 아멘"}],"고전10:4":[{"r":"출17:6","t":"내가 거기서 호렙산 반석 위에 너를 대하여 서리니 너는 반석을 치라  그것에서 물이 나리니 백성이 마시리라 모세가 이스라엘 장로들의 목전에서 그대로 행하니라"}],"고전11:23":[{"r":"고전15:3","t":"내가 받은 것을 먼저 너희에게 전하였노니 이는 성경대로 그리스도께서 우리 죄를 위하여 죽으시고"},{"r":"갈1:12","t":"이는 내가 사람에게서 받은 것도 아니요 배운 것도 아니요 오직 예수 그리스도의 계시로 말미암은 것이라"},{"r":"고전11:23~25","t":"내가 너희에게 전한 것은 주께 받은 것이니 곧 주 예수께서 잡히시던 밤에 떡을 가지사"},{"r":"마26:26~28","t":"저희가 먹을 때에 예수께서 떡을 가지사 축복하시고 떼어 제자들을 주시며 가라사대 받아 먹으라 이것이 내 몸이니라 하시고"},{"r":"막14:22~24","t":"저희가 먹을 때에 예수께서 떡을 가지사 축복하시고 떼어 제자들에게 주시며 가라사대 받으라 이것이 내 몸이니라 하시고"},{"r":"눅22:19,20","t":"또 떡을 가져 사례하시고 떼어 저희에게 주시며 가라사대 이것은 너희를 위하여 주는 내 몸이라 너희가 이를 행하여 나를 기념하라  하시고"}],"고전11:26":[{"r":"요21:22","t":"예수께서 가라사대 내가 올 때까지 그를 머물게 하고자 할찌라도 네게 무슨 상관이냐  너는 나를 따르라 하시더라"}],"고전11:27":[{"r":"민9:10","t":"이스라엘 자손에게 일러 고하여 이르라 너희나 너희 후손 중에 시체로 인하여 불정케 되든지 먼 려행 중에 있든지 할지라도 다 여호와 앞에 마땅히 유월절을 지키되"},{"r":"민9:13","t":"그러나 사람이 정결도 하고 려행 중에도 있지 아니하면서 유월절을 지키지 아니하는 자는 그 백성 중에서 끊쳐지리니 이런 사람은 그 정기에 여호와께 예물을 드리지 아니하였은즉 그 죄를 당할지며"},{"r":"요13:27","t":"조각을 받은 후 곧 사단이 그 속에 들어간지라 이에 예수께서 유다에게 이르시되 네 하는 일을 속히 하라 하시니"},{"r":"요6:51","t":"나는 하늘로서 내려온 산 떡이니 사람이 이 떡을 먹으면 영생하리라 나의 줄 떡은 곧 세상의 생명을 위한 내 살이로라 하시니라"},{"r":"요6:53~56","t":"예수께서 이르시되 내가 진실로 진실로 너희에게 이르노니 인자의 살을 먹지 아니하고 인자의 피를 마시지 아니하면 너희 속에 생명이 없느니라"}],"고전11:28":[{"r":"고후13:5","t":"너희가 믿음에 있는가 너희 자신을 시험하고 너희 자신을 확증하라 예수 그리스도께서 너희 안에 계신 줄을 너희가 스스로 알지 못하느냐  그렇지 않으면 너희가 버리운 자니라"},{"r":"갈6:4","t":"각각 자기의 일을 살피라 그리하면 자랑할 것이 자기에게만 있고 남에게는 있지 아니하리니"}],"고전12:12":[{"r":"고전10:17","t":"떡이 하나요 많은 우리가 한 몸이니 이는 우리가 다 한 떡에 참여함이라"},{"r":"고전12:27","t":"너희는 그리스도의 몸이요 지체의 각 부분이라"}],"고전12:13":[{"r":"갈3:28","t":"너희는 유대인이나, 헬라인이나, 종이나, 자주자나, 남자나, 녀자 없이 다 그리스도 예수 안에서 하나이니라"},{"r":"골3:11","t":"거기는 헬라인과 유대인이나 할례당과 무할례당이나 야인이나 스구디아인이나 종이나 자유인이 분별이 있을 수 없나니 오직 그리스도는 만유시요 만유 안에 계시니라"},{"r":"엡2:13~17","t":"이제는 전에 멀리 있던 너희가 그리스도 예수 안에서 그리스도의 피로 가까와졌느니라"},{"r":"롬6:5","t":"만일 우리가 그의 죽으심을 본받아 련합한 자가 되었으면 또한 그의 복활을 본받아 련합한 자가 되리라"},{"r":"엡2:18","t":"이는 저로 말미암아 우리 둘이 한 성령 안에서 아버지께 나아감을 얻게 하려 하심이라"},{"r":"요7:37~39","t":"명절 끝날 곧 큰날에 예수께서 서서 외쳐 가라사대 누구든지 목마르거든 내게로 와서 마시라"}],"고전12:4":[{"r":"히2:4","t":"하나님도 표적들과 기사들과 여러가지 능력과 및 자기 뜻을 따라 성령의 나눠 주신 것으로써 저희와 함께 증거하셨느니라"},{"r":"롬12:6","t":"우리에게 주신 은혜대로 받은 은사가 각각 다르니 혹 예언이면 믿음의 분수대로"},{"r":"엡4:4~6","t":"몸이 하나이요, 성령이 하나이니 이와 같이 너희가 부르심의 한 소망 안에서 부르심을 입었느니라"}],"고전12:5":[{"r":"롬12:7","t":"혹 섬기는 일이면 섬기는 일로 혹 가르치는 자면 가르치는 일로"},{"r":"엡4:11","t":"그가 혹은 사도로, 혹은 선지자로, 혹은 복음 전하는 자로, 혹은 목사와 교사로 주셨으니"}],"고전14:1":[{"r":"고전16:14","t":"너희 모든 일을 사랑으로 행하라"},{"r":"고전12:1","t":"형제들아  신령한 것에 대하여는 내가 너희의 알지 못하기를 원치 아니하노니"},{"r":"고전12:31","t":"너희는 더욱 큰 은사를 사모하라  내가 또한 제일 좋은 길을 너희에게 보이리라"},{"r":"고전11:4","t":"무릇 남자로서 머리에 무엇을 쓰고 기도나 예언을 하는 자는 그 머리를 욕되게 하는 것이요"},{"r":"고전13:2","t":"내가 예언하는 능이 있어 모든 비밀과 모든 지식을 알고 또 산을 옮길 만한 모든 믿음이 있을지라도 사랑이 없으면 내가 아무 것도 아니요"}],"고전15:13":[{"r":"살전4:14","t":"우리가 예수의 죽었다가 다시 사심을 믿을진대 이와 같이 예수 안에서 자는 자들도 하나님이 저와 함께 데리고 오시리라"}],"고전15:15":[{"r":"행2:24","t":"하나님께서 사망의 고통을 풀어 살리셨으니 이는 그가 사망에게 매여 있을 수 없었음이라"}],"고전15:17":[{"r":"롬4:25","t":"예수는 우리 범죄함을 위하여 내어줌이 되고 또한 우리를 의롭다 하심을 위하여 살아나셨느니라"}],"고전15:18":[{"r":"살전4:16","t":"주께서 호령과 천사장의 소리와 하나님의 나팔로 친히 하늘로 좇아 강림하시리니 그리스도 안에서 죽은 자들이 먼저 일어나고"},{"r":"계14:13","t":"또 내가 들으니 하늘에서 음성이 나서 가로되 기록하라 자금 이후로 주 안에서 죽는 자들은 복이 있도다 하시매 성령이 가라사대 그러하다 저희 수고를 그치고 쉬리니 이는 저희의 행한 일이 따름이라 하시더라"}],"고전15:19":[{"r":"고전4:9","t":"내가 생각건대 하나님이 사도인 우리를 죽이기로 작정한 자같이 미말에 두셨으매 우리는 세계 곧 천사와 사람에게 구경거리가 되었노라"},{"r":"딤후3:12","t":"무릇 그리스도 예수 안에서 경건하게 살고자 하는 자는 핍박을 받으리라"}],"고전15:20":[{"r":"딤후2:8","t":"나의 복음과 같이 다윗의 씨로 죽은 자 가운데서 다시 살으신 예수 그리스도를 기억하라"},{"r":"벧전1:3","t":"찬송하리로다 우리 주 예수 그리스도의 아버지 하나님이 그 많으신 긍휼대로 예수 그리스도의 죽은 자 가운데서 복활하심으로 말미암아 우리를 거듭나게 하사 산 소망이 있게 하시며"},{"r":"고전15:23","t":"그러나 각각 자기 차례대로 되리니 먼저는 첫 열매인 그리스도요 다음에는 그리스도 강림하실 때에 그에게 붙은 자요"},{"r":"행26:23","t":"곧 그리스도가 고난을 받으실 것과 죽은 자 가운데서 먼저 다시 살아나사 이스라엘과 이방인들에게 빛을 선전하시리라 함이니이다 하니라"}],"고전15:51":[{"r":"살전4:15","t":"우리가 주의 말씀으로 너희에게 이것을 말하노니 주 강림하실 때까지 우리 살아 남아 있는 자도 자는 자보다 결단코 앞서지 못하리라"},{"r":"살전4:17","t":"그 후에 우리 살아 남은 자도 저희와 함께 구름 속으로 끌어올려 공중에서 주를 영접하게 하시리니 그리하여 우리가 항상 주와 함께 있으리라"},{"r":"빌3:21","t":"그가 만물을 자기에게 복종케 하실 수 있는 자의 역사로 우리의 낮은 몸을 자기 영광의 몸의 형체와 같이 변케 하시리라"}],"고전15:52":[{"r":"마24:31","t":"저가 큰 나팔 소리와 함께 천사들을 보내리니 저희가 그 택하신 자들을 하늘 이 끝에서 저 끝까지 사방에서 모으리라"},{"r":"살전4:16","t":"주께서 호령과 천사장의 소리와 하나님의 나팔로 친히 하늘로 좇아 강림하시리니 그리스도 안에서 죽은 자들이 먼저 일어나고"},{"r":"사27:13","t":"그날에 큰 나팔을 울려 불리니 앗수르 땅에서 파멸케 된 자와 애굽 땅으로 쫓겨난 자가 돌아와서 예루살렘 성산에서 여호와께 경배하리라"},{"r":"슥9:14","t":"여호와께서 그 위에 나타나서 그 살을 번개 같이 쏘아내실 것이며 주 여호와께서 나팔을 불리시며 남방 회리바람을 타고 행하실 것이라"},{"r":"요5:25","t":"진실로 진실로 너희에게 이르노니 죽은 자들이 하나님의 아들의 음성을 들을 때가 오나니 곧 이 때라 듣는 자는 살아나리라"},{"r":"요5:28","t":"이를 기이히 여기지 말라 무덤 속에 있는 자가 다 그의 음성을 들을 때가 오나니"},{"r":"눅20:36","t":"저희는 다시 죽을 수도 없나니 이는 천사와 동등이요 복활의 자녀로서 하나님의 자녀임이니라"}],"고전15:53":[{"r":"고후5:2~4","t":"과연 우리가 여기 있어 탄식하며 하늘로부터 오는 우리 처소로 덧입기를 간절히 사모하노니"}],"고전15:54":[{"r":"사25:8","t":"사망을 영원히 멸하실 것이라 주 여호와께서 모든 얼굴에서 눈물을 씻기시며 그 백성의 수치를 온 천하에서 제하시리라 여호와께서 이같이 말씀하셨느니라"},{"r":"히2:14,15","t":"자녀들은 혈육에 함께 속하였으매 그도 또한 한 모양으로 혈육에 함께 속하심은 사망으로 말미암아 사망의 세력을 잡은 자 곧 마귀를 없이 하시며"},{"r":"계20:14","t":"사망과 음부도 불못에 던지우니 이것은 둘째 사망 곧 불못이라"},{"r":"계21:4","t":"모든 눈물을 그 눈에서 씻기시매 다시 사망이 없고 애통하는 것이나 곡하는 것이나 아픈 것이 다시 있지 아니하리니 처음 것들이 다 지나갔음이러라"}],"고전1:10":[{"r":"고전11:18","t":"첫째는 너희가 교회에 모일 때에 너희 중에 분쟁이 있다 함을 듣고 대강 믿노니"},{"r":"빌1:27","t":"오직 너희는 그리스도 복음에 합당하게 생활하라 이는 내가 너희를 가 보나 떠나 있으나 너희가 일심으로 서서 한 뜻으로 복음의 신앙을 위하여 협력하는 것과"}],"고전1:18":[{"r":"고후2:15","t":"우리는 구원 얻는 자들에게나 망하는 자들에게나 하나님 앞에서 그리스도의 향기니"},{"r":"고후4:3","t":"만일 우리 복음이 가리웠으면 망하는 자들에게 가리운 것이라"},{"r":"살후2:10","t":"부의의 모든 속임으로 멸망하는 자들에게 임하리니 이는 저희가 진리의 사랑을 받지 아니하여 구원함을 얻지 못함이니라"},{"r":"고전1:21","t":"하나님의 지혜에 있어서는 이 세상이 자기 지혜로 하나님을 알지 못하는고로 하나님께서 전도의 미련한 것으로 믿는 자들을 구원하시기를 기뻐하셨도다"},{"r":"고전1:23","t":"우리는 십자가에 못 박힌 그리스도를 전하니 유대인에게는 거리끼는 것이요 이방인에게는 미련한 것이로되"},{"r":"고전1:25","t":"하나님의 미련한 것이 사람보다 지혜 있고 하나님의 약한 것이 사람보다 강하니라"},{"r":"고전2:14","t":"육에 속한 사람은 하나님의 성령의 일을 받지 아니하나니 저희에게는 미련하게 보임이요 또 깨닫지도 못하나니 이런 일은 영적으로라야 분변함이니라"},{"r":"고전15:2","t":"너희가 만일 나의 전한 그 말을 굳게 지키고 헛되이 믿지 아니하였으면 이로 말미암아 구원을 얻으리라"},{"r":"행2:47","t":"하나님을 찬미하며 또 온 백성에게 칭송을 받으니 주께서 구원 받는 사람을 날마다 더하게 하시니라"},{"r":"롬1:16","t":"내가 복음을 부끄러워하지 아니하노니 이 복음은 모든 믿는 자에게 구원을 주시는 하나님의 능력이 됨이라 첫째는 유대인에게요 또한 헬라인에게로다"},{"r":"고전1:24","t":"오직 부르심을 입은 자들에게는 유대인이나 헬라인이나 그리스도는 하나님의 능력이요 하나님의 지혜니라"}],"고전2:13":[{"r":"고전2:1","t":"형제들아, 내가 너희에게 나아가 하나님의 증거를 전할 때에 말과 지혜의 아름다운 것으로 아니하였나니"},{"r":"고전2:4","t":"내 말과 내 전도함이 지혜의 권하는 말로 하지 아니하고 다만 성령의 나타남과 능력으로 하여"},{"r":"고전1:17","t":"그리스도께서 나를 보내심은 세례를 주게 하려 하심이 아니요 오직 복음을 전케 하려 하심이니 말의 지혜로 하지 아니함은 그리스도의 십자가가 헛되지 않게 하려 함이라"},{"r":"고전12:1","t":"형제들아  신령한 것에 대하여는 내가 너희의 알지 못하기를 원치 아니하노니"}],"고전2:9":[{"r":"약1:12","t":"시험을 참는 자는 복이 있도다 이것이 옳다 인정하심을 받은 후에 주께서 자기를 사랑하는 자들에게 약속하신 생명의 면류관을 얻을 것임이니라"},{"r":"마25:34","t":"그 때에 임금이 그 오른편에 있는 자들에게 이르시되 내 아버지께 복 받을 자들이여  나아와 창세로부터 너희를 위하여 예비된 나라를 상속하라"},{"r":"사64:4","t":"주, 외에는 자기를 앙망하는 자를 위하여 이런 일을 행한 신을 예로부터 들은 자도 없고 귀로 깨달은 자도 없고 눈으로 본 자도 없었나이다"}],"고전3:16":[{"r":"고전6:19","t":"너희 몸은 너희가 하나님께로부터 받은 바 너희 가운데 계신 성령의 전인 줄을 알지 못하느냐 너희는 너희의 것이 아니라"},{"r":"고후6:16","t":"하나님의 성전과 우상이 어찌 일치가 되리요 우리는 살아계신 하나님의 성전이라 이와 같이 하나님께서 가라사대 내가 저희 가운데 거하며 두루 행하여 나는 저희 하나님이 되고 저희는 나의 백성이 되리라 하셨느니라"},{"r":"엡2:21","t":"그의 안에서 건물마다 서로 련결하여 주 안에서 성전이 되어 가고"}],"고전3:17":[{"r":"고후7:1","t":"그런즉 사랑하는 자들아 이 약속을 가진 우리가 하나님을 두려워하는 가운데서 거룩함을 온전히 이루어 육과 영의 온갖 더러운 것에서 자신을 깨끗케 하자"}],"고전4:6":[{"r":"고전4:18,19","t":"어떤 이들은 내가 너희에게 나아가지 아니할 것같이 스스로 교만하여졌으나"},{"r":"고전5:2","t":"그리하고도 너희가 오히려 교만하여져서 어찌하여 통한히 여기지 아니하고 그 일 행한 자를 너희 중에서 물리치지 아니하였느냐"},{"r":"고전13:4","t":"사랑은 오래 참고, 사랑은 온유하며, 투기하는 자가 되지 아니하며, 사랑은 자랑하지 아니하며, 교만하지 아니하며"}],"고전6:19":[{"r":"요2:21","t":"그러나 예수는 성전된 자기 육체를 가리켜 말씀하신 것이라"},{"r":"고전3:16","t":"너희가 하나님의 성전인 것과 하나님의 성령이 너희 안에 거하시는 것을 알지 못하느뇨"},{"r":"롬14:7","t":"우리 중에 누구든지 자기를 위하여 사는 자가 없고 자기를 위하여 죽는 자도 없도다"}],"고전6:2":[{"r":"단7:22","t":"옛적부터 항상 계신 자가 와서 지극히 높으신 자의 성도를 위하여 신원하셨고 때가 이르매 성도가 나라를 얻었더라"},{"r":"마19:28","t":"예수께서 가라사대 내가 진실로 너희에게 이르노니 세상이 새롭게 되어 인자가 자기 영광의 보좌에 앉을 때에 나를 좇는 너희도 열 두 보좌에 앉아 이스라엘 열 두 지파를 심판하리라"},{"r":"계20:4","t":"또 내가 보좌들을 보니 거기 앉은 자들이 있어 심판하는 권세를 받았더라 또 내가 보니 예수의 증거와 하나님의 말씀을 인하여 목 베임을 받은 자의 령혼들과 또 짐승과 그의 우상에게 경배하지도 아니하고 이마와 손에 그의 표를 받지도 아니한 자들이 살아서 그리스도로 더불어 천년 동안 왕노릇하니"}],"고전6:20":[{"r":"고전7:23","t":"너희는 값으로 사신 것이니 사람들의 종이 되지 말라"},{"r":"행20:28","t":"너희는 자기를 위하여 또는 온 양떼를 위하여 삼가라 성령이 저들 가운데 너희로 감독자를 삼고 하나님이 자기 피로 사신 교회를 치게 하셨느니라"},{"r":"히9:12","t":"염소와 송아지의 피로 아니하고 오직 자기 피로 영원한 속죄를 이루사 단번에 성소에 들어가셨느니라"},{"r":"히9:14","t":"하물며 영원하신 성령으로 말미암아 흠 없는 자기를 하나님께 드린 그리스도의 피가 어찌 너희 량심으로 죽은 행실에서 깨끗하게하고 살아계신 하나님을 섬기게 못하겠느뇨"},{"r":"벧후2:1","t":"그러나 민간에 또한 거짓 선지자들이 일어났었나니 이와 같이 너희 중에도 거짓 선생들이 있으리라 저희는 멸망케 할 이단을 가만히 끌어들여 자기들을 사신 주를 부인하고 임박한 멸망을 스스로 취하는 자들이라"},{"r":"빌1:20","t":"나의 간절한 기대와 소망을 따라 아무 일에든지 부끄럽지 아니하고 오직 전과 같이 이제도 온전히 담대하여 살든지 죽든지 내 몸에서 그리스도가 존귀히 되게 하려 하나니"}],"고전6:3":[{"r":"벧후2:4(?)","t":"하나님이 범죄한 천사들을 용서치 아니하시고 지옥에 던져 어두운 구덩이에 두어 심판 때까지 지키게 하셨으며"},{"r":"유1:6(?)","t":"또 자기 지위를 지키지 아니하고 자기 처소를 떠난 천사들을 큰 날의 심판까지 영원한 결박으로 흑암에 가두셨으며"}],"고전9:25":[{"r":"딤전6:12","t":"믿음의 선한 싸움을 싸우라 영생을 취하라 이를 위하여 네가 부르심을 입었고 많은 증인 앞에서 선한 증거를 증거하였도다"},{"r":"딤후2:5","t":"경기하는 자가 법대로 경기하지 아니하면 면류관을 얻지 못할 것이며"},{"r":"딤후4:7","t":"내가 선한 싸움을 싸우고 나의 달려갈 길을 마치고 믿음을 지켰으니"},{"r":"유1:3","t":"사랑하는 자들아 내가 우리의 일반으로 얻은 구원을 들어 너희에게 편지하려는 뜻이 간절하던 차에 성도에게 단번에 주신 믿음의 도를 위하여 힘써 싸우라는 편지로 너희를 권하여야 할 필요를 느꼈노니"},{"r":"약1:12","t":"시험을 참는 자는 복이 있도다 이것이 옳다 인정하심을 받은 후에 주께서 자기를 사랑하는 자들에게 약속하신 생명의 면류관을 얻을 것임이니라"}],"고후10:4":[{"r":"고전9:7","t":"누가 자비량하고 병정을 다니겠느냐 누가 포도를 심고 그 실과를 먹지 않겠느냐 누가 양떼를 기르고 그 양떼의 젖을 먹지 않겠느냐"},{"r":"고후6:7","t":"진리의 말씀과, 하나님의 능력 안에 있어 의의 병기로 좌우하고"},{"r":"롬6:13","t":"또한 너희 지체를 부의의 병기로 죄에게 드리지 말고 오직 너희 자신을 죽은 자 가운데서 다시 산 자같이 하나님께 드리며 너의 지체를 의의 병기로 하나님께 드리라"},{"r":"엡6:11","t":"마귀의 궤계를 능히 대적하기 위하여 하나님의 전신 갑주를 입으라"},{"r":"살전5:8","t":"우리는 낮에 속하였으니 근신하여 믿음과 사랑의 흉배를 붙이고 구원의 소망의 투구를 쓰자"},{"r":"행7:20","t":"그 때에 모세가 났는데 하나님 보시기에 아름다운지라 그 부친의 집에서 석 달을 길리우더니"},{"r":"렘1:10","t":"보라, 내가 오늘날 너를 열방 만국 위에 세우고 너를 뽑으며 파괴하며 파멸하며 넘어뜨리며 건설하며 심게 하였느니라"},{"r":"고후13:3,4","t":"이는 그리스도께서 내 안에서 말씀하시는 증거를 너희가 구함이니 저가 너희를 향하여 약하지 않고 도리어 너희 안에서 강하시니라"},{"r":"고전2:5","t":"너희 믿음이 사람의 지혜에 있지 아니하고 다만 하나님의 능력에 있게 하려 하였노라"}],"고후10:5":[{"r":"사2:11,12","t":"그 날에 눈이 높은 자가 낮아지며 교만한 자가 굴복되고 여호와께서 홀로 높임을 받으시리라"},{"r":"고후9:13","t":"이 직무로 증거를 삼아 너희의 그리스도의 복음을 진실히 믿고 복종하는 것과 저희와 모든 사람을 섬기는 너희의 후한 연보를 인하여 하나님께 영광을 돌리고"},{"r":"롬5:19","t":"한 사람의 순종치 아니함으로 많은 사람이 죄인 된 것같이 한 사람의 순종하심으로 많은 사람이 의인이 되리라"}],"고후11:14":[{"r":"갈1:8","t":"그러나 우리나 혹 하늘로부터 온 천사라도 우리가 너희에게 전한 복음 외에 다른 복음을 전하면 저주를 받을지어다"}],"고후11:15":[{"r":"고후3:9","t":"정죄의 직분도 영광이 있은즉 의의 직분은 영광이 더욱 넘치리라"},{"r":"빌3:19","t":"저희의 마침은 멸망이요 저희의 신은 배요 그 영광은 저희의 부끄러움에 있고 땅의 일을 생각하는 자라"}],"고후13:13":[{"r":"롬16:20","t":"평강의 하나님께서 속히 사단을 너희 발 아래서 상하게 하시리라 우리 주 예수의 은혜가 너희에게 있을찌어다"},{"r":"고전16:23","t":"주 예수 그리스도의 은혜가 너희와 함께 하고"},{"r":"유1:21","t":"하나님의 사랑 안에서 자기를 지키며 영생에 이르도록 우리 주 예수 그리스도의 긍휼을 기다리라"},{"r":"빌2:1","t":"그러므로 그리스도 안에 무슨 권면이나 사랑에 무슨 위로나 성령의 무슨 교제나 긍휼이나 자비가 있거든"}],"고후2:4":[{"r":"고후7:8","t":"그러므로 내가 편지로 너희를 근심하게 한 것을 후회하였으나 지금은 후회하지 아니함은 그 편지가 너희로 잠시만 근심하게 한 줄을 앎이라"},{"r":"고후7:12","t":"그런즉 내가 너희에게 쓴 것은 그 부의 행한 자를 위한 것도 아니요 그 부의 당한 자를 위한 것도 아니요 오직 우리를 위한 너희의 간절함이 하나님 앞에서 너희에게 나타나게 하려 함이로라"},{"r":"행20:19","t":"곧 모든 겸손과 눈물이며 유대인의 간계를 인하여 당한 시험을 참고 주를 섬긴 것과"}],"고후4:10":[{"r":"고후6:9","t":"무명한 자 같으나 유명한 자요 죽는 자 같으나 보라, 우리가 살고 징계를 받는 자 같으나 죽임을 당하지 아니하고"},{"r":"고전4:9","t":"내가 생각건대 하나님이 사도인 우리를 죽이기로 작정한 자같이 미말에 두셨으매 우리는 세계 곧 천사와 사람에게 구경거리가 되었노라"},{"r":"고전15:31","t":"형제들아 내가 그리스도 예수 우리 주 안에서 가진 바 너희에게 대한 나의 자랑을 두고 단언하노니 나는 날마다 죽노라"},{"r":"고후1:5","t":"그리스도의 고난이 우리에게 넘친 것같이 우리의 위로도 그리스도로 말미암아 넘치는도다"},{"r":"고후1:9","t":"우리 마음에 사형 선고를 받은 줄 알았으니 이는 우리로 자기를 의뢰하지 말고 오직 죽은 자를 다시 살리시는 하나님만 의뢰하게 하심이라"},{"r":"롬6:5","t":"만일 우리가 그의 죽으심을 본받아 련합한 자가 되었으면 또한 그의 복활을 본받아 련합한 자가 되리라"},{"r":"롬8:36","t":"기록된바 우리가 종일 주를 위하여 죽임을 당케 되며 도살할 양같이 여김을 받았나이다 함과 같으니라"},{"r":"딤후2:11","t":"미쁘다, 이 말이여 우리가 주와 함께 죽었으면 또한 함께 살 것이요"},{"r":"롬5:10","t":"곧 우리가 원수 되었을 때에 그 아들의 죽으심으로 말미암아 하나님으로 더불어 화목되었은즉 화목된 자로서는 더욱 그의 살으심을 인하여 구원을 얻을 것이니라"},{"r":"롬6:8","t":"만일 우리가 그리스도와 함께 죽었으면 또한 그와 함께 살 줄을 믿노니"}],"고후4:8":[{"r":"고후7:5","t":"우리가 마게도냐에 이르렀을때에도 우리 육체가 편치 못하고 사방으로 환난을 당하여 밖으로는 다툼이요 안으로는 두려움이라"},{"r":"시129:2","t":"저희가 나의 소시부터 여러번 나를 괴롭게 하였으나 나를 이기지 못하였도다"}],"고후4:9":[{"r":"히13:5","t":"돈을 사랑치 말고 있는 바를 족한 줄로 알라 그가 친히 말씀하시기를 내가 과연 너희를 버리지 아니하고 과연 너희를 떠나지 아니하리라 하셨느니라"},{"r":"신4:31","t":"네 하나님 여호와는 자비하신 하나님이심이라  그가 너를 버리지 아니하시며 너를 멸하지 아니하시며 네 열조에게 맹서하신 언약을 잊지 아니하시리라"},{"r":"시37:24","t":"저는 넘어지나 아주 엎드러지지 아니함은 여호와께서 손으로 붙드심이로다"},{"r":"잠24:16","t":"대저 의인은 일곱번 넘어질지라도 다시 일어나려니와 악인은 재앙으로 인하여 엎드러지느니라"},{"r":"미7:8","t":"나의 대적이여 나로 인하여 기뻐하지 말지어다 나는 엎드러질지라도 일어날 것이요 어두운 데 앉을지라도 여호와께서 나의 빛이 되실 것임이로다"}],"고후5:17":[{"r":"고후12:2","t":"내가 그리스도 안에 있는 한 사람을 아노니 십 사년 전에 그가 세째 하늘에 이끌려 간 자라 그가 몸 안에 있었는지 몸 밖에 있었는지 나는 모르거니와 하나님은 아시느니라"},{"r":"롬16:7","t":"내 친척이요 나와 함께 갇혔던 안드로니고와 유니아에게 문안하라 저희는 사도에게 유명히 여김을 받고 또한 나보다 먼저 그리스도 안에 있는 자라"},{"r":"갈1:22","t":"유대에 그리스도 안에 있는 교회들이 나를 얼굴로 알지 못하고"},{"r":"요3:3","t":"예수께서 대답하여 가라사대 진실로 진실로 네게 이르노니 사람이 거듭나지 아니하면 하나님 나라를 볼 수 없느니라"},{"r":"롬6:4","t":"그러므로 우리가 그의 죽으심과 합하여 세례를 받음으로 그와 함께 장사되었나니 이는 아버지의 영광으로 말미암아 그리스도를 죽은 자 가운데서 살리심과 같이 우리로 또한 새 생명 가운데서 행하게 하려 함이니라"},{"r":"사43:18,19","t":"너희는 이전 일을 기억하지 말며 옛적 일을 생각하지 말라"},{"r":"계21:5","t":"보좌에 앉으신 이가 가라사대 보라 내가 만물을 새롭게 하노라 하시고 또 가라사대 이 말은 신실하고 참되니 기록하라 하시고"},{"r":"사65:17","t":"보라, 내가 새 하늘과 새 땅을 창조하나니 이전 것은 기억되거나 마음에 생각나지 아니할 것이라"},{"r":"엡2:15","t":"원수 된 것 곧 의문에 속한 계명의 률법을 자기 육체로 폐하셨으니 이는 이 둘로 자기의 안에서 한 새 사람을 지어 화평하게 하시고"},{"r":"엡4:24","t":"하나님을 따라 의와 진리의 거룩함으로 지으심을 받은 새 사람을 입으라"},{"r":"히8:13","t":"새 언약이라 말씀하셨으매 첫 것은 낡아지게 하신 것이니 낡아지고 쇠하는 것은 없어져가는 것이니라"}],"고후5:21":[{"r":"벧전2:22","t":"저는 죄를 범치 아니하시고 그 입에 궤사도 없으시며"},{"r":"롬8:3","t":"률법이 육신으로 말미암아 연약하여 할 수 없는 그것을 하나님은 하시나니 곧 죄를 인하여 자기 아들을 죄 있는 육신의 모양으로 보내어 육신에 죄를 정하사"},{"r":"갈3:13","t":"그리스도께서 우리를 위하여 저주를 받은 바 되사 률법의 저주에서 우리를 속량하셨으니 기록된 바 나무에 달린 자마다 저주 아래 있는 자라 하였음이라"},{"r":"롬4:25","t":"예수는 우리 범죄함을 위하여 내어줌이 되고 또한 우리를 의롭다 하심을 위하여 살아나셨느니라"},{"r":"롬1:17","t":"복음에는 하나님의 의가 나타나서 믿음으로 믿음에 이르게 하나니 기록된 바 오직 의인은 믿음으로 말미암아 살리라 함과 같으니라"},{"r":"고전1:30","t":"너희는 하나님께로부터 나서 그리스도 예수 안에 있고 예수는 하나님께로서 나와서 우리에게 지혜와 의로움과 거룩함과 구속함이 되셨으니"}],"고후5:7":[{"r":"요20:29","t":"예수께서 가라사대 너는 나를 본 고로 믿느냐 보지 못하고 믿는 자들은 복되도다 하시니라"},{"r":"고후4:18","t":"우리의 돌아보는 것은 보이는 것이 아니요, 보이지 않는 것이니 보이는 것은 잠간이요, 보이지 않는 것은 영원함이니라"},{"r":"고전13:12","t":"우리가 이제는 거울로 보는 것같이 희미하나 그 때에는 얼굴과 얼굴을 대하여 볼 것이요 이제는 내가 부분적으로 아나 그 때에는 주께서 나를 아신 것같이 내가 온전히 알리라"}],"고후6:17":[{"r":"사52:11","t":"너희는 떠날지어다, 떠날지어다  거기서 나오고 불정한 것을 만지지 말지어다 그 가운데서 나올지어다 여호와의 기구를 메는 자여 스스로 정결케 할지어다"},{"r":"고후7:1","t":"그런즉 사랑하는 자들아 이 약속을 가진 우리가 하나님을 두려워하는 가운데서 거룩함을 온전히 이루어 육과 영의 온갖 더러운 것에서 자신을 깨끗케 하자"},{"r":"겔20:34","t":"능한 손과 편 팔로 분노를 쏟아 너희를 렬국 중에서 나오게 하며 너희의 흩어진 열방 중에서 모아내고"},{"r":"겔20:41","t":"내가 너희를 인도하여 렬국 중에서 나오게 하고 너희의 흩어진 열방 중에서 모아 낼 때에 내가 너희를 향기로 받고 내가 또 너희로 말미암아 내 거룩함을 렬국의 목전에서 나타낼 것이며"},{"r":"습3:20","t":"내가 그 때에 너희를 이끌고 그 때에 너희를 모을찌라 내가 너희 목전에서 너희 사로잡힘을 돌이킬 때에 너희로 천하 만민 중에서 명성과 칭찬을 얻게 하리라 나 여호와의 말이니라"},{"r":"계18:4","t":"또 내가 들으니 하늘로서 다른 음성이 나서 가로되 내 백성아 거기서 나와 그의 죄에 참여하지 말고 그의 받을 재앙들을 받지 말라"}],"고후6:18":[{"r":"출4:22","t":"너는 바로에게 이르기를 여호와의 말씀에 이스라엘은 내 아들, 내 장자라"},{"r":"삼하7:14","t":"나는 그 아비가 되고 그는 내 아들이 되리니 저가 만일 죄를 범하면 내가 사람 막대기와 인생 채찍으로 징계하려니와"},{"r":"사43:6","t":"내가 북방에게 이르기를 놓으라 남방에게 이르기를 구류하지 말라 내 아들들을 원방에서 이끌며 내 딸들을 땅 끝에서 오게 하라"},{"r":"렘31:9","t":"울며 올 것이며 그들이 나의 인도함을 입고 간구할 때에 내가 그들로 넘어지지 아니하고 하숫가의 바른 길로 행하게 하리라 나는 이스라엘의 아비요 에브라임은 나의 장자니라"},{"r":"호1:10","t":"그러나 이스라엘 자손의 수가 바닷가의 모래같이 되어서 측량할 수도 없고 셀 수도 없을 것이며 전에 저희에게 이르기를 너희는 내 백성이 아니라 한 그 곳에서 저희에게 이르기를 너희는 사신 하나님의 자녀라 할 것이라"},{"r":"계21:7","t":"이기는 자는 이것들을 유업으로 얻으리라 나는 저의 하나님이 되고 그는 내 아들이 되리라"}],"고후8:9":[{"r":"빌2:6,7","t":"그는 근본 하나님의 본체시나 하나님과 동등됨을 취할 것으로 여기지 아니하시고"},{"r":"고후6:10","t":"근심하는 자 같으나 항상 기뻐하고, 가난한 자 같으나 많은 사람을 부요하게 하고, 아무 것도 없는 자 같으나 모든 것을 가진 자로다"},{"r":"마20:28","t":"인자가 온 것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라"}],"골1:15":[{"r":"고후4:4","t":"그 중에 이 세상 신이 믿지 아니하는 자들의 마음을 혼미케하여 그리스도의 영광의 복음의 광채를 비취지 못하게 함이니 그리스도는 하나님의 형상이니라"},{"r":"딤전1:17","t":"만세의 왕 곧 썩지 아니하고 보이지 아니하고 홀로 하나이신 하나님께 존귀와 영광이 세세토록 있어지이다  아멘"},{"r":"시89:27","t":"내가 또 저로 장자를 삼고 세계 열왕의 으뜸이 되게 하며"},{"r":"롬8:29","t":"하나님이 미리 아신 자들로 또한 그 아들의 형상을 본받게 하기 위하여 미리 정하셨으니 이는 그로 많은 형제 중에서 맏아들이 되게 하려 하심이니라"}],"골1:16":[{"r":"엡1:10","t":"하늘에 있는 것이나 땅에 있는 것이 다 그리스도 안에서 통일되게 하려 하심이라"},{"r":"겔10:1","t":"이에 내가 보니 그룹들 머리 위 궁창에 남보석 같은 것이 나타나는데 보좌 형상 같더라"},{"r":"엡1:21","t":"모든 정사와 권세와 능력과 주관하는 자와 이 세상 뿐 아니라 오는 세상에 일컫는 모든 이름 위에 뛰어나게 하시고"},{"r":"요1:3","t":"만물이 그로 말미암아 지은 바 되었으니 지은 것이 하나도 그가 없이는 된 것이 없느니라"},{"r":"롬11:36","t":"이는 만물이 주에게서 나오고 주로 말미암고 주에게로 돌아감이라 영광이 그에게 세세에 있으리로다 아멘"},{"r":"고전8:6","t":"그러나 우리에게는 한 하나님 곧 아버지가 계시니 만물이 그에게서 났고 우리도 그를 위하여 또한 한 주 예수 그리스도께서 계시니 만물이 그로 말미암고 우리도 그로 말미암았느니라"}],"골1:17":[{"r":"요8:58","t":"예수께서 가라사대 진실로 진실로 너희에게 이르노니 아브라함이 나기 전부터 내가 있느니라 하시니"},{"r":"요1:1","t":"태초에 말씀이 계시니라 이 말씀이 하나님과 함께 계셨으니 이 말씀은 곧 하나님이시니라"},{"r":"히1:3","t":"이는 하나님의 영광의 광채시요 그 본체의 형상이시라 그의 능력의 말씀으로 만물을 붙드시며 죄를 정결케 하는 일을 하시고 높은 곳에 계신 위엄의 우편에 앉으셨느니라"}],"골1:18":[{"r":"엡1:22,23","t":"또 만물을 그 발 아래 복종하게 하시고 그를 만물 위에 교회의 머리로 주셨느니라"},{"r":"계3:14","t":"라오디게아 교회의 사자에게 편지하기를 아멘이시요 충성되고 참된 증인이시요 하나님의 창조의 근본이신 이가 가라사대"},{"r":"행26:23","t":"곧 그리스도가 고난을 받으실 것과 죽은 자 가운데서 먼저 다시 살아나사 이스라엘과 이방인들에게 빛을 선전하시리라 함이니이다 하니라"},{"r":"고전15:20","t":"그러나 이제 그리스도께서 죽은 자 가운데서 다시 살아 잠 자는 자들의 첫 열매가 되셨도다"},{"r":"계1:5","t":"또 충성된 증인으로 죽은 자들 가운데서 먼저 나시고 땅의 임금들의 머리가 되신 예수 그리스도로 말미암아 은혜와 평강이 너희에게 있기를 원하노라 우리를 사랑하사 그의 피로 우리 죄에서 우리를 해방하시고"}],"골1:27":[{"r":"골2:2","t":"이는 저희로 마음에 위안을 받고 사랑 안에서 련합하여 원만한 리해의 모든 부요에 이르러 하나님의 비밀인 그리스도를 깨닫게 하려 함이라"},{"r":"엡3:9","t":"영원부터 만물을 창조하신 하나님 속에 감취었던 비밀의 경륜이 어떠한 것을 드러내게 하려 하심이라"},{"r":"롬16:25,26","t":"나의 복음과 예수 그리스도를 전파함은 영세 전부터 감취었다가"},{"r":"엡1:18","t":"너희 마음 눈을 밝히사 그의 부르심의 소망이 무엇이며 성도 안에서 그 기업의 영광의 풍성이 무엇이며"},{"r":"엡3:16","t":"그 영광의 풍성을 따라 그의 성령으로 말미암아 너희 속 사람을 능력으로 강건하게 하옵시며"},{"r":"딤전1:1","t":"우리 구주 하나님과 우리 소망이신 그리스도 예수의 명령을 따라 그리스도 예수의 사도 된 바울은"}],"골2:16":[{"r":"롬14:17","t":"하나님의 나라는 먹는 것과 마시는 것이 아니요 오직 성령 안에서 의와 평강과 희락이라"},{"r":"히9:10","t":"이런 것은 먹고 마시는 것과 여러 가지 씻는 것과 함께 육체의 예법만 되어 개혁할 때까지 맡겨 둔 것이니라"},{"r":"레11:2","t":"이스라엘 자손에게 고하여 이르라 륙지 모든 짐승 중 너희의 먹을만한 생물은 이러하니"},{"r":"레23:2","t":"이스라엘 자손에게 고하여 이르라 너희가 공포하여 성회를 삼을 여호와의 절기는 이러하니라"},{"r":"롬14:5","t":"혹은 이날을 저날보다 낫게 여기고 혹은 모든 날을 같게 여기나니 각각 자기 마음에 확정할찌니라"},{"r":"막2:28","t":"이러므로 인자는 안식일에도 주인이니라"},{"r":"민28:11","t":"월삭에는 수송아지 둘과 수양 하나와 일년 되고 흠없는 수양 일곱으로 여호와께 번제를 드리되"},{"r":"롬14:3","t":"먹는 자는 먹지 않는 자를 업신 여기지 말고 먹지 못하는 자는 먹는 자를 판단하지 말라 이는 하나님이 저를 받으셨음이니라"},{"r":"롬14:10","t":"네가 어찌하여 네 형제를 판단하느뇨 어찌하여 네 형제를 업신여기느뇨 우리가 다 하나님의 심판대 앞에 서리라"},{"r":"롬14:13","t":"그런즉 우리가 다시는 서로 판단하지 말고 도리어 부딪힐 것이나 거칠 것으로 형제 앞에 두지 아니할 것을 주의하라"}],"골2:17":[{"r":"히8:5","t":"저희가 섬기는 것은 하늘에 있는 것의 모형과 그림자라 모세가 장막을 지으려 할 때에 지시하심을 얻음과 같으니 가라사대 삼가 모든 것을 산에서 네게 보이던 본을 좇아 지으라 하셨느니라"},{"r":"히10:1","t":"률법은 장차 오는 좋은 일의 그림자요 참 형상이 아니므로 해마다 늘 드리는 바 같은 제사로는 나아오는 자들을 언제든지 온전케 할 수 없느니라"},{"r":"골2:9","t":"그 안에는 신성의 모든 충만이 육체로 거하시고"}],"골3:14":[{"r":"살전5:8","t":"우리는 낮에 속하였으니 근신하여 믿음과 사랑의 흉배를 붙이고 구원의 소망의 투구를 쓰자"},{"r":"엡5:2","t":"그리스도께서 너희를 사랑하신 것같이 너희도 사랑 가운데서 행하라 그는 우리를 위하여 자신을 버리사 향기로운 제물과 생축으로 하나님께 드리셨느니라"},{"r":"히6:1","t":"그러므로 우리가 그리스도 도의 초보를 버리고 죽은 행실을 회개함과 하나님께 대한 신앙과"},{"r":"요17:23","t":"곧 내가 저희 안에 아버지께서 내 안에 계셔 저희로 온전함을 이루어 하나가 되게 하려 함은 아버지께서 나를 보내신 것과 또 나를 사랑하심 같이 저희도 사랑하신 것을 세상으로 알게 하려 함이로소이다"},{"r":"엡4:3","t":"평안의 매는 줄로 성령의 하나되게 하신 것을 힘써 지키라"}],"골4:6":[{"r":"골3:16","t":"그리스도의 말씀이 너희 속에 풍성히 거하여 모든 지혜로 피차 가르치며 권면하고 시와 찬미와 신령한 노래를 부르며 마음에 감사함으로 하나님을 찬양하고"},{"r":"막9:50","t":"소금은 좋은 것이로되 만일 소금이 그 맛을 잃으면 무엇으로 이를 짜게 하리요 너희 속에 소금을 두고 서로 화목하라  하시니라"},{"r":"벧전3:15","t":"너희 마음에 그리스도를 주로 삼아 거룩하게 하고 너희 속에 있는 소망에 관한 리유를 묻는 자에게는 대답할 것을 항상 예비하되 온유와 두려움으로 하고"}],"눅10:18":[{"r":"사14:12","t":"너 아침의 아들 계명성이여  어찌 그리 하늘에서 떨어졌으며 너 렬국을 엎은 자여 어찌 그리 땅에 찍혔는고"},{"r":"계9:1","t":"다섯째 천사가 나팔을 불매 내가 보니 하늘에서 땅에 떨어진 별 하나가 있는데 저가 무저갱의 열쇠를 받았더라"},{"r":"요12:31","t":"이제 이 세상의 심판이 이르렀으니 이 세상 임금이 쫓겨나리라"},{"r":"요16:11","t":"심판에 대하여라 함은 이 세상 임금이 심판을 받았음이니라"},{"r":"골2:15","t":"정사와 권세를 벗어버려 밝히 드러내시고 십자가로 승리하셨느니라"},{"r":"계12:8,9","t":"이기지 못하여 다시 하늘에서 저희의 있을 곳을 얻지 못한지라"}],"눅12:47":[{"r":"약4:17","t":"이러므로 사람이 선을 행할 줄 알고도 행치 아니하면 죄니라"},{"r":"벧후2:21","t":"의의 도를 안 후에 받은 거룩한 명령을 저버리는 것보다 알지 못하는 것이 도리어 저희에게 나으니라"},{"r":"눅12:40","t":"이러므로 너희도 예비하고 있으라 생각지 않은 때에 인자가 오리라 하시니라"},{"r":"마11:24","t":"내가 너희에게 이르노니 심판날에 소돔 땅이 너보다 견디기 쉬우리라 하시니라"},{"r":"요15:22","t":"내가 와서 저희에게 말하지 아니하였더면 죄가 없었으려니와 지금은 그 죄를 핑계할 수 없느니라"},{"r":"요15:24","t":"내가 아무도 못한 일을 저희 중에서 하지 아니하였더면 저희가 죄가 없었으려니와 지금은 저희가 나와 및 내 아버지를 보았고 또 미워하였도다"},{"r":"신25:2,3","t":"악인에게 태형이 합당하거든 재판장은 그를 엎드리게 하고 그 죄의 경중대로 여수이 자기 앞에서 때리게 하라"}],"눅12:48":[{"r":"레5:17","t":"만일 누구든지 여호와의 금령 중 하나를 불지중에 범하여도 허물이라 벌을 당할 것이니"},{"r":"민15:29,30","t":"이스라엘 자손 중 본토 소생이든지 그들 중에 우거하는 타국인이든지 무릇 그릇 범죄한 자에게 대한 법이 동일하거니와"},{"r":"롬1:19,20","t":"이는 하나님을 알만한 것이 저희 속에 보임이라 하나님께서 이를 저희에게 보이셨느니라"},{"r":"롬2:14,15","t":"률법 없는 이방인이 본성으로 률법의 일을 행할 때는 이 사람은 률법이 없어도 자기가 자기에게 률법이 되나니"},{"r":"딤전1:13","t":"내가 전에는 훼방자요 핍박자요 포행자이었으나 도리어 긍휼을 입은 것은 내가 믿지 아니할 때에 알지 못하고 행하였음이라"},{"r":"마25:29","t":"무릇 있는 자는 받아 풍족하게 되고 없는 자는 그 있는 것까지 빼앗기리라"},{"r":"마13:12","t":"무릇 있는 자는 받아 넉넉하게 되되 무릇 없는 자는 그 있는 것도 빼앗기리라"}],"눅14:11":[{"r":"눅18:14","t":"내가 너희에게 이르노니 이 사람이 저보다 의롭다 하심을 받고 집에 내려 갔느니라 무릇 자기를 높이는 자는 낮아지고 자기를 낮추는 자는 높아지리라 하시니라"},{"r":"잠29:23","t":"사람이 교만하면 낮아지게 되겠고 마음이 겸손하면 영예를 얻으리라"},{"r":"겔21:26","t":"나 주 여호와가 말하노라 관을 제하며 면류관을 벗길지라 그대로 두지 못하리니 낮은 자를 높이고 높은 자를 낮출 것이니라"},{"r":"마18:4","t":"그러므로 누구든지 이 어린 아이와 같이 자기를 낮추는 그 이가 천국에서 큰 자니라"},{"r":"약4:6","t":"그러나 더욱 큰 은혜를 주시나니 그러므로 일렀으되 하나님이 교만한 자를 물리치시고 겸손한 자에게 은혜를 주신다 하였느니라"},{"r":"약4:10","t":"주 앞에서 낮추라 그리하면 주께서 너희를 높이시리라"},{"r":"벧전5:5,6","t":"젊은 자들아 이와 같이 장로들에게 순복하고 다 서로 겸손으로 허리를 동이라 하나님이 교만한 자를 대적하시되 겸손한 자들에게는 은혜를 주시느니라"}],"눅17:10":[{"r":"마25:30","t":"이 무익한 종을 바깥 어두운 데로 내어 쫓으라 거기서 슬피 울며 이를 갊이 있으리라 하니라"},{"r":"욥22:2,3","t":"사람이 어찌 하나님께 유익하게 하겠느냐  지혜로운 자도 스스로 유익할 따름이니라"},{"r":"욥35:7","t":"네가 의로운들 하나님께 무엇을 드리겠으며 그가 네 손에서 무엇을 받으시겠느냐"},{"r":"롬11:35","t":"누가 주께 먼저 드려서 갚으심을 받겠느뇨"}],"눅17:5":[{"r":"막6:30","t":"사도들이 예수께 모여 자기들의 행한 것과 가르친 것을 낱낱이 고하니"},{"r":"막9:24","t":"곧 그 아이의 아비가 소리를 질러 가로되 내가 믿나이다 나의 믿음 없는 것을 도와주소서  하더라"}],"눅17:6":[{"r":"마17:20","t":"가라사대 너희 믿음이 적은 연고니라 진실로 너희에게 이르노니 너희가 만일 믿음이 한 겨자씨만큼만 있으면 이 산을 명하여 여기서 저기로 옮기라 하여도 옮길 것이요 또 너희가 못할 것이 없으리라"},{"r":"마13:31","t":"또 비유를 베풀어 가라사대 천국은 마치 사람이 자기 밭에 갖다 심은 겨자씨 한 알 같으니"},{"r":"눅19:4","t":"앞으로 달려가 보기 위하여 뽕나무에 올라가니 이는 예수께서 그리로 지나가시게 됨이러라"}],"눅17:8":[{"r":"요13:4","t":"저녁 잡수시던 자리에서 일어나 겉옷을 벗고 수건을 가져다가 허리에 두르시고"},{"r":"눅12:35","t":"허리에 띠를 띠고 등불을 켜고 서 있으라"},{"r":"눅12:37","t":"주인이 와서 깨어 있는 것을 보면 그 종들은 복이 있으리로다 내가 진실로 너희에게 이르노니 주인이 띠를 띠고 그 종들을 자리에 앉히고 나아와 수종하리라"}],"눅21:34":[{"r":"약5:5","t":"너희가 땅에서 사치하고 연락하여 도살의 날에 너희 마음을 살지게 하였도다"},{"r":"마13:22","t":"가시떨기에 뿌리웠다는 것은 말씀을 들으나 세상의 념려와 재리의 유혹에 말씀이 막혀 결실치 못하는 자요"},{"r":"롬13:13","t":"낮에와 같이 단정히 행하고 방탕과 술 취하지 말며 음란과 호색하지 말며 쟁투와 시기하지 말고"},{"r":"살전5:6,7","t":"그러므로 우리는 다른 이들과 같이 자지 말고 오직 깨어 근신할지라"},{"r":"벧전4:7","t":"만물의 마지막이 가까왔으니 그러므로 너희는 정신을 차리고 근신하여 기도하라"},{"r":"살전5:3,4","t":"저희가 평안하다, 안전하다 할 그 때에 잉태된 녀자에게 해산 고통이 이름과 같이 멸망이 홀연히 저희에게 이르리니 결단코 피하지 못하리라"},{"r":"눅12:40","t":"이러므로 너희도 예비하고 있으라 생각지 않은 때에 인자가 오리라 하시니라"},{"r":"전9:12","t":"대저 사람은 자기의 시기를 알지 못하나니 물고기가 재앙의 그물에 걸리고 새가 올무에 걸림같이 인생도 재앙의 날이 홀연히 임하면 거기 걸리느니라"},{"r":"사24:17","t":"땅의 거민아 두려움과 함정과 올무가 네게 임하였나니"}],"눅21:36":[{"r":"호12:4","t":"천사와 힘을 겨루어 이기고 울며 그에게 간구하였으며 하나님은 벧엘에서 저를 만나셨고 거기서 우리에게 말씀하셨나니"},{"r":"약5:16","t":"이러므로 너희 죄를 서로 고하며 병 낫기를 위하여 서로 기도하라 의인의 간구는 역사하는 힘이 많으니라"},{"r":"계6:17","t":"그들의 진노의 큰 날이 이르렀으니 누가 능히 서리요 하더라"},{"r":"눅18:1","t":"항상 기도하고 락망치 말아야 될 것을 저희에게 비유로 하여"},{"r":"눅12:37","t":"주인이 와서 깨어 있는 것을 보면 그 종들은 복이 있으리로다 내가 진실로 너희에게 이르노니 주인이 띠를 띠고 그 종들을 자리에 앉히고 나아와 수종하리라"},{"r":"마25:13","t":"그런즉 깨어 있으라 너희는 그 날과 그 시를 알지 못하느니라"},{"r":"마26:41","t":"시험에 들지 않게 깨어 있어 기도하라  마음에는 원이로되 육신이 약하도다 하시고"},{"r":"막14:34~38","t":"말씀하시되 내 마음이 심히 고민하여 죽게 되었으니 너희는 여기 머물러 깨어 있으라 하시고"},{"r":"행20:31","t":"그러므로 너희가 일깨어 내가 삼년이나 밤낮 쉬지 않고 눈물로 각 사람을 훈계하던 것을 기억하라"},{"r":"고전16:13","t":"깨어 믿음에 굳게 서서 남자답게 강건하여라"},{"r":"살전5:6","t":"그러므로 우리는 다른 이들과 같이 자지 말고 오직 깨어 근신할지라"},{"r":"벧전5:8","t":"근신하라 깨어라 너희 대적 마귀가 우는 사자같이 두루 다니며 삼킬 자를 찾나니"},{"r":"계16:15","t":"보라, 내가 도적같이 오리니 누구든지 깨어 자기 옷을 지켜 벌거벗고 다니지 아니하며 자기의 부끄러움을 보이지 아니하는 자가 복이 있도다"}],"눅23:53":[{"r":"막11:2","t":"이르시되 너희 맞은편 마을로 가라 그리로 들어가면 곧 아직 아무 사람도 타 보지 않은 나귀 새끼의 매여 있는 것을 보리니 풀어 끌고 오너라"},{"r":"사53:9","t":"그는 강포를 행치 아니하였고 그 입에 궤사가 없었으나 그 무덤이 악인과 함께 되었으며 그 묘실이 부자와 함께 되었도다"}],"눅23:54":[{"r":"마27:62","t":"그 이튿날은 예비일 다음날이라 대제사장들과 바리새인들이 함께 빌라도에게 모여 가로되"}],"눅23:55":[{"r":"눅23:49","t":"예수의 아는 자들과 및 갈릴리로부터 따라온 녀자들도 다 멀리 서서 이 일을 보니라"},{"r":"마28:1","t":"안식일이 다하여 가고 안식 후 첫날이 되려는 미명에 막달라 마리아와 다른 마리아가 무덤을 보려고 왔더니"}],"눅23:56":[{"r":"눅24:1","t":"안식 후 첫날 새벽에 이 녀자들이 그 예비한 향품을 가지고 무덤에 가서"},{"r":"막16:1","t":"안식일이 지나매 막달라 마리아와 야고보의 어머니 마리아와 또 살로메가 가서 예수께 바르기 위하여 향품을 사다 두었다가"},{"r":"요19:39","t":"일찍 예수께 밤에 나아왔던 니고데모도 몰약과 침향 섞은 것을 백 근쯤 가지고 온지라"},{"r":"출20:10","t":"제 칠일은 너의 하나님 여호와의 안식일인즉 너나 네 아들이나 네 육축이나 네 문 안에 유하는 객이라도 아무 일도 하지 말라"},{"r":"신5:14","t":"제 칠일은 너의 하나님 여호와의 안식인즉 너나, 네 아들이나, 네 딸이나, 네 남종이나, 네 여종이나, 네 소나, 네 나귀나, 네 모든 육축이나, 네 문안에 유하는 객이라도 아무 일도 하지 말고 네 남종이나, 네 여종으로 너같이 안식하게 할지니라"}],"눅24:1":[{"r":"눅24:1~10","t":"안식 후 첫날 새벽에 이 녀자들이 그 예비한 향품을 가지고 무덤에 가서"},{"r":"마28:1~8","t":"안식일이 다하여 가고 안식 후 첫날이 되려는 미명에 막달라 마리아와 다른 마리아가 무덤을 보려고 왔더니"},{"r":"막16:1~8","t":"안식일이 지나매 막달라 마리아와 야고보의 어머니 마리아와 또 살로메가 가서 예수께 바르기 위하여 향품을 사다 두었다가"},{"r":"요20:1","t":"안식 후 첫날 이른 아침 아직 어두울 때에 막달라 마리아가 무덤에 와서 돌이 무덤에서 옮겨간 것을 보고"},{"r":"눅23:56","t":"돌아가 향품과 향유를 예비하더라 계명을 좇아 안식일에 쉬더라"}],"눅24:2":[{"r":"마27:60","t":"바위 속에 판 자기 새 무덤에 넣어두고 큰 돌을 굴려 무덤 문에 놓고 가니"},{"r":"막15:46","t":"요셉이 세마포를 사고 예수를 내려다가 이것으로 싸서 바위 속에 판 무덤에 넣어 두고 돌을 굴려 무덤 문에 놓으매"},{"r":"요11:38","t":"이에 예수께서 다시 속으로 통분히 여기시며 무덤에 가시니 무덤이 굴이라 돌로 막았거늘"}],"눅24:26":[{"r":"마1:17","t":"그런즉 모든 대 수가 아브라함부터 다윗까지 열 네 대요, 다윗부터 바벨론으로 이거할 때까지 열 네대요, 바벨론으로 이거한 후부터 그리스도까지 열 네 대러라"},{"r":"눅9:26","t":"누구든지 나와 내 말을 부끄러워하면 인자도 자기와 아버지와 거룩한 천사들의 영광으로 올 때에 그 사람을 부끄러워하리라"},{"r":"눅24:7","t":"이르시기를 인자가 죄인의 손에 넘기워 십자가에 못 박히고 제 삼일에 다시 살아나야 하리라 하셨느니라 한대"},{"r":"눅24:44","t":"또 이르시되 내가 너희와 함께 있을 때에 너희에게 말한 바 곧 모세의 률법과 선지자의 글과 시편에 나를 가리켜 기록된 모든 것이 이루어져야 하리라 한 말이 이것이라 하시고"},{"r":"눅24:46","t":"또 이르시되 이같이 그리스도가 고난을 받고 제 삼일에 죽은 자 가운데서 살아날 것과"},{"r":"히2:10","t":"만물이 인하고 만물이 말미암은 자에게는 많은 아들을 이끌어 영광에 들어가게 하시는 일에 저희 구원의 주를 고난으로 말미암아 온전케 하심이 합당하도다"},{"r":"히12:2","t":"믿음의 주요 또 온전케 하시는 이인 예수를 바라보자 저는 그 앞에 있는 즐거움을 위하여 십자가를 참으사 부끄러움을 개의치 아니하시더니 하나님 보좌 우편에 앉으셨느니라"},{"r":"벧전1:11","t":"자기 속에 계신 그리스도의 영이 그 받으실 고난과 후에 얻으실 영광을 미리 증거하여 어느 시, 어떠한 때를 지시하시는지 상고하니라"},{"r":"행3:18","t":"그러나 하나님이 모든 선지자의 입을 의탁하사 자기의 그리스도의 해 받으실 일을 미리 알게 하신 것을 이와 같이 이루셨느니라"}],"눅24:27":[{"r":"창3:15","t":"내가 너로 녀자와 원수가 되게 하고 너의 후손도 녀자의 후손과 원수가 되게 하리니 녀자의 후손은 네 머리를 상하게 할 것이요 너는 그의 발꿈치를 상하게 할 것이니라 하시고"},{"r":"창12:3","t":"너를 축복하는 자에게는 내가 복을 내리고 너를 저주하는 자에게는 내가 저주하리니 땅의 모든 족속이 너를 인하여 복을 얻을 것이니라 하신지라"},{"r":"창22:18","t":"또 네 씨로 말미암아 천하 만민이 복을 얻으리니 이는 네가 나의 말을 준행하였음이니라  하셨다 하니라"},{"r":"민21:9","t":"모세가 놋뱀을 만들어 장대 위에 다니 뱀에게 물린 자마다 놋뱀을 쳐다 본즉 살더라"},{"r":"민24:17","t":"내가 그를 보아도 이 때의 일이 아니며 내가 그를 바라보아도 가까운 일이 아니로다 한 별이 야곱에게서 나오며 한 홀이 이스라엘에게서 일어나서 모압을 이 편에서, 저 편까지 파하고 또 소동하는 자식들을 다 멸하리로다"},{"r":"신18:15","t":"네 하나님 여호와께서 너의 중 네 형제 중에서 나와 같은 선지자 하나를 너를 위하여 일으키시리니 너희는 그를 들을지니라"},{"r":"요1:45","t":"빌립이 나다나엘을 찾아 이르되 모세가 률법에 기록하였고 여러 선지자가 기록한 그 이를 우리가 만났으니 요셉의 아들 나사렛 예수니라"},{"r":"요5:46","t":"모세를 믿었더면 또 나를 믿었으리니 이는 그가 내게 대하여 기록하였음이라"},{"r":"삼하7:12~16","t":"네 수한이 차서 네 조상들과 함께 잘 때에 내가 네 몸에서 날 자식을 네 뒤에 세워 그 나라를 견고케 하리라"},{"r":"사7:14","t":"그러므로 주께서 친히 징조로 너희에게 주실 것이라 보라, 처녀가 잉태하여 아들을 낳을 것이요 그 이름을 임마누엘이라 하리라"},{"r":"사9:6","t":"이는 한 아기가 우리에게 났고 한 아들을 우리에게 주신바 되었는데 그 어깨에는 정사를 메었고 그 이름은 기묘자라 모사라 전능하신 하나님이라 영존하시는 아버지라 평강의 왕이라 할것임이라"},{"r":"사50:6","t":"나를 때리는 자들에게 내 등을 맡기며 나의 수염을 뽑는 자들에게 나의 뺨을 맡기며 수욕과 침 뱉음을 피하려고 내 얼굴을 가리우지 아니하였느니라"},{"r":"사52:13~53:12","t":"여호와께서 가라사대 보라, 내 종이 형통하리니 받들어 높이 들려서 지극히 존귀하게 되리라"},{"r":"사61:1","t":"주 여호와의 신이 내게 임하였으니 이는 여호와께서 내게 기름을 부으사 가난한 자에게 아름다운 소식을 전하게 하려 하심이라 나를 보내사 마음이 상한 자를 고치며 포로된 자에게 자유를, 갇힌 자에게 놓임을 전파하며"},{"r":"렘23:5,6","t":"나 여호와가 말하노라 보라, 때가 이르리니 내가 다윗에게 한 의로운 가지를 일으킬 것이라 그가 왕이 되어 지혜롭게 행사하며 세상에서 공평과 정의를 행할 것이며"},{"r":"단7:13,14","t":"내가 또 밤 이상 중에 보았는데 인자 같은 이가 하늘 구름을 타고 와서 옛적부터 항상 계신 자에게 나아와 그 앞에 인도되매"},{"r":"단9:24~27","t":"네 백성과 네 거룩한 성을 위하여 칠십 이레로 기한을 정하였나니 허물이 마치며 죄가 끝나며 죄악이 영속되며 영원한 의가 드러나며 이상과 예언이 응하며 또 지극히 거룩한 자가 기름부음을 받으리라"},{"r":"미5:2","t":"베들레헴 에브라다야, 너는 유다 족속 중에 작을지라도 이스라엘을 다스릴 자가 네게서 내게로 나올 것이라 그의 근본은 상고에 태초에니라"},{"r":"슥6:12","t":"고하여 이르기를 만군의 여호와께서 말씀하시되 보라, 순이라 이름하는 사람이 자기 곳에서 돌아나서 여호와의 전을 건축하리라"},{"r":"슥9:9","t":"시온의 딸아 크게 기뻐할찌어다  예루살렘의 딸아 즐거이 부를찌어다  보라, 네 왕이 네게 임하나니 그는 공의로우며 구원을 베풀며 겸손하여서 나귀를 타나니 나귀의 작은 것 곧 나귀새끼니라"},{"r":"슥12:10","t":"내가 다윗의 집과 예루살렘 거민에게 은총과 간구하는 심령을 부어 주리니 그들이 그 찌른바 그를 바라보고 그를 위하여 애통하기를 독자를 위하여 애통하듯 하며 그를 위하여 통곡하기를 장자를 위하여 통곡하듯 하리로다"},{"r":"슥13:7","t":"만군의 여호와가 말하노라 칼아 깨어서 내 목자, 내 짝된 자를 치라 목자를 치면 양이 흩어지려니와 작은 자들 위에는 내가 내 손을 드리우리라"},{"r":"말3:1","t":"만군의 여호와가 이르노라 보라, 내가 내 사자를 보내리니 그가 내 앞에서 길을 예비할 것이요 또 너희의 구하는 바 주가 홀연히 그 전에 임하리니 곧 너희의 사모하는 바 언약의 사자가 임할 것이라"},{"r":"말4:2","t":"내 이름을 경외하는 너희에게는 의로운 해가 떠올라서 치료하는 광선을 발하리니 너희가 나가서 외양간에서 나온 송아지 같이 뛰리라"},{"r":"행13:27","t":"예루살렘에 사는 자들과 저희 관원들이 예수와 및 안식일마다 외우는 바 선지자들의 말을 알지 못하므로 예수를 정죄하여 선지자들의 말을 응하게 하였도다"},{"r":"행8:35","t":"빌립이 입을 열어 이 글에서 시작하여 예수를 가르쳐 복음을 전하니"}],"눅24:4":[{"r":"행1:10","t":"올라가실 때에 제자들이 자세히 하늘을 쳐다보고 있는 데 흰 옷 입은 두사람이 저희 곁에 서서"},{"r":"행10:30","t":"고넬료가 가로되 나흘 전 이맘 때까지 내 집에서 제 구시 기도를 하는데 홀연히 한 사람이 빛난 옷을 입고 내 앞에 서서"},{"r":"요20:12","t":"흰 옷 입은 두 천사가 예수의 시체 뉘었던 곳에 하나는 머리 편에 하나는 발 편에 앉았더라"}],"눅24:5":[{"r":"눅24:37","t":"저희가 놀라고 무서워하여 그 보는 것을 영으로 생각하는지라"},{"r":"요6:57","t":"살아 계신 아버지께서 나를 보내시매 내가 아버지로 인하여 사는 것같이 나를 먹는 그 사람도 나로 인하여 살리라"},{"r":"히7:8","t":"또 여기는 죽을 자들이 십분의 일을 받으나 저기는 산다고 증거를 얻은 자가 받았느니라"},{"r":"계1:18","t":"곧 산 자라 내가 전에 죽었었노라 볼지어다 이제 세세토록 살아 있어 사망과 음부의 열쇠를 가졌노니"}],"눅24:6":[{"r":"눅9:22","t":"가라사대 인자가 많은 고난을 받고 장로들과 대제사장들과 서기관들에게 버린 바 되어 죽임을 당하고 제 삼일에 살아나야 하리라 하시고"},{"r":"눅9:44","t":"이 말을 너희 귀에 담아두라 인자가 장차 사람들의 손에 넘기우리라 하시되"},{"r":"마17:22,23","t":"갈릴리에 모일 때에 예수께서 제자들에게 이르시되 인자가 장차 사람들의 손에 넘기워"},{"r":"막9:30,31","t":"그곳을 떠나 갈릴리 가운데로 지날쌔 예수께서 아무에게도 알리고자 아니하시니"},{"r":"눅24:44","t":"또 이르시되 내가 너희와 함께 있을 때에 너희에게 말한 바 곧 모세의 률법과 선지자의 글과 시편에 나를 가리켜 기록된 모든 것이 이루어져야 하리라 한 말이 이것이라 하시고"}],"눅4:16":[{"r":"눅4:16~30","t":"예수께서 그 자라나신 곳 나사렛에 이르사 안식일에 자기 규례대로 회당에 들어가사 성경을 읽으려고 서시매"},{"r":"마13:54~58","t":"고향으로 돌아가사 저희 회당에서 가르치시니 저희가 놀라 가로되 이 사람의 이 지혜와 이런 능력이 어디서 났느뇨"},{"r":"막6:1~6","t":"예수께서 거기를 떠나사 고향으로 가시니 제자들도 좇으니라"},{"r":"눅2:39","t":"주의 률법을 좇아 모든 일을 필하고 갈릴리로 돌아가 본 동리 나사렛에 이르니라"},{"r":"눅2:51","t":"예수께서 한가지로 내려가사 나사렛에 이르러 순종하여 받드시더라 그 모친은 이 모든 말을 마음에 두니라"},{"r":"행17:2","t":"바울이 자기의 규례대로 저희에게로 들어가서 세 안식일에 성경을 가지고 강론하며"},{"r":"눅4:31","t":"갈릴리 가버나움 동리에 내려오사 안식일에 가르치시매"},{"r":"막6:2","t":"안식일이 되어 회당에서 가르치시니 많은 사람이 듣고 놀라 가로되 이 사람이 어디서 이런 것을 얻었느뇨 이 사람의 받은 지혜와 그 손으로 이루어지는 이런 권능이 어찌 됨이뇨"},{"r":"행13:15","t":"률법과 선지자의 글을 읽은 후에 회당장들이 사람을 보내어 물어 가로되 형제들아 만일 백성을 권할 말이 있거든 말하라 하니"},{"r":"행13:27","t":"예루살렘에 사는 자들과 저희 관원들이 예수와 및 안식일마다 외우는 바 선지자들의 말을 알지 못하므로 예수를 정죄하여 선지자들의 말을 응하게 하였도다"},{"r":"행15:21","t":"이는 예로부터 각 성에서 모세를 전하는 자가 있어 안식일마다 회당에서 그 글을 읽음이니라 하더라"}],"눅4:31":[{"r":"눅4:31~37","t":"갈릴리 가버나움 동리에 내려오사 안식일에 가르치시매"},{"r":"막1:21~28","t":"저희가 가버나움에 들어가니라 예수께서 곧 안식일에 회당에 들어가 가르치시매"},{"r":"마4:13","t":"나사렛을 떠나 스불론과 납달리 지경 해변에 있는 가버나움에 가서 사시니"},{"r":"막6:2","t":"안식일이 되어 회당에서 가르치시니 많은 사람이 듣고 놀라 가로되 이 사람이 어디서 이런 것을 얻었느뇨 이 사람의 받은 지혜와 그 손으로 이루어지는 이런 권능이 어찌 됨이뇨"},{"r":"눅4:15,16","t":"친히 그 여러 회당에서 가르치시매 뭇 사람에게 칭송을 받으시더라"},{"r":"마4:23","t":"예수께서 온 갈릴리에 두루 다니사 저희 회당에서 가르치시며 천국 복음을 전파하시며 백성 중에 모든 병과 모든 약한 것을 고치시니"}],"눅6:10":[{"r":"막3:34","t":"둘러 앉은 자들을 둘러 보시며 가라사대 내 모친과 내 동생들을 보라"},{"r":"막5:32","t":"예수께서 이 일 행한 녀자를 보려고 둘러 보시니"},{"r":"막10:23","t":"예수께서 둘러 보시고 제자들에게 이르시되 재물이 있는 자는 하나님의 나라에 들어가기가 심히 어렵도다 하시니"},{"r":"막10:21","t":"예수께서 그를 보시고 사랑하여 가라사대 네게 오히려 한 가지 불족한 것이 있으니 가서 네 있는 것을 다 팔아 가난한 자들을 주라 그리하면 하늘에서 보화가 네게 있으리라 그리고 와서 나를 좇으라  하시니"},{"r":"왕상13:4","t":"여로보암 왕이 하나님의 사람의 벧엘에 있는 단을 향하여 외쳐 말함을 들을 때에 단에서 손을 펴며 저를 잡으라 하더라 저를 향하여 편 손이 말라 다시 거두지 못하며"}],"눅6:11":[{"r":"딤후3:9","t":"그러나 저희가 더 나가지 못할 것은 저 두 사람의 된 것과 같이 저희 어리석음이 드러날 것임이니라"}],"눅6:5":[{"r":"눅5:24","t":"그러나 인자가 땅에서 죄를 사하는 권세가 있는 줄을 너희로 알게 하리라 하시고 중풍병자에게 말씀하시되 내가 네게 이르노니 일어나 네 침상을 가지고 집으로 가라 하시매"}],"눅6:6":[{"r":"눅6:6~11","t":"또 다른 안식일에 예수께서 회당에 들어가사 가르치실새 거기 오른손 마른 사람이 있는지라"},{"r":"마12:9~14","t":"거기를 떠나 저희 회당에 들어가시니"},{"r":"막3:1~6","t":"예수께서 다시 회당에 들어가시니 한편 손 마른 사람이 거기 있는지라"},{"r":"막6:2","t":"안식일이 되어 회당에서 가르치시니 많은 사람이 듣고 놀라 가로되 이 사람이 어디서 이런 것을 얻었느뇨 이 사람의 받은 지혜와 그 손으로 이루어지는 이런 권능이 어찌 됨이뇨"}],"눅6:7":[{"r":"요8:6","t":"저희가 이렇게 말함은 고소할 조건을 얻고자 하여 예수를 시험함이러라 예수께서 몸을 굽히사 손가락으로 땅에 쓰시니"},{"r":"눅14:1","t":"안식일에 예수께서 바리새인의 한 두령의 집에 떡 잡수시러 들어가시니 저희가 엿보고 있더라"},{"r":"눅20:20","t":"이에 저희가 엿보다가 예수를 총독의 치리와 권세 아래 붙이려 하여 정탐들을 보내어 그들로 스스로 의인인 체하며 예수의 말을 책잡게 하니"},{"r":"눅11:54","t":"그 입에서 나오는 것을 잡고자 하여 목을 지키더라"}],"눅6:8":[{"r":"마9:4","t":"예수께서 그 생각을 아시고 가라사대 너희가 어찌하여 마음에 악한 생각을 하느냐"}],"눅6:9":[{"r":"눅14:3","t":"예수께서 대답하여 률법사들과 바리새인들에게 일러 가라사대 안식일에 병 고쳐 주는 것이 합당하냐  아니하냐"}],"단2:1":[{"r":"단4:5","t":"한 꿈을 꾸고 그로 인하여 두려워하였으되 곧 내 침상에서 생각하는 것과 뇌 속으로 받은 이상을 인하여 번민하였었노라"},{"r":"단5:9","t":"그러므로 벨사살 왕이 크게 번민하여 그 낯빛이 변하였고 귀인들도 다 놀라니라"},{"r":"창41:8","t":"아침에 그 마음이 번민하여 보내어 애굽의 술객과 박사를 모두 불러 그들에게 그 꿈을 고하였으나 그것을 바로에게 해석하는 자가 없었더라"},{"r":"단6:18","t":"왕이 궁에 돌아가서는 밤이 맞도록 금식하고 그 앞에 기악을 그치고 침수를 폐하니라"},{"r":"에6:1","t":"이 밤에 왕이 잠이 오지 아니하므로 명하여 력대 일기를 가져다가 자기 앞에서 읽히더니"}],"단2:28":[{"r":"단2:22","t":"그는 깊고 은밀한 일을 나타내시고 어두운 데 있는 것을 아시며 또 빛이 그와 함께 있도다"},{"r":"단10:14","t":"이제 내가 말일에 네 백성의 당할 일을 네게 깨닫게 하러 왔노라 대저 이 이상은 오래 후의 일이니라"},{"r":"호3:5","t":"그 후에 저희가 돌아와서 그 하나님 여호와와 그 왕 다윗을 구하고 말일에는 경외하므로 여호와께로와 그 은총으로 나아가리라"},{"r":"단4:5","t":"한 꿈을 꾸고 그로 인하여 두려워하였으되 곧 내 침상에서 생각하는 것과 뇌 속으로 받은 이상을 인하여 번민하였었노라"},{"r":"단7:15","t":"나 다니엘이 중심에 근심하며 내 뇌 속에 이상이 나로 번민케 한지라"}],"단2:29":[{"r":"단2:45","t":"왕이 사람의 손으로 아니하고 산에서 뜨인 돌이 철과 놋과 진흙과 은과 김을 부숴뜨린 것을 보신 것은 크신 하나님이 장래 일을 왕께 알게 하신 것이라 이 꿈이 참되고 이 해석이 확실하니이다"}],"단2:32":[{"r":"단2:38","t":"인생들과 들짐승과 공중의 새들 어느곳에 있는 것을 무론하고 그것들을 왕의 손에 붙이사 다 다스리게 하셨으니 왕은 곧 그 김머리니이다"},{"r":"단2:39","t":"왕의 후에 왕만 못한 다른 나라가 일어날 것이요 세째로 또 놋 같은 나라가 일어나서 온 세계를 다스릴 것이며"}],"단2:33":[{"r":"단2:40","t":"네째 나라는 강하기가 철 같으리니 철은 모든 물건을 부숴뜨리고 이기는 것이라 철이 모든 것을 부수는 것 같이 그 나라가 뭇 나라를 부숴뜨리고 빻을 것이며"}],"단2:34":[{"r":"단8:25","t":"그가 꾀를 베풀어 제 손으로 궤휼을 이루고 마음에 스스로 큰 체하며 또 평화한 때에 많은 무리를 멸하며 또 스스로 서서 만왕의 왕을 대적할 것이나 그가 사람의 손을 말미암지 않고 깨어지리라"},{"r":"욥34:20","t":"그들은 밤중 순식간에 죽나니 백성은 떨며 없어지고 세력있는 자도 사람의 손을 대지 않고 제함을 당하느니라"},{"r":"애4:6","t":"전에 소돔이 사람의 손을 대지 않고 경각간에 무너지더니 이제 처녀 내 백성의 죄가 소돔의 죄악보다 중하도다"},{"r":"고후5:1","t":"만일 땅에 있는 우리의 장막 집이 무너지면 하나님께서 지으신 집 곧 손으로 지은 것이 아니요, 하늘에 있는 영원한 집이 우리에게 있는 줄 아나니"},{"r":"단2:40","t":"네째 나라는 강하기가 철 같으리니 철은 모든 물건을 부숴뜨리고 이기는 것이라 철이 모든 것을 부수는 것 같이 그 나라가 뭇 나라를 부숴뜨리고 빻을 것이며"},{"r":"단2:44,45","t":"이 열왕의 때에 하늘의 하나님이 한 나라를 세우시리니 이것은 영원히 망하지도 아니할 것이요 그 국권이 다른 백성에게로 돌아가지도 아니할 것이요 도리어 이 모든 나라를 쳐서 멸하고 영원히 설 것이라"},{"r":"사8:9","t":"너희 민족들아 훤화하라 필경 패망하리라 너희 먼 나라 백성들아 들을지니라 너희 허리를 동이라 필경 패망하리라 너희 허리에 띠를 따라 필경 패망하리라"},{"r":"마21:44","t":"이 돌 위에 떨어지는 자는 깨어지겠고 이 돌이 사람 위에 떨어지면 저를 가루로 만들어 흩으리라 하시니"},{"r":"눅20:18","t":"무릇 이 돌 위에 떨어지는 자는 깨어지겠고 이 돌이 사람 위에 떨어지면 저를 가루로 만들어 흩으리라 하시니라"}],"단2:35":[{"r":"시1:4","t":"악인은 그렇지 않음이여 오직, 바람에 나는 겨와 같도다"},{"r":"계20:11","t":"또 내가 크고 흰 보좌와 그 위에 앉으신 자를 보니 땅과 하늘이 그 앞에서 피하여 간 데 없더라"},{"r":"사2:2","t":"말일에 여호와의 전의 산이 모든 산 꼭대기에 굳게 설 것이요 모든 작은 산 위에 뛰어나리니 만방이 그리로 모여들 것이라"},{"r":"시80:9","t":"주께서 그 앞서 준비하셨으므로 그 뿌리가 깊이 땅에 편만하며"}],"단2:37":[{"r":"스7:12","t":"모든 왕의 왕 아닥사스다는 하늘의 하나님의 률법에 완전한 학사겸 제사장 에스라에게"},{"r":"겔26:7","t":"나 주 여호와가 말하노라 내가 열왕의 왕 곧 바벨론 왕 느부갓네살로 북방에서 말과 병거와 기병과 군대와 백성의 큰 무리를 거느리고 와서 두로를 치게 할 때에"},{"r":"단2:19","t":"이에 이 은밀한 것이 밤에 이상으로 다니엘에게 나타나 보이매 다니엘이 하늘에 계신 하나님을 찬송하니라"},{"r":"단5:18","t":"왕이여 지극히 높으신 하나님이 왕의 부친 느부갓네살에게 나라와 큰 권세와 영광과 위엄을 주셨고"},{"r":"스1:2","t":"바사 왕 고레스는 말하노니 하늘의 신 여호와께서 세상 만국으로 내게 주셨고 나를 명하사 유다 예루살렘에 전을 건축하라 하셨나니"},{"r":"단2:21","t":"그는 때와 기한을 변하시며 왕들을 폐하시고 왕들을 세우시며 지혜자에게 지혜를 주시고 지식자에게 총명을 주시는도다"}],"단2:38":[{"r":"단4:21","t":"그 잎사귀는 아름답고 그 열매는 많아서 만민의 식물이 될만하고 들짐승은 그 아래 거하며 공중에 나는 새는 그 가지에 깃들이더라 하시오니"},{"r":"렘27:6","t":"이제 내가 이 모든 땅을 내 종 바벨론 왕 느부갓네살의 손에 주고 또 들짐승들을 그에게 주어서 부리게 하였나니"},{"r":"단2:32","t":"그 우상의 머리는 정김이요 가슴과 팔들은 은이요 배와 넓적다리는 놋이요"}],"단2:39":[{"r":"단2:32","t":"그 우상의 머리는 정김이요 가슴과 팔들은 은이요 배와 넓적다리는 놋이요"},{"r":"단5:28","t":"{베레스}는 왕의 나라가 나뉘어서 메대와 바사 사람에게 준 바 되었다 함이니이다"},{"r":"단5:31","t":"메대 사람 다리오가 나라를 얻었는데 때에 다리오는 육십 이세였더라"},{"r":"단7:6","t":"그 후에 내가 또 본즉 다른 짐승 곧 표범과 같은 것이 있는데 그 등에는 새의 날개 넷이 있고 그 짐승에게 또 머리 넷이 있으며 또 권세를 받았으며"}],"단2:40":[{"r":"단7:7","t":"내가 밤 이상 가운데 그 다음에 본 네째 짐승은 무섭고 놀라우며 또 극히 강하며 또 큰 철 이가 있어서 먹고 부숴뜨리고 그 나머지를 발로 밟았으며 이 짐승은 전의 모든 짐승과 다르고 또 열 뿔이 있으므로"},{"r":"단7:23","t":"모신 자가 이처럼 이르되 네째 짐승은 곧 땅의 네째 나라인데 이는 모든 나라보다 달라서 천하를 삼키고 밟아 부숴뜨릴 것이며"},{"r":"단2:34","t":"또 왕이 보신즉 사람의 손으로 하지 아니하고 뜨인 돌이 신상의 철과 진흙의 발을 쳐서 부숴뜨리매"}],"단2:41":[{"r":"단2:33","t":"그 종아리는 철이요 그 발은 얼마는 철이요 얼마는 진흙이었나이다"}],"단2:44":[{"r":"단2:19","t":"이에 이 은밀한 것이 밤에 이상으로 다니엘에게 나타나 보이매 다니엘이 하늘에 계신 하나님을 찬송하니라"},{"r":"단4:3","t":"크도다, 그 이적이여 능하도다 그 기사여, 그 나라는 영원한 나라요 그 권병은 대대에 이르리로다"},{"r":"단4:34","t":"그 기한이 차매 나 느부갓네살이 하늘을 우러러 보았더니 내 총명이 다시 내게로 돌아온지라 이에 내가 지극히 높으신 자에게 감사하며 영생하시는 자를 찬양하고 존경하였노니 그 권세는 영원한 권세요 그 나라는 대대로 이르리로다"},{"r":"단6:26","t":"내가 이제 조서를 내리노라 내 나라 관할 아래 있는 사람들은 다 다니엘의 하나님 앞에서 떨며 두려워할지니 그는 사시는 하나님이시요 영원히 변치 않으실 자시며 그 나라는 망하지 아니할 것이요 그 권세는 무궁할 것이며"},{"r":"단7:14","t":"그에게 권세와 영광과 나라를 주고 모든 백성과 나라들과 각 방언하는 자로 그를 섬기게 하였으니 그 권세는 영원한 권세라 옮기지 아니할 것이요 그 나라는 폐하지 아니할 것이니라"},{"r":"단7:27","t":"나라와 권세와 온 천하 렬국의 위세가 지극히 높으신 자의 성민에게 붙인 바 되리니 그의 나라는 영원한 나라이라 모든 권세 있는 자가 다 그를 섬겨 복종하리라 하여"},{"r":"미4:7","t":"그 저는 자로 남은 백성이 되게 하며 멀리 쫓겨났던 자로 강한 나라가 되게 하고 나 여호와가 시온산에서 이제부터 영원까지 그들을 치리하리라 하셨나니"},{"r":"마3:2","t":"회개하라  천국이 가까왔느니라  하였으니"},{"r":"눅1:33","t":"영원히 야곱의 집에 왕노릇하실 것이며 그 나라가 무궁하리라"},{"r":"요18:36","t":"예수께서 대답하시되 내 나라는 이 세상에 속한 것이 아니라 만일 내 나라가 이 세상에 속한 것이었더면 내 종들이 싸워 나로 유대인들에게 넘기우지 않게 하였으리라 이제 내 나라는 여기에 속한 것이 아니니라"},{"r":"사60:12","t":"너를 섬기지 아니하는 백성과 나라는 파멸하리니 그 백성들은 반드시 진멸되리라"},{"r":"단2:34","t":"또 왕이 보신즉 사람의 손으로 하지 아니하고 뜨인 돌이 신상의 철과 진흙의 발을 쳐서 부숴뜨리매"}],"단2:45":[{"r":"단2:34","t":"또 왕이 보신즉 사람의 손으로 하지 아니하고 뜨인 돌이 신상의 철과 진흙의 발을 쳐서 부숴뜨리매"},{"r":"사28:16","t":"그러므로 주 여호와께서 가라사대 보라 내가 한 돌을 시온에 두어 기초를 삼았노니 곧 시험한 돌이요 귀하고 견고한 기초 돌이라 그것을 믿는 자는 급절하게 되지 아니하리로다"},{"r":"단2:28","t":"오직 은밀한 것을 나타내실 자는 하늘에 계신 하나님이시라 그가 느부갓네살왕에게 후일에 될 일을 알게 하셨나이다 왕의 꿈 곧 왕이 침상에서 뇌 속으로 받은 이상은 이러하니이다"}],"단5:28":[{"r":"단5:31","t":"메대 사람 다리오가 나라를 얻었는데 때에 다리오는 육십 이세였더라"},{"r":"단9:1","t":"메대 족속 아하수에로의 아들 다리오가 갈대아 나라 왕으로 세움을 입던 원년"},{"r":"사13:17","t":"보라, 은을 돌아보지 아니하며 김을 기뻐하지 아니하는 메대 사람을 내가 격동시켜 그들을 치게 하리니"},{"r":"사21:2","t":"혹독한 묵시가 내게 보였도다 주께서 가라사대 속이는 자는 속이고 략탈하는 자는 략탈하도다 엘람이여 올라가고 매대여 에워싸라 그의 모든 탄식을 내가 그치게 하였노라 하시도다"},{"r":"렘51:28","t":"렬국 곧 메대인의 왕들과 그 방백들과 그 모든 두령과 그 관할하는 모든 땅을 예비시켜 그를 치게 하라"},{"r":"단6:28","t":"이 다니엘이 다리오 왕의 시대와 바사 사람 고레스 왕의 시대에 형통하였더라"}],"단5:29":[{"r":"단5:7","t":"왕이 크게 소리하여 술객과 갈대아 술사와 점장이를 불러 오게 하고 바벨론 박사들에게 일러 가로되 무론 누구든지 이 글자를 읽고 그 해석을 내게 보이면 자주옷을 입히고 김사슬로 그 목에 드리우고 그로 나라의 세째 치리자를 삼으리라 하니라"},{"r":"단5:16","t":"내가 네게 대하여 들은즉 너는 해석을 잘하고 의문을 파한다 하도다 그런즉 이제 네가 이 글을 읽고 그 해석을 내게 알게 하면 네게 자주옷을 입히고 김사슬을 네 목에 드리우고 너로 나라의 세째 치리자를 삼으리라"},{"r":"단5:7","t":"왕이 크게 소리하여 술객과 갈대아 술사와 점장이를 불러 오게 하고 바벨론 박사들에게 일러 가로되 무론 누구든지 이 글자를 읽고 그 해석을 내게 보이면 자주옷을 입히고 김사슬로 그 목에 드리우고 그로 나라의 세째 치리자를 삼으리라 하니라"},{"r":"단5:16","t":"내가 네게 대하여 들은즉 너는 해석을 잘하고 의문을 파한다 하도다 그런즉 이제 네가 이 글을 읽고 그 해석을 내게 알게 하면 네게 자주옷을 입히고 김사슬을 네 목에 드리우고 너로 나라의 세째 치리자를 삼으리라"}],"단5:30":[{"r":"렘50:24","t":"바벨론아 내가 너를 잡으려고 올무를 놓았더니 네가 깨닫지 못하고 걸렸고 네가 나 여호와와 다투었으므로 만난 바 되어 잡혔도다"},{"r":"렘51:31","t":"보발군이 달려 만나고 사자가 달려 만나서 바벨론 왕에게 고하기를 그 성읍 사방이 함락되었으며"},{"r":"렘51:39","t":"열정이 일어날 때에 내가 연회를 베풀고 그들로 취하여 기뻐하다가 영영히 잠들어 깨지 못하게 하리라 여호와의 말이니라"},{"r":"렘51:57","t":"만군의 여호와라 일컫는 왕이 이같이 말씀하시되 내가 그 방백들과 박사들과 감독들과 관장들과 용사들로 취하게 하리니 그들이 영영히 자고 깨지 못하리라"},{"r":"단9:1","t":"메대 족속 아하수에로의 아들 다리오가 갈대아 나라 왕으로 세움을 입던 원년"}],"단7:1":[{"r":"단5:1","t":"벨사살 왕이 그 귀인 일천 명을 위하여 큰 잔치를 배설하고 그 일천 명 앞에서 술을 마시니라"},{"r":"단1:17","t":"하나님이 이 네 소년에게 지식을 얻게 하시며 모든 학문과 재조에 명철하게 하신 외에 다니엘은 또 모든 이상과 몽조를 깨달아 알더라"},{"r":"단7:15","t":"나 다니엘이 중심에 근심하며 내 뇌 속에 이상이 나로 번민케 한지라"},{"r":"단2:28","t":"오직 은밀한 것을 나타내실 자는 하늘에 계신 하나님이시라 그가 느부갓네살왕에게 후일에 될 일을 알게 하셨나이다 왕의 꿈 곧 왕이 침상에서 뇌 속으로 받은 이상은 이러하니이다"},{"r":"단4:5","t":"한 꿈을 꾸고 그로 인하여 두려워하였으되 곧 내 침상에서 생각하는 것과 뇌 속으로 받은 이상을 인하여 번민하였었노라"}],"단7:10":[{"r":"시21:9","t":"네가 노할 때에 저희로 풀무 같게 할 것이라 여호와께서 진노로 저희를 삼키시리니 불이 저희를 소멸하리로다"},{"r":"시103:21","t":"여호와를 봉사하여 그 뜻을 행하는 너희 모든 천군이여 여호와를 송축하라"},{"r":"시68:17","t":"하나님의 병거가 천천이요 만만이라 주께서 그 중에 계심이 시내산 성소에 계심 같도다"},{"r":"히12:22","t":"그러나 너희가 이른 곳은 시온산과 살아계신 하나님의 도성인 하늘의 예루살렘과 천만 천사와"},{"r":"계5:11","t":"내가 또 보고 들으매 보좌와 생물들과 장로들을 둘러 선 많은 천사의 음성이 있으니 그 수가 만만이요 천천이라"},{"r":"슥3:4","t":"여호와께서 자기 앞에 선 자들에게 명하사 그 더러운 옷을 벗기라 하시고 또 여호수아에게 이르시되 내가 네 죄과를 제하여 버렸으니 네게 아름다운 옷을 입히리라 하시기로"},{"r":"단7:22","t":"옛적부터 항상 계신 자가 와서 지극히 높으신 자의 성도를 위하여 신원하셨고 때가 이르매 성도가 나라를 얻었더라"},{"r":"단7:26","t":"그러나 심판이 시작된즉 그는 권세를 빼앗기고 끝까지 멸망할 것이요"},{"r":"계11:18","t":"이방들이 분노하매 주의 진노가 임하여 죽은 자를 심판하시며 종 선지자들과 성도들과 또 무론대소하고 주의 이름을 경외하는 자들에게 상 주시며 또 땅을 망하게 하는 자들을 멸망시키실 때로소이다 하더라"},{"r":"계20:4","t":"또 내가 보좌들을 보니 거기 앉은 자들이 있어 심판하는 권세를 받았더라 또 내가 보니 예수의 증거와 하나님의 말씀을 인하여 목 베임을 받은 자의 령혼들과 또 짐승과 그의 우상에게 경배하지도 아니하고 이마와 손에 그의 표를 받지도 아니한 자들이 살아서 그리스도로 더불어 천년 동안 왕노릇하니"},{"r":"계20:12","t":"또 내가 보니 죽은 자들이 무론대소하고 그 보좌 앞에 섰는데 책들이 펴 있고 또 다른 책이 펴졌으니 곧 생명책이라 죽은 자들이 자기 행위를 따라 책들에 기록된 대로 심판을 받으니"}],"단7:13":[{"r":"마26:64","t":"예수께서 가라사대 네가 말하였느니라 그러나 내가 너희에게 이르노니 이 후에 인자가 권능의 우편에 앉은 것과 하늘 구름을 타고 오는 것을 너희가 보리라 하시니"},{"r":"막14:62","t":"예수께서 이르시되 내가 그니라  인자가 권능자의 우편에 앉은 것과 하늘 구름을 타고 오는 것을 너희가 보리라 하시니"},{"r":"계1:7","t":"볼지어다  구름을 타고 오시리라 각인의 눈이 그를 보겠고 그를 찌른 자들도 볼 터이요 땅에 있는 모든 족속이 그를 인하여 애곡하리니 그러하리라 아멘"},{"r":"계14:14","t":"또 내가 보니 흰 구름이 있고 구름 위에 사람의 아들과 같은 이가 앉았는데 그 머리에는 김 면류관이 있고 그 손에는 이한 낫을 가졌더라"}],"단7:14":[{"r":"시110:1,2","t":"(다윗의 시) 여호와께서 내 주에게 말씀하시기를 내가 네 원수로 네 발등상 되게 하기까지 너는 내 우편에 앉으라 하셨도다"},{"r":"사9:6,7","t":"이는 한 아기가 우리에게 났고 한 아들을 우리에게 주신바 되었는데 그 어깨에는 정사를 메었고 그 이름은 기묘자라 모사라 전능하신 하나님이라 영존하시는 아버지라 평강의 왕이라 할것임이라"},{"r":"계11:15","t":"일곱째 천사가 나팔을 불매 하늘에 큰 음성들이 나서 가로되 세상 나라가 우리 주와 그 그리스도의 나라가 되어 그가 세세토록 왕노릇하시리로다 하니"},{"r":"단3:4","t":"반포하는 자가 크게 외쳐 가로되 백성들과 나라들과 각 방언하는 자들아 왕이 너희 무리에게 명하시나니"},{"r":"단2:44","t":"이 열왕의 때에 하늘의 하나님이 한 나라를 세우시리니 이것은 영원히 망하지도 아니할 것이요 그 국권이 다른 백성에게로 돌아가지도 아니할 것이요 도리어 이 모든 나라를 쳐서 멸하고 영원히 설 것이라"}],"단7:17":[{"r":"단7:3","t":"큰 짐승 넷이 바다에서 나왔는데 그 모양이 각각 다르니"}],"단7:18":[{"r":"단7:22","t":"옛적부터 항상 계신 자가 와서 지극히 높으신 자의 성도를 위하여 신원하셨고 때가 이르매 성도가 나라를 얻었더라"},{"r":"단7:27","t":"나라와 권세와 온 천하 렬국의 위세가 지극히 높으신 자의 성민에게 붙인 바 되리니 그의 나라는 영원한 나라이라 모든 권세 있는 자가 다 그를 섬겨 복종하리라 하여"},{"r":"마25:34","t":"그 때에 임금이 그 오른편에 있는 자들에게 이르시되 내 아버지께 복 받을 자들이여  나아와 창세로부터 너희를 위하여 예비된 나라를 상속하라"},{"r":"고전6:2","t":"성도가 세상을 판단할 것을 너희가 알지 못하느냐 세상도 너희에게 판단을 받겠거든 지극히 작은 일 판단하기를 감당치 못하겠느냐"},{"r":"계2:26","t":"이기는 자와 끝까지 내 일을 지키는 그에게 만국을 다스리는 권세를 주리니"},{"r":"계20:4","t":"또 내가 보좌들을 보니 거기 앉은 자들이 있어 심판하는 권세를 받았더라 또 내가 보니 예수의 증거와 하나님의 말씀을 인하여 목 베임을 받은 자의 령혼들과 또 짐승과 그의 우상에게 경배하지도 아니하고 이마와 손에 그의 표를 받지도 아니한 자들이 살아서 그리스도로 더불어 천년 동안 왕노릇하니"}],"단7:2":[{"r":"단8:8","t":"수염소가 스스로 심히 강대하여 가더니 강성할 때에 그 큰 뿔이 꺾이고 그 대신에 현저한 뿔 넷이 하늘 사방을 향하여 났더라"},{"r":"단11:4","t":"그러나 그가 강성할 때에 그 나라가 갈라져 천하 사방에 나누일 것이나 그 자손에게로 돌아가지도 아니할 것이요 또 자기가 주장하던 권세대로도 되지 아니하리니 이는 그 나라가 뽑혀서 이 외의 사람들에게로 돌아갈 것임이니라"},{"r":"겔37:9","t":"또 내게 이르시되 인자야 너는 생기를 향하여 대언하라 생기에게 대언하여 이르기를 주 여호와의 말씀에 생기야 사방에서부터 와서 이 사망을 당한 자에게 불어서 살게 하라 하셨다 하라"},{"r":"슥2:6","t":"여호와의 말씀에 내가 너를 하늘의 사방 바람 같이 흩어지게 하였거니와 이제 너희는 북방 땅에서 도망할지니라 나 여호와의 말이니라"},{"r":"계7:1","t":"이 일 후에 내가 네 천사가 땅 네모퉁이에 선 것을 보니 땅의 사방의 바람을 붙잡아 바람으로 하여금 땅에나 바다에나 각종 나무에 불지 못하게 하더라"}],"단7:20":[{"r":"단7:8","t":"내가 그 뿔을 유심히 보는 중 다른 작은 뿔이 그 사이에서 나더니 먼저 뿔 중에 셋이 그 앞에 뿌리까지 뽑혔으며 이 작은 뿔에는 사람의 눈 같은 눈이 있고 또 입이 있어 큰 말을 하였느니라"}],"단7:25":[{"r":"단11:36","t":"이 왕이 자기 뜻대로 행하며 스스로 높여 모든 신보다 크다 하며 비상한 말로 신들의 신을 대적하며 형통하기를 분노하심이 쉴 때까지 하리니 이는 그 작정된 일이 반드시 이룰 것임이니라"},{"r":"단2:9","t":"너희가 만일 이 꿈을 나로 알게 하지 아니하면 너희를 처치할 법이 오직 하나이니 이는 너희가 거짓말과 망령된 말을 내 앞에서 꾸며 말하여 때가 변하기를 기다리려 함이니라 이제 그 꿈을 내게 알게 하라 그리하면 너희가 그 해석도 보일 줄을 내가 알리라"},{"r":"단2:21","t":"그는 때와 기한을 변하시며 왕들을 폐하시고 왕들을 세우시며 지혜자에게 지혜를 주시고 지식자에게 총명을 주시는도다"},{"r":"단12:7","t":"내가 들은즉 그 세마포 옷을 입고 강물 위에 있는 자가 그 좌우 손을 들어 하늘을 향하여 영생하시는 자를 가리켜 맹서하여 가로되 반드시 한 때, 두 때, 반 때를 지나서 성도의 권세가 다 깨어지기까지니 그렇게 되면 이 모든 일이 다 끝나리라 하더라"},{"r":"계12:14","t":"그 녀자가 큰 독수리의 두 날개를 받아 광야 자기 곳으로 날아가 거기서 그 뱀의 낯을 피하여 한 때와 두 때와 반 때를 양육 받으매"}],"단7:3":[{"r":"계13:1","t":"내가 보니 바다에서 한 짐승이 나오는데 뿔이 열이요 머리가 일곱이라 그 뿔에는 열 면류관이 있고 그 머리들에는 참람한 이름들이 있더라"}],"단7:5":[{"r":"단2:39","t":"왕의 후에 왕만 못한 다른 나라가 일어날 것이요 세째로 또 놋 같은 나라가 일어나서 온 세계를 다스릴 것이며"}],"단7:6":[{"r":"합1:8","t":"그 말은 표범보다 빠르고 저녁 이리보다 사나우며 그 기병은 원방에서부터 빨리 달려오는 기병이라 마치 식물을 움키려하는 독수리의 날음과 같으니라"},{"r":"계13:2","t":"내가 본 짐승은 표범과 비슷하고 그 발은 곰의 발 같고 그 입은 사자의 입 같은데 용이 자기의 능력과 보좌와 큰 권세를 그에게 주었더라"},{"r":"단11:5","t":"남방의 왕은 강할 것이나 그 군들 중에 하나는 그보다 강하여 권세를 떨치리니 그 권세가 심히 클 것이요"}],"단7:7":[{"r":"단7:19","t":"이에 내가 네째 짐승의 진상을 알고자 하였으니 곧 그것은 모든 짐승과 달라서 심히 무섭고 그 이는 철이요 그 발톱은 놋이며 먹고 부숴뜨리고 나머지는 발로 밟았으며"},{"r":"단7:23","t":"모신 자가 이처럼 이르되 네째 짐승은 곧 땅의 네째 나라인데 이는 모든 나라보다 달라서 천하를 삼키고 밟아 부숴뜨릴 것이며"},{"r":"단7:20","t":"또 그것의 머리에는 열 뿔이 있고 그 외에 또 다른 뿔이 나오매 세 뿔이 그 앞에 빠졌으며 그 뿔에는 눈도 있고 큰 말하는 입도 있고 그 모양이 동류보다 강하여 보인 것이라"},{"r":"계12:3","t":"하늘에 또 다른 이적이 보이니 보라 한 큰 붉은 용이 있어 머리가 일곱이요 뿔이 열이라 그 여러 머리에 일곱 면류관이 있는데"},{"r":"계13:1","t":"내가 보니 바다에서 한 짐승이 나오는데 뿔이 열이요 머리가 일곱이라 그 뿔에는 열 면류관이 있고 그 머리들에는 참람한 이름들이 있더라"},{"r":"계17:12","t":"네가 보던 열 뿔은 열 왕이니 아직 나라를 얻지 못하였으나 다만 짐승으로 더불어 임금처럼 권세를 일시동안 받으리라"}],"단7:8":[{"r":"단7:20,21","t":"또 그것의 머리에는 열 뿔이 있고 그 외에 또 다른 뿔이 나오매 세 뿔이 그 앞에 빠졌으며 그 뿔에는 눈도 있고 큰 말하는 입도 있고 그 모양이 동류보다 강하여 보인 것이라"},{"r":"단7:24","t":"그 열 뿔은 이 나라에서 일어날 열 왕이요 그 후에 또 하나가 일어나리니 그는 먼저 있던 자들과 다르고 또 세 왕을 복종시킬 것이며"},{"r":"단8:9","t":"그 중 한 뿔에서 또 작은 뿔 하나가 나서 남편과 동편과 또 영화로운 땅을 향하여 심히 커지더니"},{"r":"단7:20","t":"또 그것의 머리에는 열 뿔이 있고 그 외에 또 다른 뿔이 나오매 세 뿔이 그 앞에 빠졌으며 그 뿔에는 눈도 있고 큰 말하는 입도 있고 그 모양이 동류보다 강하여 보인 것이라"},{"r":"계13:5,6","t":"또 짐승이 큰 말과 참람된 말하는 입을 받고 또 마흔 두 달 일할 권세를 받으니라"}],"단7:9":[{"r":"계20:4","t":"또 내가 보좌들을 보니 거기 앉은 자들이 있어 심판하는 권세를 받았더라 또 내가 보니 예수의 증거와 하나님의 말씀을 인하여 목 베임을 받은 자의 령혼들과 또 짐승과 그의 우상에게 경배하지도 아니하고 이마와 손에 그의 표를 받지도 아니한 자들이 살아서 그리스도로 더불어 천년 동안 왕노릇하니"},{"r":"마19:28","t":"예수께서 가라사대 내가 진실로 너희에게 이르노니 세상이 새롭게 되어 인자가 자기 영광의 보좌에 앉을 때에 나를 좇는 너희도 열 두 보좌에 앉아 이스라엘 열 두 지파를 심판하리라"},{"r":"왕상22:19","t":"미가야가 가로되 그런즉 왕은 여호와의 말씀을 들으소서 내가 보니 여호와께서 그 보좌에 앉으셨고 하늘의 만군이 그 좌우편에 모시고 서 있는데"},{"r":"단7:22","t":"옛적부터 항상 계신 자가 와서 지극히 높으신 자의 성도를 위하여 신원하셨고 때가 이르매 성도가 나라를 얻었더라"},{"r":"시90:2","t":"산이 생기기 전, 땅과 세계도 주께서 조성하시기 전 곧 영원부터 영원까지 주는 하나님이시니이다"},{"r":"마28:3","t":"그 형상이 번개 같고 그 옷은 눈같이 희거늘"},{"r":"계1:14","t":"그 머리와 털의 희기가 흰 양털같고 눈 같으며 그의 눈은 불꽃 같고"},{"r":"겔1:16","t":"그 바퀴의 형상과 그 구조는 넷이 한결 같은데 황옥 같고 그 형상과 구조는 바퀴 안에 바퀴가 있는 것 같으며"},{"r":"겔10:2","t":"하나님이 가는 베옷 입은 사람에게 일러 가라사대 너는 그룹 밑바퀴 사이로 들어가서 그 속에서 숯불을 두 손에 가득히 움켜 가지고 성읍 위에 흩으라 하시매 그가 내 목전에 들어가더라"}],"단8:14":[{"r":"단8:26","t":"이미 말한바 주야에 대한 이상이 확실하니 너는 그 이상을 간수하라 이는 여러 날 후의 일임이니라"}],"단8:20":[{"r":"단8:3","t":"내가 눈을 들어본즉 강 가에 두 뿔 가진 수양이 섰는데 그 두 뿔이 다 길어도 한 뿔은 다른 뿔보다도 길었고 그 긴 것은 나중에 난 것이더라"},{"r":"단6:8","t":"그런즉 원컨대 금령을 세우시고 그 조서에 어인을 찍어서 메대와 바사의 변개치 아니하는 규례를 따라 그것을 다시 고치지 못하게 하옵소서 하매"}],"단8:21":[{"r":"단8:5","t":"내가 생각할 때에 한 수염소가 서편에서부터 와서 온 지면에 두루 다니되 땅에 닿지 아니하며 그 염소 두 눈 사이에는 현저한 뿔이 있더라"},{"r":"단10:20","t":"그가 이르되 내가 어찌하여 네게 나아온 것을 네가 아느냐 이제 내가 돌아가서 바사군과 싸우려니와 내가 나간 후에는 헬라군이 이를 것이라"},{"r":"단11:3","t":"장차 한 능력 있는 왕이 일어나서 큰 권세로 다스리며 임의로 행하리라"}],"단8:22":[{"r":"단8:8","t":"수염소가 스스로 심히 강대하여 가더니 강성할 때에 그 큰 뿔이 꺾이고 그 대신에 현저한 뿔 넷이 하늘 사방을 향하여 났더라"},{"r":"단8:24","t":"그 권세가 강할 것이나 자기의 힘으로 말미암은 것이 아니며 그가 장차 비상하게 파괴를 행하고 자의로 행하여 형통하며 강한 자들과 거룩한 백성을 멸하리라"}],"단9:20":[{"r":"사65:24","t":"그들이 부르기 전에 내가 응답하겠고 그들이 말을 마치기 전에 내가 들을 것이며"},{"r":"단9:16","t":"주여, 내가 구하옵나니 주는 주의 공의를 좇으사 주의 분노를 주의 성 예루살렘, 주의 거룩한 산에서 떠나게 하옵소서 이는 우리의 죄와 우리의 열조의 죄악을 인하여 예루살렘과 주의 백성이 사면에 있는 자에게 수욕을 받음이니이다"}],"단9:21":[{"r":"단8:16","t":"내가 들은즉 을래 강 두 언덕 사이에서 사람의 목소리가 있어 외쳐 이르되 가브리엘아 이 이상을 이 사람에게 깨닫게 하라 하더니"},{"r":"출29:39","t":"한 어린 양은 아침에 드리고, 한 어린 양은 저녁 때에 드릴지며"},{"r":"왕상18:36","t":"저녁 소제 드릴 때에 이르러 선지자 엘리야가 나아가서 말하되 아브라함과 이삭과 이스라엘의 하나님 여호와여 주께서 이스라엘 중에서 하나님이 되심과 내가 주의 종이 됨과 내가 주의 말씀대로 이 모든 일을 행하는 것을 오늘날 알게 하옵소서"},{"r":"스9:4,5","t":"이에 이스라엘 하나님의 말씀을 인하여 떠는 자가 이 사로잡혔던 자의 죄를 인하여 다 내게로 모여 오더라 내가 저녁 제사 드릴 때까지 기가 막혀 앉았더니"},{"r":"단8:18","t":"그가 내게 말할 때에 내가 얼굴을 땅에 대고 엎드리어 깊이 잠들매 그가 나를 어루만져서 일으켜 세우며"}],"단9:22":[{"r":"단8:16","t":"내가 들은즉 을래 강 두 언덕 사이에서 사람의 목소리가 있어 외쳐 이르되 가브리엘아 이 이상을 이 사람에게 깨닫게 하라 하더니"},{"r":"단1:4","t":"곧 흠이 없고 아름다우며 모든 재조를 통달하며 지식이 구비하며 학문에 익숙하여 왕궁에 모실 만한 소년을 데려오게 하였고 그들에게 갈대아 사람의 학문과 방언을 가르치게 하였고"},{"r":"단1:17","t":"하나님이 이 네 소년에게 지식을 얻게 하시며 모든 학문과 재조에 명철하게 하신 외에 다니엘은 또 모든 이상과 몽조를 깨달아 알더라"}],"단9:23":[{"r":"단9:20","t":"내가 이같이 말하여 기도하며 내 죄와 및 내 백성 이스라엘의 죄를 자복하고 내 하나님의 거룩한 산을 위하여 내 하나님 여호와 앞에 간구할 때"},{"r":"단10:12","t":"그가 이르되 다니엘아 두려워하지 말라 네가 깨달으려 하여 네 하나님 앞에 스스로 겸비케 하기로 결심하던 첫 날부터 네 말이 들으신 바 되었으므로 내가 네 말로 인하여 왔느니라"},{"r":"단10:14","t":"이제 내가 말일에 네 백성의 당할 일을 네게 깨닫게 하러 왔노라 대저 이 이상은 오래 후의 일이니라"},{"r":"단10:11","t":"내게 이르되 은총을 크게 받은 사람 다니엘아 내가 네게 이르는 말을 깨닫고 일어서라 내가 네게 보내심을 받았느니라 그가 내게 이 말을 한 후에 내가 떨며 일어서매"},{"r":"단10:19","t":"가로되 은총을 크게 받은 사람이여 두려워하지 말라 평안하라 강건하라 강건하라 그가 이같이 내게 말하매 내가 곧 힘이 나서 가로되 내 주께서 나로 힘이 나게 하셨사오니 말씀하옵소서"},{"r":"마24:15","t":"그러므로 너희가 선지자 다니엘의 말한 바 멸망의 가증한 것이 거룩한 곳에 선 것을 보거든 읽는 자는 깨달을진저"},{"r":"막13:14","t":"멸망의 가증한 것이 서지 못할 곳에 선 것을 보거든 읽는 자는 깨달을진저그 때에 유대에 있는 자들은 산으로 도망할지어다"}],"단9:24":[{"r":"느11:1","t":"백성의 두목들은 예루살렘에 머물렀고 그 남은 백성은 제비뽑아 십분의 일은 거룩한 성 예루살렘에 와서 거하게 하고 그 구분은 다른 성읍에 거하게 하였으며"},{"r":"겔4:6","t":"그 수가 차거든 너는 우편으로 누워 유다 족속의 죄악을 담당하라 내가 네게 사십일로 정하였나니 일일이 일년이니라"},{"r":"단8:13","t":"내가 들은즉 거룩한 자가 말하더니 다른 거룩한 자가 그 말하는 자에게 묻되 이상에 나타난바 매일 드리는 제사와 망하게 하는 죄악에 대한 일과 성소와 백성이 내어준바 되며 짓밟힐 일이 어느 때까지 이를꼬 하매"},{"r":"시78:38","t":"오직 하나님은 자비하심으로 죄악을 사하사 멸하지 아니하시고 그 진노를 여러번 돌이키시며 그 분을 다 발하지 아니하셨으니"},{"r":"히2:17","t":"그러므로 저가 범사에 형제들과 같이 되심이 마땅하도다 이는 하나님의 일에 자비하고 충성된 대제사장이 되어 백성의 죄를 구속하려 하심이라"},{"r":"렘31:34","t":"그들이 다시는 각기 이웃과 형제를 가리켜 이르기를 너는 여호와를 알라 하지 아니하리니 이는 작은 자로부터 큰 자까지 다 나를 앎이니라 내가 그들의 죄악을 사하고 다시는 그 죄를 기억지 아니하리라 여호와의 말이니라"},{"r":"롬3:25,26","t":"이 예수를 하나님이 그의 피로 인하여 믿음으로 말미암는 화목 제물로 세우셨으니 이는 하나님께서 길이 참으시는 중에 전에 지은 죄를 간과하심으로 자기의 의로우심을 나타내려 하심이니"},{"r":"렘23:5,6","t":"나 여호와가 말하노라 보라, 때가 이르리니 내가 다윗에게 한 의로운 가지를 일으킬 것이라 그가 왕이 되어 지혜롭게 행사하며 세상에서 공평과 정의를 행할 것이며"},{"r":"시45:7","t":"왕이 정의를 사랑하고 악을 미워하시니 그러므로 하나님 곧 왕의 하나님이 즐거움의 기름으로 왕에게 부어 왕의 동류보다 승하게 하셨나이다"},{"r":"사61:1","t":"주 여호와의 신이 내게 임하였으니 이는 여호와께서 내게 기름을 부으사 가난한 자에게 아름다운 소식을 전하게 하려 하심이라 나를 보내사 마음이 상한 자를 고치며 포로된 자에게 자유를, 갇힌 자에게 놓임을 전파하며"},{"r":"행4:26,27","t":"세상의 군왕들이 나서며 관원들이 함께 모여 주와 그 그리스도를 대적하도다 하신 이로소이다"}],"단9:25":[{"r":"단9:23","t":"곧 네가 기도를 시작할 즈음에 명령이 내렸으므로 이제 네게 고하러 왔느니라 너는 크게 은총을 입은 자라 그런즉 너는 이 일을 생각하고 그 이상을 깨달을지니라"},{"r":"시51:18","t":"주의 은택으로 시온에 선을 행하시고 예루살렘 성을 쌓으소서"},{"r":"대하36:23","t":"바사 왕 고레스는 말하노니 하늘의 신 여호와께서 세상 만국으로 내게 주셨고 나를 명하여 유다 예루살렘에 전을 건축하라 하셨나니 너희 중에 무릇 그 백성 된 자는 다 올라갈지어다  너희 하나님 여호와께서 함께 하시기를 원하노라 하였더라"},{"r":"스1:3","t":"이스라엘의 하나님은 참 신이시라 너희 중에 무릇 그 백성 된 자는 다 유다 예루살렘으로 올라가서 거기 있는 여호와의 전을 건축하라  너희 하나님이 함께 하시기를 원하노라"},{"r":"스4:24","t":"이에 예루살렘에서 하나님의 전 역사가 그쳐서 바사 왕 다리오 제 이년까지 이르니라"},{"r":"스6:15","t":"다리오 왕 육년 아달월 삼일에 전을 필역하니라"},{"r":"느6:15","t":"성 역사가 오십이일만에 엘룰월 이십오일에 끝나매"},{"r":"요1:41","t":"그가 먼저 자기의 형제 시몬을 찾아 말하되 우리가 메시야를 만났다 하고 메시야는 번역하면 그리스도라"},{"r":"사55:4","t":"내가 그를 만민에게 증거로 세웠고 만민의 인도자와 명령자를 삼았었나니"},{"r":"느4:7,8","t":"산발랏과, 도비야와, 아라비아 사람들과, 암몬 사람들과, 아스돗 사람들이 예루살렘 성이 중수되어 그 퇴락한 곳이 수보되어 간다 함을 듣고 심히 분하여"},{"r":"느4:16~18","t":"그 때로부터 내 종자의 절반은 역사하고 절반은 갑옷을 입고 창과 방패와 활을 가졌고 민장은 유다 온 족속의 뒤에 있었으며"}],"단9:26":[{"r":"사53:8","t":"그가 곤욕과 심문을 당하고 끌려 갔으니 그 세대 중에 누가 생각하기를 그가 산 자의 땅에서 끊어짐은 마땅히 형벌 받을 내 백성의 허물을 인함이라 하였으리요"},{"r":"막9:12","t":"가라사대 엘리야가 과연 먼저와서 모든 것을 회부하거니와 어찌 인자에 대하여 기록하기를 많은 고난을 받고 멸시를 당하리라 하였느냐"},{"r":"눅24:26","t":"그리스도가 이런 고난을 받고 자기의 영광에 들어가야 할 것이 아니냐  하시고"},{"r":"마24:2","t":"대답하여 가라사대 너희가 이 모든 것을 보지 못하느냐  내가 진실로 너희에게 이르노니 돌 하나도 돌 위에 남지 않고 다 무너뜨리우리라"},{"r":"막13:2","t":"예수께서 이르시되 네가 이 큰 건물들을 보느냐  돌 하나도 돌 위에 남지 않고 다 무너뜨려지리라 하시니라"},{"r":"눅19:43~44","t":"날이 이를지라 네 원수들이 토성을 쌓고 너를 둘러 사면으로 가두고"},{"r":"나1:8","t":"그가 범람한 물로 그곳을 진멸하시고 자기 대적들을 흑암으로 쫓아내시리라"},{"r":"단11:10","t":"그 아들들이 전쟁을 준비하고 심히 많은 군대를 모아서 물의 넘침같이 나아올 것이며 그가 또 와서 남방 왕의 견고한 성까지 칠 것이요"},{"r":"단11:22","t":"넘치는 물 같은 군대가 그에게 넘침을 입어 패할 것이요 동맹한 왕도 그렇게 될 것이며"},{"r":"단11:26","t":"자기의 진미를 먹는 자가 그를 멸하리니 그 군대가 흩어질 것이요 많은 자가 엎드러져 죽으리라"},{"r":"단11:40","t":"마지막 때에 남방 왕이 그를 찌르리니 북방 왕이 병거와 마병과 많은 배로 회리바람처럼 그에게로 마주 와서 그 여러 나라에 들어가며 물이 넘침 같이 지나갈 것이요"},{"r":"마24:6","t":"란리와 란리 소문을 듣겠으나 너희는 삼가 두려워 말라 이런 일이 있어야 하되 끝은 아직 아니니라"},{"r":"마24:14","t":"이 천국 복음이 모든 민족에게 증거되기 위하여 온 세상에 전파되리니 그제야 끝이 오리라"},{"r":"마24:6","t":"란리와 란리 소문을 듣겠으나 너희는 삼가 두려워 말라 이런 일이 있어야 하되 끝은 아직 아니니라"},{"r":"마24:14","t":"이 천국 복음이 모든 민족에게 증거되기 위하여 온 세상에 전파되리니 그제야 끝이 오리라"}],"단9:27":[{"r":"마24:15","t":"그러므로 너희가 선지자 다니엘의 말한 바 멸망의 가증한 것이 거룩한 곳에 선 것을 보거든 읽는 자는 깨달을진저"},{"r":"막13:14","t":"멸망의 가증한 것이 서지 못할 곳에 선 것을 보거든 읽는 자는 깨달을진저그 때에 유대에 있는 자들은 산으로 도망할지어다"},{"r":"눅21:20","t":"너희가 예루살렘이 군대들에게 에워싸이는 것을 보거든 그 멸망이 가까운 줄을 알라"},{"r":"사10:23","t":"이미 작정되었은즉 주 만군의 여호와께서 온 세계 중에 끝까지 행하시리라"}],"대하20:20":[{"r":"삼하14:2","t":"드고아에 보내어 거기서 슬기있는 녀인 하나를 데려다가 이르되 청컨대 너는 상주된 것처럼 상복을 입고 기름을 바르지 말고 죽은 사람을 위하여 오래 슬퍼하는 녀인 같이 하고"},{"r":"사7:9","t":"8절과 같음"}],"딛1:16":[{"r":"요일2:4","t":"저를 아노라 하고 그의 계명을 지키지 아니하는 자는 거짓말하는 자요 진리가 그 속에 있지 아니하되"},{"r":"딤전5:8","t":"누구든지 자기 친족 특히 자기 가족을 돌아보지 아니하면 믿음을 배반한 자요 부신자보다 더 악한 자니라"},{"r":"딤후3:8","t":"얀네와 얌브레가 모세를 대적한 것같이 저희도 진리를 대적하니 이 사람들은 그 마음이 부패한 자요 믿음에 관하여는 버리운 자들이라"}],"딛1:2":[{"r":"딤후1:1","t":"하나님의 뜻으로 말미암아 그리스도 예수 안에 있는 생명의 약속대로 그리스도 예수의 사도 된 바울은"},{"r":"히9:15","t":"이를 인하여 그는 새 언약의 중보니 이는 첫 언약 때에 범한 죄를 속하려고 죽으사 부르심을 입은 자로 하여금 영원한 기업의 약속을 얻게 하려 하심이니라"},{"r":"딛2:13","t":"복스러운 소망과 우리의 크신 하나님 구주 예수 그리스도의 영광이 나타나심을 기다리게 하셨으니"},{"r":"딛3:7","t":"우리로 저의 은혜를 힘입어 의롭다 하심을 얻어 영생의 소망을 따라 후사가 되게 하려 하심이라"},{"r":"민23:19","t":"하나님은 인생이 아니시니 식언치 않으시고 인자가 아니시니 후회가 없으시도다 어찌 그 말씀하신 바를 행치 않으시며 하신 말씀을 실행치 않으시랴"},{"r":"딤후2:13","t":"우리는 미쁨이 없을지라도 주는 일향 미쁘시니 자기를 부인하실 수 없으시리라"},{"r":"히6:18","t":"이는 하나님이 거짓말을 하실 수 없는 이 두 가지 변치 못할 사실을 인하여 앞에 있는 소망을 얻으려고 피하여 가는 우리로 큰 안위를 받게 하려 하심이라"},{"r":"딤후1:9","t":"하나님이 우리를 구원하사 거룩하신 부르심으로 부르심은 우리의 행위대로 하심이 아니요 오직 자기 뜻과 영원한 때 전부터 그리스도 예수 안에서 우리에게 주신 은혜대로 하심이라"},{"r":"롬1:2","t":"이 복음은 하나님이 선지자들로 말미암아 그의 아들에 관하여 성경에 미리 약속하신 것이라"}],"딤전3:6":[{"r":"딤전6:4","t":"저는 교만하여 아무 것도 알지 못하고 변론과 언쟁을 좋아하는 자니 이로써 투기와 분쟁과 훼방과 악한 생각이 나며"},{"r":"딤후3:4","t":"배반하여 팔며, 조급하며, 자고하며, 쾌락을 사랑하기를 하나님 사랑하는 것보다 더하며,"}],"딤전4:1":[{"r":"요14:17","t":"저는 진리의 영이라 세상은 능히 저를 받지 못하나니 이는 저를 보지도 못하고 알지도 못함이라 그러나 너희는 저를 아나니 저는 너희와 함께 거하심이요 또 너희 속에 계시겠음이라"},{"r":"살후2:3~9","t":"누가 아무렇게 하여도 너희가 미혹하지 말라 먼저 배도하는 일이 있고 저 부법의 사람 곧 멸망의 아들이 나타나기 전에는 이르지 아니하리니"},{"r":"딤후3:1","t":"네가 이것을 알라 말세에 고통하는 때가 이르리니"},{"r":"고전11:19","t":"너희 중에 편당이 있어야 너희 중에 옳다 인정함을 받은 자들이 나타나게 되리라"},{"r":"요일4:6","t":"우리는 하나님께 속하였으니 하나님을 아는 자는 우리의 말을 듣고 하나님께 속하지 아니한 자는 우리의 말을 듣지 아니하나니 진리의 영과 미혹의 영을 이로써 아느니라"},{"r":"마7:15","t":"거짓 선지자들을 삼가라 양의 옷을 입고 너희에게 나아오나 속에는 노략질하는 이리라"}],"딤전4:2":[{"r":"엡4:19","t":"저희가 감각 없는 자 되어 자신을 방탕에 방임하여 모든 더러운 것을 욕심으로 행하되"},{"r":"살전2:3","t":"우리의 권면은 간사에서나 불정에서 난 것도 아니요 궤계에 있는 것도 아니라"},{"r":"살후2:11","t":"이러므로 하나님이 유혹을 저의 가운데 역사하게 하사 거짓 것을 믿게 하심은"}],"딤후2:15":[{"r":"빌1:20","t":"나의 간절한 기대와 소망을 따라 아무 일에든지 부끄럽지 아니하고 오직 전과 같이 이제도 온전히 담대하여 살든지 죽든지 내 몸에서 그리스도가 존귀히 되게 하려 하나니"}],"딤후2:19":[{"r":"민16:5","t":"고라와 그 모든 무리에게 말하여 가로되 아침에 여호와께서 자기에게 속한 자가 누구인지 거룩한 자가 누구인지 보이시고 그 자를 자기에게 가까이 나아오게 하시되 곧 그가 택하신 자를 자기에게 가까이 나아오게 하시리니"},{"r":"나1:7","t":"여호와는 선하시며 환난 날에 산성이시라 그는 자기에게 의뢰하는 자들을 아시느니라"},{"r":"요10:14","t":"나는 선한 목자라  내가 내 양을 알고 양도 나를 아는 것이"},{"r":"요10:27","t":"내 양은 내 음성을 들으며 나는 저희를 알며 저희는 나를 따르느니라"},{"r":"눅13:27","t":"저가 너희에게 일러 가로되 나는 너희가 어디로서 왔는지 알지 못하노라 행악하는 모든 자들아  나를 떠나가라 하리라"},{"r":"고전8:3","t":"또 누구든지 하나님을 사랑하면 이 사람은 하나님의 아시는 바 되었느니라"},{"r":"사26:13","t":"여호와 우리 하나님이시여 주 외에 다른 주들이 우리를 관할하였사오나 우리가 주만 의뢰하고 주의 이름을 부르리이다"}],"딤후3:16":[{"r":"롬15:4","t":"무엇이든지 전에 기록한 바는 우리의 교훈을 위하여 기록된 것이니 우리로 하여금 인내로 또는 성경의 안위로 소망을 가지게 함이니라"},{"r":"벧후1:20,21","t":"먼저 알 것은 경의 모든 예언은 사사로이 풀 것이 아니니"}],"딤후3:17":[{"r":"딤전6:11","t":"오직 너 하나님의 사람아  이것들을 피하고 의와 경건과 믿음과 사랑과 인내와 온유를 좇으며"},{"r":"눅6:40","t":"제자가 그 선생보다 높지 못하나 무릇 온전케 된 자는 그 선생과 같으리라"},{"r":"딤후2:21","t":"그러므로 누구든지 이런 것에서 자기를 깨끗하게 하면 귀히 쓰는 그릇이 되어 거룩하고 주인의 쓰심에 합당하며 모든 선한 일에 예비함이 되리라"}],"레11:44":[{"r":"레19:2","t":"너는 이스라엘 자손의 온 회중에게 고하여 이르라 너희는 거룩하라  나 여호와 너희 하나님이 거룩함이니라"},{"r":"레20:7","t":"너희는 스스로 깨끗케 하여 거룩할지어다 나는 너희 하나님 여호와니라"},{"r":"레20:26","t":"너희는 내게 거룩할지어다 이는 나 여호와가 거룩하고 내가 또 너희로 나의 소유를 삼으려고 너희를 만민 중에서 구별하였음이니라"},{"r":"레21:8","t":"너는 그를 거룩하게 하라  그는 네 하나님의 식물을 드림이니라 너는 그를 거룩히 여기라 나 여호와 너희를 거룩하게 하는 자는 거룩함이니라"},{"r":"출19:6","t":"너희가 내게 대하여 제사장 나라가 되며 거룩한 백성이 되리라 너는 이 말을 이스라엘 자손에게 고할지니라"},{"r":"벧전1:16","t":"기록하였으되 내가 거룩하니 너희도 거룩할지어다 하셨느니라"},{"r":"살전4:7","t":"하나님이 우리를 부르심은 불정케 하심이 아니요 거룩케 하심이니"}],"레11:45":[{"r":"출6:7","t":"너희로 내 백성을 삼고 나는 너희 하나님이 되리니 나는 애굽 사람의 무거운 짐 밑에서 너희를 빼어낸 너희 하나님 여호와인줄 너희가 알지라"}],"레11:47":[{"r":"레10:10","t":"그리하여야 너희가 거룩하고 속된 것을 분별하며 불정하고 정한 것을 분별하고"},{"r":"레20:25","t":"너희는 짐승의 정하고 불정함과 새의 정하고 불정함을 구별하고 내가 너희를 위하여 불정한 것으로 구별한 짐승이나 새나 땅에 기는 곤충으로 인하여 너희 몸을 더럽히지 말라"}],"레19:31":[{"r":"레20:6","t":"음란하듯 신접한 자와 박수를 추종하는 자에게는 내가 진노하여 그를 그 백성 중에서 끊으리니"},{"r":"레20:27","t":"남자나 녀자가 신접하거나 박수가 되거든 반드시 죽일지니 곧 돌로 그를 치라 그 피가 자기에게로 돌아가리라"},{"r":"신18:11","t":"진언자나, 신접자나, 박수나, 초혼자를 너의 중에 용납하지 말라"},{"r":"사8:19","t":"혹이 너희에게 고하기를 지절거리며 속살거리는 신접한 자와 마술사에게 물으라 하거든 백성이 자기 하나님께 구할 것이 아니냐 산 자를 위하여 죽은 자에게 구하겠느냐 하라"},{"r":"출22:18","t":"너는 무당을 살려 두지 말지니라"},{"r":"삼상28:3","t":"사무엘이 죽었으므로 온 이스라엘이 그를 애곡하며 그의 본성 라마에 장사하였고 사울은 신접한 자와 박수를 그 땅에서 쫓아 내었었더라"},{"r":"삼상28:7","t":"사울이 그 신하들에게 이르되 나를 위하여 신접한 녀인을 찾으라 내가 그리로 가서 그에게 물으리라 그 신하들이 그에게 이르되 보소서, 엔돌에 신접한 녀인이 있나이다"},{"r":"삼상28:9","t":"녀인이 그에게 이르되 네가 사울의 행한 일 곧 그가 신접한 자와 박수를 이 땅에서 멸절시켰음을 아나니 네가 어찌하여 내 생명에 올무를 놓아 나를 죽게 하려느냐"},{"r":"대상10:13","t":"사울의 죽은 것은 여호와께 범죄하였음이라 저가 여호와의 말씀을 지키지 아니하고 또 신접한 자에게 가르치기를 청하고"},{"r":"행16:16","t":"우리가 기도하는 곳에 가다가 점하는 귀신 들린 여종 하나를 만나니 점으로 그 주인들을 크게 이하게 하는지라"}],"레23:27":[{"r":"레16:29,30","t":"너희는 영원히 이 규례를 지킬지니라  칠월 곧 그 달 십일에 너희는 스스로 괴롭게 하고 아무 일도 하지 말되 본토인이든지 너희 중에 우거하는 객이든지 그리하라"},{"r":"민29:7","t":"칠월 십일에는 너희가 성회로 모일 것이요 마음을 괴롭게 하고 아무 로동도 하지 말 것이며"}],"레23:29":[{"r":"출30:33","t":"무릇 이와 같은 것을 만드는 자나 무릇 이것을 타인에게 붓는 자는 그 백성 중에서 끊쳐지리라 하라"}],"레25:20":[{"r":"레25:4,5","t":"제 칠년에는 땅으로 쉬어 안식하게 할지니 여호와께 대한 안식이라 너는 그 밭에 파종하거나 포도원을 다스리지 말며"},{"r":"마6:25","t":"그러므로 내가 너희에게 이르노니 목숨을 위하여 무엇을 먹을까  무엇을 마실까  몸을 위하여 무엇을 입을까  념려하지 말라 목숨이 음식보다 중하지 아니하며 몸이 의복보다 중하지 아니하냐"},{"r":"마6:31","t":"그러므로 념려하여 이르기를 무엇을 먹을까  무엇을 마실까  무엇을 입을까  하지 말라"},{"r":"눅12:22","t":"또 제자들에게 이르시되 그러므로 내가 너희에게 이르노니 너희 목숨을 위하여 무엇을 먹을까  몸을 위하여 무엇을 입을까  념려하지 말라"},{"r":"눅12:29","t":"너희는 무엇을 먹을까  무엇을 마실까  하여 구하지 말며 근심하지도 말라"}],"레25:21":[{"r":"신28:8","t":"여호와께서 명하사 네 창고와 네 손으로 하는 모든 일에 복을 내리시고 네 하나님 여호와께서 네게 주시는 땅에서 네게 복을 주실 것이며"}],"렘49:37":[{"r":"렘1:17","t":"그러므로 너는 네 허리를 동이고 일어나 내가 네게 명한 바를 다 그들에게 고하라 그들을 인하여 두려워 말라 두렵건대 내가 너로 그들 앞에서 두려움을 당하게 할까 하노라"},{"r":"렘12:13","t":"무리가 밀을 심어도 가시를 거두며 수고하여도 소득이 없은즉 그 소산으로 인하여 스스로 수치를 당하리니 이는 여호와의 분노를 인함이니라"},{"r":"렘9:16","t":"그들과 그들의 조상이 알지 못하던 렬국 중에 그들을 헤치고 진멸되기까지 그 뒤로 칼을 보내리라 하셨느니라"}],"롬10:17":[{"r":"갈3:2","t":"내가 너희에게 다만 이것을 알려 하노니 너희가 성령을 받은 것은 률법의 행위로냐  듣고 믿음으로냐"},{"r":"갈3:5","t":"너희에게 성령을 주시고 너희 가운데서 능력을 행하시는 이의 일이 률법의 행위에서냐  듣고 믿음에서냐"}],"롬10:9":[{"r":"마10:32","t":"누구든지 사람 앞에서 나를 시인하면 나도 하늘에 계신 내 아버지 앞에서 저를 시인할 것이요"},{"r":"눅12:8","t":"내가 또한 너희에게 말하노니 누구든지 사람 앞에서 나를 시인하면 인자도 하나님의 사자들 앞에서 저를 시인할 것이요"},{"r":"고전12:3","t":"그러므로 내가 너희에게 알게 하노니 하나님의 영으로 말하는 자는 누구든지 예수를 저주할 자라 하지 않고 또 성령으로 아니하고는 누구든지 예수를 주시라 할 수 없느니라"},{"r":"빌2:11","t":"모든 입으로 예수 그리스도를 주라 시인하여 하나님 아버지께 영광을 돌리게 하셨느니라"},{"r":"벧전1:21","t":"너희는 저를 죽은 자 가운데서 살리시고 영광을 주신 하나님을 그리스도로 말미암아 믿는 자니 너희 믿음과 소망이 하나님께 있게 하셨느니라"},{"r":"행2:24","t":"하나님께서 사망의 고통을 풀어 살리셨으니 이는 그가 사망에게 매여 있을 수 없었음이라"},{"r":"행16:31","t":"가로되 주 예수를 믿으라  그리하면 너와 네 집이 구원을 얻으리라  하고"}],"롬12:1":[{"r":"고전1:10","t":"형제들아 내가 우리 주 예수 그리스도의 이름으로 너희를 권하노니 다 같은 말을 하고 너희 가운데 분쟁이 없이 같은 마음과 같은 뜻으로 온전히 합하라"},{"r":"고후10:1","t":"너희를 대하여 대면하면 겸비하고 떠나 있으면 담대한 나 바울은 이제 그리스도의 온유와 관용으로 친히 너희를 권하고"},{"r":"엡4:1","t":"그러므로 주 안에서 갇힌 내가 너희를 권하노니 너희가 부르심을 입은 부름에 합당하게 행하여"},{"r":"히10:20","t":"그 길은 우리를 위하여 휘장 가운데로 열어 놓으신 새롭고 산 길이요 휘장은 곧 저의 육체니라"},{"r":"롬6:13","t":"또한 너희 지체를 부의의 병기로 죄에게 드리지 말고 오직 너희 자신을 죽은 자 가운데서 다시 산 자같이 하나님께 드리며 너의 지체를 의의 병기로 하나님께 드리라"},{"r":"롬6:16","t":"너희 자신을 종으로 드려 누구에게 순종하든지 그 순종함을 받는 자의 종이 되는 줄을 너희가 알지 못하느냐 혹은 죄의 종으로 사망에 이르고 순종의 종으로 의에 이르느니라"},{"r":"롬6:19","t":"너희 육신이 연약하므로 내가 사람의 예대로 말하노니 전에 너희가 너희 지체를 불정과 부법에 드려 부법에 이른 것같이 이제는 너희 지체를 의에게 종으로 드려 거룩함에 이르라"},{"r":"시50:13,14","t":"내가 수소의 고기를 먹으며 염소의 피를 마시겠느냐"},{"r":"고전6:20","t":"값으로 산 것이 되었으니 그런즉 너희 몸으로 하나님께 영광을 돌리라"},{"r":"벧전2:5","t":"너희도 산 돌같이 신령한 집으로 세워지고 예수 그리스도로 말미암아 하나님이 기쁘게 받으실 신령한 제사를 드릴 거룩한 제사장이 될지니라"}],"롬15:4":[{"r":"롬4:23","t":"저에게 의로 여기셨다 기록된 것은 아브라함만 위한 것이 아니요"},{"r":"딤후3:16","t":"모든 성경은 하나님의 감동으로 된 것으로 교훈과 책망과 바르게 함과 의로 교육하기에 유익하니"},{"r":"시119:50","t":"이 말씀은 나의 곤난 중에 위로라 주의 말씀이 나를 살리셨음이니이다"}],"롬3:10":[{"r":"롬3:10~12","t":"기록한 바 의인은 없나니 하나도 없으며"},{"r":"시14:1~3","t":"(다윗의 시. 영장으로 한 노래)어리석은 자는 그 마음에 이르기를 하나님이 없다 하도다 저희는 부패하고 소행이 가증하여 선을 행하는 자가 없도다"},{"r":"시53:1~3","t":"(다윗의 마스길. 영장으로 마할랏에 맞춘 노래) 어리석은 자는 그 마음에 이르기를 하나님이 없다 하도다 저희는 부패하며 가증한 악을 행함이여 선을 행하는 자가 없도다"}],"롬3:13":[{"r":"시5:9","t":"저희 입에 신실함이 없고 저희 심중이 심히 악하며 저희 목구멍은 열린 무덤같고 저희 혀로는 아첨하나이다"},{"r":"렘5:16","t":"그 전통은 열림 묘실이요 그 사람들은 다 용사라"},{"r":"시140:3","t":"뱀 같이 그 혀를 날카롭게 하니 그 입술 아래는 독사의 독이 있나이다 셀라"}],"롬3:14":[{"r":"시10:7","t":"그 입에는 저주와 궤휼과 포학이 충만하며 혀 밑에는 잔해와 죄악이 있나이다"}],"롬3:15":[{"r":"롬3:15~17","t":"그 발은 피 흘리는데 빠른지라"},{"r":"잠1:16","t":"대저 그 발은 악으로 달려가며 피를 흘리는 데 빠름이니라"},{"r":"사59:7,8","t":"그 발은 행악하기에 빠르고 무죄한 피를 흘리기에 신속하며 그 사상은 죄악의 사상이라 황폐와 파멸이 그 길에 끼쳐졌으며"}],"롬3:17":[{"r":"눅1:79","t":"어두움과 죽음의 그늘에 앉은 자에게 비취고 우리 발을 평강의 길로 인도하시리로다 하니라"}],"롬3:18":[{"r":"시36:1","t":"(여호와의 종 다윗의 시. 영장으로 한 노래) 악인의 죄얼이 내 마음에 이르기를 그 목전에는 하나님을 두려워함이 없다 하니"}],"롬3:19":[{"r":"요10:34","t":"예수께서 가라사대 너희 률법에 기록한바 내가 너희를 신이라 하였노라 하지 아니하였느냐"},{"r":"요15:25","t":"그러나 이는 저희 률법에 기록된 바 저희가 연고 없이 나를 미워하였다 한 말을 응하게 하려 함이니라"},{"r":"욥5:16","t":"그러므로 가난한 자가 소망이 있고 부의가 스스로 입을 막느니라"},{"r":"시63:11","t":"왕은 하나님을 즐거워하리니 주로 맹서한 자마다 자랑할 것이나 거짓말 하는 자의 입은 막히리로다"},{"r":"시107:42","t":"정직한 자는 보고 기뻐하며 모든 악인은 자기 입을 봉하리로다"},{"r":"겔16:63","t":"이는 내가 네 모든 행한 일을 용서한 후에 너로 기억하고 놀라고 부끄러워서 다시는 입을 열지 못하게 하려 함이니라 나 주 여호와의 말이니라 하셨다 하라"},{"r":"롬1:20","t":"창세로부터 그의 보이지 아니하는 것들 곧 그의 영원하신 능력과 신성이 그 만드신 만물에 분명히 보여 알게 되나니 그러므로 저희가 핑계치 못할찌니라"},{"r":"롬2:1","t":"그러므로 남을 판단하는 사람아  무론 누구든지 네가 핑계치 못할 것은 남을 판단하는 것으로 네가 너를 정죄함이니 판단하는 네가 같은 일을 행함이니라"},{"r":"롬3:9","t":"그러면 어떠하뇨 우리는 나으뇨 결코 아니라 유대인이나 헬라인이나 다 죄 아래 있다고 우리가 이미 선언하였느니라"}],"롬3:20":[{"r":"갈2:16","t":"사람이 의롭게 되는 것은 률법의 행위에서 난 것이 아니요 오직 예수 그리스도를 믿음으로 말미암는 줄 아는고로 우리도 그리스도 예수를 믿나니 이는 우리가 률법의 행위에서 아니고 그리스도를 믿음으로서 의롭다 함을 얻으려 함이라 률법의 행위로서는 의롭다 함을 얻을 육체가 없느니라"},{"r":"시143:2","t":"주의 종에게 심판을 행치 마소서 주의 목전에는 의로운 인생이 하나도 없나이다"},{"r":"행13:39","t":"또 모세의 률법으로 너희가 의롭다 하심을 얻지 못하던 모든 일에도 이 사람을 힘입어 믿는 자마다 의롭다 하심을 얻는 이것이라"},{"r":"롬7:7","t":"그런즉 우리가 무슨 말 하리요 률법이 죄냐 그럴 수 없느니라 률법으로 말미암지 않고는 내가 죄를 알지 못하였니 곧 률법이 탐내지 말라 하지 아니하였더면 내가 탐심을 알지 못하였으리라"},{"r":"롬4:15","t":"률법은 진노를 이루게 하나니 률법이 없는 곳에는 범함도 없느니라"},{"r":"롬5:13","t":"죄가 률법 있기 전에도 세상에 있었으나 률법이 없을 때에는 죄를 죄로 여기지 아니하느니라"},{"r":"롬5:20","t":"률법이 가입한 것은 범죄를 더하게 하려 함이라 그러나 죄가 더한 곳에 은혜가 넘쳤나니"}],"롬3:23":[{"r":"롬3:9","t":"그러면 어떠하뇨 우리는 나으뇨 결코 아니라 유대인이나 헬라인이나 다 죄 아래 있다고 우리가 이미 선언하였느니라"}],"롬4:17":[{"r":"창17:5","t":"이제 후로는 네 이름을 아브람이라 하지 아니하고 아브라함이라 하리니 이는 내가 너로 렬국의 아비가 되게 함이니라"},{"r":"롬4:18","t":"아브라함이 바랄 수 없는 중에 바라고 믿었으니 이는 네 후손이 이같으리라 하신 말씀대로 많은 민족의 조상이 되게 하려 하심을 인함이라"},{"r":"히11:19","t":"저가 하나님이 능히 죽은 자 가운데서 다시 살리실 줄로 생각한 지라 비유컨대 죽은 자 가운데서 도로 받은 것이니라"},{"r":"요5:21","t":"아버지께서 죽은 자들을 일으켜 살리심같이 아들도 자기의 원하는 자들을 살리느니라"},{"r":"고전1:28","t":"하나님께서 세상의 천한 것들과 멸시 받는 것들과 없는 것들을 택하사 있는 것들을 폐하려 하시나니"},{"r":"히11:3","t":"믿음으로 모든 세계가 하나님의 말씀으로 지어진 줄을 우리가 아나니 보이는 것은 나타난 것으로 말미암아 된 것이 아니니라"}],"롬4:18":[{"r":"창15:5","t":"그를 이끌고 밖으로 나가 가라사대 하늘을 우러러 뭇 별을 셀 수 있나 보라 또 그에게 이르시되 네 자손이 이와 같으리라"}],"롬4:23":[{"r":"롬15:4","t":"무엇이든지 전에 기록한 바는 우리의 교훈을 위하여 기록된 것이니 우리로 하여금 인내로 또는 성경의 안위로 소망을 가지게 함이니라"},{"r":"고전9:9,10","t":"모세 률법에 곡식을 밟아 떠는 소에게 망을 씌우지 말라 기록하였으니 하나님께서 어찌 소들을 위하여 념려하심이냐"},{"r":"고전10:6","t":"그런 일은 우리의 거울이 되어 우리로 하여금 저희가 악을 즐겨한 것 같이 즐겨하는 자가 되지 않게 하려 함이니"},{"r":"고전10:11","t":"저희에게 당한 이런 일이 거울이 되고 또한 말세를 만난 우리의 경계로 기록하였느니라"},{"r":"딤후3:16,17","t":"모든 성경은 하나님의 감동으로 된 것으로 교훈과 책망과 바르게 함과 의로 교육하기에 유익하니"},{"r":"시102:18","t":"이 일이 장래 세대를 위하여 기록되리니 창조함을 받을 백성이 여호와를 찬송하리로다"}],"롬4:24":[{"r":"행2:24","t":"하나님께서 사망의 고통을 풀어 살리셨으니 이는 그가 사망에게 매여 있을 수 없었음이라"},{"r":"롬10:9","t":"네가 만일 네 입으로 예수를 주로 시인하며 또 하나님께서 그를 죽은 자 가운데서 살리신 것을 네 마음에 믿으면 구원을 얻으리니"},{"r":"벧전1:21","t":"너희는 저를 죽은 자 가운데서 살리시고 영광을 주신 하나님을 그리스도로 말미암아 믿는 자니 너희 믿음과 소망이 하나님께 있게 하셨느니라"}],"롬4:25":[{"r":"롬5:6","t":"우리가 아직 연약할 때에 기약대로 그리스도께서 경건치 않은 자를 위하여 죽으셨도다"},{"r":"롬5:8","t":"우리가 아직 죄인 되었을 때에 그리스도께서 우리를 위하여 죽으심으로 하나님께서 우리에게 대한 자기의 사랑을 확증하셨느니라"},{"r":"롬8:32","t":"자기 아들을 아끼지 아니하시고 우리 모든 사람을 위하여 내어 주신 이가 어찌 그 아들과 함께 모든 것을 우리에게 은사로 주지 아니하시겠느뇨"},{"r":"사53:5,6","t":"그가 찔림은 우리의 허물을 인함이요 그가 상함은 우리의 죄악을 인함이라 그가 징계를 받음으로 우리가 평화를 누리고 그가 채찍에 맞음으로 우리가 나음을 입었도다"},{"r":"마20:28","t":"인자가 온 것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라"},{"r":"갈1:4","t":"그리스도께서 하나님 곧 우리 아버지의 뜻을 따라 이 악한 세대에서 우리를 건지시려고 우리 죄를 위하여 자기 몸을 드리셨으니"},{"r":"딤전1:15","t":"미쁘다 모든 사람이 받을 만한 이 말이여 그리스도 예수께서 죄인을 구원하시려고 세상에 임하셨다 하였도다 죄인 중에 내가 괴수니라"},{"r":"롬5:18","t":"그런즉 한 범죄로 많은 사람이 정죄에 이른 것 같이 의의 한 행동으로 말미암아 많은 사람이 의롭다 하심을 받아 생명에 이르렀느니라"},{"r":"고전15:17","t":"그리스도께서 다시 사신 것이 없으면 너희의 믿음도 헛되고 너희가 여전히 죄 가운데 있을 것이요"}],"롬5:1":[{"r":"롬3:28","t":"그러므로 사람이 의롭다 하심을 얻는 것은 률법의 행위에 있지 않고 믿음으로 되는 줄 우리가 인정하노라"},{"r":"롬15:13","t":"소망의 하나님이 모든 기쁨과 평강을 믿음 안에서 너희에게 충만케 하사 성령의 능력으로 소망이 넘치게 하시기를 원하노라"},{"r":"히12:28","t":"그러므로 우리가 진동치 못할 나라를 받았은즉 은혜를 받자 이로 말미암아 경건함과 두려움으로 하나님을 기쁘시게 섬길지니"}],"롬5:12":[{"r":"창2:17","t":"선악을 알게하는 나무의 실과는 먹지 말라, 네가 먹는 날에는 정녕 죽으리라  하시니라"},{"r":"창3:6","t":"녀자가 그 나무를 본즉 먹음직도 하고, 보암직도 하고, 지혜롭게 할 만큼 탐스럽기도 한 나무인지라 녀자가 그 실과를 따먹고 자기와 함께 한 남편에게도 주매 그도 먹은지라"},{"r":"고전15:21,22","t":"사망이 사람으로 말미암았으니 죽은 자의 복활도 사람으로 말미암는도다"},{"r":"롬6:9","t":"이는 그리스도께서 죽은 자 가운데서 사셨으매 다시 죽지 아니하시고 사망이 다시 그를 주장하지 못할줄을 앎이로라"},{"r":"시51:5","t":"내가 죄악 중에 출생하였음이여 모친이 죄중에 나를 잉태하였나이다"},{"r":"롬6:23","t":"죄의 삯은 사망이요 하나님의 은사는 그리스도 예수 우리 주 안에 있는 영생이니라"},{"r":"약1:15","t":"욕심이 잉태한즉 죄를 낳고 죄가 장성한즉 사망을 낳느니라"},{"r":"엡2:3","t":"전에는 우리도 다 그 가운데서 우리 육체의 욕심을 따라 지내며 육체와 마음의 원하는 것을 하여 다른 이들과 같이 본질상 진노의 자녀이었더니"},{"r":"롬5:14","t":"그러나 아담으로부터 모세까지 아담의 범죄와 같은 죄를 짓지 아니한 자들 위에도 사망이 왕노릇하였나니 아담은 오실 자의 표상이라"},{"r":"롬5:21","t":"이는 죄가 사망 안에서 왕노릇한 것 같이 은혜도 또한 의로 말미암아 왕노릇하여 우리 주 예수 그리스도로 말미암아 영생에 이르게 하려 함이니라"},{"r":"고전15:22","t":"아담 안에서 모든 사람이 죽은것 같이 그리스도 안에서 모든 사람이 삶을 얻으리라"}],"롬5:3":[{"r":"마5:12","t":"기뻐하고 즐거워하라  하늘에서 너희의 상이 큼이라 너희 전에 있던 선지자들을 이같이 핍박하였느니라"},{"r":"눅21:19","t":"너희의 인내로 너희 령혼을 얻으리라"},{"r":"약1:3","t":"이는 너희 믿음의 시련이 인내를 만들어 내는 줄 너희가 앎이라"}],"롬5:5":[{"r":"시119:116","t":"주의 말씀대로 나를 붙들어 살게 하시고 내 소망이 부끄럽지 말게 하소서"},{"r":"빌1:20","t":"나의 간절한 기대와 소망을 따라 아무 일에든지 부끄럽지 아니하고 오직 전과 같이 이제도 온전히 담대하여 살든지 죽든지 내 몸에서 그리스도가 존귀히 되게 하려 하나니"},{"r":"행2:17,18","t":"하나님이 가라사대 말세에 내가 내 영으로 모든 육체에게 부어 주리니 너희의 자녀들은 예언할 것이요 너희의 젊은이들은 환상을 보고 너희의 늙은이들은 꿈을 꾸리라"},{"r":"행2:33","t":"하나님이 오른손으로 예수를 높이시매 그가 약속하신 성령을 아버지께 받아서 너희 보고 듣는 이것을 부어 주셨느니라"},{"r":"딛3:6","t":"성령을 우리 구주 예수 그리스도로 말미암아 우리에게 풍성히 부어주사"},{"r":"갈4:6","t":"너희가 아들인고로 하나님이 그 아들의 영을 우리 마음 가운데 보내사 아바, 아버지라 부르게 하셨느니라"}],"롬6:10":[{"r":"행7:27","t":"그 동무를 해하는 사람이 모세를 밀뜨려 가로되 누가 너를 관원과 재판장으로 우리 위에 세웠느냐"}],"롬6:11":[{"r":"롬6:2","t":"그럴 수 없느니라 죄에 대하여 죽은 우리가 어찌 그 가운데 더 살리요"}],"롬6:12":[{"r":"롬6:14","t":"죄가 너희를 주관치 못하리니 이는 너희가 법 아래 있지 아니하고 은혜 아래 있음이니라"},{"r":"시19:13","t":"또 주의 종으로 고범죄를 짓지 말게 하사 그 죄가 나를 주장치 못하게 하소서 그리하시면 내가 정직하여 큰 죄과에서 벗어나겠나이다"},{"r":"시119:133","t":"나의 행보를 주의 말씀에 굳게 세우시고 아무 죄악이 나를 주장치 못하게 하소서"},{"r":"미7:19","t":"다시 우리를 긍휼히 여기셔서 우리의 죄악을 발로 밟으시고 우리의 모든 죄를 깊은 바다에 던지시리이다"},{"r":"고후5:17","t":"그런즉 누구든지 그리스도 안에 있으면 새로운 피조물이라 이전 것은 지나갔으니 보라  새것이 되었도다"}],"롬6:23":[{"r":"롬2:7","t":"참고 선을 행하여 영광과 존귀와 썩지 아니함을 구하는 자에게는 영생으로 하시고"},{"r":"롬5:12","t":"이러므로 한 사람으로 말미암아 죄가 세상에 들어오고 죄로 말미암아 사망이 왔나니 이와 같이 모든 사람이 죄를 지었으므로 사망이 모든 사람에게 이르렀느니라"}],"롬6:3":[{"r":"갈3:27","t":"누구든지 그리스도와 합하여 세례를 받은 자는 그리스도로 옷입었느니라"},{"r":"마28:19","t":"그러므로 너희는 가서 모든 족속으로 제자를 삼아 아버지와 아들과 성령의 이름으로 세례를 주고"}],"롬6:4":[{"r":"골2:12","t":"너희가 세례로 그리스도와 함께 장사한 바 되고 또 죽은 자들 가운데서 그를 일으키신 하나님의 역사를 믿음으로 말미암아 그 안에서 함께 일으키심을 받았느니라"},{"r":"요11:40","t":"예수께서 가라사대 내 말이 네가 믿으면 하나님의 영광을 보리라 하지 아니하였느냐  하신대"},{"r":"고후13:4","t":"그리스도께서 약하심으로 십자가에 못 박히셨으나 오직 하나님의 능력으로 살으셨으니 우리도 저의 안에서 약하나 너희를 향하여 하나님의 능력으로 저와 함께 살리라"},{"r":"롬6:9","t":"이는 그리스도께서 죽은 자 가운데서 사셨으매 다시 죽지 아니하시고 사망이 다시 그를 주장하지 못할줄을 앎이로라"},{"r":"롬8:11","t":"예수를 죽은 자 가운데서 살리신 이의 영이 너희 안에 거하시면 그리스도 예수를 죽은 자 가운데서 살리신 이가 너희 안에 거하시는 그의 영으로 말미암아 너희 죽을 몸도 살리시리라"},{"r":"행2:24","t":"하나님께서 사망의 고통을 풀어 살리셨으니 이는 그가 사망에게 매여 있을 수 없었음이라"},{"r":"고후5:17","t":"그런즉 누구든지 그리스도 안에 있으면 새로운 피조물이라 이전 것은 지나갔으니 보라  새것이 되었도다"},{"r":"갈6:15","t":"할례나 무할례가 아무 것도 아니로되 오직 새로 지으심을 받은 자뿐이니라"},{"r":"엡4:23","t":"오직 심령으로 새롭게 되어"},{"r":"엡4:24","t":"하나님을 따라 의와 진리의 거룩함으로 지으심을 받은 새 사람을 입으라"},{"r":"골3:10","t":"새 사람을 입었으니 이는 자기를 창조하신 자의 형상을 좇아 지식에까지 새롭게 하심을 받는 자니라"},{"r":"롬7:6","t":"이제는 우리가 얽매였던 것에 대하여 죽었으므로 률법에서 벗어났으니 이러므로 우리가 영의 새로운 것으로 섬길 것이요 의문의 묵은 것으로 아니할찌니라"}],"롬6:5":[{"r":"빌3:10,11","t":"내가 그리스도와 그 복활의 권능과 그 고난에 참여함을 알려하여 그의 죽으심을 본받아"},{"r":"골2:12","t":"너희가 세례로 그리스도와 함께 장사한 바 되고 또 죽은 자들 가운데서 그를 일으키신 하나님의 역사를 믿음으로 말미암아 그 안에서 함께 일으키심을 받았느니라"},{"r":"골3:1","t":"그러므로 너희가 그리스도와 함께 다시 살리심을 받았으면 위엣 것을 찾으라  거기는 그리스도께서 하나님 우편에 앉아 계시느니라"},{"r":"고후4:10","t":"우리가 항상 예수 죽인 것을 몸에 짊어짐은 예수의 생명도 우리 몸에 나타나게 하려 함이라"}],"롬7:15":[{"r":"롬7:18,19","t":"내 속 곧 내 육신에 선한 것이 거하지 아니하는 줄을 아노니 원함은 내게 있으나 선을 행하는 것은 없노라"},{"r":"갈5:17","t":"육체의 소욕은 성령을 거스리고 성령의 소욕은 육체를 거스리나니 이 둘이 서로 대적함으로 너희의 원하는 것을 하지 못하게 하려 함이니라"}],"롬7:24":[{"r":"롬6:6","t":"우리가 알거니와 우리 옛 사람이 예수와 함께 십자가에 못 박힌 것은 죄의 몸이 멸하여 다시는 우리가 죄에게 종노릇하지 아니하려 함이니"},{"r":"롬8:23","t":"이뿐 아니라 또한 우리 곧 성령의 처음 익은 열매를 받은 우리까지도 속으로 탄식하여 양자 될 것 곧 우리 몸의 구속을 기다리느니라"}],"롬8:13":[{"r":"골3:5","t":"그러므로 땅에 있는 지체를 죽이라 곧 음란과 불정과 사욕과 악한 정욕과 탐심이니 탐심은 우상 숭배니라"}],"롬8:14":[{"r":"갈5:18","t":"너희가 만일 성령의 인도하시는 바가 되면 률법 아래 있지 아니하리라"},{"r":"롬8:16","t":"성령이 친히 우리 영으로 더불어 우리가 하나님의 자녀인 것을 증거하시나니"},{"r":"롬8:19","t":"피조물의 고대하는 바는 하나님의 아들들의 나타나는 것이니"},{"r":"롬9:8","t":"곧 육신의 자녀가 하나님의 자녀가 아니라 오직 약속의 자녀가 씨로 여기심을 받느니라"},{"r":"롬9:26","t":"너희는 내 백성이 아니라 한 그곳에서 저희가 살아계신 하나님의 아들이라 부름을 얻으리라 함과 같으니라"},{"r":"신14:1","t":"너희는 너희 하나님 여호와의 자녀니 죽은 자를 위하여 자기 몸을 베지 말며 눈섭 사이 이마 위의 털을 밀지 말라"},{"r":"호1:10","t":"그러나 이스라엘 자손의 수가 바닷가의 모래같이 되어서 측량할 수도 없고 셀 수도 없을 것이며 전에 저희에게 이르기를 너희는 내 백성이 아니라 한 그 곳에서 저희에게 이르기를 너희는 사신 하나님의 자녀라 할 것이라"},{"r":"요1:12","t":"영접하는 자 곧 그 이름을 믿는 자들에게는 하나님의 자녀가 되는 권세를 주셨으니"},{"r":"요일3:1","t":"보라, 아버지께서 어떠한 사랑을 우리에게 주사 하나님의 자녀라 일컬음을 얻게 하셨는고 우리가 그러하도다 그러므로 세상이 우리를 알지 못함은 그를 알지 못함이니라"}],"롬8:15":[{"r":"딤후1:7","t":"하나님이 우리에게 주신 것은 두려워하는 마음이 아니요 오직 능력과 사랑과 근신하는 마음이니"},{"r":"갈2:4","t":"이는 가만히 들어온 거짓 형제 까닭이라 저희가 가만히 들어온 것은 그리스도 예수 안에서 우리의 가진 자유를 엿보고 우리를 종으로 삼고자 함이로되"},{"r":"히2:15","t":"또 죽기를 무서워하므로 일생에 매여 종노릇 하는 모든 자들을 놓아주려 하심이니"},{"r":"요일4:18","t":"사랑 안에 두려움이 없고 온전한 사랑이 두려움을 내어 쫓나니 두려움에는 형벌이 있음이라 두려워하는 자는 사랑 안에서 온전히 이루지 못하였느니라"},{"r":"고전2:12","t":"우리가 세상의 영을 받지 아니하고 오직 하나님께로 온 영을 받았으니 이는 우리로 하여금 하나님께서 우리에게 은혜로 주신 것들을 알게 하려 하심이라"},{"r":"롬8:23","t":"이뿐 아니라 또한 우리 곧 성령의 처음 익은 열매를 받은 우리까지도 속으로 탄식하여 양자 될 것 곧 우리 몸의 구속을 기다리느니라"},{"r":"갈4:5","t":"률법 아래 있는 자들을 속량하시고 우리로 아들의 명분을 얻게 하려 하심이라"},{"r":"롬9:4","t":"저희는 이스라엘 사람이라 저희에게는 양자 됨과 영광과 언약들과 률법을 세우신 것과 예배와 약속들이 있고"},{"r":"사56:5","t":"내가 내 집에서, 내 성안에서 자녀보다 나은 기념물과 이름을 주며 영영한 이름을 주어 끊치지 않게 할 것이며"},{"r":"렘31:9","t":"울며 올 것이며 그들이 나의 인도함을 입고 간구할 때에 내가 그들로 넘어지지 아니하고 하숫가의 바른 길로 행하게 하리라 나는 이스라엘의 아비요 에브라임은 나의 장자니라"},{"r":"갈4:6","t":"너희가 아들인고로 하나님이 그 아들의 영을 우리 마음 가운데 보내사 아바, 아버지라 부르게 하셨느니라"},{"r":"막14:36","t":"가라사대 아바, 아버지여  아버지께는 모든 것이 가능하오니 이 잔을 내게서 옮기시옵소서 그러나 나의 원대로 마옵시고 아버지의 원대로 하옵소서 하시고"}],"롬8:16":[{"r":"고후1:22","t":"저가 또한 우리에게 인치시고 보증으로 성령을 우리 마음에 주셨느니라"},{"r":"고후5:5","t":"곧 이것을 우리에게 이루게 하시고 보증으로 성령을 우리에게 주신 이는 하나님이시니라"},{"r":"엡1:13,14","t":"그 안에서 너희도 진리의 말씀 곧 너희의 구원의 복음을 듣고 그 안에서 또한 믿어 약속의 성령으로 인치심을 받았으니"},{"r":"요일3:24","t":"그의 계명들을 지키는 자는 주 안에 거하고 주는 저 안에 거하시나니 우리에게 주신 성령으로 말미암아 그가 우리 안에 거하시는 줄을 우리가 아느니라"}],"롬8:2":[{"r":"고전15:45","t":"기록된 바 첫 사람 아담은 산 영이 되었다 함과 같이 마지막 아담은 살려 주는 영이 되었나니"},{"r":"고후3:6","t":"저가 또 우리로 새 언약의 일군 되기에 만족케 하셨으니 의문으로 하지 아니하고 오직 영으로 함이니 의문은 죽이는 것이요 영은 살리는 것임이니라"},{"r":"롬8:12","t":"그러므로 형제들아 우리가 빚진 자로되 육신에게 져서 육신대로 살 것이 아니니라"},{"r":"롬6:14","t":"죄가 너희를 주관치 못하리니 이는 너희가 법 아래 있지 아니하고 은혜 아래 있음이니라"},{"r":"롬6:18","t":"죄에게서 해방되어 의에게 종이 되었느니라"},{"r":"롬7:4","t":"그러므로 내 형제들아 너희도 그리스도의 몸으로 말미암아 률법에 대하여 죽임을 당하였으니 이는 다른이 곧 죽은 자 가운데서 살아나신 이에게 가서 우리로 하나님을 위하여 열매를 맺히게 하려 함이니라"}],"롬8:5":[{"r":"갈6:8","t":"자기의 육체를 위하여 심는 자는 육체로부터 썩어진 것을 거두고 성령을 위하여 심는 자는 성령으로부터 영생을 거두리라"},{"r":"갈5:19~21","t":"육체의 일은 현저하니 곧 음행과, 더러운 것과, 호색과,"},{"r":"갈5:22,23","t":"오직 성령의 열매는 사랑과, 희락과, 화평과, 오래 참음과, 자비와, 양선과, 충성과,"},{"r":"갈5:25","t":"만일 우리가 성령으로 살면 또한 성령으로 행할지니"}],"롬8:6":[{"r":"롬8:13","t":"너희가 육신대로 살면 반드시 죽을 것이로되 영으로써 몸의 행실을 죽이면 살리니"},{"r":"골2:18","t":"누구든지 일부러 겸손함과 천사 숭배함을 인하여 너희 상을 빼앗지 못하게 하라 저가 그 본 것을 의지하여 그 육체의 마음을 좇아 헛되이 과장하고"},{"r":"롬6:21","t":"너희가 그 때에 무슨 열매를 얻었느뇨 이제는 너희가 그 일을 부끄러워하나니 이는 그 마지막이 사망임이니라"}],"롬8:9":[{"r":"롬8:11","t":"예수를 죽은 자 가운데서 살리신 이의 영이 너희 안에 거하시면 그리스도 예수를 죽은 자 가운데서 살리신 이가 너희 안에 거하시는 그의 영으로 말미암아 너희 죽을 몸도 살리시리라"},{"r":"고전3:16","t":"너희가 하나님의 성전인 것과 하나님의 성령이 너희 안에 거하시는 것을 알지 못하느뇨"},{"r":"고전6:19","t":"너희 몸은 너희가 하나님께로부터 받은 바 너희 가운데 계신 성령의 전인 줄을 알지 못하느냐 너희는 너희의 것이 아니라"},{"r":"고후6:16","t":"하나님의 성전과 우상이 어찌 일치가 되리요 우리는 살아계신 하나님의 성전이라 이와 같이 하나님께서 가라사대 내가 저희 가운데 거하며 두루 행하여 나는 저희 하나님이 되고 저희는 나의 백성이 되리라 하셨느니라"},{"r":"딤후1:14","t":"우리 안에 거하시는 성령으로 말미암아 네게 부탁한 아름다운 것을 지키라"},{"r":"행16:7","t":"무시아 앞에 이르러 비두니아로 가고자 애쓰되 예수의 영이 허락지 아니하시는지라"},{"r":"유1:19","t":"이 사람들은 당을 짓는 자며 육에 속한 자며 성령은 없는 자니라"},{"r":"요14:17","t":"저는 진리의 영이라 세상은 능히 저를 받지 못하나니 이는 저를 보지도 못하고 알지도 못함이라 그러나 너희는 저를 아나니 저는 너희와 함께 거하심이요 또 너희 속에 계시겠음이라"}],"롬9:27":[{"r":"사10:22","t":"이스라엘이여 네 백성이 바다의 모래 같을지라도 남은 자만 돌아오리니 넘치는 공의로 훼멸이 작정되었음이라"},{"r":"호1:10","t":"그러나 이스라엘 자손의 수가 바닷가의 모래같이 되어서 측량할 수도 없고 셀 수도 없을 것이며 전에 저희에게 이르기를 너희는 내 백성이 아니라 한 그 곳에서 저희에게 이르기를 너희는 사신 하나님의 자녀라 할 것이라"},{"r":"롬11:5","t":"그런즉 이와 같이 이제도 은혜로 택하심을 따라 남은 자가 있느니라"}],"마10:32":[{"r":"롬10:9,10","t":"네가 만일 네 입으로 예수를 주로 시인하며 또 하나님께서 그를 죽은 자 가운데서 살리신 것을 네 마음에 믿으면 구원을 얻으리니"},{"r":"히10:35","t":"그러므로 너희 담대함을 버리지 말라 이것이 큰 상을 얻느니라"},{"r":"계3:5","t":"이기는 자는 이와 같이 흰 옷을 입을 것이요 내가 그 이름을 생명책에서 반드시 흐리지 아니하고 그 이름을 내 아버지 앞과 그 천사들 앞에서 시인하리라"}],"마10:33":[{"r":"딤후2:12","t":"참으면 또한 함께 왕노릇 할 것이요 우리가 주를 부인하면 주도 우리를 부인하실 것이라"},{"r":"벧후2:1","t":"그러나 민간에 또한 거짓 선지자들이 일어났었나니 이와 같이 너희 중에도 거짓 선생들이 있으리라 저희는 멸망케 할 이단을 가만히 끌어들여 자기들을 사신 주를 부인하고 임박한 멸망을 스스로 취하는 자들이라"},{"r":"요일2:23","t":"아들을 부인하는 자에게는 또한 아버지가 없으되 아들을 시인하는 자에게는 아버지도 있느니라"},{"r":"막8:38","t":"누구든지 이 음란하고 죄 많은 세대에서 나와 내 말을 부끄러워하면 인자도 아버지의 영광으로 거룩한 천사들과 함께 올 때에 그사람을 부끄러워하리라"},{"r":"마7:23","t":"그 때에 내가 저희에게 밝히 말하되 내가 너희를 도무지 알지 못하니 부법을 행하는 자들아 내게서 떠나가라 하리라"},{"r":"마25:12","t":"대답하여 가로되 진실로 너희에게 이르노니 내가 너희를 알지 못하노라 하였느니라"},{"r":"눅13:25","t":"집 주인이 일어나 문을 한 번 닫은 후에 너희가 밖에 서서 문을 두드리며 주여, 열어 주소서 하면 저가 대답하여 가로되 나는 너희가 어디로서 온 자인지 알지 못하노라 하리니"}],"마16:16":[{"r":"요11:27","t":"가로되 주여, 그러하외다 주는 그리스도시요 세상에 오시는 하나님의 아들이신 줄 내가 믿나이다"},{"r":"마1:17","t":"그런즉 모든 대 수가 아브라함부터 다윗까지 열 네 대요, 다윗부터 바벨론으로 이거할 때까지 열 네대요, 바벨론으로 이거한 후부터 그리스도까지 열 네 대러라"},{"r":"신5:26","t":"무릇 육신을 가진 자가 우리처럼 사시는 하나님의 음성이 불 가운데서 발함을 듣고 생존한 자가 누구니이까"},{"r":"수3:10","t":"또 말하되 사시는 하나님이 너희 가운데 계시사 가나안 족속과, 헷 족속과, 히위 족속과, 브리스 족속과, 기르가스 족속과, 아모리 족속과, 여부스 족속을 너희 앞에서 정녕히 쫓아내실 줄을 이 일로 너희가 알리라"},{"r":"시42:2","t":"내 령혼이 하나님 곧 생존하시는 하나님을 갈망하나니 내가 어느 때에 나아가서 하나님 앞에 뵈올꼬"},{"r":"렘10:10","t":"오직 여호와는 참 하나님이시요 사시는 하나님이시요 영원한 왕이시라 그 진노하심에 땅이 진동하며 그 분노하심을 열방이 능히 당치 못하느니라"},{"r":"단6:20","t":"다니엘의 든 굴에 가까이 이르러는 슬피 소리질러 다니엘에게 물어 가로되 사시는 하나님의 종 다니엘아 너의 항상 섬기는 네 하나님이 사자에게서 너를 구원하시기에 능하셨느냐"},{"r":"호1:10","t":"그러나 이스라엘 자손의 수가 바닷가의 모래같이 되어서 측량할 수도 없고 셀 수도 없을 것이며 전에 저희에게 이르기를 너희는 내 백성이 아니라 한 그 곳에서 저희에게 이르기를 너희는 사신 하나님의 자녀라 할 것이라"},{"r":"행14:15","t":"가로되 여러분이여 어찌하여 이러한 일을 하느냐  우리도 너희와 같은 성정을 가진 사람이라 너희에게 복음을 전하는 것은 이 헛된 일을 버리고 천지와 바다와 그 가운데 만유를 지으시고 살아 계신 하나님께로 돌아오라 함이라"},{"r":"고후3:3","t":"너희는 우리로 말미암아 나타난 그리스도의 편지니 이는 먹으로 쓴 것이 아니요 오직 살아 계신 하나님의 영으로 한 것이며 또 돌비에 쓴 것이 아니요 오직 육의 심비에 한 것이라"},{"r":"딤전4:10","t":"이를 위하여 우리가 수고하고 진력하는 것은 우리 소망을 살아계신 하나님께 둠이니 곧 모든 사람 특히 믿는 자들의 구주시라"},{"r":"히3:12","t":"형제들아 너희가 삼가 혹 너희 중에 누가 믿지 아니하는 악심을 품고 살아 계신 하나님에게서 떨어질까 념려할 것이요"},{"r":"마14:33","t":"배에 있는 사람들이 예수께 절하며 가로되 진실로 하나님의 아들이로소이다 하더라"}],"마16:17":[{"r":"요1:42","t":"데리고 예수께로 오니 예수께서 보시고 가라사대 네가 요한의 아들 시몬이니 장차 게바라 하리라 하시니라 게바는 번역하면 베드로라"},{"r":"요21:15~17","t":"저희가 조반 먹은 후에 예수께서 시몬 베드로에게 이르시되 요한의 아들 시몬아, 네가 이 사람들보다 나를 더 사랑하느냐  하시니 가로되 주여, 그러하외다 내가 주를 사랑하는 줄 주께서 아시나이다 가라사대 내 어린 양을 먹이라 하시고"},{"r":"마13:16","t":"그러나 너희 눈은 봄으로 너희 귀는 들음으로 복이 있도다"},{"r":"고전15:50","t":"형제들아 내가 이것을 말하노니 혈과 육은 하나님 나라를 유업으로 받을 수 없고 또한 썩은 것은 썩지 아니한 것을 유업으로 받지 못하느니라"},{"r":"갈1:16","t":"그 아들을 이방에 전하기 위하여 그를 내 속에 나타내시기를 기뻐하실 때에 내가 곧 혈육과 의논하지 아니하고"},{"r":"엡6:12","t":"우리의 씨름은 혈과 육에 대한 것이 아니요 정사와 권세와 이 어두움의 세상 주관자들과 하늘에 있는 악의 영들에게 대함이라"},{"r":"히2:14","t":"자녀들은 혈육에 함께 속하였으매 그도 또한 한 모양으로 혈육에 함께 속하심은 사망으로 말미암아 사망의 세력을 잡은 자 곧 마귀를 없이 하시며"},{"r":"고전2:10","t":"오직 하나님이 성령으로 이것을 우리에게 보이셨으니 성령은 모든 것 곧 하나님의 깊은 것이라도 통달하시느니라"},{"r":"고전2:12","t":"우리가 세상의 영을 받지 아니하고 오직 하나님께로 온 영을 받았으니 이는 우리로 하여금 하나님께서 우리에게 은혜로 주신 것들을 알게 하려 하심이라"},{"r":"마11:25","t":"그 때에 예수께서 대답하여 가라사대 천지의 주재이신 아버지여  이것을 지혜롭고 슬기있는 자들에게는 숨기시고 어린 아이들에게는 나타내심을 감사하나이다"},{"r":"요6:45","t":"선지자의 글에 저희가 다 하나님의 가르치심을 받으리라 기록되었은즉 아버지께 듣고 배운 사람마다 내게로 오느니라"}],"마16:18":[{"r":"마10:2","t":"열 두 사도의 이름은 이러하니 베드로라 하는 시몬을 비롯하여 그의 형제 안드레와, 세베대의 아들 야고보와, 그의 형제 요한,"},{"r":"요1:42","t":"데리고 예수께로 오니 예수께서 보시고 가라사대 네가 요한의 아들 시몬이니 장차 게바라 하리라 하시니라 게바는 번역하면 베드로라"},{"r":"엡2:20","t":"너희는 사도들과 선지자들의 터 위에 세우심을 입은 자라 그리스도 예수께서 친히 모퉁이 돌이 되셨느니라"},{"r":"계21:14","t":"그 성에 성곽은 열 두 기초석이 있고 그 위에 어린 양의 십 이 사도의 열 두 이름이 있더라"},{"r":"마7:24","t":"그러므로 누구든지 나의 이 말을 듣고 행하는 자는 그 집을 반석위에 지은 지혜로운 사람 같으리니"},{"r":"마11:23","t":"가버나움아  네가 하늘에까지 높아지겠느냐  음부에까지 낮아지리라 네게서 행한 모든 권능을 소돔에서 행하였더면 그 성이 오늘날까지 있었으리라"},{"r":"욥38:17","t":"사망의 문이 네게 나타났었느냐  사망의 그늘진 문을 네가 보았었느냐"},{"r":"사38:10","t":"내가 말하기를 내가 중년에 음부의 문에 들어가고 여년을 빼앗기게 되리라 하였도다"}],"마16:27":[{"r":"마24:30","t":"그 때에 인자의 징조가 하늘에서 보이겠고 그 때에 땅의 모든 족속들이 통곡하며 그들이 인자가 구름을 타고 능력과 큰 영광으로 오는 것을 보리라"},{"r":"마25:31","t":"인자가 자기 영광으로 모든 천사와 함께 올 때에 자기 영광의 보좌에 앉으리니"},{"r":"마26:64","t":"예수께서 가라사대 네가 말하였느니라 그러나 내가 너희에게 이르노니 이 후에 인자가 권능의 우편에 앉은 것과 하늘 구름을 타고 오는 것을 너희가 보리라 하시니"},{"r":"단7:10","t":"불이 강처럼 흘러 그 앞에서 나오며 그에게 수종하는 자는 천천이요 그 앞에 시위한 자는 만만이며 심판을 베푸는데 책들이 펴 놓였더라"},{"r":"단7:13","t":"내가 또 밤 이상 중에 보았는데 인자 같은 이가 하늘 구름을 타고 와서 옛적부터 항상 계신 자에게 나아와 그 앞에 인도되매"},{"r":"슥14:5","t":"그 산 골짜기는 아셀까지 미칠찌라 너희가 그의 산 골짜기로 도망하되 유다 왕 웃시야 때에 지진을 피하여 도망하던 것 같이 하리라 나의 하나님 여호와께서 임하실 것이요 모든 거룩한 자가 주와 함께 하리라"},{"r":"요1:51","t":"또 가라사대 진실로 진실로 너희에게 이르노니 하늘이 열리고 하나님의 사자들이 인자 위에 오르락 내리락 하는 것을 보리라 하시니라"},{"r":"행1:11","t":"가로되 갈릴리 사람들아 어찌하여 서서 하늘을 쳐다보느냐  너희 가운데서 하늘로 올리우신 이 예수는 하늘로 가심을 본 그대로 오시리라 하였느니라"},{"r":"살전1:10","t":"또 죽은 자들 가운데서 다시 살리신 그의 아들이 하늘로부터 강림하심을 기다린다고 말하니 이는 장래 노하심에서 우리를 건지시는 예수시니라"},{"r":"살전4:16","t":"주께서 호령과 천사장의 소리와 하나님의 나팔로 친히 하늘로 좇아 강림하시리니 그리스도 안에서 죽은 자들이 먼저 일어나고"},{"r":"유1:14","t":"아담의 칠세 손 에녹이 사람들에게 대하여도 예언하여 이르되 보라, 주께서 그 수만의 거룩한 자와 함께 임하셨나니"},{"r":"계1:7","t":"볼지어다  구름을 타고 오시리라 각인의 눈이 그를 보겠고 그를 찌른 자들도 볼 터이요 땅에 있는 모든 족속이 그를 인하여 애곡하리니 그러하리라 아멘"},{"r":"신33:2","t":"일렀으되 여호와께서 시내에서 오시고 세일산에서 일어나시고 바란산에서 비취시고 일만 성도 가운데서 강림하셨고 그 오른손에는 불 같은 률법이 있도다"},{"r":"마13:41","t":"인자가 그 천사들을 보내리니 저희가 그 나라에서 모든 넘어지게 하는 것과 또 부법을 행하는 자들을 거두어 내어"},{"r":"롬2:6","t":"하나님께서 각 사람에게 그 행한 대로 보응하시되"},{"r":"롬14:12","t":"이러므로 우리 각인이 자기 일을 하나님께 직고하리라"},{"r":"고후5:10","t":"이는 우리가 다 반드시 그리스도의 심판대 앞에 드러나 각각 선악간에 그 몸으로 행한 것을 따라 받으려 함이라"},{"r":"히9:27","t":"한번 죽는 것은 사람에게 정하신 것이요 그 후에는 심판이 있으리니"},{"r":"벧전1:17","t":"외모로 보시지 않고 각 사람의 행위대로 판단하시는 자를 너희가 아버지라 부른즉 너희의 나그네로 있을 때를 두려움으로 지내라"},{"r":"계2:23","t":"또 내가 사망으로 그의 자녀를 죽이리니 모든 교회가 나는 사람의 뜻과 마음을 살피는 자인 줄 알지라 내가 너희 각 사람의 행위대로 갚아주리라"},{"r":"계20:12","t":"또 내가 보니 죽은 자들이 무론대소하고 그 보좌 앞에 섰는데 책들이 펴 있고 또 다른 책이 펴졌으니 곧 생명책이라 죽은 자들이 자기 행위를 따라 책들에 기록된 대로 심판을 받으니"},{"r":"계22:12","t":"보라, 내가 속히 오리니 내가 줄 상이 내게 있어 각 사람에게 그의 일한 대로 갚아 주리라"},{"r":"행10:42","t":"우리를 명하사 백성에게 전도하되 하나님이 산 자와 죽은 자의 재판장으로 정하신 자가 곧 이 사람인 것을 증거하게 하셨고"},{"r":"고전3:8","t":"심는 이와 물 주는 이가 일반이나 각각 자기의 일하는 대로 자기의 상을 받으리라"}],"마18:10":[{"r":"마6:29","t":"그러나 내가 너희에게 말하노니 솔로몬의 모든 영광으로도 입은 것이 이 꽃 하나만 같지 못하였느니라"},{"r":"마25:40","t":"임금이 대답하여 가라사대 내가 진실로 너희에게 이르노니 너희가 여기 내 형제 중에 지극히 작은 자 하나에게 한 것이 곧 내게 한 것이니라 하시고"},{"r":"마25:45","t":"이에 임금이 대답하여 가라사대 내가 진실로 너희에게 이르노니 이 지극히 작은 자 하나에게 하지 아니한 것이 곧 내게 하지 아니한 것이니라 하시리니"},{"r":"눅15:7","t":"내가 너희에게 이르노니 이와 같이 죄인 하나가 회개하면 하늘에서는 회개할 것 없는 의인 아흔 아홉을 인하여 기뻐하는 것보다 더하리라"},{"r":"눅15:10","t":"내가 너희에게 이르노니 이와 같이 죄인 하나가 회개하면 하나님의 사자들 앞에 기쁨이 되느니라"},{"r":"행12:15","t":"저희가 말하되 네가 미쳤다 하나 계집아이는 힘써 말하되 참말이라 하니 저희가 말하되 그러면 그의 천사라 하더라"},{"r":"시34:7","t":"여호와의 사자가 주를 경외하는 자를 둘러 진치고 저희를 건지시는도다"},{"r":"시91:11","t":"저가 너를 위하여 그 사자들을 명하사 네 모든 길에 너를 지키게 하심이라"},{"r":"히1:14","t":"모든 천사들은 부리는 영으로서 구원 얻을 후사들을 위하여 섬기라고 보내심이 아니뇨"},{"r":"눅1:19","t":"천사가 대답하여 가로되 나는 하나님 앞에 섰는 가브리엘이라 이 좋은 소식을 전하여 네게 말하라고 보내심을 입었노라"},{"r":"계8:2","t":"내가 보매 하나님 앞에 시위한 일곱 천사가 있어 일곱 나팔을 받았더라"},{"r":"에1:14","t":"때에 왕에게 가까이 하여 왕의 기색을 살피며 나라 첫 자리에 앉은 자는 바사와 메대의 일곱 방백 곧 가르스나와, 세달과, 아드마다와, 다시스와, 메레스와, 마르스나와, 므무간이라"}],"마1:21":[{"r":"마1:25","t":"아들을 낳기까지 동침치 아니하더니 낳으매 이름을 예수라 하니라"},{"r":"눅1:31","t":"보라, 네가 수태하여 아들을 낳으리니 그 이름을 예수라 하라"},{"r":"눅2:21","t":"할례할 팔일이 되매 그 이름을 예수라 하니 곧 수태하기 전에 천사의 일컬은 바러라"},{"r":"눅2:11","t":"오늘날 다윗의 동리에 너희를 위하여 구주가 나셨으니 곧 그리스도 주시니라"},{"r":"행4:12","t":"다른 이로서는 구원을 얻을 수 없나니 천하 인간에 구원을 얻을 만한 다른 이름을 우리에게 주신 일이 없음이니라 하였더라"},{"r":"행5:31","t":"이스라엘로 회개케 하사 죄 사함을 얻게 하시려고 그를 오른손으로 높이사 임금과 구주를 삼으셨느니라"},{"r":"행13:23","t":"하나님이 약속하신 대로 이 사람의 씨에서 이스라엘을 위하여 구주를 세우셨으니 곧 예수라"},{"r":"행13:38","t":"그러므로 형제들아  너희가 알것은 이 사람을 힘입어 죄 사함을 너희에게 전하는 이것이며"},{"r":"행3:26","t":"하나님이 그 종을 세워 복 주시려고 너희에게 먼저 보내사 너희로 하여금 돌이켜 각각 그 악함을 버리게 하셨느니라"}],"마1:23":[{"r":"사7:14","t":"그러므로 주께서 친히 징조로 너희에게 주실 것이라 보라, 처녀가 잉태하여 아들을 낳을 것이요 그 이름을 임마누엘이라 하리라"},{"r":"사8:10","t":"너희는 함께 도모하라 필경 이루지 못하리라 말을 내어라 시행되지 못하리라 이는 하나님이 우리와 함께 하심이니라"},{"r":"사8:8","t":"흘러 유다에 들어와서 창일하고 목에까지 미치리라 임마누엘이여  그의 펴는 날개가 네 땅에 편만하리라 하셨느니라"},{"r":"마28:20","t":"내가 너희에게 분부한 모든 것을 가르쳐 지키게 하라 볼찌어다  내가 세상 끝날까지 너희와 항상 함께 있으리라  하시니라"}],"마24:12":[{"r":"눅18:8","t":"내가 너희에게 이르노니 속히 그 원한을 풀어 주시리라 그러나 인자가 올 때에 세상에서 믿음을 보겠느냐 하시니라"},{"r":"계2:4","t":"그러나 너를 책망할 것이 있나니 너의 처음 사랑을 버렸느니라"}],"마24:13":[{"r":"마10:22","t":"또 너희가 내 이름을 인하여 모든 사람에게 미움을 받을 것이나 나중까지 견디는 자는 구원을 얻으리라"}],"마24:14":[{"r":"롬10:18","t":"그러나 내가 말하노니 저희가 듣지 아니하였느뇨 그렇지 아니하다 그 소리가 온 땅에 퍼졌고 그 말씀이 땅 끝까지 이르렀도다 하였느니라"},{"r":"골1:6","t":"이 복음이 이미 너희에게 이르매 너희가 듣고 참으로 하나님의 은혜를 깨달은 날부터 너희 중에서와 같이 또한 온 천하에서도 열매를 맺어 자라는도다"},{"r":"골1:23","t":"만일 너희가 믿음에 거하고 터 위에 굳게 서서 너희 들은 바 복음의 소망에서 흔들리지 아니하면 그리하리라 이 복음은 천하 만민에게 전파된 바요 나 바울은 이 복음의 일군이 되었노라"},{"r":"막14:9","t":"내가 진실로 너희에게 이르노니 온 천하에 어디서든지 복음이 전파되는 곳에는 이 녀자의 행한 일도 말하여 저를 기념하리라 하시니라"},{"r":"마28:19","t":"그러므로 너희는 가서 모든 족속으로 제자를 삼아 아버지와 아들과 성령의 이름으로 세례를 주고"},{"r":"마10:18","t":"또 너희가 나를 인하여 총독들과 임금들 앞에 끌려 가리니 이는 저희와 이방인들에게 증거가 되게 하려 하심이라"},{"r":"마24:6","t":"란리와 란리 소문을 듣겠으나 너희는 삼가 두려워 말라 이런 일이 있어야 하되 끝은 아직 아니니라"}],"마24:15":[{"r":"단9:27","t":"그가 장차 많은 사람으로 더불어 한 이레 동안의 언약을 굳게 정하겠고 그가 그 이레의 절반에 제사와 예물을 금지할 것이며 또 잔포하여 미운 물건이 날개를 의지하여 설 것이며 또 이미 정한 종말까지 진노가 황폐케 하는 자에게 쏟아지리라 하였느니라"},{"r":"단11:31","t":"군대는 그의 편에 서서 성소 곧 견고한 곳을 더럽히며 매일 드리는 제사를 폐하며 멸망케 하는 미운 물건을 세울 것이며"},{"r":"단12:11","t":"매일 드리는 제사를 폐하며 멸망케 할 미운 물건을 세울 때부터 일천 이백 구십 일을 지낼 것이요"},{"r":"요11:48","t":"만일 저를 이대로 두면 모든 사람이 저를 믿을 것이요 그리고 로마인들이 와서 우리 땅과 민족을 빼앗아 가리라 하니"},{"r":"행6:13","t":"거짓 증인들을 세우니 가로되 이 사람이 이 거룩한 곳과 률법을 거스려 말하기를 마지 아니하는도다"},{"r":"행21:28","t":"외치되 이스라엘 사람들아 도우라 이 사람은 각처에서 우리 백성과 률법과 이 곳을 훼방하여 모든 사람을 가르치는 그 자인데 또 헬라인을 데리고 성전에 들어가서 이 거룩한 곳을 더럽게 하였다하니"},{"r":"단9:22,23","t":"내게 가르치며 내게 말하여 가로되 다니엘아 내가 이제 네게 지혜와 총명을 주려고 나왔나니"},{"r":"단9:25","t":"그러므로 너는 깨달아 알지니라 예루살렘을 중건하라는 영이 날때부터 기름부음을 받은 자 곧 왕이 일어나기까지 일곱 이레와 육십이 이레가 지날 것이요 그 때 곤난한 동안에 성이 중건되어 거리와 해자가 이룰 것이며"},{"r":"계1:3","t":"이 예언의 말씀을 읽는 자와 듣는 자들과 그 가운데 기록한 것을 지키는 자들이 복이 있나니 때가 가까움이라"}],"마24:17":[{"r":"눅5:19","t":"무리 때문에 메고 들어갈 길을 얻지 못한지라 지붕에 올라가 기와를 벗기고 병자를 침상채 무리 가운데로 예수 앞에 달아 내리니"},{"r":"눅17:31","t":"그 날에 만일 사람이 지붕 위에 있고 그 세간이 집 안에 있으면 그것을 가지러 내려 오지 말 것이요 밭에 있는 자도 이와 같이 뒤로 돌이키지 말 것이니라"}],"마24:19":[{"r":"눅23:29","t":"보라, 날이 이르면 사람이 말하기를 수태 못하는 이와 해산하지 못한 배와 먹이지 못한 젖이 복이 있다 하리라"}],"마24:21":[{"r":"마24:29","t":"그 날 환난 후에 즉시 해가 어두워지며 달이 빛을 내지 아니하며 별들이 하늘에서 떨어지며 하늘의 권능들이 흔들리리라"},{"r":"단12:1","t":"그 때에 네 민족을 호위하는 대군 미가엘이 일어날 것이요 또 환난이 있으리니 이는 개국 이래로 그 때까지 없던 환난일 것이며 그 때에 네 백성 중 무릇 책에 기록된 모든 자가 구원을 얻을 것이라"},{"r":"계7:14","t":"내가 가로되 내 주여 당신이 알리이다 하니 그가 나더러 이르되 이는 큰 환난에서 나오는 자들인데 어린 양의 피에 그 옷을 씻어 희게 하였느니라"},{"r":"계16:18","t":"번개와 음성들과 뢰성이 있고 또 지진이 있어 어찌 큰지 사람이 땅에 있어 옴으로 이같이 큰 지진이 없었더라"}],"마24:22":[{"r":"마24:24","t":"거짓 그리스도들과 거짓 선지자들이 일어나 큰 표적과 기사를 보이어 할 수만 있으면 택하신 자들도 미혹하게 하리라"},{"r":"마24:31","t":"저가 큰 나팔 소리와 함께 천사들을 보내리니 저희가 그 택하신 자들을 하늘 이 끝에서 저 끝까지 사방에서 모으리라"},{"r":"사65:8,9","t":"여호와께서 이같이 말씀하시되 포도송이에는 즙이 있으므로 혹이 말하기를 그것을 상하지 말라 거기 복이 있느니라 하나니 나도 내 종들을 위하여 그같이 행하여 다 멸하지 아니하고"},{"r":"눅18:7","t":"하물며 하나님께서 그 밤낮 부르짖는 택하신 자들의 원한을 풀어 주지 아니하시겠느냐 저희에게 오래 참으시겠느냐"},{"r":"마22:14","t":"청함을 받은 자는 많되 택함을 입은 자는 적으니라"}],"마24:24":[{"r":"요일2:18","t":"아이들아 이것이 마지막 때라 적그리스도가 이르겠다 함을 너희가 들은 것과 같이 지금도 많은 적그리스도가 일어났으니 이러므로 우리가 마지막 때인 줄 아노라"},{"r":"마24:11","t":"거짓 선지자가 많이 일어나 많은 사람을 미혹하게 하겠으며"},{"r":"신13:1~3","t":"너희 중에 선지자나 꿈 꾸는 자가 일어나서 이적과 기사를 네게 보이고"},{"r":"살후2:9~11","t":"악한 자의 임함은 사단의 역사를 따라 모든 능력과 표적과 거짓 기적과"},{"r":"계13:13,14","t":"큰 이적을 행하되 심지어 사람들 앞에서 불이 하늘로부터 땅에 내려오게 하고"},{"r":"계16:14","t":"저희는 귀신의 영이라 이적을 행하여 온 천하 임금들에게 가서 하나님 곧 전능하신 이의 큰 날에 전쟁을 위하여 그들을 모으더라"},{"r":"계19:20","t":"짐승이 잡히고 그 앞에서 이적을 행하던 거짓 선지자도 함께 잡혔으니 이는 짐승의 표를 받고 그의 우상에게 경배하던 자들을 이적으로 미혹하던 자라 이 둘이 산 채로 류황불 붙는 못에 던지우고"},{"r":"행8:9","t":"그 성에 시몬이라 하는 사람이 전부터 있어 마술을 행하여 사마리아 백성을 놀라게 하며 자칭 큰 자라 하니"}],"마24:25":[{"r":"요13:19","t":"지금부터 일이 이루기 전에 미리 너희에게 이름은 일이 이룰 때에 내가 그인줄 너희로 믿게 하려 함이로라"},{"r":"요14:29","t":"이제 일이 이루기 전에 너희에게 말한 것은 일이 이룰 때에 너희로 믿게 하려 함이라"},{"r":"벧후3:17","t":"그러므로 사랑하는 자들아  너희가 이것을 미리 알았은즉 무법한 자들의 미혹에 이끌려 너희 굳센데서 떨어질까 삼가라"}],"마24:29":[{"r":"마24:21","t":"이는 그 때에 큰 환난이 있겠음이라 창세로부터 지금까지 이런 환난이 없었고 후에도 없으리라"},{"r":"사13:10","t":"하늘의 별들과 별 떨기가 그 빛을 내지 아니하며 해가 돋아도 어두우며 달이 그 빛을 비취지 아니할 것이로다"},{"r":"사24:23","t":"그 때에 달이 무색하고 해가 부끄러워하리니 이는 만군의 여호와께서 시온산과 예루살렘에서 왕이 되시고 그 장로들 앞에서 영광을 나타내실 것임이니라"},{"r":"겔32:7","t":"내가 너를 불 끄듯 할 때에 하늘을 가리워 별로 어둡게 하며 해를 구름으로 가리우며 달로 빛을 발하지 못하게 할 것임이여"},{"r":"욜2:10","t":"그 앞에서 땅이 진동하며 하늘이 떨며 일월이 캄캄하며 별들이 빛을 거두도다"},{"r":"욜2:31","t":"여호와의 크고 두려운 날이 이르기 전에 해가 어두워지고 달이 핏빛 같이 변하려니와"},{"r":"욜3:15","t":"해와 달이 캄캄하며 별들이 그 빛을 거두도다"},{"r":"행2:20","t":"주의 크고 영화로운 날이 이르기 전에 해가 변하여 어두워지고 달이 변하여 피가 되리라"},{"r":"암5:20","t":"여호와의 날이 어찌 어두워서 빛이 없음이 아니며 캄캄하여 빛남이 없음이 아니냐"},{"r":"암8:9","t":"주 여호와께서 가라사대 그 날에 내가 해로 대낮에 지게 하여 백주에 땅을 캄캄케 하며"},{"r":"습1:15","t":"그 날은 분노의 날이요, 환난과 고통의 날이요, 황무와 패괴의 날이요, 캄캄하고 어두운 날이요, 구름과 흑암의 날이요,"},{"r":"계6:12","t":"내가 보니 여섯째 인을 떼실 때에 큰 지진이 나며 해가 총담같이 검어지고 온 달이 피같이 되며"},{"r":"계8:12","t":"네째 천사가 나팔을 부니 해 삼분의 일과 달 삼분의 일과 별들의 삼분의 일이 침을 받아 그 삼분의 일이 어두워지니 낮 삼분의 일은 비췸이 없고 밤도 그러하더라"},{"r":"계6:13","t":"하늘의 별들이 무화과 나무가 대풍에 흔들려 선 과실이 떨어지는 것같이 땅에 떨어지며"},{"r":"사14:12","t":"너 아침의 아들 계명성이여  어찌 그리 하늘에서 떨어졌으며 너 렬국을 엎은 자여 어찌 그리 땅에 찍혔는고"},{"r":"사34:4","t":"하늘의 만상이 사라지고 하늘들이 두루마리 같이 말리되 그 만상의 쇠잔함이 포도나무 잎이 마름 같고 무화과나무 잎이 마름 같으리라"}],"마24:3":[{"r":"마21:1","t":"저희가 예루살렘에 가까이 와서 감람산 벳바게에 이르렀을 때에 예수께서 두 제자를 보내시며"},{"r":"막4:34","t":"비유가 아니면 말씀하지 아니 하시고 다만 혼자 계실 때에 그 제자들에게 모든것을 해석하시더라"},{"r":"행1:6,7","t":"저희가 모였을때에 예수께 묻자와 가로되 주께서 이스라엘 나라를 회부하심이 이때니이까  하니"},{"r":"마24:27","t":"번개가 동편에서 나서 서편까지 번쩍임같이 인자의 임함도 그러하리라"},{"r":"마24:37","t":"노아의 때와 같이 인자의 임함도 그러하리라"},{"r":"마24:39","t":"홍수가 나서 저희를 다 멸하기까지 깨닫지 못하였으니 인자의 임함도 이와 같으리라"},{"r":"살전2:19","t":"우리의 소망이나 기쁨이나 자랑의 면류관이 무엇이냐  그의 강림하실 때 우리 주 예수 앞에 너희가 아니냐"},{"r":"마13:39","t":"가라지를 심은 원수는 {마귀}요 추수 때는 세상 끝이요 추숫군은 천사들이니"}],"마24:37":[{"r":"눅17:26,27","t":"노아의 때에 된 것과 같이 인자의 때에도 그러하리라"},{"r":"마24:27","t":"번개가 동편에서 나서 서편까지 번쩍임같이 인자의 임함도 그러하리라"}],"마24:38":[{"r":"창7:7~16","t":"노아가 아들들과 아내와 자부들과 함께 홍수를 피하여 방주에 들어갔고"},{"r":"마22:30","t":"복활 때에는 장가도 아니가고 시집도 아니가고 하늘에 있는 천사들과 같으니라"}],"마24:4":[{"r":"렘29:8","t":"만군의 여호와 이스라엘의 하나님이 이같이 말하노라 너희 중 선지자들에게와 복술에게 혹하지 말며 너희가 꾼 바 꿈도 신청하지 말라"},{"r":"엡5:6","t":"누구든지 헛된 말로 너희를 속이지 못하게 하라 이를 인하여 하나님의 진노가 부순종의 아들들에게 임하나니"},{"r":"골2:8","t":"누가 철학과 헛된 속임수로 너희를 노략할까 주의하라 이것이 사람의 유전과 세상의 초등 학문을 좇음이요 그리스도를 좇음이 아니니라"},{"r":"살후2:3","t":"누가 아무렇게 하여도 너희가 미혹하지 말라 먼저 배도하는 일이 있고 저 부법의 사람 곧 멸망의 아들이 나타나기 전에는 이르지 아니하리니"},{"r":"요일3:7","t":"자녀들아  아무도 너희를 미혹하지 못하게 하라 의를 행하는 자는 그의 의로우심과 같이 의롭고"}],"마24:5":[{"r":"마24:11","t":"거짓 선지자가 많이 일어나 많은 사람을 미혹하게 하겠으며"},{"r":"마24:24","t":"거짓 그리스도들과 거짓 선지자들이 일어나 큰 표적과 기사를 보이어 할 수만 있으면 택하신 자들도 미혹하게 하리라"},{"r":"렘14:14","t":"여호와께서 내게 이르시되 선지자들이 내 이름으로 거짓 예언을 하도다 나는 그들을 보내지 아니하였고 그들에게 명하거나 이르지 아니하였거늘 그들이 거짓 계시와 복술과 허탄한 것과 자기 마음의 속임으로 너희에게 예언하도다"},{"r":"렘14:14","t":"여호와께서 내게 이르시되 선지자들이 내 이름으로 거짓 예언을 하도다 나는 그들을 보내지 아니하였고 그들에게 명하거나 이르지 아니하였거늘 그들이 거짓 계시와 복술과 허탄한 것과 자기 마음의 속임으로 너희에게 예언하도다"},{"r":"요일2:18","t":"아이들아 이것이 마지막 때라 적그리스도가 이르겠다 함을 너희가 들은 것과 같이 지금도 많은 적그리스도가 일어났으니 이러므로 우리가 마지막 때인 줄 아노라"},{"r":"마1:17","t":"그런즉 모든 대 수가 아브라함부터 다윗까지 열 네 대요, 다윗부터 바벨론으로 이거할 때까지 열 네대요, 바벨론으로 이거한 후부터 그리스도까지 열 네 대러라"}],"마24:6":[{"r":"살후2:2","t":"혹 영으로나, 혹 말로나, 혹 우리에게서 받았다 하는 편지로나 주의 날이 이르렀다고 쉬 동심하거나 두려워하거나 하지 아니할 그것이라"},{"r":"계1:1","t":"예수 그리스도의 계시라 이는 하나님이 그에게 주사 반드시 속히 될 일을 그 종들에게 보이시려고 그 천사를 그 종 요한에게 보내어 지시하신 것이라"}],"마24:7":[{"r":"대하15:6","t":"이 나라가 저 나라와 서로 치고 이 성읍이 저 성읍과 또한 그러하여 피차 상한 바 되었나니 이는 하나님이 모든 고난으로 요란케 하셨음이니라"},{"r":"계6:4","t":"이에 붉은 다른 말이 나오더라 그 탄 자가 허락을 받아 땅에서 화평을 제하여 버리며 서로 죽이게 하고 또 큰 칼을 받았더라"},{"r":"사19:2","t":"그가 애굽인을 격동하사 애굽인을 치게 하시리니 그들이 각기 형제를 치며 각기 이웃을 칠 것이요 성읍이 성읍을 치며 나라가 나라를 칠 것이며"},{"r":"행11:28","t":"그 중에 아가보라 하는 한 사람이 일어나 성령으로 말하되 천하가 크게 흉년 들리라 하더니 글라우디오 때에 그렇게 되니라"},{"r":"계6:8","t":"내가 보매 청황색 말이 나오는데 그 탄 자의 이름은 사망이니 음부가 그 뒤를 따르더라 저희가 땅 사분 일의 권세를 얻어 검과 흉년과 사망과 땅의 짐승으로써 죽이더라"},{"r":"계6:12","t":"내가 보니 여섯째 인을 떼실 때에 큰 지진이 나며 해가 총담같이 검어지고 온 달이 피같이 되며"}],"마24:8":[{"r":"요16:21","t":"녀자가 해산하게 되면 그 때가 이르렀으므로 근심하나 아이를 낳으면 세상에 사람 난 기쁨을 인하여 그 고통을 다시 기억지 아니하느니라"},{"r":"행2:24","t":"하나님께서 사망의 고통을 풀어 살리셨으니 이는 그가 사망에게 매여 있을 수 없었음이라"},{"r":"롬8:22","t":"피조물이 다 이제까지 함께 탄식하며 함께 고통하는 것을 우리가 아나니"}],"마25:34":[{"r":"마25:40","t":"임금이 대답하여 가라사대 내가 진실로 너희에게 이르노니 너희가 여기 내 형제 중에 지극히 작은 자 하나에게 한 것이 곧 내게 한 것이니라 하시고"},{"r":"눅19:38","t":"가로되 찬송하리로다 주의 이름으로 오시는 왕이여  하늘에는 평화요 가장 높은 곳에는 영광이로다 하니"},{"r":"계17:14","t":"저희가 어린 양으로 더불어 싸우려니와 어린 양은 만주의 주시요 만왕의 왕이시므로 저희를 이기실 터이요 또 그와 함께 있는 자들 곧 부르심을 입고 빼내심을 얻고 진실한 자들은 이기리로다"},{"r":"계19:16","t":"그 옷과 그 다리에 이름 쓴 것이 있으니 만왕의 왕이요 만주의 주라 하였더라"},{"r":"사6:5","t":"그 때에 내가 말하되 화로다 나여, 망하게 되었도다 나는 입술이 불정한 사람이요 입술이 불정한 백성 중에 거하면서 만군의 여호와이신 왕을 뵈었음이로다"},{"r":"왕상2:19","t":"밧세바가 이에 아도니야를 위하여 말하려고 솔로몬왕에게 이르니 왕이 일어나 영접하여 절한 후에 다시 위에 앉고 그 모친을 위하여 자리를 베풀게 하고 그 우편에 앉게 하는지라"},{"r":"시45:9","t":"왕의 귀비 중에는 열왕의 딸이 있으며 왕후는 오빌의 김으로 꾸미고 왕의 우편에 서도다"},{"r":"시110:1","t":"(다윗의 시) 여호와께서 내 주에게 말씀하시기를 내가 네 원수로 네 발등상 되게 하기까지 너는 내 우편에 앉으라 하셨도다"},{"r":"시37:22","t":"주의 복을 받은 자는 땅을 차지하고 주의 저주를 받은 자는 끊어지리로다"},{"r":"사65:23","t":"그들의 수고가 헛되지 않겠고 그들의 생산한 것이 재난에 걸리지 아니하리니 그들은 여호와의 복된 자의 자손이요 그 소생도 그들과 함께 될 것임이라"},{"r":"마13:35","t":"이는 선지자로 말씀하신 바 내가 입을 열어 비유로 말하고 창세부터 감추인 것들을 드러내리라 함을 이루려 하심이니라"},{"r":"마20:23","t":"가라사대 너희가 과연 내 잔을 마시려니와 내 좌우편에 앉는 것은 나의 줄 것이 아니라 내 아버지께서 누구를 위하여 예비하셨든지 그들이 얻을 것이니라"},{"r":"고전2:9","t":"기록된 바 하나님이 자기를 사랑하는 자들을 위하여 예비하신 모든 것은 눈으로 보지 못하고 귀로도 듣지 못하고 사람의 마음으로도 생각지 못하였다 함과 같으니라"},{"r":"히11:16","t":"저희가 이제는 더 나은 본향을 사모하니 곧 하늘에 있는 것이라 그러므로 하나님이 저희 하나님이라 일컬음 받으심을 부끄러워 아니하시고 저희를 위하여 한 성을 예비하셨느니라"},{"r":"눅12:32","t":"적은 무리여 무서워 말라 너희 아버지께서 그 나라를 너희에게 주시기를 기뻐하시느니라"},{"r":"눅22:29","t":"내 아버지께서 나라를 내게 맡기신 것같이 나도 너희에게 맡겨"},{"r":"마19:29","t":"또 내 이름을 위하여 집이나 형제나 자매나 부모나 자식이나 전토를 버린 자마다 여러 배를 받고 또 영생을 상속하리라"},{"r":"벧전3:9","t":"악을 악으로, 욕을 욕으로 갚지 말고 도리어 복을 빌라 이를 위하여 너희가 부르심을 입었으니 이는 복을 유업으로 받게 하려 하심이라"},{"r":"계21:7","t":"이기는 자는 이것들을 유업으로 얻으리라 나는 저의 하나님이 되고 그는 내 아들이 되리라"},{"r":"롬8:17","t":"자녀이면 또한 후사 곧 하나님의 후사요 그리스도와 함께 한 후사니 우리가 그와 함께 영광을 받기 위하여 고난도 함께 받아야 될 것이니라"},{"r":"딛3:7","t":"우리로 저의 은혜를 힘입어 의롭다 하심을 얻어 영생의 소망을 따라 후사가 되게 하려 하심이라"},{"r":"히1:14","t":"모든 천사들은 부리는 영으로서 구원 얻을 후사들을 위하여 섬기라고 보내심이 아니뇨"},{"r":"약2:5","t":"내 사랑하는 형제들아 들을지어다 하나님이 세상에 대하여는 가난한 자를 택하사 믿음에 부요하게 하시고 또 자기를 사랑하는 자들에게 약속하신 나라를 유업으로 받게 아니하셨느냐"}],"마26:41":[{"r":"마6:13","t":"우리를 시험에 들게 하지 마옵시고 다만 악에서 구하옵소서 나라와 권세와 영광이 아버지께 영원히 있사옵나이다 아멘"},{"r":"벧전4:7","t":"만물의 마지막이 가까왔으니 그러므로 너희는 정신을 차리고 근신하여 기도하라"}],"마28:19":[{"r":"막16:15,16","t":"또 가라사대 너희는 온 천하에 다니며 만민에게 복음을 전파하라"},{"r":"눅24:47","t":"또 그의 이름으로 죄 사함을 얻게 하는 회개가 예루살렘으로부터 시작하여 모든 족속에게 전파될 것이 기록되었으니"},{"r":"마24:14","t":"이 천국 복음이 모든 민족에게 증거되기 위하여 온 세상에 전파되리니 그제야 끝이 오리라"},{"r":"막11:17","t":"이에 가르쳐 이르시되 기록된 바 내 집은 만민의 기도하는 집이라 칭함을 받으리라고 하지 아니하였느냐  너희는 강도의 굴혈을 만들었도다 하시매"},{"r":"롬1:5","t":"그로 말미암아 우리가 은혜와 사도의 직분을 받아 그 이름을 위하여 모든 이방인 중에서 믿어 순종케 하나니"},{"r":"마13:52","t":"예수께서 가라사대 그러므로 천국의 제자된 서기관마다 마치 새 것과 옛 것을 그 곳간에서 내어 오는 집 주인과 같으니라"},{"r":"고후13:13","t":"주 예수 그리스도의 은혜와 하나님의 사랑과 성령의 교통하심이 너희 무리와 함께 있을지어다"},{"r":"행8:16","t":"이는 아직 한 사람에게도 성령 내리신 일이 없고 오직 주 예수의 이름으로 세례만 받을 뿐이러라"}],"마28:20":[{"r":"행1:2","t":"그의 택하신 사도들에게 성령으로 명하시고 승천하신 날까지의 일을 기록하였노라"},{"r":"요14:15","t":"너희가 나를 사랑하면 나의 계명을 지키리라"},{"r":"마13:39","t":"가라지를 심은 원수는 {마귀}요 추수 때는 세상 끝이요 추숫군은 천사들이니"},{"r":"마1:23","t":"보라, 처녀가 잉태하여 아들을 낳을 것이요 그 이름은 임마누엘이라 하리라 하셨으니 이를 번역한즉 하나님이 우리와 함께 계시다함이라"},{"r":"마18:20","t":"두 세 사람이 내 이름으로 모인 곳에는 나도 그들 중에 있느니라"},{"r":"요12:26","t":"사람이 나를 섬기려면 나를 따르라  나 있는 곳에 나를 섬기는 자도 거기 있으리니 사람이 나를 섬기면 내 아버지께서 저를 귀히 여기시리라"},{"r":"요14:3","t":"가서 너희를 위하여 처소를 예비하면 내가 다시 와서 너희를 내게로 영접하여 나 있는 곳에 너희도 있게하리라"},{"r":"요17:24","t":"아버지여 내게 주신 자도 나 있는 곳에 나와 함께 있어 아버지께서 창세 전부터 나를 사랑하시므로 내게 주신 나의 영광을 저희로 보게 하시기를 원하옵니다"},{"r":"행18:10","t":"내가 너와 함께 있으매 아무 사람도 너를 대적하여 해롭게 할 자가 없을 것이니 이는 이 성중에 내 백성이 많음이라 하시더라"}],"마3:14":[{"r":"요13:6","t":"시몬 베드로에게 이르시니 가로되 주여, 주께서 내 발을 씻기시나이까"}],"마3:15":[{"r":"요9:4","t":"때가 아직 낮이매 나를 보내신 이의 일을 우리가 하여야 하리라 밤이 오리니 그 때는 아무도 일할 수 없느니라"}],"마3:16":[{"r":"행7:56","t":"말하되 보라 하늘이 열리고 인자가 하나님 우편에 서신 것을 보노라 한대"},{"r":"요1:32~33","t":"요한이 또 증거하여 가로되 내가 보매 성령이 비둘기같이 하늘로서 내려와서 그의 위에 머물렀더라"},{"r":"눅4:18","t":"주의 성령이 내게 임하셨으니 이는 가난한 자에게 복음을 전하게 하시려고 내게 기름을 부으시고 나를 보내사 포로된 자에게 자유를 눈먼 자에게 다시보게 함을 전파하며 눌린 자를 자유케 하고"},{"r":"눅4:21","t":"이에 예수께서 저희에게 말씀하시되 이 글이 오늘날 너희 귀에 응하였느니라 하시니"},{"r":"행10:38","t":"하나님이 나사렛 예수에게 성령과 능력을 기름붓듯 하셨으매 저가 두루 다니시며 착한 일을 행하시고 마귀에게 눌린 모든 자를 고치셨으니 이는 하나님이 함께 하셨음이라"}],"마3:17":[{"r":"요12:28","t":"아버지여 아버지의 이름을 영광스럽게 하옵소서 하시니 이에 하늘에서 소리가 나서 가로되 내가 이미 영광스럽게 하였고 또 다시 영광스럽게 하리라 하신대"},{"r":"마17:5","t":"말할 때에 홀연히 빛난 구름이 저희를 덮으며 구름 속에서 소리가 나서 가로되 이는 내 사랑하는 아들이요 내 기뻐하는 자니 너희는 저의 말을 들으라  하는지라"},{"r":"벧후1:17","t":"지극히 큰 영광 중에서 이러한 소리가 그에게 나기를 이는 내 사랑하는 아들이요 내 기뻐하는 자라 하실 때에 저가 하나님 아버지께 존귀와 영광을 받으셨느니라"},{"r":"시2:7","t":"내가 영을 전하노라 여호와께서 내게 이르시되 너는 내 아들이라 오늘날 내가 너를 낳았도다"},{"r":"사42:1","t":"내가 붙드는 나의 종, 내 마음에 기뻐하는 나의 택한 사람을 보라 내가 나의 신을 그에게 주었은즉 그가 이방에 공의를 베풀리라"},{"r":"엡1:6","t":"이는 그의 사랑하시는 자 안에서 우리에게 거저 주시는 바 그의 은혜의 영광을 찬미하게 하려는 것이라"},{"r":"골1:13","t":"그가 우리를 흑암의 권세에서 건져내사 그의 사랑의 아들의 나라로 옮기셨으니"},{"r":"요일5:9","t":"만일 우리가 사람들의 증거를 받을진대 하나님의 증거는 더욱 크도다 하나님의 증거는 이것이니 그 아들에 관하여 증거하신 것이니라"}],"마5:17":[{"r":"롬3:31","t":"그런즉 우리가 믿음으로 말미암아 률법을 폐하느뇨 그럴 수 없느니라 도리어 률법을 굳게 세우느니라"},{"r":"마7:12","t":"그러므로 무엇이든지 남에게 대접을 받고자 하는대로 너희도 남을 대접하라 이것이 률법이요 선지자니라"},{"r":"롬10:4","t":"그리스도는 모든 믿는 자에게 의를 이루기 위하여 률법의 마침이 되시니라"},{"r":"롬13:8","t":"피차 사랑의 빚 외에는 아무에게든지 아무 빚도 지지 말라 남을 사랑하는 자는 률법을 다 이루었느니라"},{"r":"갈3:24","t":"이같이 률법이 우리를 그리스도에게로 인도하는 몽학 선생이 되어 우리로 하여금 믿음으로 말미암아 의롭다 함을 얻게 하려 함이니라"}],"마5:18":[{"r":"눅16:17","t":"그러나 률법의 한 획이 떨어짐 보다 천지의 없어짐이 쉬우리라"},{"r":"마24:35","t":"천지는 없어지겠으나 내 말은 없어지지 아니하리라"}],"마5:5":[{"r":"시37:11","t":"오직 온유한 자는 땅을 차지하며 풍부한 화평으로 즐기리로다"}],"마6:33":[{"r":"마5:6","t":"의에 주리고 목마른 자는 복이 있나니 저희가 배부를 것임이요"},{"r":"마5:20","t":"내가 너희에게 이르노니 너희 의가 서기관과 바리새인보다 더 낫지 못하면 결단코 천국에 들어가지 못하리라"},{"r":"마6:10","t":"나라이 임하옵시며 뜻이 하늘에서 이룬 것같이 땅에서도 이루어지이다"},{"r":"왕상3:11~14","t":"이에 하나님이 저에게 이르시되 네가 이것을 구하도다 자기를 위하여 수도 구하지 아니하며, 부도 구하지 아니하며, 자기의 원수의 생명 멸하기도 구하지 아니하고 오직 송사를 듣고 분별하는 지혜를 구하였은즉"},{"r":"막10:29,30","t":"예수께서 가라사대 내가 진실로 너희에게 이르노니 나와 및 복음을 위하여 집이나, 형제나, 자매나, 어미나, 아비나, 자식이나, 전토를 버린 자는"},{"r":"딤전4:8","t":"육체의 련습은 약간의 유익이 있으나 경건은 범사에 유익하니 금생과 내생에 약속이 있느니라"},{"r":"벧전3:9","t":"악을 악으로, 욕을 욕으로 갚지 말고 도리어 복을 빌라 이를 위하여 너희가 부르심을 입었으니 이는 복을 유업으로 받게 하려 하심이라"}],"마6:6":[{"r":"왕하4:33","t":"들어가서는 문을 닫으니 두 사람 뿐이라 엘리사가 여호와께 기도하고"},{"r":"사26:20","t":"내 백성아 갈지어다 네 밀실에 들어가서 네 문을 닫고 분노가 지나기까지 잠간 숨을지어다"},{"r":"마6:4","t":"네 구제함이 은밀하게 하라 은밀한 중에 보시는 너의 아버지가 갚으시리라"},{"r":"마6:18","t":"이는 금식하는 자로 사람에게 보이지 않고 오직 은밀한 중에 계신 네 아버지께 보이게 하려 함이라 은밀한 중에 보시는 네 아버께서 갚으시리라"}],"마6:9":[{"r":"마6:9~13","t":"그러므로 너희는 이렇게 기도하라 하늘에 계신 우리 아버지여  이름이 거룩히 여김을 받으시오며"},{"r":"눅11:2~4","t":"예수께서 이르시되 너희는 기도할 때에 이렇게 하라 아버지여 이름이 거룩히 여김을 받으시오며 나라이 임하옵시며"},{"r":"마6:1","t":"사람에게 보이려고 그들 앞에서 너희 의를 행치 않도록 주의하라 그렇지 아니하면 하늘에 계신 너희 아버지께 상을 얻지 못하느니라"},{"r":"요17:6","t":"세상 중에서 내게 주신 사람들에게 내가 아버지의 이름을 나타내었나이다 저희는 아버지의 것이었는데 내게 주셨으며 저희는 아버지의 말씀을 지키었나이다"},{"r":"사29:23","t":"그 자손은 나의 손으로 그 가운데서 행한 것을 볼 때에 내 이름을 거룩하다 하며 야곱의 거룩한 자를 거룩하다 하며 이스라엘의 하나님을 경외할 것이며"},{"r":"눅1:49","t":"능하신 이가 큰 일을 내게 행하셨으니 그 이름이 거룩하시며"},{"r":"벧전3:15","t":"너희 마음에 그리스도를 주로 삼아 거룩하게 하고 너희 속에 있는 소망에 관한 리유를 묻는 자에게는 대답할 것을 항상 예비하되 온유와 두려움으로 하고"}],"마7:11":[{"r":"마12:34","t":"독사의 자식들아  너희는 악하니 어떻게 선한 말을 할 수 있느냐  이는 마음에 가득한 것을 입으로 말함이라"},{"r":"창6:5","t":"여호와께서 사람의 죄악이 세상에 관영함과 그 마음의 생각의 모든 계획이 항상 악할 뿐임을 보시고"},{"r":"창8:21","t":"여호와께서 그 향기를 흠향하시고 그 중심에 이르시되 내가 다시는 사람으로 인하여 땅을 저주하지 아니하리니 이는 사람의 마음의 계획하는 바가 어려서부터 악함이라 내가 전에 행한 것 같이 모든 생물을 멸하지 아니하리니"}],"마7:9":[{"r":"마4:3","t":"시험하는 자가 예수께 나아가서 가로되 네가 만일 하나님의 아들이어든 명하여 이 돌들이 떡덩이가 되게 하라"}],"막11:24":[{"r":"마7:7","t":"구하라  그러면 너희에게 주실 것이요 찾으라  그러면 찾을 것이요 문을 두드리라  그러면 너희에게 열릴 것이니"},{"r":"사65:24","t":"그들이 부르기 전에 내가 응답하겠고 그들이 말을 마치기 전에 내가 들을 것이며"},{"r":"마6:8","t":"그러므로 저희를 본받지 말라 구하기 전에 너희에게 있어야 할 것을 하나님 너희 아버지께서 아시느니라"}],"막2:27":[{"r":"출23:12","t":"너는 육일 동안에 네 일을 하고 제 칠일에는 쉬라 네 소와 나귀가 쉴 것이며 네 계집 종의 자식과 나그네가 숨을 돌리리라"},{"r":"신5:14","t":"제 칠일은 너의 하나님 여호와의 안식인즉 너나, 네 아들이나, 네 딸이나, 네 남종이나, 네 여종이나, 네 소나, 네 나귀나, 네 모든 육축이나, 네 문안에 유하는 객이라도 아무 일도 하지 말고 네 남종이나, 네 여종으로 너같이 안식하게 할지니라"},{"r":"골2:16","t":"그러므로 먹고 마시는 것과 절기나 월삭이나 안식일을 인하여 누구든지 너희를 평론하지 못하게 하라"}],"막2:28":[{"r":"막2:10","t":"그러나 인자가 땅에서 죄를 사하는 권세가 있는 줄을 너희로 알게 하려 하노라 하시고 중풍병자에게 말씀하시되"}],"말3:10":[{"r":"잠3:9,10","t":"네 재물과 네 소산물의 처음 익은 열매로 여호와를 공경하라"},{"r":"고후9:6~8","t":"이것이 곧 적게 심는 자는 적게 거두고 많이 심는 자는 많이 거둔다 하는 말이로다"},{"r":"창7:11","t":"노아 육백세 되던 해 이월 곧 그 달 십칠일이라 그 날에 큰 깊음의 샘들이 터지며 하늘의 창들이 열려"}],"말3:11":[{"r":"욜1:4","t":"팟종이가 남긴 것을 메뚜기가 먹고 메뚜기가 남긴 것을 늣이 먹고 늣이 남긴 것을 황충이 먹었도다"}],"말3:12":[{"r":"사62:4","t":"다시는 너를 버리운 자라 칭하지 아니하며 다시는 네 땅을 황무지라 칭하지 아니하고 오직, 너를 헵시바라 하며 네 땅을 쀼라라 하리니 이는 여호와께서 너를 기뻐하실 것이며 네 땅이 결혼한 바가 될 것임이라"},{"r":"습3:19","t":"그 때에 내가 너를 괴롭게 하는 자를 다 벌하고 저는 자를 구원하며 쫓겨난 자를 모으며 온 세상에서 수욕 받는 자로 칭찬과 명성을 얻게 하리라"}],"말3:16":[{"r":"신6:6,7","t":"오늘날 내가 네게 명하는 이 말씀을 너는 마음에 새기고"},{"r":"출32:32","t":"그러나 합의하시면 이제 그들의 죄를 사하시옵소서  그렇지 않사오면 원컨대 주의 기록하신 책에서 내 이름을 지워 버려주옵소서"}],"말4:1":[{"r":"살후1:7,8","t":"환난 받는 너희에게는 우리와 함께 안식으로 갚으시는 것이 하나님의 공의시니 주 예수께서 저의 능력의 천사들과 함께 하늘로부터 불꽃 중에 나타나실 때에"},{"r":"말4:5","t":"보라, 여호와의 크고 두려운 날이 이르기 전에 내가 선지 엘리야를 너희에게 보내리니"},{"r":"말3:2","t":"그의 임하는 날을 누가 능히 당하며 그의 나타나는 때에 누가 능히 서리요 그는 김을 연단하는 자의 불과 표백하는 자의 잿물과 같을 것이라"},{"r":"말3:15","t":"지금 우리는 교만한 자가 복되다 하며 악을 행하는 자가 창성하며 하나님을 시험하는 자가 화를 면한다 하노라 함이니라"},{"r":"사47:14","t":"보라, 그들은 초개 같아서 불에 타리니 그 불꽃의 세력에서 스스로 구원치 못할 것이라 이 불은 더웁게 할 숯불이 아니요 그 앞에 앉을 만한 불도 아니니라"},{"r":"마3:12","t":"손에 키를 들고 자기의 타작 마당을 정하게 하사 알곡은 모아 곡간에 들이고 쭉정이는 꺼지지 않는 불에 태우시리라"},{"r":"눅3:17","t":"손에 키를 들고 자기의 타작 마당을 정하게 하사 알곡은 모아 곡간에 들이고 쭉정이는 꺼지지 않는 불에 태우시리라"}],"말4:2":[{"r":"말3:16","t":"그 때에 여호와를 경외하는 자들이 피차에 말하매 여호와께서 그것을 분명히 들으시고 여호와를 경외하는 자와 그 이름을 존중히 생각하는 자를 위하여 여호와 앞에 있는 기념책에 기록하셨느니라"},{"r":"렘23:6","t":"그의 날에 유다는 구원을 얻겠고 이스라엘은 평안히 거할 것이며 그 이름은 여호와 우리의 의라 일컬음을 받으리라"},{"r":"시84:11","t":"여호와 하나님은 해요 방패시라 여호와께서 은혜와 영화를 주시며 정직히 행하는 자에게 좋은 것을 아끼지 아니하실 것임이니이다"},{"r":"눅1:78","t":"이는 우리 하나님의 긍휼을 인함이라 이로써 돋는 해가 위로부터 우리에게 임하여"},{"r":"요1:4","t":"그 안에 생명이 있었으니 이 생명은 사람들의 빛이라"},{"r":"요8:12","t":"예수께서 또 일러 가라사대 나는 세상의 빛이니 나를 따르는 자는 어두움에 다니지 아니하고 생명의 빛을 얻으리라"},{"r":"요9:5","t":"내가 세상에 있는 동안에는 세상의 빛이로라"},{"r":"요12:46","t":"나는 빛으로 세상에 왔나니 무릇 나를 믿는 자로 어두움에 거하지 않게 하려 함이로라"},{"r":"사53:5","t":"그가 찔림은 우리의 허물을 인함이요 그가 상함은 우리의 죄악을 인함이라 그가 징계를 받음으로 우리가 평화를 누리고 그가 채찍에 맞음으로 우리가 나음을 입었도다"},{"r":"렘50:11","t":"나의 산업을 노략하는 자여  너희가 즐거워하며 기뻐하며 곡식을 가는 송아지같이 뛰며 힘센 말같이 울도다"}],"말4:3":[{"r":"말3:17","t":"만군의 여호와가 이르노라 내가 나의 정한 날에 그들로 나의 특별한 소유를 삼을 것이요 또 사람이 자기를 섬기는 아들을 아낌 같이 내가 그들을 아끼리니"}],"민12:6":[{"r":"창46:2","t":"밤에 하나님이 리상 중에 이스라엘에게 나타나시고 불러 가라사대 야곱아, 야곱아, 하시는지라 야곱이 가로되 내가 여기 있나이다 하매"},{"r":"겔1:1","t":"제 삼십년 사월 오일에 내가 그발강 가 사로잡힌 자 중에 있더니 하늘이 열리며 하나님의 이상을 내게 보이시니"},{"r":"단8:2","t":"내가 이상을 보았는데 내가 그것을 볼 때에 내 몸은 엘람도 수산성에 있었고 내가 이상을 보기는 을래 강변에서니라"},{"r":"단10:8","t":"그러므로 나만 홀로 있어서 이 큰 이상을 볼 때에 내 몸에 힘이 빠졌고 나의 아름다운 빛이 변하여 썩은 듯하였고 나의 힘이 다 없어졌으나"},{"r":"단10:16","t":"인자와 같은 이가 있어 내 입술을 만진지라 내가 곧 입을 열어 내 앞에 섰는 자에게 말하여 가로되 내 주여 이 이상을 인하여 근심이 내게 더하므로 내가 힘이 없어졌나이다"},{"r":"눅1:11","t":"주의 사자가 저에게 나타나 향단 우편에 선지라"},{"r":"눅1:22","t":"그가 나와서 저희에게 말을 못하니 백성들이 그 성소 안에서 이상은 본 줄 알았더라 그가 형용으로 뜻을 표시하며 그냥 벙어리 대로 있더니"},{"r":"행10:11","t":"하늘이 열리며 한 그릇이 내려 오는 것을 보니 큰 보자기 같고 네 귀를 매어 땅에 드리웠더라"},{"r":"행22:17,18","t":"후에 내가 예루살렘으로 돌아와서 성전에서 기도할 때에 비몽사몽 간에"},{"r":"창20:6","t":"하나님이 꿈에 또 그에게 이르시되 네가 온전한 마음으로 이렇게 한 줄을 나도 알았으므로 너를 막아 내게 범죄하지 않게 하였나니 녀인에게 가까이 못하게 함이 이 까닭이니라"},{"r":"창31:10,11","t":"그 양떼가 새끼 밸 때에 내가 꿈에 눈을 들어 보니 양떼를 탄 수양은 다 얼룩무늬 있는것, 점 있는 것, 아롱진 것이었더라"},{"r":"왕상3:5","t":"기브온에서 밤에 여호와께서 솔로몬의 꿈에 나타나시니라 하나님이 이르시되 내가 네게 무엇을 줄꼬  너는 구하라"},{"r":"욥33:15","t":"사람이 침상에서 졸며 깊이 잠들 때에나 꿈에나 밤의 이상 중에"},{"r":"마1:20","t":"이 일을 생각할 때에 주의 사자가 현몽하여 가로되 다윗의 자손 요셉아 네 아내 마리아 데려오기를 무서워 말라 저에게 잉태된 자는 성령으로 된 것이라"},{"r":"마27:19","t":"총독이 재판 자리에 앉았을때에 그 아내가 사람을 보내어 가로되 저 옳은 사람에게 아무 상관도 하지 마옵소서 오늘 꿈에 내가 그 사람을 인하여 애를 많이 썼나이다 하더라"}],"벧전1:23":[{"r":"벧전1:3","t":"찬송하리로다 우리 주 예수 그리스도의 아버지 하나님이 그 많으신 긍휼대로 예수 그리스도의 죽은 자 가운데서 복활하심으로 말미암아 우리를 거듭나게 하사 산 소망이 있게 하시며"},{"r":"요3:3","t":"예수께서 대답하여 가라사대 진실로 진실로 네게 이르노니 사람이 거듭나지 아니하면 하나님 나라를 볼 수 없느니라"},{"r":"약1:18","t":"그가 그 조물 중에 우리로 한 첫 열매가 되게 하시려고 자기의 뜻을 좇아 진리의 말씀으로 우리를 낳으셨느니라"},{"r":"요1:13","t":"이는 혈통으로나 육정으로나 사람의 뜻으로 나지 아니하고 오직 하나님께로서 난 자들이니라"},{"r":"히4:12","t":"하나님의 말씀은 살았고 운동력이 있어 좌우에 날선 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 쪼개기까지 하며 또 마음의 생각과 뜻을 감찰하나니"},{"r":"단6:26","t":"내가 이제 조서를 내리노라 내 나라 관할 아래 있는 사람들은 다 다니엘의 하나님 앞에서 떨며 두려워할지니 그는 사시는 하나님이시요 영원히 변치 않으실 자시며 그 나라는 망하지 아니할 것이요 그 권세는 무궁할 것이며"}],"벧전1:8":[{"r":"요일4:20","t":"누구든지 하나님을 사랑하노라 하고 그 형제를 미워하면 이는 거짓말하는 자니 보는 바 그 형제를 사랑치 아니하는 자가 보지 못하는 바 하나님을 사랑할 수 없느니라"},{"r":"히11:27","t":"믿음으로 애굽을 떠나 임금의 노함을 무서워 아니하고 곧 보이지 아니하는 자를 보는 것같이 하여 참았으며"},{"r":"요20:29","t":"예수께서 가라사대 너는 나를 본 고로 믿느냐 보지 못하고 믿는 자들은 복되도다 하시니라"}],"벧전1:9":[{"r":"롬6:22","t":"그러나 이제는 너희가 죄에게서 해방되고 하나님께 종이 되어 거룩함에 이르는 열매를 얻었으니 이 마지막은 영생이라"}],"벧전2:21":[{"r":"벧전3:9","t":"악을 악으로, 욕을 욕으로 갚지 말고 도리어 복을 빌라 이를 위하여 너희가 부르심을 입었으니 이는 복을 유업으로 받게 하려 하심이라"},{"r":"행14:22","t":"제자들의 마음을 굳게 하여 이 믿음에 거하라 권하고 또 우리가 하나님 나라에 들어가려면 많은 환난을 겪어야 할 것이라 하고"},{"r":"마11:29","t":"나는 마음이 온유하고 겸손하니 나의 멍에를 메고 내게 배우라 그러면 너희 마음이 쉼을 얻으리니"}],"벧전3:21":[{"r":"벧전1:3","t":"찬송하리로다 우리 주 예수 그리스도의 아버지 하나님이 그 많으신 긍휼대로 예수 그리스도의 죽은 자 가운데서 복활하심으로 말미암아 우리를 거듭나게 하사 산 소망이 있게 하시며"},{"r":"막16:16","t":"믿고 세례를 받는 사람은 구원을 얻을 것이요 믿지 않는 사람은 정죄를 받으리라"},{"r":"행16:33","t":"밤 그 시에 간수가 저희를 데려다가 그 맞은 자리를 씻기고 자기와 그 권속이 다 세례를 받은 후"},{"r":"롬6:3~6","t":"무릇 그리스도 예수와 합하여 세례를 받은 우리는 그의 죽으심과 합하여 세례 받은 줄을 알지 못하느뇨"},{"r":"딛3:5","t":"우리를 구원하시되 우리의 행한 바 의로운 행위로 말미암지 아니하고 오직 그의 긍휼하심을 좇아 중생의 씻음과 성령의 새롭게 하심으로 하셨나니"},{"r":"롬10:10","t":"사람이 마음으로 믿어 의에 이르고 입으로 시인하여 구원에 이르느니라"},{"r":"벧전3:16","t":"선한 량심을 가지라 이는 그리스도 안에 있는 너희의 선행을 욕하는 자들로 그 비방하는 일에 부끄러움을 당하게 하려 함이라"}],"벧후2:6":[{"r":"창19:24","t":"여호와께서 하늘 곧 여호와에게로서 류황과 불을 비같이 소돔과 고모라에 내리사"},{"r":"유1:15","t":"이는 뭇사람을 심판하사 모든 경건치 않은 자의 경건치 않게 행한 모든 경건치 않은 일과 또 경건치 않은 죄인의 주께 거스려 한 모든 강퍅한 말을 인하여 저희를 정죄하려 하심이라 하였느니라"},{"r":"민26:10","t":"땅이 그 입을 열어서 그 무리와 고라를 삼키매 그들이 죽었고 당시에 불이 이백 오십명을 삼켜 징계가 되게 하였으나"}],"벧후3:10":[{"r":"마24:43","t":"너희가 알지 못함이니라 너희도 아는 바니 만일 집 주인이 도적이 어느 경점에 올 줄을 알았더면 깨어 있어 그 집을 뚫지 못하게 하였으리라"},{"r":"계6:14","t":"하늘은 종이 축이 말리는 것같이 떠나가고 각 산과 섬이 제 자리에서 옮기우매"},{"r":"계20:11","t":"또 내가 크고 흰 보좌와 그 위에 앉으신 자를 보니 땅과 하늘이 그 앞에서 피하여 간 데 없더라"},{"r":"계21:1","t":"또 내가 새 하늘과 새 땅을 보니 처음 하늘과 처음 땅이 없어졌고 바다도 다시 있지 않더라"},{"r":"마24:35","t":"천지는 없어지겠으나 내 말은 없어지지 아니하리라"},{"r":"사34:4","t":"하늘의 만상이 사라지고 하늘들이 두루마리 같이 말리되 그 만상의 쇠잔함이 포도나무 잎이 마름 같고 무화과나무 잎이 마름 같으리라"},{"r":"사24:19","t":"땅이 깨어지고 깨어지며 땅이 갈라지고 땅이 흔들리고 흔들리며"},{"r":"미1:4","t":"그 아래서 산들이 녹고 골짜기들이 갈라지기를 불 앞의 밀 같고 비탈로 쏟아지는 물 같을 것이니"},{"r":"나1:5","t":"그로 인하여 산들이 진동하며 작은 산들이 녹고 그의 앞에서는 땅 곧 세계와 그 가운데 거하는 자들이 솟아 오르는도다"}],"벧후3:11":[{"r":"벧전1:15","t":"오직 너희를 부르신 거룩한 자처럼 너희도 모든 행실에 거룩한 자가 되라"}],"벧후3:12":[{"r":"눅12:36","t":"너희는 마치 그 주인이 혼인 집에서 돌아와 문을 두드리면 곧 열어주려고 기다리는 사람과 같이 되라"},{"r":"고전1:7","t":"너희가 모든 은사에 불족함이 없이 우리 주 예수 그리스도의 나타나심을 기다림이라"},{"r":"살전1:10","t":"또 죽은 자들 가운데서 다시 살리신 그의 아들이 하늘로부터 강림하심을 기다린다고 말하니 이는 장래 노하심에서 우리를 건지시는 예수시니라"},{"r":"딛2:13","t":"복스러운 소망과 우리의 크신 하나님 구주 예수 그리스도의 영광이 나타나심을 기다리게 하셨으니"},{"r":"유1:21","t":"하나님의 사랑 안에서 자기를 지키며 영생에 이르도록 우리 주 예수 그리스도의 긍휼을 기다리라"},{"r":"벧후3:10","t":"그러나 주의 날이 도적같이 오리니 그 날에는 하늘이 큰 소리로 떠나가고 체질이 뜨거운 불에 풀어지고 땅과 그 중에 있는 모든 일이 드러나리로다"}],"벧후3:13":[{"r":"사60:21","t":"네 백성이 다 의롭게 되어 영영히 땅을 차지하리니 그들은 나의 심은 가지요 나의 손으로 만든 것으로서 나의 영광을 나타낼 것인즉"},{"r":"계21:27","t":"무엇이든지 속된 것이나 가증한 일 또는 거짓말하는 자는 결코 그리로 들어오지 못하되 오직 어린 양의 생명책에 기록된 자들 뿐이라"},{"r":"사65:17","t":"보라, 내가 새 하늘과 새 땅을 창조하나니 이전 것은 기억되거나 마음에 생각나지 아니할 것이라"},{"r":"사66:22","t":"나 여호와가 말하노라 나의 지을 새 하늘과 새 땅이 내 앞에 항상 있을 것 같이 너희 자손과 너희 이름이 항상 있으리라"},{"r":"계21:1","t":"또 내가 새 하늘과 새 땅을 보니 처음 하늘과 처음 땅이 없어졌고 바다도 다시 있지 않더라"}],"벧후3:16":[{"r":"롬8:19","t":"피조물의 고대하는 바는 하나님의 아들들의 나타나는 것이니"},{"r":"고전15:24","t":"그 후에는 나중이니 저가 모든 정사와 모든 권세와 능력을 멸하시고 나라를 아버지 하나님께 바칠 때라"},{"r":"살전4:15","t":"우리가 주의 말씀으로 너희에게 이것을 말하노니 주 강림하실 때까지 우리 살아 남아 있는 자도 자는 자보다 결단코 앞서지 못하리라"},{"r":"히5:11","t":"멜기세덱에 관하여는 우리가 할 말이 많으나 너희의 듣는 것이 둔하므로 해석하기 어려우니라"},{"r":"사28:13","t":"여호와께서 그들에게 말씀하시되 경계에 경계를 더하며 경계에 경계를 더하며 교훈에 교훈을 더하며 교훈에 교훈을 더하고 여기서도 조금, 저기서도 조금 하사 그들로 가다가 뒤로 넘어져 부러지며 걸리며 잡히게 하시리라"}],"벧후3:9":[{"r":"전8:11","t":"악한 일에 징벌이 속히 실행되지 않으므로 인생들이 악을 행하기에 마음이 담대하도다"},{"r":"계2:21","t":"또 내가 그에게 회개할 기회를 주었으되 그 음행을 회개하고자 아니하는도다"},{"r":"합2:3","t":"이 묵시는 정한 때가 있나니 그 종말이 속히 이르겠고 결코 거짓되지 아니하리라 비록 더딜찌라도 기다리라 지체되지 않고 정녕 응하리라"},{"r":"히10:37","t":"잠시 잠간 후면 오실 이가 오시리니 지체하지 아니하시리라"},{"r":"눅18:7","t":"하물며 하나님께서 그 밤낮 부르짖는 택하신 자들의 원한을 풀어 주지 아니하시겠느냐 저희에게 오래 참으시겠느냐"},{"r":"벧전3:20","t":"그들은 전에 노아의 날 방주 예비할 동안 하나님이 오래 참고 기다리실 때에 순종치 아니하던 자들이라 방주에서 물로 말미암아 구원을 얻은 자가 몇 명 뿐이니 겨우 여덟 명이라"},{"r":"겔18:23","t":"나 주 여호와가 말하노라 내가 어찌 악인의 죽는 것을 조금인들 기뻐하랴 그가 돌이켜 그 길에서 떠나서 사는 것을 어찌 기뻐하지 아니하겠느냐"},{"r":"겔18:32","t":"나 주 여호와가 말하노라 죽는 자의 죽는 것은 내가 기뻐하지 아니하노니 너희는 스스로 돌이키고 살지니라"},{"r":"겔33:11","t":"주 여호와의 말씀에 나의 삶을 두고 맹서하노니 나는 악인의 죽는 것을 기뻐하지 아니하고 악인이 그 길에서 돌이켜 떠나서 사는 것을 기뻐하노라 이스라엘 족속아 돌이키고 돌이키라 너희 악한 길에서 떠나라 어찌 죽고자 하느냐 하셨다 하라"},{"r":"딤전2:4","t":"하나님은 모든 사람이 구원을 받으며 진리를 아는데 이르기를 원하시느니라"}],"빌1:21":[{"r":"갈2:20","t":"내가 그리스도와 함께 십자가에 못 박혔나니 그런즉 이제는 내가 산 것이 아니요 오직 내 안에 그리스도께서 사신 것이라 이제 내가 육체 가운데 사는 것은 나를 사랑하사 나를 위하여 자기 몸을 버리신 하나님의 아들을 믿는 믿음 안에서 사는 것이라"}],"빌1:6":[{"r":"살전1:3","t":"너희의 믿음의 역사와 사랑의 수고와 우리 주 예수 그리스도에 대한 소망의 인내를 우리 하나님 아버지 앞에서 쉬지 않고 기억함이니"},{"r":"고전1:8","t":"주께서 너희를 우리 주 예수 그리스도의 날에 책망할 것이 없는 자로 끝까지 견고케 하시리라"},{"r":"시57:2","t":"내가 지극히 높으신 하나님께 부르짖음이여  곧 나를 위하여 모든 것을 이루시는 하나님께로다"},{"r":"시138:8","t":"여호와께서 내게 관계된 것을 완전케 하실지라 여호와여, 주의 인자하심이 영원하오니 주의 손으로 지으신 것을 버리지 마옵소서"},{"r":"살전5:24","t":"너희를 부르시는 이는 미쁘시니 그가 또한 이루시리라"}],"빌2:14":[{"r":"벧전4:9","t":"서로 대접하기를 원망 없이 하고"},{"r":"딤전2:8","t":"그러므로 각처에서 남자들이 분노와 다툼이 없이 거룩한 손을 들어 기도하기를 원하노라"}],"빌2:15":[{"r":"신32:5","t":"그들이 여호와를 향하여 악을 행하니 하나님의 자녀가 아니요 흠이 있는 사곡한 종류로다"},{"r":"벧전2:12","t":"너희가 이방인 중에서 행실을 선하게 가져 너희를 악행한다고 비방하는 자들로 하여금 너희 선한 일을 보고 권고하시는 날에 하나님께 영광을 돌리게 하려 함이라"},{"r":"유1:24","t":"능히 너희를 보호하사 거침이 없게 하시고 너희로 그 영광 앞에 흠이 없이 즐거움으로 서게 하실 자,"},{"r":"마5:45","t":"이같이 한즉 하늘에 계신 너희 아버지의 아들이 되리니 이는 하나님이 그 해를 악인과 선인에게 비취게 하시며 비를 의로운 자와 부의한 자에게 내리우심이니라"},{"r":"엡5:1","t":"그러므로 사랑을 입은 자녀같이 너희는 하나님을 본받는 자가 되고"},{"r":"마5:14","t":"너희는 세상의 빛이라  산 위에 있는 동리가 숨기우지 못할 것이요"},{"r":"마5:16","t":"이같이 너희 빛을 사람 앞에 비취게 하여 저희로 너희 착한 행실을 보고 하늘에 계신 너희 아버지께 영광을 돌리게 하라"},{"r":"딛2:10","t":"떼어 먹지 말고 오직 선한 충성을 다하게 하라 이는 범사에 우리 구주 하나님의 교훈을 빛나게 하려 함이라"}],"빌2:2":[{"r":"롬12:16","t":"서로 마음을 같이 하며 높은 데 마음을 두지 말고 도리어 낮은 데 처하며 스스로 지혜 있는 체 말라"}],"빌3:10":[{"r":"엡4:13","t":"우리가 다 하나님의 아들을 믿는 것과 아는 일에 하나가 되어 온전한 사람을 이루어 그리스도의 장성한 분량이 충만한 데까지 이르리니"},{"r":"롬1:4","t":"성결의 영으로는 죽은 가운데서 복활하여 능력으로 하나님의 아들로 인정되셨으니 곧 우리 주 예수 그리스도시니라"},{"r":"롬6:5","t":"만일 우리가 그의 죽으심을 본받아 련합한 자가 되었으면 또한 그의 복활을 본받아 련합한 자가 되리라"},{"r":"벧전4:13","t":"오직 너희가 그리스도의 고난에 참여하는 것으로 즐거워하라 이는 그의 영광을 나타내실 때에 너희로 즐거워하고 기뻐하게 하려함이라"},{"r":"고후1:5","t":"그리스도의 고난이 우리에게 넘친 것같이 우리의 위로도 그리스도로 말미암아 넘치는도다"}],"빌3:11":[{"r":"행26:7","t":"이 약속은 우리 열 두 지파가 밤낮으로 간절히 하나님을 받들어 섬김으로 얻기를 바라는 바인데 아그립바 왕이여 이 소망을 인하여 내가 유대인들에게 송사를 받는 것이니이다"}],"빌4:4":[{"r":"빌3:1","t":"종말로 나의 형제들아 주 안에서 기뻐하라  너희에게 같은 말을 쓰는 것이 내게는 수고로움이 없고 너희에게는 안전하니라"}],"빌4:6":[{"r":"마6:25","t":"그러므로 내가 너희에게 이르노니 목숨을 위하여 무엇을 먹을까  무엇을 마실까  몸을 위하여 무엇을 입을까  념려하지 말라 목숨이 음식보다 중하지 아니하며 몸이 의복보다 중하지 아니하냐"},{"r":"잠16:3","t":"너의 행사를 여호와께 맡기라 그리하면 너의 경영하는 것이 이루리라"},{"r":"롬1:8","t":"첫째는 내가 예수 그리스도로 말미암아 너희 모든 사람을 인하여 내 하나님께 감사함은 너희 믿음이 온 세상에 전파됨이로다"}],"빌4:7":[{"r":"엡3:19","t":"그 넓이와 길이와 높이와 깊이가 어떠함을 깨달아 하나님의 모든 충만하신 것으로 너희에게 충만하게 하시기를 구하노라"},{"r":"빌4:9","t":"너희는 내게 배우고 받고 듣고 본 바를 행하라 그리하면 평강의 하나님이 너희와 함께 계시리라"},{"r":"사26:3","t":"주께서 심지가 견고한 자를 평강에 평강으로 지키시리니 이는 그가 주를 의뢰함이니이다"},{"r":"골3:15","t":"그리스도의 평강이 너희 마음을 주장하게 하라 평강을 위하여 너희가 한 몸으로 부르심을 받았나니 또한 너희는 감사하는 자가 되라"},{"r":"요14:27","t":"평안을 너희에게 끼치노니 곧 나의 평안을 너희에게 주노라 내가 너희에게 주는 것은 세상이 주는 것 같지 아니하니라 너희는 마음에 근심도 말고 두려워하지도 말라"}],"사14:12":[{"r":"욥38:7","t":"그 때에 새벽 별들이 함께 노래하며 하나님의 아들들이 다 기쁘게 소리하였었느니라"},{"r":"사24:21","t":"그 날에 여호와께서 높은 데서 높은 군대를 벌하시며 땅에서 땅 왕들을 벌하시리니"},{"r":"사34:4","t":"하늘의 만상이 사라지고 하늘들이 두루마리 같이 말리되 그 만상의 쇠잔함이 포도나무 잎이 마름 같고 무화과나무 잎이 마름 같으리라"}],"사14:13":[{"r":"렘51:53","t":"가령 바벨론이 하늘까지 솟아 오른다 하자 그 성을 높이어 견고히 한다 하자 멸망시킬 자가 내게서부터 그들에게 임하리라 여호와의 말이니라"},{"r":"암9:2","t":"저희가 파고 음부로 들어갈찌라도 내 손이 거기서 취하여 낼 것이요 하늘로 올라갈찌라도 내가 거기서 취하여 내리울 것이며"},{"r":"마11:23","t":"가버나움아  네가 하늘에까지 높아지겠느냐  음부에까지 낮아지리라 네게서 행한 모든 권능을 소돔에서 행하였더면 그 성이 오늘날까지 있었으리라"},{"r":"눅10:15","t":"가버나움아 네가 하늘에까지 높아지겠느냐  음부에까지 낮아지리라"},{"r":"단5:22,23","t":"벨사살이여 왕은 그의 아들이 되어서 이것을 다 알고도 오히려 마음을 낮추지 아니하고"},{"r":"살후2:4","t":"저는 대적하는 자라 범사에 일컫는 하나님이나 숭배함을 받는 자 위에 뛰어나 자존하여 하나님 성전에 앉아 자기를 보여 하나님이라 하느니라"}],"사1:18":[{"r":"미6:2","t":"너희 산들과 땅의 견고한 지대들아 너희는 여호와의 쟁변을 들으라 여호와께서 자기 백성과 쟁변하시며 이스라엘과 변론하실 것이라"},{"r":"사43:26","t":"너는 나로 기억이 나게 하고 서로 변론하자 너는 네 일을 말하여 의를 나타내라"},{"r":"시51:7","t":"우슬초로 나를 정결케 하소서 내가 정하리이다 나를 씻기소서 내가 눈보다 희리이다"},{"r":"계7:14","t":"내가 가로되 내 주여 당신이 알리이다 하니 그가 나더러 이르되 이는 큰 환난에서 나오는 자들인데 어린 양의 피에 그 옷을 씻어 희게 하였느니라"}],"사25:9":[{"r":"사26:8","t":"여호와여  주의 심판하시는 길에서 우리가 주를 기다렸사오며 주의 이름 곧 주의 기념 이름을 우리 령혼이 사모하나이다"},{"r":"창49:18","t":"여호와여, 나는 주의 구원을 기다리나이다"},{"r":"시27:14","t":"너는 여호와를 바랄지어다  강하고 담대하며 여호와를 바랄지어다"},{"r":"시9:14","t":"그리하시면 내가 주의 찬송을 다 전할 것이요 딸 같은 시온의 문에서 주의 구원을 기뻐하리이다"}],"사28:13":[{"r":"사8:15","t":"많은 사람들이 그로 인하여 거칠 것이며 넘어질 것이며 부러질 것이며 걸릴 것이며 잡힐 것이니라"}],"사33:22":[{"r":"삿2:16","t":"여호와께서 사사를 세우사 노략하는 자의 손에서 그들을 건져내게 하셨으나"},{"r":"약4:12","t":"립법자와 재판자는 오직 하나이시니 능히 구원하기도 하시며 멸하기도 하시느니라 너는 누구관대 이웃을 판단하느냐"},{"r":"삼상12:6","t":"사무엘이 백성에게 이르되 모세와 아론을 세우시며 너희 열조를 애굽 땅에서 인도하여 내신 이는 여호와시니"},{"r":"시60:7","t":"길르앗이 내 것이요 므낫세도 내 것이며 에브라임은 내 머리의 보호자요 유다는 나의 홀이며"},{"r":"삼상12:13","t":"이제 너희의 구한 왕 너희의 택한 왕을 보라 여호와께서 너희 위에 왕을 세우셨느니라"}],"사44:24":[{"r":"사43:14","t":"너희의 구속자요 이스라엘의 거룩한 자 여호와가 말하노라 너희를 위하여 내가 바벨론에 보내어 모든 갈대아 사람으로 자기들의 연락하던 배를 타고 도망하여 내려가게 하리라"},{"r":"사44:2","t":"너를 지으며 너를 모태에서 조성하고 너를 도와줄 여호와가 말하노라 나의 종 야곱, 나의 택한 여수룬아 두려워 말라"},{"r":"사42:5","t":"하늘을 창조하여 펴시고 땅과 그 소산을 베푸시며 땅 위의 백성에게 호흡을 주시며 땅에 행하는 자에게 신을 주시는 하나님 여호와께서 이같이 말씀하시되"},{"r":"사42:5","t":"하늘을 창조하여 펴시고 땅과 그 소산을 베푸시며 땅 위의 백성에게 호흡을 주시며 땅에 행하는 자에게 신을 주시는 하나님 여호와께서 이같이 말씀하시되"},{"r":"사45:12","t":"내가 땅을 만들고 그 위에 사람을 창조하였으며 내가 친수로 하늘을 펴고 그 만상을 명하였노라"}],"사46:10":[{"r":"사41:26","t":"누가 처음부터 이 일을 우리에게 고하여 알게 하였느뇨 누가 이전부터 우리에게 고하여 이가 옳다고 말하게 하였느뇨 능히 고하는 자도 없고 보이는 자도 없고 너희 말을 듣는 자도 없도다"},{"r":"사44:26","t":"내 종의 말을 응하게 하며 내 사자의 모략을 성취하게 하며 예루살렘에 대하여는 이르기를 거기 사람이 살리라 하며 유다 성읍들에 대하여는 이르기를 중건될 것이라 내가 그 황폐한 곳들을 부구시키리라 하며"},{"r":"사44:28","t":"고레스에 대하여는 이르기를 그는 나의 목자라 나의 모든 기쁨을 성취하리라 하며 예루살렘에 대하여는 이르기를 중건되리라 하며 성전에 대하여는 이르기를 네 기초가 세움이 되리라 하는 자니라"},{"r":"시33:11","t":"여호와의 도모는 영영히 서고 그 심사는 대대에 이르리로다"},{"r":"잠19:21","t":"사람의 마음에는 많은 계획이 있어도 오직 여호와의 뜻이 완전히 서리라"},{"r":"히6:17","t":"하나님은 약속을 기업으로 받는 자들에게 그 뜻이 변치 아니함을 충분히 나타내시려고 그 일에 맹서로 보증하셨나니"}],"사50:4":[{"r":"출4:11","t":"여호와께서 그에게 이르시되 누가 사람의 입을 지었느뇨  누가 벙어리나 귀머거리나 눈 밝은 자나 소경이 되게 하였느뇨  나 여호와가 아니뇨"},{"r":"마11:28","t":"수고하고 무거운 짐진 자들아  다 내게로 오라 내가 너희를 쉬게 하리라"},{"r":"잠15:23","t":"사람은 그 입의 대답으로 말미암아 기쁨을 얻나니 때에 맞은 말이 얼마나 아름다운고"},{"r":"사40:1,2","t":"너희 하나님이 가라사대 너희는 위로하라 내 백성을 위로하라"}],"사51:7":[{"r":"시37:31","t":"그 마음에는 하나님의 법이 있으니 그 걸음에 실족함이 없으리로다"},{"r":"사51:1","t":"의를 좇으며 여호와를 찾아 구하는 너희는 나를 들을지어다 너희를 떠낸 반석과 너희를 파낸 우묵한 구덩이를 생각하여 보라"},{"r":"사41:14","t":"지렁이 같은 너 야곱아, 너희 이스라엘 사람들아 두려워 말라 나 여호와가 말하노니 내가 너를 도울 것이라 네 구속자는 이스라엘의 거룩한 자니라"},{"r":"마10:28","t":"몸은 죽여도 령혼은 능히 죽이지 못하는 자들을 두려워하지 말고 오직 몸과 령혼을 능히 지옥에 멸하시는 자를 두려워하라"}],"사55:11":[{"r":"사40:8","t":"풀은 마르고 꽃은 시드나 우리 하나님의 말씀은 영영히 서리라 하라"}],"사65:21":[{"r":"겔28:26","t":"그들이 그 가운데 평안히 거하여 집을 건축하며 포도원을 심고 그들의 사면에서 멸시하던 모든 자를 내가 국문할 때에 그들이 평안히 살며 나를 그 하나님 여호와인 줄 알리라"},{"r":"신28:30","t":"네가 녀자와 약혼하였으나 다른 사람이 그와 같이 잘 것이요 집을 건축하였으나 거기 거하지 못할 것이요 포도원을 심었으나 네가 그 과실을 쓰지 못할 것이며"}],"사65:22":[{"r":"시92:12~14","t":"의인은 종려나무 같이 번성하며 레바논의 백향목같이 발육하리로다"}],"사66:22":[{"r":"사65:17","t":"보라, 내가 새 하늘과 새 땅을 창조하나니 이전 것은 기억되거나 마음에 생각나지 아니할 것이라"},{"r":"사53:10","t":"여호와께서 그로 상함을 받게 하시기를 원하사 질고를 당케 하셨은즉 그 령혼을 속건 제물로 드리기에 이르면 그가 그 씨를 보게 되며 그 날은 길 것이요 또 그의 손으로 여호와의 뜻을 성취하리로다"},{"r":"시89:29","t":"또 그 후손을 영구케 하여 그 위를 하늘의 날과 같게 하리로다"}],"사66:23":[{"r":"슥14:16","t":"예루살렘을 치러 왔던 렬국 중에 남은 자가 해마다 올라와서 그 왕 만군의 여호와께 숭배하며 초막절을 지킬 것이라"},{"r":"시86:9","t":"주여, 주의 지으신 모든 열방이 와서 주의 앞에 경배하며 주의 이름에 영화를 돌리리이다"}],"사6:8":[{"r":"창1:26","t":"하나님이 가라사대 우리의 형상을 따라 우리의 모양대로 우리가 사람을 만들고 그로 바다의 고기와, 공중의 새와, 육축과, 온 땅과, 땅에 기는 모든 것을 다스리게 하자 하시고"}],"살전4:15":[{"r":"왕상13:17","t":"이는 여호와의 말씀이 내게 이르시기를 네가 거기서 떡도 먹지 말고 물도 마시지 말며 또 네가 오던 길로 돌아가지도 말라 하셨음이로라"},{"r":"살전2:19","t":"우리의 소망이나 기쁨이나 자랑의 면류관이 무엇이냐  그의 강림하실 때 우리 주 예수 앞에 너희가 아니냐"},{"r":"고전15:51","t":"보라  내가 너희에게 비밀을 말하노니 우리가 다 잠잘 것이 아니요 마지막 나팔에 순식간에 홀연히 다 변화하리니"}],"살전4:16":[{"r":"마16:27","t":"인자가 아버지의 영광으로 그 천사들과 함께 오리니 그 때에 각 사람의 행한 대로 갚으리라"},{"r":"욥2:11","t":"때에 욥의 친구 세 사람이 그에게 이 모든 재앙이 임하였다 함을 듣고 각각 자기 처소에서부터 이르렀으니 곧 데만 사람 엘리바스와 수아 사람 빌닷과 나아마 사람 소발이라 그들이 욥을 조문하고 위로하려 하여 상약하고 오더니"},{"r":"유1:9","t":"천사장 미가엘이 모세의 시체에 대하여 마귀와 다투어 변론할 때에 감히 훼방하는 판결을 쓰지 못하고 다만 말하되 주께서 너를 꾸짖으시기를 원하노라 하였거늘"},{"r":"마24:31","t":"저가 큰 나팔 소리와 함께 천사들을 보내리니 저희가 그 택하신 자들을 하늘 이 끝에서 저 끝까지 사방에서 모으리라"},{"r":"고전15:52","t":"나팔 소리가 나매 죽은 자들이 썩지 아니할 것으로 다시 살고 우리도 변화하리라"},{"r":"살후1:7","t":"환난 받는 너희에게는 우리와 함께 안식으로 갚으시는 것이 하나님의 공의시니 주 예수께서 저의 능력의 천사들과 함께 하늘로부터 불꽃 중에 나타나실 때에"},{"r":"고전15:23","t":"그러나 각각 자기 차례대로 되리니 먼저는 첫 열매인 그리스도요 다음에는 그리스도 강림하실 때에 그에게 붙은 자요"},{"r":"살후2:1","t":"형제들아  우리가 너희에게 구하는 것은 우리 주 예수 그리스도의 강림하심과 우리가 그 앞에 모임에 관하여"},{"r":"계14:13","t":"또 내가 들으니 하늘에서 음성이 나서 가로되 기록하라 자금 이후로 주 안에서 죽는 자들은 복이 있도다 하시매 성령이 가라사대 그러하다 저희 수고를 그치고 쉬리니 이는 저희의 행한 일이 따름이라 하시더라"}],"살전4:17":[{"r":"단7:13","t":"내가 또 밤 이상 중에 보았는데 인자 같은 이가 하늘 구름을 타고 와서 옛적부터 항상 계신 자에게 나아와 그 앞에 인도되매"},{"r":"행1:9","t":"이 말씀을 마치시고 저희 보는데서 올리워 가시니 구름이 저를 가리워 보이지 않게 하더라"},{"r":"계11:12","t":"하늘로부터 큰 음성이 있어 이리로 올라오라 함을 저희가 듣고 구름을 타고 하늘로 올라가니 저희 원수들도 구경하더라"},{"r":"고후12:2","t":"내가 그리스도 안에 있는 한 사람을 아노니 십 사년 전에 그가 세째 하늘에 이끌려 간 자라 그가 몸 안에 있었는지 몸 밖에 있었는지 나는 모르거니와 하나님은 아시느니라"},{"r":"요12:26","t":"사람이 나를 섬기려면 나를 따르라  나 있는 곳에 나를 섬기는 자도 거기 있으리니 사람이 나를 섬기면 내 아버지께서 저를 귀히 여기시리라"}],"살전5:1":[{"r":"단2:21","t":"그는 때와 기한을 변하시며 왕들을 폐하시고 왕들을 세우시며 지혜자에게 지혜를 주시고 지식자에게 총명을 주시는도다"},{"r":"행1:7","t":"가라사대 때와 기한은 아버지께서 자기의 권한에 두셨으니 너희의 알 바 아니요"},{"r":"살전4:9","t":"형제 사랑에 관하여는 너희에게 쓸 것이 없음은 너희가 친히 하나님의 가르치심을 받아 서로 사랑함이라"}],"살전5:17":[{"r":"눅18:1","t":"항상 기도하고 락망치 말아야 될 것을 저희에게 비유로 하여"}],"살전5:18":[{"r":"엡5:20","t":"범사에 우리 주 예수 그리스도의 이름으로 항상 아버지 하나님께 감사하며"}],"살전5:2":[{"r":"살후2:2","t":"혹 영으로나, 혹 말로나, 혹 우리에게서 받았다 하는 편지로나 주의 날이 이르렀다고 쉬 동심하거나 두려워하거나 하지 아니할 그것이라"},{"r":"마24:43","t":"너희가 알지 못함이니라 너희도 아는 바니 만일 집 주인이 도적이 어느 경점에 올 줄을 알았더면 깨어 있어 그 집을 뚫지 못하게 하였으리라"},{"r":"눅17:24","t":"번개가 하늘 아래 이편에서 번뜻하여 하늘 아래 저편까지 비췸같이 인자도 자기 날에 그러하리라"}],"살전5:23":[{"r":"롬15:33","t":"평강의 하나님께서 너희 모든 사람과 함께 계실지어다  아멘"},{"r":"출31:13","t":"너는 이스라엘 자손에게 고하여 이르기를 너희는 나의 안식일을 지키라  이는 나와 너희 사이에 너희 대대의 표징이니 나는 너희를 거룩하게 하는 여호와인 줄 너희로 알게 함이라"},{"r":"요17:17","t":"저희를 진리로 거룩하게 하옵소서  아버지의 말씀은 진리니이다"},{"r":"눅1:46,47","t":"마리아가 가로되 내 령혼이 주를 찬양하며"},{"r":"히4:12","t":"하나님의 말씀은 살았고 운동력이 있어 좌우에 날선 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 쪼개기까지 하며 또 마음의 생각과 뜻을 감찰하나니"},{"r":"고전14:14","t":"내가 만일 방언으로 기도하면 나의 영이 기도하거니와 나의 마음은 열매를 맺히지 못하리라"},{"r":"살전2:19","t":"우리의 소망이나 기쁨이나 자랑의 면류관이 무엇이냐  그의 강림하실 때 우리 주 예수 앞에 너희가 아니냐"},{"r":"벧후3:14","t":"그러므로 사랑하는 자들아  너희가 이것을 바라보나니 주 앞에서 점도 없고 흠도 없이 평강 가운데서 나타나기를 힘쓰라"},{"r":"유1:1","t":"예수 그리스도의 종이요 야고보의 형제인 유다는 부르심을 입은 자 곧 하나님 아버지 안에서 사랑을 얻고 예수 그리스도를 위하여 지키심을 입은 자들에게 편지하노라"}],"살전5:3":[{"r":"사13:8","t":"그들이 놀라며 괴로움과 슬픔에 잡혀서 임산한 녀자같이 고통하며 서로 보고 놀라며 얼굴은 불꽃 같으리로다"},{"r":"눅21:34","t":"너희는 스스로 조심하라  그렇지 않으면 방탕함과 술취함과 생활의 념려로 마음이 둔하여지고 뜻밖에 그 날이 덫과 같이 너희에게 임하리라"},{"r":"시35:8","t":"멸망으로 졸지에 저에게 임하게 하시며 그 숨긴 그물에 스스로 잡히게 하시며 멸망 중에 떨어지게 하소서"},{"r":"눅17:26~30","t":"노아의 때에 된 것과 같이 인자의 때에도 그러하리라"},{"r":"살후1:9","t":"이런 자들이 주의 얼굴과 그의 힘의 영광을 떠나 영원한 멸망의 형벌을 받으리로다"}],"살전5:4":[{"r":"요일2:8","t":"다시 내가 너희에게 새 계명을 쓰노니 저에게와 너희에게도 참된 것이라 이는 어두움이 지나가고 참 빛이 벌써 비췸이니라"}],"살전5:5":[{"r":"눅16:8","t":"주인이 옳지 않은 청지기가 일을 지혜 있게 하였으므로 칭찬하였으니 이 세대의 아들들이 자기 시대에 있어서는 빛의 아들들보다 더 지혜로움이니라"}],"살후1:10":[{"r":"고전3:13","t":"각각 공력이 나타날 터인데 그 날이 공력을 밝히리니 이는 불로 나타내고 그 불이 각 사람의 공력이 어떠한 것을 시험할 것임이니라"},{"r":"살전1:10","t":"또 죽은 자들 가운데서 다시 살리신 그의 아들이 하늘로부터 강림하심을 기다린다고 말하니 이는 장래 노하심에서 우리를 건지시는 예수시니라"},{"r":"시89:7","t":"하나님은 거룩한 자의 회중에서 심히 엄위하시오며 둘러 있는 모든 자 위에 더욱 두려워할 자시니이다"},{"r":"사49:3","t":"내게 이르시되 너는 나의 종이요 내 영광을 나타낼 이스라엘이라 하셨느니라"},{"r":"요17:10","t":"내 것은 다 아버지의 것이요 아버지의 것은 내 것이온데 내가 저희로 말미암아 영광을 받았나이다"},{"r":"고전1:6","t":"그리스도의 증거가 너희 중에 견고케 되어"},{"r":"살전2:1","t":"형제들아 우리가 너희 가운데 들어감이 헛되지 않은 줄을 너희가 친히 아나니"},{"r":"살전2:13","t":"이러므로 우리가 하나님께 쉬지 않고 감사함은 너희가 우리에게 들은 바 하나님의 말씀을 받을 때에 사람의 말로 아니하고 하나님의 말씀으로 받음이니 진실로 그러하다 이 말씀이 또한 너희 믿는 자 속에서 역사하느니라"},{"r":"딤전3:16","t":"크도다  경건의 비밀이여 그렇지 않다 하는 이 없도다 그는 육신으로 나타난 바 되시고 영으로 의롭다 하심을 입으시고 천사들에게 보이시고 만국에서 전파되시고 세상에서 믿은 바 되시고 영광가운데서 올리우셨음이니라"}],"살후1:5":[{"r":"빌1:28","t":"아무 일에든지 대적하는 자를 인하여 두려워하지 아니하는 이 일을 듣고자 함이라 이것이 저희에게는 멸망의 빙거요 너희에게는 구원의 빙거니 이는 하나님께로부터 난 것이니라"},{"r":"행14:22","t":"제자들의 마음을 굳게 하여 이 믿음에 거하라 권하고 또 우리가 하나님 나라에 들어가려면 많은 환난을 겪어야 할 것이라 하고"},{"r":"눅20:35","t":"저 세상과 및 죽은 자 가운데서 복활함을 얻기에 합당히 여김을 입은 자들은 장가가고 시집가는 일이 없으며"}],"살후1:6":[{"r":"출23:22","t":"네가 그 목소리를 잘 청종하고 나의 모든 말대로 행하면 내가 네 원수에게 원수가 되고 네 대적에게 대적이 될지라"},{"r":"욥3:4","t":"그 날이 캄캄하였었더라면, 하나님이 위에서 돌아보지 마셨더라면, 빛도 그 날을 비취지 말았었더라면,"},{"r":"욥3:7","t":"그 밤이 적막하였었더라면, 그 가운데서 즐거운 소리가 일어나지 말았었더라면,"}],"살후1:7":[{"r":"계6:11","t":"각각 저희에게 흰 두루마기를 주시며 가라사대 아직 잠시 동안 쉬되 저희 동무 종들과 형제들도 자기처럼 죽임을 받아 그 수가 차기까지 하라 하시더라"},{"r":"계11:18","t":"이방들이 분노하매 주의 진노가 임하여 죽은 자를 심판하시며 종 선지자들과 성도들과 또 무론대소하고 주의 이름을 경외하는 자들에게 상 주시며 또 땅을 망하게 하는 자들을 멸망시키실 때로소이다 하더라"},{"r":"계14:13","t":"또 내가 들으니 하늘에서 음성이 나서 가로되 기록하라 자금 이후로 주 안에서 죽는 자들은 복이 있도다 하시매 성령이 가라사대 그러하다 저희 수고를 그치고 쉬리니 이는 저희의 행한 일이 따름이라 하시더라"},{"r":"계6:10","t":"큰 소리로 불러 가로되 거룩하고 참되신 대주재여 땅에 거하는 자들을 심판하여 우리 피를 신원하여 주지 아니하시기를 어느 때까지 하시려나이까 하니"},{"r":"유1:14","t":"아담의 칠세 손 에녹이 사람들에게 대하여도 예언하여 이르되 보라, 주께서 그 수만의 거룩한 자와 함께 임하셨나니"},{"r":"사66:15,16","t":"보라, 여호와께서 불에 옹위되어 강림하시리니 그 수레들은 회리바람 같으리로다 그가 혁혁한 위세로 노를 베푸시며 맹렬한 화염으로 견책하실 것이라"},{"r":"마25:41","t":"또 왼편에 있는 자들에게 이르시되 저주를 받은 자들아  나를 떠나 {마귀}와 그 사자들을 위하여 예비된 영영한 불에 들어가라"},{"r":"고전3:13","t":"각각 공력이 나타날 터인데 그 날이 공력을 밝히리니 이는 불로 나타내고 그 불이 각 사람의 공력이 어떠한 것을 시험할 것임이니라"},{"r":"히10:27","t":"오직 무서운 마음으로 심판을 기다리는 것과 대적하는 자를 소멸할 맹렬한 불만 있으리라"},{"r":"히12:29","t":"우리 하나님은 소멸하는 불이심이니라"},{"r":"벧후3:7","t":"이제 하늘과 땅은 그 동일한 말씀으로 불사르기 위하여 간수하신 바 되어 경건치 아니한 사람들의 심판과 멸망의 날까지 보존하여 두신 것이니라"},{"r":"계21:8","t":"그러나 두려워하는 자들과, 믿지 아니하는 자들과, 흉악한 자들과, 살인자들과, 행음자들과, 술객들과, 우상 숭배자들과, 모든 거짓말 하는 자들은 불과 류황으로 타는 못에 참여하리니 이것이 둘째 사망이라"},{"r":"말4:1","t":"만군의 여호와가 이르노라 보라, 극렬한 풀무불 같은 날이 이르리니 교만한 자와 악을 행하는 자는 다 초개 같을 것이라 그 이르는 날이 그들을 살라 그 뿌리와 가지를 남기지 아니할 것이로되"},{"r":"눅17:30","t":"인자의 나타나는 날에도 이러하리라"}],"살후1:8":[{"r":"갈4:8","t":"그러나 너희가 그 때에는 하나님을 알지 못하여 본질상 하나님이 아닌 자들에게 종노릇하였더니"},{"r":"롬2:8","t":"오직 당을 지어 진리를 좇지 아니하고 부의를 좇는 자에게는 노와 분으로 하시리라"}],"살후1:9":[{"r":"사2:10","t":"너희는 바위 틈에 들어가며 진토에 숨어 여호와의 위엄과 그 광대하심의 영광을 피하라"},{"r":"사2:19","t":"사람들이 암혈과 토굴로 들어가서 여호와께서 일어나사 땅을 진동시키는 그의 위엄과 그 광대하심의 영광을 피할 것이라"},{"r":"사2:21","t":"암혈과 험악한 바위틈에 들어가서 여호와께서 일어나사 땅을 진동시키시는 그의 위엄과 그 광대하심의 영광을 피하리라"},{"r":"살후2:8","t":"그 때에 부법한 자가 나타나리니 주 예수께서 그 입의 기운으로 저를 죽이시고 강림하여 나타나심으로 폐하시리라"},{"r":"빌3:19","t":"저희의 마침은 멸망이요 저희의 신은 배요 그 영광은 저희의 부끄러움에 있고 땅의 일을 생각하는 자라"},{"r":"살전5:3","t":"저희가 평안하다, 안전하다 할 그 때에 잉태된 녀자에게 해산 고통이 이름과 같이 멸망이 홀연히 저희에게 이르리니 결단코 피하지 못하리라"}],"살후2:10":[{"r":"고전1:18","t":"십자가의 도가 멸망하는 자들에게는 미련한 것이요 구원을 얻는 우리에게는 하나님의 능력이라"}],"살후2:3":[{"r":"엡5:6","t":"누구든지 헛된 말로 너희를 속이지 못하게 하라 이를 인하여 하나님의 진노가 부순종의 아들들에게 임하나니"},{"r":"딤전4:1","t":"그러나 성령이 밝히 말씀하시기를 후일에 어떤 사람들이 믿음에서 떠나 미혹케 하는 영과 귀신의 가르침을 좇으리라 하셨으니"},{"r":"살후2:8","t":"그 때에 부법한 자가 나타나리니 주 예수께서 그 입의 기운으로 저를 죽이시고 강림하여 나타나심으로 폐하시리라"},{"r":"단7:25","t":"그가 장차 말로 지극히 높으신 자를 대적하며 또 지극히 높으신 자의 성도를 괴롭게 할 것이며 그가 또 때와 법을 변개코자 할 것이며 성도는 그의 손에 붙인 바 되어 한 때와 두 때와 반 때를 지내리라"},{"r":"단8:25","t":"그가 꾀를 베풀어 제 손으로 궤휼을 이루고 마음에 스스로 큰 체하며 또 평화한 때에 많은 무리를 멸하며 또 스스로 서서 만왕의 왕을 대적할 것이나 그가 사람의 손을 말미암지 않고 깨어지리라"},{"r":"단11:36","t":"이 왕이 자기 뜻대로 행하며 스스로 높여 모든 신보다 크다 하며 비상한 말로 신들의 신을 대적하며 형통하기를 분노하심이 쉴 때까지 하리니 이는 그 작정된 일이 반드시 이룰 것임이니라"},{"r":"계13:5,6","t":"또 짐승이 큰 말과 참람된 말하는 입을 받고 또 마흔 두 달 일할 권세를 받으니라"},{"r":"요17:12","t":"내가 저희와 함께 있을 때에 내게 주신 아버지의 이름으로 저희를 보전하와 지키었나이다 그 중에 하나도 멸망치 않고 오직 멸망의 자식뿐이오니 이는 성경을 응하게 함이니이다"},{"r":"마23:15","t":"화 있을진저  외식하는 서기관들과 바리새인들이여 너희는 교인 하나를 얻기 위하여 바다와 륙지를 두루 다니다가 생기면 너희보다 배나 더 지옥 자식이 되게 하는도다"}],"살후2:4":[{"r":"행17:23","t":"내가 두루 다니며 너희의 위하는 것들을 보다가 알지 못하는 신에게라고 새긴 단도 보았으니 그런즉 너희가 알지 못하고 위하는 그것을 내가 너희에게 알게 하리라"},{"r":"사14:14","t":"가장 높은 구름에 올라 지극히 높은 자와 비기리라 하도다"},{"r":"겔28:2","t":"인자야 너는 두로 왕에게 이르기를 주 여호와의 말씀에 네 마음이 교만하여 말하기를 나는 신이라 내가 하나님의 자리 곧 바다 중심에 앉았다 하도다 네 마음이 하나님의 마음 같은 체 할지라도 너는 사람이요 신이 아니어늘"}],"살후2:9":[{"r":"계3:14","t":"라오디게아 교회의 사자에게 편지하기를 아멘이시요 충성되고 참된 증인이시요 하나님의 창조의 근본이신 이가 가라사대"},{"r":"마24:24","t":"거짓 그리스도들과 거짓 선지자들이 일어나 큰 표적과 기사를 보이어 할 수만 있으면 택하신 자들도 미혹하게 하리라"}],"삼하23:1":[{"r":"삼하7:8,9","t":"그러므로 이제 내 종 다윗에게 이처럼 말하라 만군의 여호와께서 이처럼 말씀하시기를 내가 너를 목장 곧 양을 따르는 데서 취하여 내 백성 이스라엘의 주권자를 삼고"},{"r":"시78:70,71","t":"또 그 종 다윗을 택하시되 양의 우리에서 취하시며"}],"삼하23:2":[{"r":"벧후1:21","t":"예언은 언제든지 사람의 뜻으로 낸 것이 아니요 오직 성령의 감동하심을 입은 사람들이 하나님께 받아 말한 것임이니라"}],"수21:43":[{"r":"창13:15","t":"보이는 땅을 내가 너와 네 자손에게 주리니 영원히 이르리라"},{"r":"창15:18","t":"그 날에 여호와께서 아브람으로 더불어 언약을 세워 가라사대 내가 이 땅을 애굽강에서부터 그 큰 강 유브라데까지 네 자손에게 주노니"},{"r":"창26:3","t":"이 땅에 유하면 내가 너와 함께 있어 네게 주고 내가 이 모든 땅을 너와 네 자손에게 주리라 내가 네 아비 아브라함에게 맹서한 것을 이루어"},{"r":"창28:4","t":"아브라함에게 허락하신 복을 네게 주시되 너와 너와 함께 네 자손에게 주사 너로 하나님이 아브라함에게 주신 땅 곧 너의 우거하는 땅을 유업으로 받게 하시기를 원하노라"},{"r":"창28:13","t":"또 본즉 여호와께서 그 위에 서서 가라사대 나는 여호와니 너의 조부 아브라함의 하나님이요 이삭의 하나님이라  너 누운 땅을 내가 너와 네 자손에게 주리니"}],"수21:44":[{"r":"수11:23","t":"이와 같이 여호수아가 여호와께서 모세에게 이르신 말씀대로 그 온 땅을 취하여 이스라엘 지파의 구별을 따라 기업으로 주었더라 그 땅에 전쟁이 그쳤더라"},{"r":"수2:24","t":"또 여호수아에게 이르되 진실로 여호와께서 그 온 땅을 우리 손에 붙이셨으므로 그 땅의 모든 거민이 우리 앞에서 간담이 녹더이다"},{"r":"신7:24","t":"그들의 왕들을 네 손에 붙이시리니 너는 그 이름을 천하에서 제하여 버리라 너를 당할 자가 없이 네가 필경은 그들을 진멸하리라 너는 그들의 조각한 신상들을 불사르고 그것에 입힌 은이나 김을 탐내지 말며 취하지 말라 두렵건대 네가 그것으로 인하여 올무에 들까 하노니 이는 네 하나님 여호와의 가증히 여기시는 것임이니라"},{"r":"수10:8","t":"때에 여호와께서 여호수아에게 이르시되 그들을 두려워 말라  내가 그들을 네 손에 붙였으니 그들의 한 사람도 너를 당할 자 없으리라 하신지라"},{"r":"수23:9","t":"대저 여호와께서 강대한 나라들을 너희 앞에서 쫓아내셨으므로 오늘날까지 너희를 당한 자가 하나도 없었느니라"}],"수21:45":[{"r":"수23:14,15","t":"보라, 나는 오늘날 온 세상이 가는 길로 가려니와 너희 하나님 여호와께서 너희에게 대하여 말씀하신 모든 선한 일이 하나도 틀리지 아니하고 다 너희에게 응하여 그 중에 하나도 어김이 없음을 너희 모든 사람의 마음과 뜻에 아는 바라"}],"스7:10":[{"r":"스7:25","t":"에스라여  너는 네 손에 있는 네 하나님의 지혜를 따라 네 하나님의 률법을 아는 자로 유사와 재판관을 삼아 강 서편 모든 백성을 재판하게 하고 그 알지 못하는 자는 너희가 가르치라"},{"r":"신33:10","t":"주의 법도를 야곱에게, 주의 률법을 이스라엘에게 가르치며 주 앞에 분향하고 온전한 번제를 주의 단 위에 드리리로다"},{"r":"대하17:7","t":"저가 위에 있은지 삼년에 그 방백 벤하일과, 오바댜와, 스가랴와, 느다넬과, 미가야를 보내어 유다 여러 성읍에 가서 가르치게 하고"},{"r":"말2:7","t":"대저 제사장의 입술은 지식을 지켜야 하겠고 사람들이 그 입에서 률법을 구하게 되어야 할 것이니 제사장은 만군의 여호와의 사자가 됨이어늘"},{"r":"마23:2,3","t":"서기관들과 바리새인들이 모세의 자리에 앉았으니"},{"r":"느8:1~8","t":"이스라엘 자손이 그 본성에 거하였더니 칠월에 이르러는 모든 백성이 일제히 수문 앞 광장에 모여 학사 에스라에게 여호와께서 이스라엘에게 명하신 모세의 률법책을 가지고 오기를 청하매"}],"스7:12":[{"r":"겔26:7","t":"나 주 여호와가 말하노라 내가 열왕의 왕 곧 바벨론 왕 느부갓네살로 북방에서 말과 병거와 기병과 군대와 백성의 큰 무리를 거느리고 와서 두로를 치게 할 때에"},{"r":"단2:37","t":"왕이여 왕은 열왕의 왕이시라 하늘의 하나님이 나라와 권세와 능력과 영광을 왕에게 주셨고"},{"r":"스7:6","t":"이 에스라가 바벨론에서 올라왔으니 저는 이스라엘 하나님 여호와께서 주신 바 모세의 률법에 익숙한 학사로서 그 하나님 여호와의 도우심을 입으므로 왕에게 구하는 것은 다 받는 자더니"}],"스7:13":[{"r":"스4:10,11","t":"기타 백성 곧 존귀한 오스납발이 사마리아 성과 강 서편 다른 땅에 옮겨 둔 자들과 함께 고한다 하였더라"},{"r":"스4:17","t":"왕이 방백 르훔과 서기관 심새와 사마리아에 거한 저희 동료와 강 서편 다른 땅 백성에게 조서를 내리니 일렀으되 너희는 평안할지어다"},{"r":"스6:8","t":"내가 또 조서를 내려서 하나님의 이 전을 건축함에 대하여 너희가 유다 사람의 장로들에게 행할 것을 알게 하노니 왕의 재산 곧 강 서편 세김 중에서 그 경비를 이 사람들에게 신속히 주어 저희로 지체치 않게 하라"}],"스7:9":[{"r":"스7:6","t":"이 에스라가 바벨론에서 올라왔으니 저는 이스라엘 하나님 여호와께서 주신 바 모세의 률법에 익숙한 학사로서 그 하나님 여호와의 도우심을 입으므로 왕에게 구하는 것은 다 받는 자더니"}],"습1:5":[{"r":"렘19:13","t":"예루살렘 집들과 유다 왕들의 집들 곧 그 집들이 그 집 위에서 하늘의 만상에 분향하고 다른 신들에게 전제를 부음으로 더러워졌은즉 도벳 땅처럼 되리라 하셨다 하라"},{"r":"왕상18:21","t":"엘리야가 모든 백성에게 가까이 나아가 이르되 너희가 어느 때까지 두 사이에서 머뭇머뭇 하려느냐 여호와가 만일 하나님이면 그를 좇고 바알이 만일 하나님이면 그를 좇을지니라 하니 백성이 한 말도 대답지 아니하는지라"},{"r":"왕하17:33","t":"이와 같이 저희가 여호와도 경외하고 또한 어디서부터 옮겨왔든지 그 민족의 풍속대로 자기의 신들도 섬겼더라"},{"r":"왕하17:41","t":"그 여러 민족이 여호와를 경외하고 또 그 아로새긴 우상을 섬기더니 그 자자 손손이 그 열조의 행한 것을 좇아 오늘까지 그대로 하니라"},{"r":"왕상11:5","t":"이는 시돈 사람의 여신 아스다롯을 좇고 암몬 사람의 가증한 밀곰을 좇음이라"},{"r":"왕상11:33","t":"이는 저희가 나를 버리고 시돈 사람의 여신 아스다롯과, 모압의 신 그모스와, 암몬 자손의 신 밀곰을 숭배하며 그 아비 다윗의 행함 같지 아니하여 내 길로 행치 아니하며 나 보기에 정직한 일과 나의 법도와 나의 율례를 행치 아니함이니라"},{"r":"렘49:1","t":"암몬 자손에 대한 말씀이라 여호와께서 이같이 말씀하시되 이스라엘이 무자하냐 상속자가 없느냐 말감이 갓을 점령하며 그 백성이 그 성읍들에 거함은 어찜이뇨"}],"시103:19":[{"r":"시11:4","t":"여호와께서 그 성전에 계시니 여호와의 보좌는 하늘에 있음이여 그 눈이 인생을 통촉하시고 그 안목이 저희를 감찰하시도다"},{"r":"시93:2","t":"주의 보좌는 예로부터 견고히 섰으며 주는 영원부터 계셨나이다"},{"r":"시47:2","t":"지존하신 여호와는 엄위하시고 온 땅에 큰 임군이 되심이로다"},{"r":"단4:17","t":"이는 순찰자들의 명령대로요 거룩한 자들의 말대로니 곧 인생으로 지극히 높으신 자가 인간 나라를 다스리시며 자기의 뜻대로 그것을 누구에게든지 주시며 또 지극히 천한 자로 그 위에 세우시는 줄을 알게 하려 함이니라 하였느니라"}],"시103:20":[{"r":"시78:25","t":"사람이 권세 있는 자의 떡을 먹음이여 하나님이 식물을 충족히 주셨도다"},{"r":"마6:10","t":"나라이 임하옵시며 뜻이 하늘에서 이룬 것같이 땅에서도 이루어지이다"},{"r":"시148:2","t":"그의 모든 사자여 찬양하며 모든 군대여 찬양할지어다"},{"r":"눅2:13","t":"홀연히 허다한 천군이 그 천사와 함께 있어 하나님을 찬송하여 가로되"}],"시104:30":[{"r":"욥33:4","t":"하나님의 신이 나를 지으셨고 전능자의 기운이 나를 살리시느니라"},{"r":"계21:5","t":"보좌에 앉으신 이가 가라사대 보라 내가 만물을 새롭게 하노라 하시고 또 가라사대 이 말은 신실하고 참되니 기록하라 하시고"}],"시111:2":[{"r":"시92:5","t":"여호와여, 주의 행사가 어찌 그리 크신지요 주의 생각이 심히 깊으시니이다"},{"r":"계3:2","t":"너는 일깨워 그 남은 바 죽게 된 것을 굳게 하라 내 하나님 앞에 네 행위의 온전한 것을 찾지 못하였노니"},{"r":"시139:14","t":"내가 주께 감사하옴은 나를 지으심이 신묘막측하심이라 주의 행사가 기이함을 내 령혼이 잘 아나이다"},{"r":"시119:45","t":"내가 주의 법도를 구하였사오니 자유롭게 행보할 것이오며"},{"r":"시119:94","t":"나는 주의 것이오니 나를 구원하소서 내가 주의 법도를 찾았나이다"},{"r":"시119:155","t":"구원이 악인에게서 멀어짐은 저희가 주의 율례를 구하지 아니함이니이다"},{"r":"시112:1","t":"할렐루야  여호와를 경외하며 그 계명을 크게 즐거워하는 자는 복이 있도다"},{"r":"시143:5","t":"내가 옛날을 기억하고 주의 모든 행하신 것을 묵상하며 주의 손이 행사를 생각하고"}],"시111:3":[{"r":"시145:5","t":"주의 존귀하고 영광스러운 위엄과 주의 기사를 나는 묵상하리이다"},{"r":"시112:3","t":"부요와 재물이 그 집에 있음이여 그 의가 영원히 있으리로다"},{"r":"시112:9","t":"저가 재물을 흩어 빈궁한 자에게 주었으니 그 의가 영원히 있고 그 뿔이 영화로이 들리리로다"}],"시111:4":[{"r":"시78:4","t":"우리가 이를 그 자손에게 숨기지 아니하고 여호와의 영예와 그 능력과 기이한 사적을 후대에 전하리로다"},{"r":"시86:15","t":"그러나 주여, 주는 긍휼히 여기시며 은혜를 베푸시며 노하기를 더디 하시며 인자와 진실이 풍성하신 하나님이시오니"}],"시116:1":[{"r":"시66:19","t":"그러나 하나님이 실로 들으셨으며 내 기도 소리에 주의하셨도다"},{"r":"시118:21","t":"주께서 내게 응답하시고 나의 구원이 되셨으니 내가 주께 감사하리이다"},{"r":"시18:1","t":"(여호와의 종 다윗의 시. 영장으로 한 노래. 여호와께서 다윗을 그 모든 원수와 사울의 손에서 구원하신 날에 다윗이 이 노래의 말로 여호와께 아뢰어 가로되) 나의 힘이 되신 여호와여, 내가 주를 사랑하나이다"}],"시116:2":[{"r":"시31:2","t":"내게 귀를 기울여 속히 건지시고 내게 견고한 바위와 구원하는 보장이 되소서"}],"시119:147":[{"r":"시5:3","t":"여호와여, 아침에 주께서 나의 소리를 들으시리니 아침에 내가 주께 기도하고 바라리이다"},{"r":"시119:74","t":"주를 경외하는 자가 나를 보고 기뻐할 것은 내가 주의 말씀을 바라는 연고니이다"}],"시119:148":[{"r":"시119:15","t":"내가 주의 법도를 묵상하며 주의 도에 주의하며"},{"r":"시42:8","t":"낮에는 여호와께서 그 인자함을 베푸시고 밤에는 그 찬송이 내게 있어 생명의 하나님께 기도하리로다"}],"시119:160":[{"r":"시139:17","t":"하나님이여, 주의 생각이 내게 어찌 그리 보배로우신지요 그 수가 어찌 그리 많은지요"},{"r":"시119:142","t":"주의 의는 영원한 의요 주의 법은 진리로소이다"},{"r":"시119:172","t":"주의 모든 계명이 의로우므로 내 혀가 주의 말씀을 노래할지니이다"},{"r":"시119:7","t":"내가 주의 의로운 판단을 배울 때에는 정직한 마음으로 주께 감사하리이다"}],"시119:85":[{"r":"시119:51","t":"교만한 자가 나를 심히 조롱하였어도 나는 주의 법을 떠나지 아니하였나이다"},{"r":"시7:15","t":"저가 웅덩이를 파 만듦이여 제가 만든 함정에 빠졌도다"}],"시119:93":[{"r":"시119:83","t":"내가 연기 중의 가죽병 같이 되었으나 오히려 주의 율례를 잊지 아니하나이다"}],"시119:94":[{"r":"시119:45","t":"내가 주의 법도를 구하였사오니 자유롭게 행보할 것이오며"}],"시11:6":[{"r":"창19:24","t":"여호와께서 하늘 곧 여호와에게로서 류황과 불을 비같이 소돔과 고모라에 내리사"},{"r":"욥18:15","t":"그에게 속하지 않은 자가 그 장막에 거하리니 류황이 그 처소에 뿌려질 것이며"},{"r":"겔38:22","t":"내가 또 온역과 피로 그를 국문하며 쏟아지는 폭우와 큰 우박덩이와 불과 류황으로 그와 그 모든 떼와 그 함께한 많은 백성에게 비를 내리듯 하리라"},{"r":"시75:8","t":"여호와의 손에 잔이 있어 술 거품이 일어나는도다 속에 섞은 것이 가득한 그 잔을 하나님이 쏟아 내시나니 실로 그 찌끼까지도 땅의 모든 악인이 기울여 마시리로다"},{"r":"욥21:20","t":"자기의 멸망을 자기의 눈으로 보게 하시며 전능자의 진노를 마시게 하셔야 할 것이니라"}],"시12:6":[{"r":"시18:30","t":"하나님의 도는 완전하고 여호와의 말씀은 정미하니 저는 자기에게 피하는 모든 자의 방패시로다"},{"r":"시119:140","t":"주의 말씀이 심히 정미하므로 주의 종이 이를 사랑하나이다"},{"r":"잠30:5","t":"하나님의 말씀은 다 순전하며 하나님은 그를 의지하는 자의 방패시니라"},{"r":"시19:8","t":"여호와의 교훈은 정직하여 마음을 기쁘게 하고 여호와의 계명은 순결하여 눈을 밝게 하도다"}],"시139:14":[{"r":"시72:18","t":"홀로 기사를 행하시는 여호와 하나님 곧 이스라엘의 하나님을 찬송하며"}],"시146:4":[{"r":"시104:29","t":"주께서 낯을 숨기신즉 저희가 떨고 주께서 저희 호흡을 취하신즉 저희가 죽어 본 흙으로 돌아가나이다"},{"r":"전12:7","t":"흙은 여전히 땅으로 돌아가고 신은 그 주신 하나님께로 돌아가기 전에 기억하라"},{"r":"욥10:9","t":"기억하옵소서 주께서 내 몸 지으시기를 흙을 뭉치듯 하셨거늘 다시 나를 티끌로 돌려 보내려 하시나이까"},{"r":"욥34:14,15","t":"그가 만일 자기만 생각하시고 그 신과 기운을 거두실진대"}],"시19:7":[{"r":"롬7:12","t":"이로 보건대 률법도 거룩하며 계명도 거룩하며 의로우며 선하도다"},{"r":"시23:3","t":"내 령혼을 소생시키시고 자기 이름을 위하여 의의 길로 인도하시는도다"},{"r":"딤후3:16","t":"모든 성경은 하나님의 감동으로 된 것으로 교훈과 책망과 바르게 함과 의로 교육하기에 유익하니"},{"r":"출25:16","t":"내가 네게 줄 증거판을 궤 속에 둘지며"},{"r":"시78:5","t":"여호와께서 증거를 야곱에게 세우시며 법도를 이스라엘에게 정하시고 우리 열조에게 명하사 저희 자손에게 알게 하라 하셨으니"},{"r":"시111:7","t":"그 손의 행사는 진실과 공의며 그 법도는 다 확실하니"},{"r":"시119:130","t":"주의 말씀을 열므로 우둔한 자에게 비취어 깨닫게 하나이다"},{"r":"잠1:4","t":"어리석은 자로 슬기롭게 하며 젊은 자에게 지식과 근신함을 주기 위한 것이니"},{"r":"마11:25","t":"그 때에 예수께서 대답하여 가라사대 천지의 주재이신 아버지여  이것을 지혜롭고 슬기있는 자들에게는 숨기시고 어린 아이들에게는 나타내심을 감사하나이다"},{"r":"고전1:27","t":"그러나 하나님께서 세상의 미련한 것들을 택하사 지혜 있는 자들을 부끄럽게 하려 하시고 세상의 약한 것들을 택하사 강한 것들을 부끄럽게 하려 하시며"},{"r":"딤후3:15","t":"또 네가 어려서부터 성경을 알았나니 성경은 능히 너로 하여금 그리스도 예수 안에 있는 믿음으로 말미암아 구원에 이르는 지혜가 있게 하느니라"}],"시19:8":[{"r":"시103:18","t":"곧 그 언약을 지키고 그 법도를 기억하여 행하는 자에게로다"},{"r":"시111:7","t":"그 손의 행사는 진실과 공의며 그 법도는 다 확실하니"},{"r":"시119:4","t":"주께서 주의 법도로 명하사 우리로 근실히 지키게 하셨나이다"},{"r":"시119:27","t":"나로 주의 법도의 길을 깨닫게 하소서 그리하시면 내가 주의 기사를 묵상하리이다"},{"r":"시12:6","t":"여호와의 말씀은 순결함이여 흙 도가니에 일곱번 단련한 은 같도다"},{"r":"시13:3","t":"여호와 내 하나님이여, 나를 생각하사 응답하시고 나의 눈을 밝히소서 두렵건대 내가 사망의 잠을 잘까 하오며"}],"시37:10":[{"r":"욥24:24","t":"그들은 높아져도 잠시간에 없어지나니 낮아져서 범인처럼 제함을 당하고 곡식 이삭같이 베임을 입느니라"},{"r":"욥7:10","t":"그는 다시 자기 집으로 돌아가지 못하겠고 자기 처소도 다시 그를 알지 못하리이다"}],"시37:11":[{"r":"마5:5","t":"온유한 자는 복이 있나니 저희가 땅을 기업으로 받을 것임이요"},{"r":"시119:165","t":"주의 법을 사랑하는 자에게는 큰 평안이 있으니 저희에게 장애물이 없으리이다"},{"r":"사32:17","t":"의의 공효는 화평이요 의의 결과는 영원한 평안과 안전이라"}],"시37:3":[{"r":"시62:8","t":"백성들아 시시로 저를 의지하고 그 앞에 마음을 토하라 하나님은 우리의 피난처시로다 셀라"},{"r":"시115:9~11","t":"이스라엘아, 여호와를 의지하라  그는 너희 도움이시요 너희 방패시로다"},{"r":"잠3:5","t":"너는 마음을 다하여 여호와를 의뢰하고 네 명철을 의지하지 말라"},{"r":"사26:4","t":"너희는 여호와를 영원히 의뢰하라 주 여호와는 영원한 반석이심이로다"},{"r":"레26:5","t":"너희의 타작은 포도 딸 때까지 미치며 너희의 포도 따는 것은 파종할 때까지 미치리니 너희가 음식을 배불리 먹고 너희 땅에 안전히 거하리라"},{"r":"잠2:21","t":"대저 정직한 자는 땅에 거하며 완전한 자는 땅에 남아 있으리라"}],"시37:34":[{"r":"시37:9","t":"대저 행악하는 자는 끊어질 것이나 여호와를 기대하는 자는 땅을 차지하리로다"},{"r":"시27:14","t":"너는 여호와를 바랄지어다  강하고 담대하며 여호와를 바랄지어다"},{"r":"시52:5,6","t":"그런즉 하나님이 영영히 너를 멸하심이여  너를 취하여 네 장막에서 뽑아내며 생존하는 땅에서 네 뿌리를 빼시리로다 셀라"},{"r":"시91:8","t":"오직, 너는 목도하리니 악인의 보응이 네게 보이리로다"}],"시37:4":[{"r":"욥22:26","t":"이에 네가 전능자를 기뻐하여 하나님께로 얼굴을 들 것이라"},{"r":"사58:14","t":"네가 여호와의 안에서 즐거움을 얻을 것이라 내가 너를 땅의 높은 곳에 올리고 네 조상 야곱의 업으로 기르리라 여호와의 입의 말이니라"},{"r":"빌3:1","t":"종말로 나의 형제들아 주 안에서 기뻐하라  너희에게 같은 말을 쓰는 것이 내게는 수고로움이 없고 너희에게는 안전하니라"},{"r":"빌4:4","t":"주 안에서 항상 기뻐하라  내가 다시 말하노니 기뻐하라"},{"r":"마6:33","t":"너희는 먼저 그의 나라와 그의 의를 구하라  그리하면 이 모든 것을 너희에게 더하시리라"}],"시37:5":[{"r":"시22:8","t":"저가 여호와께 의탁하니 구원하실걸, 저를 기뻐하시니 건지실걸 하나이다"},{"r":"시55:22","t":"네 짐을 여호와께 맡겨 버리라 너를 붙드시고 의인의 요동함을 영영히 허락지 아니하시리로다"},{"r":"잠16:3","t":"너의 행사를 여호와께 맡기라 그리하면 너의 경영하는 것이 이루리라"},{"r":"벧전5:7","t":"너희 념려를 다 주께 맡겨 버리라 이는 저가 너희를 권고하심이니라"}],"시50:3":[{"r":"출19:16","t":"제 삼일 아침에 우뢰와 번개와 빽빽한 구름이 산 위에 있고 나팔소리가 심히 크니 진중 모든 백성이 다 떨더라"},{"r":"시21:9","t":"네가 노할 때에 저희로 풀무 같게 할 것이라 여호와께서 진노로 저희를 삼키시리니 불이 저희를 소멸하리로다"},{"r":"시27:3","t":"군대가 나를 대적하여 진 칠지라도 내 마음이 두렵지 아니하며 전쟁이 일어나 나를 치려 할지라도 내가 오히려 안연하리로다"},{"r":"레10:2","t":"불이 여호와 앞에서 나와 그들을 삼키매 그들이 여호와 앞에서 죽은지라"},{"r":"민16:35","t":"여호와께로서 불이 나와서 분향하는 이백 오십인을 소멸하였더라"},{"r":"단7:10","t":"불이 강처럼 흘러 그 앞에서 나오며 그에게 수종하는 자는 천천이요 그 앞에 시위한 자는 만만이며 심판을 베푸는데 책들이 펴 놓였더라"}],"시50:4":[{"r":"신4:26","t":"내가 오늘날 천지를 불러 증거를 삼노니 너희가 요단을 건너가서 얻는 땅에서 속히 망할 것이라 너희가 거기서 너희 날이 길지 못하고 전멸될 것이니라"},{"r":"신31:28","t":"너희 지파 모든 장로와 유사들을 내 앞에 모으라 내가 이 말씀을 그들의 귀에 들리고 그들에게 천지로 증거를 삼으리라"},{"r":"신32:1","t":"하늘이여  귀를 기울이라 내가 말하리라 땅은 내 입의 말을 들을지어다"},{"r":"사1:2","t":"하늘이여  들으라 땅이여  귀를 기울이라 여호와께서 말씀하시기를 내가 자식을 양육하였거늘 그들이 나를 거역하였도다"},{"r":"미6:1,2","t":"작은 산으로 네 목소리를 듣게 하라 하셨나니"}],"시50:5":[{"r":"시30:4","t":"주의 성도들아  여호와를 찬송하며 그 거룩한 이름에 감사할지어다"},{"r":"시52:9","t":"주께서 이를 행하셨으므로 내가 영영히 주께 감사하고 주의 이름이 선함으로 주의 성도 앞에서 내가 주의 이름을 의지하리이다"},{"r":"시79:2","t":"저희가 주의 종들의 시체를 공중의 새에게 밥으로 주며 주의 성도들의 육체를 땅 짐승에게 주며"},{"r":"시149:9","t":"기록한 판단대로 저희에게 시행할지로다 이런 영광은 그 모든 성도에게 있도다 할렐루야"},{"r":"출24:7,8","t":"언약서를 가져 백성에게 랑독하여 들리매 그들이 가로되 여호와의 모든 말씀을 우리가 준행하리이다"},{"r":"창15:9~18","t":"여호와께서 그에게 이르시되 나를 위하여 삼년 된 암소와, 삼년 된 암염소와, 삼년 된 수양과, 산비둘기와, 집비둘기 새끼를 취할지니라"}],"시50:6":[{"r":"시89:5","t":"여호와여, 주의 기사를 하늘이 찬양할 것이요 주의 성실도 거룩한 자의 회중에서 찬양하리이다"},{"r":"시97:6","t":"하늘이 그 의를 선포하니 모든 백성이 그 영광을 보았도다"},{"r":"계16:5","t":"내가 들으니 물을 차지한 천사가 가로되 전에도 계셨고 시방도 계신 거룩하신 이여 이렇게 심판하시니 의로우시도다"},{"r":"계16:7","t":"또 내가 들으니 제단이 말하기를 그러하다 주 하나님 곧 전능하신 이시여 심판하시는 것이 참되시고 의로우시도다 하더라"},{"r":"계19:2","t":"그의 심판은 참되고 의로운지라 음행으로 땅을 더럽게 한 큰 음녀를 심판하사 자기 종들의 피를 그의 손에 갚으셨도다 하고"},{"r":"시58:11","t":"때에 사람의 말이 진실로 의인에게 갚음이 있고 진실로 땅에서 판단하시는 하나님이 계시다 하리로다"},{"r":"시75:7","t":"오직 재판장이신 하나님이 이를 낮추시고 저를 높이시느니라"}],"시62:8":[{"r":"시37:3","t":"여호와를 의뢰하여 선을 행하라  땅에 거하여 그의 성실로 식물을 삼을지어다"},{"r":"시42:4","t":"내가 전에 성일을 지키는 무리와 동행하여 기쁨과 찬송의 소리를 발하며 저희를 하나님의 집으로 인도하였더니 이제 이 일을 기억하고 내 마음이 상하는도다"}],"시6:5":[{"r":"시30:9","t":"내가 무덤에 내려갈 때에 나의 피가 무슨 유익이 있으리요 어찌 진토가 주를 찬송하며 주의 진리를 선포하리이까"},{"r":"시88:10~12","t":"주께서 사망한 자에게 기사를 보이시겠나이까 유혼이 일어나 주를 찬송하리이까  셀라"},{"r":"시115:17","t":"죽은 자가 여호와를 찬양하지 못하나니 적막한 데 내려가는 아무도 못하리로다"},{"r":"사38:18","t":"음부가 주께 사례하지 못하며 사망이 주를 찬양하지 못하며 구덩이에 들어간 자가 주의 신실을 바라지 못하되"},{"r":"창37:35","t":"그 모든 자녀가 위로하되 그가 그 위로를 받지 아니하여 가로되 내가 슬퍼하며 음부에 내려 아들에게로 가리라 하고 그 아비가 그를 위하여 울었더라"}],"시74:4":[{"r":"애2:6,7","t":"성막을 동산의 초막같이 헐어 버리시며 공회 처소를 훼파하셨도다 여호와께서 시온 가운데서 절기와 안식일을 잊어버리게 하시며 진노하사 왕과 제사장을 멸시하셨도다"},{"r":"민2:2","t":"이스라엘 자손은 각각 그 기와 그 종족의 기호 곁에 진을 치되 회막을 사면으로 대하여 치라"},{"r":"마24:15","t":"그러므로 너희가 선지자 다니엘의 말한 바 멸망의 가증한 것이 거룩한 곳에 선 것을 보거든 읽는 자는 깨달을진저"},{"r":"시74:9","t":"우리의 표적이 보이지 아니하며 선지자도 다시 없으며 이런 일이 얼마나 오랠는지 우리 중에 아는 자도 없나이다"}],"시74:5":[{"r":"렘46:22","t":"애굽의 소리가 뱀의 소리 같으리니 이는 그들의 군대가 벌목하는 자같이 도끼를 가지고 올 것임이니라"}],"시74:6":[{"r":"왕상6:18","t":"전 안에 입힌 백향목에는 박과 핀 꽃을 아로새겼고 모두 백향목이라 돌이 보이지 아니하며"},{"r":"왕상6:29","t":"내외소 사면 벽에는 모두 그룹들과 종려와 핀 꽃 형상을 아로새겼고"},{"r":"왕상6:32","t":"감람목으로 만든 그 두 문짝에 그룹과 종려와 핀 꽃을 아로새기고 김으로 입히되 곧 그룹들과 종려에 김으로 입혔더라"},{"r":"왕상6:35","t":"그 문짝에 그룹들과 종려와 핀 꽃을 아로새기고 김으로 입히되 그 새긴데 맞게 하였고"}],"시74:7":[{"r":"왕하25:9","t":"여호와의 전과 왕궁을 사르고 예루살렘의 모든 집을 귀인의 집까지 불살랐으며"},{"r":"시79:1","t":"(아삽의 시) 하나님이여, 열방이 주의 기업에 들어와서 주의 성전을 더럽히고 예루살렘으로 돌 무더기가 되게 하였나이다"},{"r":"시26:8","t":"여호와여, 내가 주의 계신 집과 주의 영광이 거하는 곳을 사랑하오니"},{"r":"시89:39","t":"주의 종의 언약을 미워하사 그 관을 땅에 던져 욕되게 하셨으며"},{"r":"애2:2","t":"주께서 야곱의 모든 거처를 삼키시고 긍휼히 여기지 아니하셨음이여 노하사 처녀 유다의 견고한 성을 헐어 땅에 엎으시고 나라와 방백으로 욕되게 하셨도다"}],"시74:8":[{"r":"시83:4","t":"말하기를 가서 저희를 끊어 다시 나라가 되지 못하게 하여 이스라엘의 이름으로 다시는 기억되지 못하게 하자 하나이다"},{"r":"시74:4","t":"주의 대적이 주의 회중에서 훤화하며 자기 기를 세워 표적을 삼았으니"}],"시74:9":[{"r":"시74:4","t":"주의 대적이 주의 회중에서 훤화하며 자기 기를 세워 표적을 삼았으니"},{"r":"삼상3:1","t":"아이 사무엘이 엘리 앞에서 여호와를 섬길 때에는 여호와의 말씀이 희귀하여 이상이 흔히 보이지 않았더라"},{"r":"애2:9","t":"성문이 땅에 묻히며 빗장이 꺾여 훼파되고 왕과 방백들이 률법없는 열방 가운데 있으며 그 선지자들은 여호와의 묵시를 받지 못하는도다"},{"r":"겔7:26","t":"환난에 환난이 더하고 소문에 소문이 더할 때에 그들이 선지자에게 묵시를 구하나 헛될 것이며 제사장에게는 률법이 없어질 것이요 장로에게는 모략이 없어질 것이며"},{"r":"암8:11","t":"주 여호와께서 가라사대 보라 날이 이를지라 내가 기근을 땅에 보내리니 양식이 없어 주림이 아니며 물이 없어 갈함이 아니요 여호와의 말씀을 듣지 못한 기갈이라"},{"r":"시6:3","t":"나의 령혼도 심히 떨리나이다 여호와여, 어느 때까지니이까"},{"r":"시79:5","t":"여호와여, 어느 때까지니이까  영원히 노하시리이까  주의 진노가 불붙듯 하시리이까"},{"r":"시80:4","t":"만군의 하나님 여호와여, 주의 백성의 기도에 대하여 어느 때까지 노하시리이까"}],"신10:12":[{"r":"미6:8","t":"사람아 주께서 선한 것이 무엇임을 네게 보이셨나니 여호와께서 네게 구하시는 것이 오직 공의를 행하며 인자를 사랑하며 겸손히 네 하나님과 함께 행하는 것이 아니냐"},{"r":"신6:2","t":"곧 너와 네 아들과 네 손자로 평생에 네 하나님 여호와를 경외하며 내가 너희에게 명한 그 모든 규례와 명령을 지키게 하기 위한 것이며 또 네 날을 장구케 하기 위한 것이라"},{"r":"신6:13","t":"네 하나님 여호와를 경외하며 섬기며 그 이름으로 맹서할 것이니라"},{"r":"신5:33","t":"너희 하나님 여호와께서 너희에게 명하신 모든 도를 행하라  그리하면 너희가 삶을 얻고 복을 얻어서 너희의 얻은 땅에서 너희의 날이 장구하리라"},{"r":"신6:5","t":"너는 마음을 다하고, 성품을 다하고, 힘을 다하여 네 하나님 여호와를 사랑하라"}],"신10:13":[{"r":"신7:11","t":"그런즉 너는 오늘날 내가 네게 명하는 명령과 규례와 법도를 지켜 행할지니라"},{"r":"신6:24","t":"여호와께서 우리에게 이 모든 규례를 지키라 명하셨으니 이는 우리로 우리 하나님 여호와를 경외하여 항상 복을 누리게 하기 위하심이며 또 여호와께서 우리로 오늘날과 같이 생활하게 하려 하심이라"}],"신17:2":[{"r":"신17:2~7","t":"네 하나님 여호와께서 네게 주시는 어느 성중에서든지 너의 가운데 혹시 어떤 남자나 녀자가 네 하나님 여호와의 목전에 악을 행하여 그 언약을 어기고"},{"r":"신13:6~14","t":"네 동복 형제나 네 자녀나 네 품의 아내나 너와 생명을 함께 하는 친구가 가만히 너를 꾀어 이르기를 너와 네 열조가 알지 못하던 다른 신들"},{"r":"수7:11","t":"이스라엘이 범죄하여 내가 그들에게 명한 나의 언약을 어기었나니 곧 그들이 바친 물건을 취하고 도적하고 사기하여 자기 기구 가운데 두었느니라"},{"r":"수7:15","t":"바친 물건을 가진 자로 뽑힌 자를 불사르되 그와 그 모든 소유를 그리하라 이는 여호와의 언약을 어기고 이스라엘 가운데서 망령된 일을 행하였음이라 하셨다 하라"},{"r":"수23:16","t":"만일 너희가 너희 하나님 여호와께서 너희에게 명하신 언약을 범하고 가서 다른 신들을 섬겨 그에게 절하면 여호와의 진노가 너희에게 미치리니 너희에게 주신 아름다운 땅에서 너희가 속히 망하리라"},{"r":"삿2:20","t":"여호와께서 이스라엘에게 진노하여 이르시되 이 백성이 내가 그 열조와 세운 언약을 어기고 나의 목소리를 청종치 아니하였은즉"},{"r":"왕하18:12","t":"이는 저희가 그 하나님 여호와의 말씀을 준행치 아니하고 그 언약을 배반하고 여호와의 종 모세의 모든 명한 것을 거스려 듣지도 아니하며 행치도 아니하였음이더라"},{"r":"호6:7","t":"저희는 아담처럼 언약을 어기고 거기서 내게 패역을 행하였느니라"},{"r":"호8:1","t":"나팔을 네 입에 댈지어다 대적이 독수리처럼 여호와의 집에 덮치리니 이는 무리가 내 언약을 어기며 내 률법을 범함이로다"}],"신17:3":[{"r":"렘7:31","t":"힌놈의 아들 골짜기에 도벳 사당을 건축하고 그 자녀를 불에 살랐나니 내가 명하지 아니하였고 내 마음에 생각지도 아니한 일이니라"},{"r":"렘19:5","t":"또 그들이 바알을 위하여 산당을 건축하고 자기 아들들을 바알에게 번제로 불살라 드렸나니 이는 내가 명하거나 뜻한 바가 아니니라"},{"r":"렘32:35","t":"힌놈의 아들의 골짜기에 바알의 산당을 건축하였으며 자기들의 자녀를 몰렉의 불에 지나가게 하였느니라 그들이 이런 가증한 일을 행하여 유다로 범죄케 한 것은 나의 명한 것도 아니요 내 마음에 둔 것도 아니니라"},{"r":"신4:19","t":"또 두렵건대 네가 하늘을 향하여 눈을 들어 일월 성신 하늘 위의 군중 곧 너희 하나님 여호와께서 천하 만민을 위하여 분정하신 것을 보고 미혹하여 그것에 경배하며 섬길까 하노라"}],"신18:11":[{"r":"레19:31","t":"너희는 신접한 자와 박수를 믿지 말며 그들을 추종하여 스스로 더럽히지 말라 나는 너희 하나님 여호와니라"},{"r":"삼상28:7","t":"사울이 그 신하들에게 이르되 나를 위하여 신접한 녀인을 찾으라 내가 그리로 가서 그에게 물으리라 그 신하들이 그에게 이르되 보소서, 엔돌에 신접한 녀인이 있나이다"}],"신18:12":[{"r":"신22:5","t":"녀자는 남자의 의복을 입지 말 것이요 남자는 녀자의 의복을 입지 말 것이라 이같이 하는 자는 네 하나님 여호와께 가증한 자니라"},{"r":"신25:16","t":"무릇 이같이 하는 자, 무릇 불정당히 행하는 자는 네 하나님 여호와께 가증하니라"},{"r":"신9:4","t":"네 하나님 여호와께서 그들을 네 앞에서 쫓아내신 후에 네가 심중에 이르기를 나의 의로움을 인하여 여호와께서 나를 이 땅으로 인도하여 들여서 그것을 얻게 하셨다 하지 말라 실상은 이 민족들이 악함을 인하여 여호와께서 그들을 네 앞에서 쫓아내심이니라"}],"신32:16":[{"r":"시78:58","t":"자기 산당으로 그 노를 격동하며 저희 조각한 우상으로 그를 진노케 하였으매"},{"r":"민25:11","t":"제사장 아론의 손자 엘르아살의 아들 비느하스가 나의 질투심으로 질투하여 이스라엘 자손 중에서 나의 노를 돌이켜서 나의 질투심으로 그들을 진멸하지 않게 하였도다"}],"신32:17":[{"r":"시106:37","t":"저희가 그 자녀로 사신에게 제사하였도다"},{"r":"고전10:20","t":"대저 이방인의 제사하는 것은 귀신에게 하는 것이요 하나님께 제사하는 것이 아니니 나는 너희가 귀신과 교제하는 자 되기를 원치 아니하노라"},{"r":"삿5:8","t":"무리가 새 신들을 택하였으므로 그 때에 전쟁이 성문에 미쳤으나 이스라엘 사만명 중에 방패와 창이 보였던고"}],"신4:36":[{"r":"출19:9","t":"여호와께서 모세에게 이르시되 내가 빽빽한 구름 가운데서 네게 일함은 내가 너와 말하는 것을 백성으로 듣게하며 또한 너를 영원히 믿게 하려함이니라 모세가 백성의 말로 여호와께 고하였으므로"},{"r":"출19:19","t":"나팔 소리가 점점 커질 때에 모세가 말한즉 하나님이 음성으로 대답하시더라"},{"r":"느9:13","t":"또 시내산에 강림하시고 하늘에서부터 저희와 말씀하사 정직한 규례와 진정한 률법과 선한 율례와 계명을 저희에게 주시고"}],"신6:4":[{"r":"막12:29","t":"예수께서 대답하시되 첫째는 이것이니 이스라엘아  들으라 주, 곧 우리 하나님은 유일한 주시라"},{"r":"사42:8","t":"나는 여호와니 이는 내 이름이라 나는 내 영광을 다른 자에게, 내 찬송을 우상에게 주지 아니하리라"},{"r":"슥14:9","t":"여호와께서 천하의 왕이 되시리니 그 날에는 여호와께서 홀로 하나이실 것이요 그 이름이 홀로 하나이실 것이며"},{"r":"요17:3","t":"영생은 곧 유일하신 참 하나님과 그의 보내신 자 예수 그리스도를 아는 것이니이다"},{"r":"고전8:4","t":"그러므로 우상의 제물 먹는 일에 대하여는 우리가 우상은 세상에 아무 것도 아니며 또한 하나님은 한 분 밖에 없는 줄 아노라"},{"r":"고전8:6","t":"그러나 우리에게는 한 하나님 곧 아버지가 계시니 만물이 그에게서 났고 우리도 그를 위하여 또한 한 주 예수 그리스도께서 계시니 만물이 그로 말미암고 우리도 그로 말미암았느니라"}],"신6:5":[{"r":"마22:37","t":"예수께서 가라사대 네 마음을 다하고 목숨을 다하고 뜻을 다하여 주 너의 하나님을 사랑하라 하셨으니"},{"r":"막12:30","t":"네 마음을 다하고 목숨을 다하고 뜻을 다하고 힘을 다하여 주 너의 하나님을 사랑하라 하신 것이라"},{"r":"눅10:27","t":"대답하여 가로되 네 마음을 다하며 목숨을 다하며 힘을 다하며 뜻을 다하여 주 너의 하나님을 사랑하고 또한 네 이웃을 네 몸과 같이 사랑하라 하였나이다"},{"r":"왕하23:25","t":"요시야와 같이 마음을 다하며 성품을 다하며 힘을 다하여 여호와를 향하여 모세의 모든 률법을 온전히 준행한 임금은 요시야 전에도 없었고 후에도 그와 같은 자가 없었더라"}],"암3:7":[{"r":"창18:17","t":"여호와께서 가라사대 나의 하려는 것을 아브라함에게 숨기겠느냐"},{"r":"렘15:1","t":"여호와께서 내게 이르시되 모세와 사무엘이 내 앞에 섰다 할지라도 내 마음은 이 백성을 향할 수 없나니 그들을 내 앞에서 쫓아 내치라"}],"약1:2":[{"r":"벧전1:6","t":"그러므로 너희가 이제 여러 가지 시험을 인하여 잠간 근심하게 되지 않을 수 없었으나 오히려 크게 기뻐하도다"},{"r":"마5:12","t":"기뻐하고 즐거워하라  하늘에서 너희의 상이 큼이라 너희 전에 있던 선지자들을 이같이 핍박하였느니라"}],"약1:3":[{"r":"벧전1:7","t":"너희 믿음의 시련이 불로 연단하여도 없어질 김보다 더 귀하여 예수 그리스도의 나타나실 때에 칭찬과 영광과 존귀를 얻게 하려함이라"},{"r":"롬5:3","t":"다만 이뿐 아니라 우리가 환난중에도 즐거워하나니 이는 환난은 인내를"},{"r":"약5:11","t":"보라, 인내하는 자를 우리가 복되다 하나니 너희가 욥의 인내를 들었고 주께서 주신 결말을 보았거니와 주는 가장 자비하시고 긍휼히 여기는 자시니라"},{"r":"히10:36","t":"너희에게 인내가 필요함은 너희가 하나님의 뜻을 행한 후에 약속을 받기 위함이라"},{"r":"벧후1:6","t":"지식에 절제를 절제에, 인내를, 인내에 경건을,"}],"약2:10":[{"r":"마5:19","t":"그러므로 누구든지 이 계명 중에 지극히 작은 것 하나라도 버리고 또 그같이 사람을 가르치는 자는 천국에서 지극히 작다 일컬음을 받을 것이요 누구든지 이를 행하며 가르치는 자는 천국에서 크다 일컬음을 받으리라"},{"r":"갈3:10","t":"무릇 률법 행위에 속한 자들은 저주 아래 있나니 기록된 바 누구든지 률법책에 기록된 대로 온갖 일을 항상 행하지 아니하는 자는 저주 아래 있는 자라 하였음이라"}],"약2:11":[{"r":"출20:13,14","t":"살인하지 말지니라"}],"약2:12":[{"r":"약1:25","t":"자유하게 하는 온전한 률법을 들여다 보고 있는 자는 듣고 잊어 버리는 자가 아니요 실행하는 자니 이 사람이 그 행하는 일에 복을 받으리라"}],"약2:19":[{"r":"신6:4","t":"이스라엘아 들으라, 우리 하나님 여호와는 오직 하나인 여호와시니"},{"r":"고전8:6","t":"그러나 우리에게는 한 하나님 곧 아버지가 계시니 만물이 그에게서 났고 우리도 그를 위하여 또한 한 주 예수 그리스도께서 계시니 만물이 그로 말미암고 우리도 그로 말미암았느니라"},{"r":"롬2:17~25","t":"유대인이라 칭하는 네가 률법을 의지하며 하나님을 자랑하며"},{"r":"마8:29","t":"이에 저희가 소리질러 가로되 하나님의 아들이여  우리와 당신과 무슨 상관이 있나이까  때가 이르기 전에 우리를 괴롭게 하려고 여기 오셨나이까 하더니"},{"r":"막1:24","t":"나사렛 예수여  우리가 당신과 무슨 상관이 있나이까  우리를 멸하러 왔나이까  나는 당신이 누구인줄 아노니 하나님의 거룩한 자니이다"},{"r":"막5:7","t":"큰 소리로 부르짖어 가로되 지극히 높으신 하나님의 아들 예수여  나와 당신과 무슨 상관이 있나이까  원컨대 하나님 앞에 맹서하고 나를 괴롭게 마옵소서 하니"},{"r":"눅4:33,34","t":"회당에 더러운 귀신 들린 사람이 있어 크게 소리질러 가로되"},{"r":"행16:17","t":"바울과 우리를 좇아와서 소리 질러 가로되 이 사람들은 지극히 높은 하나님의 종으로 구원의 길을 너희에게 전하는 자라 하며"},{"r":"행19:15","t":"악귀가 대답하여 가로되 예수도 내가 알고 바울도 내가 알거니와 너희는 누구냐  하며"}],"약4:3":[{"r":"요일5:14","t":"그를 향하여 우리의 가진 바 담대한 것이 이것이니 그의 뜻대로 무엇을 구하면 들으심이라"}],"약5:1":[{"r":"눅6:24","t":"그러나 화 있을찐저 너희 부요한 자여 너희는 너희의 위로를 이미 받았도다"},{"r":"잠11:28","t":"자기의 재물을 의지하는 자는 패망하려니와 의인은 푸른 잎사귀 같아서 번성하리라"},{"r":"암6:1","t":"화 있을진저 시온에서 안일한 자와 사마리아 산에서 마음이 든든한 자 곧 열국 중 우승하여 유명하므로 이스라엘 족속이 따르는 자들이여"},{"r":"딤전6:9","t":"부하려 하는 자들은 시험과 올무와 여러가지 어리석고 해로운 정욕에 떨어지나니 곧 사람으로 침륜과 멸망에 빠지게 하는 것이라"},{"r":"롬3:16","t":"파멸과 고생이 그 길에 있어"}],"약5:2":[{"r":"욥13:28","t":"나는 썩은 물건의 후패함 같으며 {좀}먹은 의복 같으니이다"},{"r":"사50:9","t":"주 여호와께서 나를 도우시리니 나를 정죄할 자 누구뇨 그들은 다 옷과 같이 해어지며 좀에게 먹히리라"},{"r":"마6:19,20","t":"너희를 위하여 보물을 땅에 쌓아 두지 말라 거기는 {좀}과 동록이 해하며 동록이 구멍을 뚫고 도적질하느니라"}],"약5:3":[{"r":"마6:19","t":"너희를 위하여 보물을 땅에 쌓아 두지 말라 거기는 {좀}과 동록이 해하며 동록이 구멍을 뚫고 도적질하느니라"},{"r":"눅12:21","t":"자기를 위하여 재물을 쌓아 두고 하나님께 대하여 부요치 못한 자가 이와 같으니라"},{"r":"롬2:5","t":"다만 네 고집과 회개치 아니한 마음을 따라 진노의 날 곧 하나님의 의로우신 판단이 나타나는 그 날에 임할 진노를 네게 쌓는도다"},{"r":"약5:8","t":"너희도 길이 참고 마음을 굳게 하라 주의 강림이 가까우니라"},{"r":"약5:9","t":"형제들아  서로 원망하지 말라 그리하여야 심판을 면하리라 보라, 심판자가 문 밖에 서 계시니라"}],"약5:4":[{"r":"욥24:10","t":"그들이 옷이 없어 벌거벗고 다니며 주리면서 곡식 단을 메며"},{"r":"레19:13","t":"너는 네 이웃을 압제하지 말며 늑탈하지 말며 품군의 삯을 아침까지 밤새도록 네게 두지 말며"},{"r":"신24:15","t":"그 품삯을 당일에 주고 해진 후까지 끌지 말라 이는 그가 빈궁하므로 마음에 품삯을 사모함이라 두렵건대 그가 너를 여호와께 호소하면 죄가 네게로 돌아갈까 하노라"},{"r":"롬9:29","t":"또한 이사야가 미리 말한 바 만일 만군의 주께서 우리에게 씨를 남겨 두시지 아니하셨더면 우리가 소돔과 같이 되고 고모라와 같았으리로다 함과 같으니라"}],"약5:5":[{"r":"욥21:13","t":"그날을 형통하게 지내다가 경각간에 음부에 내려가느니라"},{"r":"눅16:19","t":"한 부자가 있어 자색 옷과 고운 베옷을 입고 날마다 호화로이 연락하는데"},{"r":"벧후2:13","t":"부의의 값으로 부의를 당하며 낮에 연락을 기쁘게 여기는 자들이니 점과 흠이라 너희와 함께 연회할 때에 저희 간사한 가운데 연락하며"},{"r":"딤전5:6","t":"일락을 좋아하는 이는 살았으나 죽었느니라"},{"r":"렘12:3","t":"여호와여, 주께서 나를 아시고 나를 보시며 내 마음이 주를 향하여 어떠함을 감찰하시오니 양을 잡으려고 끌어 냄과 같이 그들을 끌어 내시되 죽일 날을 위하여 그들을 예비하옵소서"}],"약5:6":[{"r":"행3:14","t":"너희가 거룩하고 의로운 자를 부인하고 도리어 살인한 사람을 놓아주기를 구하여"},{"r":"약4:2","t":"너희가 욕심을 내어도 얻지 못하고 살인하고 시기하여도 능히 취하지 못하나니 너희가 다투고 싸우는도다 너희가 얻지 못함은 구하지 아니함이요"}],"약5:7":[{"r":"신11:14","t":"여호와께서 너희 땅에 이른 비, 늦은 비를 적당한 때에 내리시리니 너희가 곡식과 포도주와 기름을 얻을 것이요"}],"약5:8":[{"r":"살전3:13","t":"너희 마음을 굳게 하시고 우리 주 예수께서 그의 모든 성도와 함께 강림하실 때에 하나님 우리 아버지 앞에서 거룩함에 흠이 없게 하시기를 원하노라"},{"r":"벧전4:7","t":"만물의 마지막이 가까왔으니 그러므로 너희는 정신을 차리고 근신하여 기도하라"},{"r":"롬13:11,12","t":"또한 너희가 이 시기를 알거니와 자다가 깰 때가 벌써 되었으니 이는 이제 우리의 구원이 처음 믿을 때보다 가까왔음이니라"},{"r":"빌4:5","t":"너희 관용을 모든 사람에게 알게 하라 주께서 가까우시니라"},{"r":"히10:25","t":"모이기를 폐하는 어떤 사람들의 습관과 같이 하지 말고 오직 권하여 그 날이 가까움을 볼수록 더욱 그리하자"},{"r":"히10:37","t":"잠시 잠간 후면 오실 이가 오시리니 지체하지 아니하시리라"}],"엡1:10":[{"r":"골1:16","t":"만물이 그에게 창조되되 하늘과 땅에서 보이는 것들과 보이지 않는 것들과 혹은 보좌들이나 주관들이나 정사들이나 권세들이나 만물이 다 그로 말미암고 그를 위하여 창조되었고"},{"r":"골1:20","t":"그의 십자가의 피로 화평을 이루사 만물 곧 땅에 있는 것들이나 하늘에 있는 것들을 그로 말미암아 자기와 화목케 되기를 기뻐하심이라"},{"r":"엡3:14","t":"이러하므로 내가 하늘과 땅에 있는 각 족속에게"},{"r":"빌2:9,10","t":"이러므로 하나님이 그를 지극히 높여 모든 이름 위에 뛰어난 이름을 주사"}],"엡1:17":[{"r":"롬15:6","t":"한 마음과 한 입으로 하나님 곧 우리 주 예수 그리스도의 아버지께 영광을 돌리게 하려 하노라"},{"r":"골1:9","t":"이로써 우리도 듣던 날부터 너희를 위하여 기도하기를 그치지 아니하고 구하노니 너희로 하여금 모든 신령한 지혜와 총명에 하나님의 뜻을 아는 것으로 채우게 하시고"}],"엡1:18":[{"r":"히6:4","t":"한번 비췸을 얻고 하늘의 은사를 맛보고 성령에 참여한 바 되고"},{"r":"히10:32","t":"전날에 너희가 빛을 받은 후에 고난의 큰 싸움에 참은 것을 생각하라"},{"r":"계3:17,18","t":"네가 말하기를 나는 부자라 부요하여 불족한 것이 없다 하나 네 곤고한 것과 가련한 것과 가난한 것과 눈먼 것과 벌거벗은 것을 알지 못하도다"},{"r":"행26:18","t":"그 눈을 뜨게 하여 어두움에서 빛으로 사단의 권세에서 하나님께로 돌아가게 하고 죄 사함과 나를 믿어 거룩케 된 무리 가운데서 기업을 얻게 하리라 하더이다"},{"r":"엡4:4","t":"몸이 하나이요, 성령이 하나이니 이와 같이 너희가 부르심의 한 소망 안에서 부르심을 입었느니라"},{"r":"엡2:12","t":"그 때에 너희는 그리스도 밖에 있었고 이스라엘 나라 밖의 사람이라 약속의 언약들에 대하여 외인이요 세상에서 소망이 없고 하나님도 없는 자이더니"},{"r":"엡3:8","t":"모든 성도 중에 지극히 작은 자보다 더 작은 나에게 이 은혜를 주신 것은 측량할 수 없는 그리스도의 풍성을 이방인에게 전하게 하시고"},{"r":"엡3:16","t":"그 영광의 풍성을 따라 그의 성령으로 말미암아 너희 속 사람을 능력으로 강건하게 하옵시며"},{"r":"골1:27","t":"하나님이 그들로 하여금 이 비밀의 영광이 이방인 가운데 어떻게 풍성한 것을 알게 하려 하심이라 이 비밀은 너희 안에 계신 그리스도시니 곧 영광의 소망이니라"},{"r":"엡1:7","t":"우리가 그리스도 안에서 그의 은혜의 풍성함을 따라 그의 피로 말미암아 구속 곧 죄 사함을 받았으니"}],"엡2:20":[{"r":"마16:18","t":"또 내가 네게 이르노니 너는 베드로라 내가 이 반석 위에 내 교회를 세우리니 음부의 권세가 이기지 못하리라"},{"r":"계21:14","t":"그 성에 성곽은 열 두 기초석이 있고 그 위에 어린 양의 십 이 사도의 열 두 이름이 있더라"},{"r":"렘12:16","t":"그들이 내 백성의 도를 부지런히 배우며 사는 여호와 내 이름으로 맹서하기를 자기들이 내 백성을 가리켜 바알로 맹서하게 한 것 같이 하면 그들이 내 백성 중에 세움을 입으려니와"},{"r":"고전3:10","t":"내게 주신 하나님의 은혜를 따라 내가 지혜로운 건축자와 같이 터를 닦아 두매 다른 이가 그 위에 세우나 그러나 각각 어떻게 그 위에 세우기를 조심할지니라"},{"r":"고전3:11","t":"이 닦아 둔 것 외에 능히 다른 터를 닦아 둘 자가 없으니 이 터는 곧 예수 그리스도라"},{"r":"시118:22","t":"건축자의 버린 돌이 집 모퉁이의 머릿돌이 되었나니"},{"r":"사28:16","t":"그러므로 주 여호와께서 가라사대 보라 내가 한 돌을 시온에 두어 기초를 삼았노니 곧 시험한 돌이요 귀하고 견고한 기초 돌이라 그것을 믿는 자는 급절하게 되지 아니하리로다"},{"r":"벧전2:6","t":"경에 기록하였으되 보라, 내가 택한 보배롭고 요긴한 모퉁이 돌을 시온에 두노니 저를 믿는 자는 부끄러움을 당치 아니하리라 하였으니"}],"엡4:30":[{"r":"사63:10","t":"그들이 반역하여 주의 성신을 근심케 하였으므로 그가 돌이켜 그들의 대적이 되사 친히 그들을 치셨더니"},{"r":"살전5:19","t":"성령을 소멸치 말며"},{"r":"엡1:7","t":"우리가 그리스도 안에서 그의 은혜의 풍성함을 따라 그의 피로 말미암아 구속 곧 죄 사함을 받았으니"},{"r":"엡1:13","t":"그 안에서 너희도 진리의 말씀 곧 너희의 구원의 복음을 듣고 그 안에서 또한 믿어 약속의 성령으로 인치심을 받았으니"}],"엡5:25":[{"r":"엡5:28","t":"이와 같이 남편들도 자기 아내 사랑하기를 제 몸같이 할지니 자기 아내를 사랑하는 자는 자기를 사랑하는 것이라"},{"r":"엡5:33","t":"그러나 너희도 각각 자기의 아내 사랑하기를 자기같이 하고 아내도 그 남편을 경외하라"},{"r":"벧전3:7","t":"남편된 자들아  이와 같이 지식을 따라 너희 아내와 동거하고 저는 더 연약한 그릇이요 또 생명의 은혜를 유업으로 함께 받을 자로 알아 귀히 여기라 이는 너희 기도가 막히지 아니하게 하려 함이라"},{"r":"엡5:2","t":"그리스도께서 너희를 사랑하신 것같이 너희도 사랑 가운데서 행하라 그는 우리를 위하여 자신을 버리사 향기로운 제물과 생축으로 하나님께 드리셨느니라"}],"엡5:26":[{"r":"딛3:5","t":"우리를 구원하시되 우리의 행한 바 의로운 행위로 말미암지 아니하고 오직 그의 긍휼하심을 좇아 중생의 씻음과 성령의 새롭게 하심으로 하셨나니"},{"r":"계7:14","t":"내가 가로되 내 주여 당신이 알리이다 하니 그가 나더러 이르되 이는 큰 환난에서 나오는 자들인데 어린 양의 피에 그 옷을 씻어 희게 하였느니라"},{"r":"엡6:17","t":"구원의 투구와 성령의 검 곧 하나님의 말씀을 가지라"},{"r":"히6:5","t":"하나님의 선한 말씀과 래세의 능력을 맛보고"},{"r":"요15:3","t":"너희는 내가 일러 준 말로 이미 깨끗하였으니"}],"엡5:27":[{"r":"엡5:24","t":"그러나 교회가 그리스도에게 하듯 아내들도 범사에 그 남편에게 복종할지니라"},{"r":"아4:7","t":"나의 사랑, 너는 순전히 어여뻐서 아무 흠이 없구나"}],"엡6:18":[{"r":"골4:2~4","t":"기도를 항상 힘쓰고 기도에 감사함으로 깨어 있으라"},{"r":"눅18:1","t":"항상 기도하고 락망치 말아야 될 것을 저희에게 비유로 하여"},{"r":"유1:20","t":"사랑하는 자들아  너희는 너희의 지극히 거룩한 믿음 위에 자기를 건축하며 성령으로 기도하며"},{"r":"롬8:26","t":"이와 같이 성령도 우리 연약함을 도우시나니 우리가 마땅히 빌 바를 알지 못하나 오직 성령이 말할 수 없는 탄식으로 우리를 위하여 친히 간구하시느니라"},{"r":"막13:33","t":"주의하라  깨어 있으라  그 때가 언제인지 알지 못함이니라"},{"r":"딤전2:1","t":"그러므로 내가 첫째로 권하노니 모든 사람을 위하여 간구와 기도와 도고와 감사를 하되"}],"옵1:15":[{"r":"욜1:15","t":"오호라  그 날이여 여호와의 날이 가까왔나니 곧 멸망같이 전능자에게로서 이르리로다"},{"r":"렘50:29","t":"활 쏘는 자를 바벨론에 소집하라 무릇 활을 당기는 자여  그 사면으로 진을 치고 쳐서 피하는 자가 없게 하라 그 일한 대로 갚고 그 행한대로 그에게 행하라 그가 이스라엘의 거룩한 자 여호와를 향하여 교만하였음이니라"},{"r":"겔35:15","t":"이스라엘 족속의 기업이 황무함을 인하여 네가 즐거워한 것 같이 내가 너로 황무케 하리라 세일산아 너와 에돔 온 땅이 황무하리니 무리가 나를 여호와인 줄 알리라 하셨다 하라"},{"r":"합2:8","t":"네가 여러 나라를 노략하였으므로 그 모든 민족의 남은 자가 너를 노략하리니 이는 네가 사람의 피를 흘렸음이요 또 땅에 성읍에 그 안의 모든 거민에게 강포를 행하였음이니라 하리라"}],"옵1:16":[{"r":"욜3:17","t":"그런즉 너희가 나는 내 성산 시온에 거하는 너희 하나님 여호와인 줄 알 것이라 예루살렘이 거룩하리니 다시는 이방 사람이 그 가운데로 통행하지 못하리로다"},{"r":"렘25:27,28","t":"너는 그들에게 이르기를 만군의 여호와 이스라엘의 하나님의 말씀에 너희는 마시라, 취하라, 토하라, 엎드러지고 다시는 일어나지 말라 이는 내가 너희 중에 칼을 보냄을 인함이니라 하셨다 하라"}],"왕하23:4":[{"r":"왕하25:18","t":"시위대 장관이 대제사장 스라야와 부제사장 스바냐와 전 문지기 세 사람을 잡고"},{"r":"렘52:24","t":"시위대 장관이 대제사장 스라야와 부제사장 스바냐와 전 문지기 세 사람을 잡고"},{"r":"왕하21:3","t":"그 부친 히스기야의 헐어버린 산당을 다시 세우며 이스라엘 왕 아합의 소위를 본받아 바알을 위하여 단을 쌓으며 아세라 목상을 만들며 하늘의 일월 성신을 숭배하여 섬기며"},{"r":"신16:21","t":"네 하나님 여호와를 위하여 쌓은 단 곁에 아무 나무로든지 아세라 상을 세우지 말며"},{"r":"왕하23:15","t":"이스라엘로 범죄케 한 느밧의 아들 여로보암이 벧엘에 세운 단과 산당을 왕이 헐고 또 그 산당을 불사르고 빻아서 가루를 만들며 또 아세라 목상을 불살랐더라"}],"왕하23:5":[{"r":"왕하21:3","t":"그 부친 히스기야의 헐어버린 산당을 다시 세우며 이스라엘 왕 아합의 소위를 본받아 바알을 위하여 단을 쌓으며 아세라 목상을 만들며 하늘의 일월 성신을 숭배하여 섬기며"}],"요13:12":[{"r":"요13:4","t":"저녁 잡수시던 자리에서 일어나 겉옷을 벗고 수건을 가져다가 허리에 두르시고"},{"r":"요13:7","t":"예수께서 대답하여 가라사대 나의 하는 것을 네가 이제는 알지 못하나 이 후에는 알리라"}],"요13:13":[{"r":"눅6:46","t":"너희는 나를 불러 주여, 주여 하면서도 어찌하여 나의 말하는 것을 행치 아니하느냐"},{"r":"마23:8","t":"그러나 너희는 랍비라 칭함을 받지 말라 너희 선생은 하나이요 너희는 다 형제니라"},{"r":"마23:10","t":"또한 지도자라 칭함을 받지 말라 너희 지도자는 하나이니 곧 그리스도니라"},{"r":"고전8:6","t":"그러나 우리에게는 한 하나님 곧 아버지가 계시니 만물이 그에게서 났고 우리도 그를 위하여 또한 한 주 예수 그리스도께서 계시니 만물이 그로 말미암고 우리도 그로 말미암았느니라"},{"r":"고전12:3","t":"그러므로 내가 너희에게 알게 하노니 하나님의 영으로 말하는 자는 누구든지 예수를 저주할 자라 하지 않고 또 성령으로 아니하고는 누구든지 예수를 주시라 할 수 없느니라"},{"r":"빌2:11","t":"모든 입으로 예수 그리스도를 주라 시인하여 하나님 아버지께 영광을 돌리게 하셨느니라"},{"r":"엡6:9","t":"상전들아 너희도 저희에게 이와 같이 하고 공갈을 그치라 이는 저희와 너희의 상전이 하늘에 계시고 그에게는 외모로 사람을 취하는 일이 없는 줄 너희가 앎이니라"}],"요13:14":[{"r":"딤전5:10","t":"선한 행실의 증거가 있어 혹은 자녀를 양육하며 혹은 나그네를 대접하며 혹은 성도들의 발을 씻기며 혹은 환난 당한 자들을 구제하며 혹은 모든 선한 일을 좇은 자라야 할 것이요"},{"r":"벧전5:5","t":"젊은 자들아 이와 같이 장로들에게 순복하고 다 서로 겸손으로 허리를 동이라 하나님이 교만한 자를 대적하시되 겸손한 자들에게는 은혜를 주시느니라"}],"요13:15":[{"r":"마11:29","t":"나는 마음이 온유하고 겸손하니 나의 멍에를 메고 내게 배우라 그러면 너희 마음이 쉼을 얻으리니"}],"요13:16":[{"r":"요15:20","t":"내가 너희더러 종이 주인보다 더 크지 못하다 한 말을 기억하라 사람들이 나를 핍박하였은즉 너희도 핍박할 터이요 내 말을 지켰은즉 너희 말도 지킬 터이라"},{"r":"마10:24","t":"제자가 그 선생보다 또는 종이 그 상전보다 높지 못하나니"}],"요14:1":[{"r":"요14:27","t":"평안을 너희에게 끼치노니 곧 나의 평안을 너희에게 주노라 내가 너희에게 주는 것은 세상이 주는 것 같지 아니하니라 너희는 마음에 근심도 말고 두려워하지도 말라"},{"r":"요16:22,23","t":"지금은 너희가 근심하나 내가 다시 너희를 보리니 너희 마음이 기쁠 것이요 너희 기쁨을 빼앗을 자가 없느니라"},{"r":"벧전3:14","t":"그러나 의를 위하여 고난을 받으면 복 있는 자니 저희의 두려워함을 두려워 말며 소동치 말고"},{"r":"요17:3","t":"영생은 곧 유일하신 참 하나님과 그의 보내신 자 예수 그리스도를 아는 것이니이다"},{"r":"막11:22","t":"예수께서 대답하여 저희에게 이르시되 하나님을 믿으라"},{"r":"요12:44","t":"예수께서 외쳐 가라사대 나를 믿는 자는 나를 믿는 것이 아니요 나를 보내신 이를 믿는 것이며"}],"요14:13":[{"r":"요15:16","t":"너희가 나를 택한 것이 아니요 내가 너희를 택하여 세웠나니 이는 너희로 가서 과실을 맺게 하고 또 너희 과실이 항상 있게 하여 내 이름으로 아버지께 무엇을 구하든지 다 받게 하려 함이니라"},{"r":"요16:23,24","t":"그 날에는 너희가 아무 것도 내게 묻지 아니하리라 내가 진실로 진실로 너희에게 이르노니 너희가 무엇이든지 아버지께 구하는 것을 내 이름으로 주시리라"},{"r":"마7:7","t":"구하라  그러면 너희에게 주실 것이요 찾으라  그러면 찾을 것이요 문을 두드리라  그러면 너희에게 열릴 것이니"},{"r":"요13:31","t":"저가 나간 후에 예수께서 가라사대 지금 인자가 영광을 얻었고 하나님도 인자를 인하여 영광을 얻으셨도다"}],"요14:15":[{"r":"요14:21","t":"나의 계명을 가지고 지키는 자라야 나를 사랑하는 자니 나를 사랑하는 자는 내 아버지께 사랑을 받을 것이요 나도 그를 사랑하여 그에게 나를 나타내리라"},{"r":"요14:23","t":"예수께서 대답하여 가라사대 사람이 나를 사랑하면 내 말을 지키리니 내 아버지께서 저를 사랑하실 것이요 우리가 저에게 와서 거처를 저와 함께 하리라"},{"r":"요15:10","t":"내가 아버지의 계명을 지켜 그의 사랑 안에 거하는 것같이 너희도 내 계명을 지키면 내 사랑 안에 거하리라"},{"r":"요일5:3","t":"하나님을 사랑하는 것은 이것이니 우리가 그의 계명들을 지키는 것이라 그의 계명들은 무거운 것이 아니로다"},{"r":"요이1:6","t":"또 사랑은 이것이니 우리가 그 계명을 좇아 행하는 것이요 계명은 이것이니 너희가 처음부터 들은 바와 같이 그 가운데서 행하라 하심이라"},{"r":"요일2:3","t":"우리가 그의 계명을 지키면 이로써 우리가 저를 아는 줄로 알 것이요"}],"요14:16":[{"r":"요16:26","t":"그 날에 너희가 내 이름으로 구할 것이요 내가 너희를 위하여 아버지께 구하겠다 하는 말이 아니니"},{"r":"요17:9","t":"내가 저희를 위하여 비옵나니 내가 비옵는 것은 세상을 위함이 아니요 내게 주신 자들을 위함이니이다 저희는 아버지의 것이로소이다"},{"r":"요17:15","t":"내가 비옵는 것은 저희를 세상에서 데려가시기를 위함이 아니요 오직 악에 빠지지 않게 보전하시기를 위함이니이다"},{"r":"요17:20","t":"내가 비옵는 것은 이 사람들만 위함이 아니요 또 저희 말을 인하여 나를 믿는 사람들도 위함이니"},{"r":"요14:26","t":"보혜사 곧 아버지께서 내 이름으로 보내실 성령 그가 너희에게 모든 것을 가르치시고 내가 너희에게 말한 모든 것을 생각나게 하시리라"},{"r":"요15:26","t":"내가 아버지께로서 너희에게 보낼 보혜사 곧 아버지께로서 나오시는 진리의 성령이 오실때에 그가 나를 증거하실 것이요"},{"r":"요16:7","t":"그러하나 내가 너희에게 실상을 말하노니 내가 떠나가는 것이 너희에게 유익이라 내가 떠나가지 아니하면 보혜사가 너희에게로 오시지 아니할 것이요 가면 내가 그를 너희에게로 보내리니"},{"r":"요일2:1","t":"나의 자녀들아  내가 이것을 너희에게 씀은 너희로 죄를 범치 않게 하려 함이라 만일 누가 죄를 범하면 아버지 앞에서 우리에게 대언자가 있으니 곧 의로우신 예수 그리스도시라"},{"r":"롬8:26","t":"이와 같이 성령도 우리 연약함을 도우시나니 우리가 마땅히 빌 바를 알지 못하나 오직 성령이 말할 수 없는 탄식으로 우리를 위하여 친히 간구하시느니라"}],"요14:17":[{"r":"요15:26","t":"내가 아버지께로서 너희에게 보낼 보혜사 곧 아버지께로서 나오시는 진리의 성령이 오실때에 그가 나를 증거하실 것이요"},{"r":"요16:13","t":"그러하나 진리의 성령이 오시면 그가 너희를 모든 진리 가운데로 인도하시리니 그가 자의로 말하지 않고 오직 듣는 것을 말하시며 장래 일을 너희에게 알리시리라"},{"r":"고전2:12~14","t":"우리가 세상의 영을 받지 아니하고 오직 하나님께로 온 영을 받았으니 이는 우리로 하여금 하나님께서 우리에게 은혜로 주신 것들을 알게 하려 하심이라"},{"r":"요일2:27","t":"너희는 주께 받은 바 기름 부음이 너희 안에 거하나니 아무도 너희를 가르칠 필요가 없고 오직 그의 기름 부음이 모든 것을 너희에게 가르치며 또 참되고 거짓이 없으니 너희를 가르치신 그대로 주 안에 거하라"},{"r":"요일4:6","t":"우리는 하나님께 속하였으니 하나님을 아는 자는 우리의 말을 듣고 하나님께 속하지 아니한 자는 우리의 말을 듣지 아니하나니 진리의 영과 미혹의 영을 이로써 아느니라"},{"r":"요일5:7","t":"증거하는 이는 성령이시니 성령은 진리니라"},{"r":"고전2:14","t":"육에 속한 사람은 하나님의 성령의 일을 받지 아니하나니 저희에게는 미련하게 보임이요 또 깨닫지도 못하나니 이런 일은 영적으로라야 분변함이니라"},{"r":"행2:4","t":"저희가 다 성령의 충만함을 받고 성령이 말하게 하심을 따라 다른 방언으로 말하기를 시작하니라"},{"r":"요일2:27","t":"너희는 주께 받은 바 기름 부음이 너희 안에 거하나니 아무도 너희를 가르칠 필요가 없고 오직 그의 기름 부음이 모든 것을 너희에게 가르치며 또 참되고 거짓이 없으니 너희를 가르치신 그대로 주 안에 거하라"},{"r":"요이1:2","t":"우리 안에 거하여 영원히 우리와 함께 할 진리를 인함이로다"},{"r":"롬8:9","t":"만일 너희 속에 하나님의 영이 거하시면 너희가 육신에 있지 아니하고 영에 있나니 누구든지 그리스도의 영이 없으면 그리스도의 사람이 아니라"}],"요14:2":[{"r":"요2:16","t":"비둘기 파는 사람들에게 이르시되 이것을 여기서 가져가라 내 아버지의 집으로 장사하는 집을 만들지 말라 하시니"},{"r":"요16:7","t":"그러하나 내가 너희에게 실상을 말하노니 내가 떠나가는 것이 너희에게 유익이라 내가 떠나가지 아니하면 보혜사가 너희에게로 오시지 아니할 것이요 가면 내가 그를 너희에게로 보내리니"},{"r":"요8:21,22","t":"다시 이르시되 내가 가리니 너희가 나를 찾다가 너희 죄 가운데서 죽겠고 나의 가는 곳에는 너희가 오지 못하리라"},{"r":"요13:33","t":"소자들아 내가 아직 잠시 너희와 함께 있겠노라 너희가 나를 찾을터이나 그러나 일찍 내가 유대인들에게 너희는 나의 가는 곳에 올 수 없다고 말한 것과 같이 지금 너희에게도 이르노라"},{"r":"요13:36","t":"시몬 베드로가 가로되 주여 어디로 가시나이까  예수께서 대답하시되 나의 가는 곳에 네가 지금은 따라 올 수 없으나 후에는 따라 오리라"}],"요14:26":[{"r":"요14:16","t":"내가 아버지께 구하겠으니 그가 또 다른 보혜사를 너희에게 주사 영원토록 너희와 함께 있게 하시리니"},{"r":"눅24:49","t":"볼지어다 내가 내 아버지의 약속하신 것을 너희에게 보내리니 너희는 위로부터 능력을 입히울 때까지 이 성에 유하라 하시니라"},{"r":"행2:33","t":"하나님이 오른손으로 예수를 높이시매 그가 약속하신 성령을 아버지께 받아서 너희 보고 듣는 이것을 부어 주셨느니라"},{"r":"요15:26","t":"내가 아버지께로서 너희에게 보낼 보혜사 곧 아버지께로서 나오시는 진리의 성령이 오실때에 그가 나를 증거하실 것이요"},{"r":"요16:7","t":"그러하나 내가 너희에게 실상을 말하노니 내가 떠나가는 것이 너희에게 유익이라 내가 떠나가지 아니하면 보혜사가 너희에게로 오시지 아니할 것이요 가면 내가 그를 너희에게로 보내리니"},{"r":"요16:13","t":"그러하나 진리의 성령이 오시면 그가 너희를 모든 진리 가운데로 인도하시리니 그가 자의로 말하지 않고 오직 듣는 것을 말하시며 장래 일을 너희에게 알리시리라"},{"r":"고전2:10","t":"오직 하나님이 성령으로 이것을 우리에게 보이셨으니 성령은 모든 것 곧 하나님의 깊은 것이라도 통달하시느니라"},{"r":"요일2:20","t":"너희는 거룩하신 자에게서 기름 부음을 받고 모든 것을 아느니라"},{"r":"요일2:27","t":"너희는 주께 받은 바 기름 부음이 너희 안에 거하나니 아무도 너희를 가르칠 필요가 없고 오직 그의 기름 부음이 모든 것을 너희에게 가르치며 또 참되고 거짓이 없으니 너희를 가르치신 그대로 주 안에 거하라"},{"r":"요2:22","t":"죽은 자 가운데서 살아나신 후에야 제자들이 이 말씀하신 것을 기억하고 성경과 및 예수의 하신 말씀을 믿었더라"}],"요14:29":[{"r":"요13:19","t":"지금부터 일이 이루기 전에 미리 너희에게 이름은 일이 이룰 때에 내가 그인줄 너희로 믿게 하려 함이로라"},{"r":"요16:4","t":"오직 너희에게 이 말을 이른 것은 너희로 그 때를 당하면 내가 너희에게 이 말 한 것을 기억나게 하려 함이요 처음부터 이 말을 하지 아니한 것은 내가 너희와 함께 있었음이니라"}],"요14:3":[{"r":"요14:18","t":"내가 너희를 고아와 같이 버려두지 아니하고 너희에게로 오리라"},{"r":"요14:28","t":"내가 갔다가 너희에게로 온다 하는 말을 너희가 들었나니 나를 사랑하였더면 나의 아버지께로 감을 기뻐하였으리라 아버지는 나보다 크심이니라"},{"r":"요21:22,23","t":"예수께서 가라사대 내가 올 때까지 그를 머물게 하고자 할찌라도 네게 무슨 상관이냐  너는 나를 따르라 하시더라"},{"r":"요12:26","t":"사람이 나를 섬기려면 나를 따르라  나 있는 곳에 나를 섬기는 자도 거기 있으리니 사람이 나를 섬기면 내 아버지께서 저를 귀히 여기시리라"}],"요15:10":[{"r":"요10:18","t":"이를 내게서 빼앗는 자가 있는 것이 아니라 내가 스스로 버리노라 나는 버릴 권세도 있고 다시 얻을 권세도 있으니 이 계명은 내 아버지에게서 받았노라 하시니라"},{"r":"요8:55","t":"너희는 그를 알지 못하되 나는 아노니 만일 내가 알지 못한다 하면 나도 너희같이 거짓말장이가 되리라 나는 그를 알고 또 그의 말씀을 지키노라"},{"r":"요17:4","t":"아버지께서 내게 하라고 주신 일을 내가 이루어 아버지를 이 세상에서 영화롭게 하였사오니"},{"r":"빌2:8","t":"사람의 모양으로 나타나셨으매 자기를 낮추시고 죽기까지 복종하셨으니 곧 십자가에 죽으심이라"},{"r":"요14:15","t":"너희가 나를 사랑하면 나의 계명을 지키리라"},{"r":"요14:23","t":"예수께서 대답하여 가라사대 사람이 나를 사랑하면 내 말을 지키리니 내 아버지께서 저를 사랑하실 것이요 우리가 저에게 와서 거처를 저와 함께 하리라"}],"요15:26":[{"r":"요14:16,17","t":"내가 아버지께 구하겠으니 그가 또 다른 보혜사를 너희에게 주사 영원토록 너희와 함께 있게 하시리니"},{"r":"요14:26","t":"보혜사 곧 아버지께서 내 이름으로 보내실 성령 그가 너희에게 모든 것을 가르치시고 내가 너희에게 말한 모든 것을 생각나게 하시리라"},{"r":"고전12:3","t":"그러므로 내가 너희에게 알게 하노니 하나님의 영으로 말하는 자는 누구든지 예수를 저주할 자라 하지 않고 또 성령으로 아니하고는 누구든지 예수를 주시라 할 수 없느니라"},{"r":"요일5:7","t":"증거하는 이는 성령이시니 성령은 진리니라"}],"요15:9":[{"r":"요5:20","t":"아버지께서 아들을 사랑하사 자기의 행하시는 것을 다 아들에게 보이시고 또 그보다 더 큰 일을 보이사 너희로 기이히 여기게 하시리라"},{"r":"요13:34","t":"새 계명을 너희에게 주노니 서로 사랑하라  내가 너희를 사랑한 것같이 너희도 서로 사랑하라"}],"요16:13":[{"r":"요14:17","t":"저는 진리의 영이라 세상은 능히 저를 받지 못하나니 이는 저를 보지도 못하고 알지도 못함이라 그러나 너희는 저를 아나니 저는 너희와 함께 거하심이요 또 너희 속에 계시겠음이라"},{"r":"요14:26","t":"보혜사 곧 아버지께서 내 이름으로 보내실 성령 그가 너희에게 모든 것을 가르치시고 내가 너희에게 말한 모든 것을 생각나게 하시리라"},{"r":"행8:31","t":"대답하되 지도하는 사람이 없으니 어찌 깨달을 수 있느뇨  하고 빌립을 청하여 병거에 올라 같이 앉으라 하니라"},{"r":"요1:17","t":"률법은 모세로 말미암아 주신 것이요 은혜와 진리는 예수 그리스도로 말미암아 온 것이라"},{"r":"요14:6","t":"예수께서 가라사대 내가 곧 길이요, 진리요, 생명이니  나로 말미암지 않고는 아버지께로 올 자가 없느니라"},{"r":"시25:5","t":"주의 진리로 나를 지도하시고 교훈하소서 주는 내 구원의 하나님이시니 내가 종일 주를 바라나이다"},{"r":"요15:15","t":"이제부터는 너희를 종이라 하지 아니하리니 종은 주인의 하는 것을 알지 못함이라 너희를 친구라 하였노니 내가 내 아버지께 들은 것을 다 너희에게 알게 하였음이니라"}],"요16:14":[{"r":"요7:39","t":"이는 그를 믿는 자의 받을 성령을 가리켜 말씀하신 것이라 예수께서 아직 영광을 받지 못하신고로 성령이 아직 저희에게 계시지 아니하시더라"}],"요16:7":[{"r":"요7:39","t":"이는 그를 믿는 자의 받을 성령을 가리켜 말씀하신 것이라 예수께서 아직 영광을 받지 못하신고로 성령이 아직 저희에게 계시지 아니하시더라"},{"r":"요15:26","t":"내가 아버지께로서 너희에게 보낼 보혜사 곧 아버지께로서 나오시는 진리의 성령이 오실때에 그가 나를 증거하실 것이요"},{"r":"요14:16","t":"내가 아버지께 구하겠으니 그가 또 다른 보혜사를 너희에게 주사 영원토록 너희와 함께 있게 하시리니"},{"r":"요14:2","t":"내 아버지 집에 거할 곳이 많도다 그렇지 않으면 너희에게 일렀으리라 내가 너희를 위하여 처소를 예비하러 가노니"},{"r":"행2:33","t":"하나님이 오른손으로 예수를 높이시매 그가 약속하신 성령을 아버지께 받아서 너희 보고 듣는 이것을 부어 주셨느니라"},{"r":"요14:26","t":"보혜사 곧 아버지께서 내 이름으로 보내실 성령 그가 너희에게 모든 것을 가르치시고 내가 너희에게 말한 모든 것을 생각나게 하시리라"}],"요16:8":[{"r":"요15:26","t":"내가 아버지께로서 너희에게 보낼 보혜사 곧 아버지께로서 나오시는 진리의 성령이 오실때에 그가 나를 증거하실 것이요"},{"r":"요8:46","t":"너희 중에 누가 나를 죄로 책잡겠느냐  내가 진리를 말하매 어찌하여 나를 믿지 아니하느냐"}],"요16:9":[{"r":"요8:24","t":"이러므로 내가 너희에게 말하기를 너희가 너희 죄 가운데서 죽으리라 하였노라 너희가 만일 내가 그인줄 믿지 아니하면 너희 죄 가운데서 죽으리라"},{"r":"행2:36,37","t":"그런즉 이스라엘 온 집이 정녕 알지니 너희가 십자가에 못 박은 이 예수를 하나님이 주와 그리스도가 되게 하셨느니라 하니라"},{"r":"고전12:3","t":"그러므로 내가 너희에게 알게 하노니 하나님의 영으로 말하는 자는 누구든지 예수를 저주할 자라 하지 않고 또 성령으로 아니하고는 누구든지 예수를 주시라 할 수 없느니라"}],"요17:3":[{"r":"요일5:20","t":"또 아는 것은 하나님의 아들이 이르러 우리에게 지각을 주사 우리로 참된 자를 알게 하신 것과 또한 우리가 참된 자 곧 그의 아들 예수 그리스도 안에 있는 것이니 그는 참 하나님이시요 영생이시라"},{"r":"요5:44","t":"너희가 서로 영광을 취하고 유일하신 하나님께로부터 오는 영광은 구하지 아니하니 어찌 나를 믿을 수 있느냐"},{"r":"살전1:9","t":"저희가 우리에 대하여 스스로 고하기를 우리가 어떻게 너희 가운데 들어간 것과 너희가 어떻게 우상을 버리고 하나님께로 돌아와서 사시고 참되신 하나님을 섬기며"},{"r":"요일5:20","t":"또 아는 것은 하나님의 아들이 이르러 우리에게 지각을 주사 우리로 참된 자를 알게 하신 것과 또한 우리가 참된 자 곧 그의 아들 예수 그리스도 안에 있는 것이니 그는 참 하나님이시요 영생이시라"},{"r":"렘10:10","t":"오직 여호와는 참 하나님이시요 사시는 하나님이시요 영원한 왕이시라 그 진노하심에 땅이 진동하며 그 분노하심을 열방이 능히 당치 못하느니라"},{"r":"요3:17","t":"하나님이 그 아들을 세상에 보내신 것은 세상을 심판하려 하심이 아니요 저로 말미암아 세상이 구원을 받게 하려 하심이라"},{"r":"호2:20","t":"진실함으로 네게 장가들리니 네가 여호와를 알리라"},{"r":"호6:3","t":"그러므로 우리가 여호와를 알자 힘써 여호와를 알자 그의 나오심은 새벽 빛같이 일정하니 비와 같이, 땅을 적시는 늦은 비와 같이 우리에게 임하시리라 하리라"},{"r":"벧후1:2,3","t":"하나님과 우리 주 예수를 앎으로 은혜와 평강이 너희에게 더욱 많을지어다"}],"요1:1":[{"r":"창1:1","t":"태초에 하나님이 천지를 창조하시니라"},{"r":"골1:17","t":"또한 그가 만물보다 먼저 계시고 만물이 그 안에 함께 섰느니라"},{"r":"요일1:1","t":"태초부터 있는 생명의 말씀에 관하여는 우리가 들은바요 눈으로 본 바요 주목하고 우리 손으로 만진 바라"},{"r":"계1:4","t":"요한은 아시아에 있는 일곱 교회에 편지하노니 이제도 계시고 전에도 계시고 장차 오실 이와 그 보좌 앞에 일곱 영과"},{"r":"계1:8","t":"주 하나님이 가라사대 나는 알파와 오메가라 이제도 있고 전에도 있었고 장차 올 자요 전능한 자라 하시더라"},{"r":"계1:17","t":"내가 볼 때에 그 발 앞에 엎드러져 죽은 자같이 되매 그가 오른손을 내게 얹고 가라사대 두려워 말라 나는 처음이요 나중이니"},{"r":"계3:14","t":"라오디게아 교회의 사자에게 편지하기를 아멘이시요 충성되고 참된 증인이시요 하나님의 창조의 근본이신 이가 가라사대"},{"r":"계21:6","t":"또 내게 말씀하시되 이루었도다 나는 알파와 오메가요 처음과 나중이라 내가 생명수 샘물로 목마른 자에게 값없이 주리니"},{"r":"계22:13","t":"나는 알파의 오메가요 처음과 나중이요 시작과 끝이라"},{"r":"계19:13","t":"또 그가 피 뿌린 옷을 입었는데 그 이름은 하나님의 말씀이라 칭하더라"},{"r":"히4:12","t":"하나님의 말씀은 살았고 운동력이 있어 좌우에 날선 어떤 검보다도 예리하여 혼과 영과 및 관절과 골수를 찔러 쪼개기까지 하며 또 마음의 생각과 뜻을 감찰하나니"},{"r":"요일1:1","t":"태초부터 있는 생명의 말씀에 관하여는 우리가 들은바요 눈으로 본 바요 주목하고 우리 손으로 만진 바라"},{"r":"요일1:2","t":"이 생명이 나타내신 바 된지라 이 영원한 생명을 우리가 보았고 증거하여 너희에게 전하노니 이는 아버지와 함께 계시다가 우리에게 나타내신 바 된 자니라"},{"r":"요17:5","t":"아버지여 창세 전에 내가 아버지와 함께 가졌던 영화로써 지금도 아버지와 함께 나를 영화롭게 하옵소서"},{"r":"빌2:6","t":"그는 근본 하나님의 본체시나 하나님과 동등됨을 취할 것으로 여기지 아니하시고"},{"r":"요1:18","t":"본래 하나님을 본 사람이 없으되 아버지 품 속에 있는 독생하신 하나님이 나타내셨느니라"},{"r":"롬9:5","t":"조상들도 저희 것이요 육신으로하면 그리스도가 저희에게서 나셨으니 저는 만물 위에 계셔 세세에 찬양을 받으실 하나님이시니라 아멘"}],"요1:12":[{"r":"요일5:13","t":"내가 하나님의 아들의 이름을 믿는 너희에게 이것을 쓴 것은 너희로 하여금 너희에게 영생이 있음을 알게 하려 함이라"},{"r":"갈3:26","t":"너희가 다 믿음으로 말미암아 그리스도 예수 안에서 하나님의 아들이 되었으니"},{"r":"요11:52","t":"또 그 민족만 위할 뿐 아니라 흩어진 하나님의 자녀를 모아 하나가 되게 하기 위하여 죽으실 것을 미리 말함이러라"},{"r":"요일3:1","t":"보라, 아버지께서 어떠한 사랑을 우리에게 주사 하나님의 자녀라 일컬음을 얻게 하셨는고 우리가 그러하도다 그러므로 세상이 우리를 알지 못함은 그를 알지 못함이니라"},{"r":"마5:45","t":"이같이 한즉 하늘에 계신 너희 아버지의 아들이 되리니 이는 하나님이 그 해를 악인과 선인에게 비취게 하시며 비를 의로운 자와 부의한 자에게 내리우심이니라"},{"r":"요일5:1","t":"예수께서 그리스도이심을 믿는 자마다 하나님께로서 난 자니 또한 내신 이를 사랑하는 자마다 그에게 난 자를 사랑하느니라"}],"요1:13":[{"r":"벧전1:23","t":"너희가 거듭난 것이 썩어질 씨로 된 것이 아니요 썩지 아니할 씨로 된 것이니 하나님의 살아 있고 항상 있는 말씀으로 되었느니라"},{"r":"요3:6","t":"육으로 난 것은 육이요 성령으로 난 것은 영이니"},{"r":"약1:18","t":"그가 그 조물 중에 우리로 한 첫 열매가 되게 하시려고 자기의 뜻을 좇아 진리의 말씀으로 우리를 낳으셨느니라"},{"r":"요3:3","t":"예수께서 대답하여 가라사대 진실로 진실로 네게 이르노니 사람이 거듭나지 아니하면 하나님 나라를 볼 수 없느니라"},{"r":"벧전1:3","t":"찬송하리로다 우리 주 예수 그리스도의 아버지 하나님이 그 많으신 긍휼대로 예수 그리스도의 죽은 자 가운데서 복활하심으로 말미암아 우리를 거듭나게 하사 산 소망이 있게 하시며"}],"요1:14":[{"r":"요1:1","t":"태초에 말씀이 계시니라 이 말씀이 하나님과 함께 계셨으니 이 말씀은 곧 하나님이시니라"},{"r":"롬1:3","t":"이 아들로 말하면 육신으로는 다윗의 혈통에서 나셨고"},{"r":"롬8:3","t":"률법이 육신으로 말미암아 연약하여 할 수 없는 그것을 하나님은 하시나니 곧 죄를 인하여 자기 아들을 죄 있는 육신의 모양으로 보내어 육신에 죄를 정하사"},{"r":"갈4:4","t":"때가 차매 하나님이 그 아들을 보내사 녀자에게서 나게 하시고 률법 아래 나게 하신 것은"},{"r":"빌2:7,8","t":"오히려 자기를 비어 종의 형체를 가져 사람들과 같이 되었고"},{"r":"골1:22","t":"이제는 그의 육체의 죽음으로 말미암아 화목케 하사 너희를 거룩하고 흠 없고 책망할 것이 없는 자로 그 앞에 세우고자 하셨으니"},{"r":"딤전3:16","t":"크도다  경건의 비밀이여 그렇지 않다 하는 이 없도다 그는 육신으로 나타난 바 되시고 영으로 의롭다 하심을 입으시고 천사들에게 보이시고 만국에서 전파되시고 세상에서 믿은 바 되시고 영광가운데서 올리우셨음이니라"},{"r":"히2:14","t":"자녀들은 혈육에 함께 속하였으매 그도 또한 한 모양으로 혈육에 함께 속하심은 사망으로 말미암아 사망의 세력을 잡은 자 곧 마귀를 없이 하시며"},{"r":"요일4:2","t":"하나님의 영은 이것으로 알지니 곧 예수 그리스도께서 육체로 오신 것을 시인하는 영마다 하나님께 속한 것이요"},{"r":"요이1:7","t":"미혹하는 자가 많이 세상에 나왔나니 이는 예수 그리스도께서 육체로 임하심을 부인하는 자라 이것이 미혹하는 자요 적그리스도니"},{"r":"요6:51","t":"나는 하늘로서 내려온 산 떡이니 사람이 이 떡을 먹으면 영생하리라 나의 줄 떡은 곧 세상의 생명을 위한 내 살이로라 하시니라"},{"r":"계7:15","t":"그러므로 그들이 하나님의 보좌 앞에 있고 또 그의 성전에서 밤낮 하나님을 섬기매 보좌에 앉으신 이가 그들 위에 장막을 치시리니"},{"r":"계21:3","t":"내가 들으니 보좌에서 큰 음성이 나서 가로되 보라, 하나님의 장막이 사람들과 함께 있으매 하나님이 저희와 함께 거하시리니 저희는 하나님의 백성이 되고 하나님은 친히 저희와 함께 계셔서"},{"r":"요2:11","t":"예수께서 이 처음 표적을 갈릴리 가나에서 행하여 그 영광을 나타내시매 제자들이 그를 믿으니라"},{"r":"눅9:32","t":"베드로와 및 함께 있는 자들이 곤하여 졸다가 아주 깨어 예수의 영광과 및 함께 선 두 사람을 보더니"},{"r":"벧후1:16,17","t":"우리 주 예수 그리스도의 능력과 강림하심을 너희에게 알게 한 것이 공교히 만든 이야기를 좇은 것이 아니요 우리는 그의 크신 위엄을 친히 본 자라"},{"r":"요일1:1","t":"태초부터 있는 생명의 말씀에 관하여는 우리가 들은바요 눈으로 본 바요 주목하고 우리 손으로 만진 바라"},{"r":"요일4:14","t":"아버지가 아들을 세상의 구주로 보내신 것을 우리가 보았고 또 증거하노니"},{"r":"요1:17","t":"률법은 모세로 말미암아 주신 것이요 은혜와 진리는 예수 그리스도로 말미암아 온 것이라"},{"r":"요14:6","t":"예수께서 가라사대 내가 곧 길이요, 진리요, 생명이니  나로 말미암지 않고는 아버지께로 올 자가 없느니라"}],"요1:3":[{"r":"요1:10","t":"그가 세상에 계셨으며 세상은 그로 말미암아 지은 바 되었으되 세상이 그를 알지 못하였고"},{"r":"시33:6","t":"여호와의 말씀으로 하늘이 지음이 되었으며 그 만상이 그 입기운으로 이루었도다"},{"r":"고전8:6","t":"그러나 우리에게는 한 하나님 곧 아버지가 계시니 만물이 그에게서 났고 우리도 그를 위하여 또한 한 주 예수 그리스도께서 계시니 만물이 그로 말미암고 우리도 그로 말미암았느니라"},{"r":"골1:16","t":"만물이 그에게 창조되되 하늘과 땅에서 보이는 것들과 보이지 않는 것들과 혹은 보좌들이나 주관들이나 정사들이나 권세들이나 만물이 다 그로 말미암고 그를 위하여 창조되었고"},{"r":"히1:2","t":"이 모든 날 마지막에 아들로 우리에게 말씀하셨으니 이 아들을 만유의 후사로 세우시고 또 저로 말미암아 모든 세계를 지으셨느니라"}],"요20:21":[{"r":"요17:18","t":"아버지께서 나를 세상에 보내신 것같이 나도 저희를 세상에 보내었고"},{"r":"히3:1","t":"그러므로 함께 하늘의 부르심을 입은 거룩한 형제들아  우리의 믿는 도리의 사도시며 대제사장이신 예수를 깊이 생각하라"},{"r":"요3:17","t":"하나님이 그 아들을 세상에 보내신 것은 세상을 심판하려 하심이 아니요 저로 말미암아 세상이 구원을 받게 하려 하심이라"},{"r":"요13:20","t":"내가 진실로 진실로 너희에게 이르노니 나의 보낸 자를 영접하는 자는 나를 영접하는 것이요 나를 영접하는 자는 나를 보내신 이를 영접하는 것이니라"},{"r":"행1:2","t":"그의 택하신 사도들에게 성령으로 명하시고 승천하신 날까지의 일을 기록하였노라"}],"요20:22":[{"r":"창2:7","t":"여호와 하나님이 흙으로 사람을 지으시고 생기를 그 코에 불어 넣으시니 사람이 생령이 된지라"},{"r":"행2:4","t":"저희가 다 성령의 충만함을 받고 성령이 말하게 하심을 따라 다른 방언으로 말하기를 시작하니라"},{"r":"요7:39","t":"이는 그를 믿는 자의 받을 성령을 가리켜 말씀하신 것이라 예수께서 아직 영광을 받지 못하신고로 성령이 아직 저희에게 계시지 아니하시더라"}],"요3:16":[{"r":"요1:29","t":"이튿날 요한이 예수께서 자기에게 나아오심을 보고 가로되 보라  세상 죄를 지고 가는 하나님의 어린 양이로다"},{"r":"롬5:8","t":"우리가 아직 죄인 되었을 때에 그리스도께서 우리를 위하여 죽으심으로 하나님께서 우리에게 대한 자기의 사랑을 확증하셨느니라"},{"r":"엡2:4","t":"긍휼에 풍성하신 하나님이 우리를 사랑하신 그 큰 사랑을 인하여"},{"r":"살후2:16","t":"우리 주 예수 그리스도와 우리를 사랑하시고 영원한 위로와 좋은 소망을 은혜로 주신 하나님 우리 아버지께"},{"r":"요일3:1","t":"보라, 아버지께서 어떠한 사랑을 우리에게 주사 하나님의 자녀라 일컬음을 얻게 하셨는고 우리가 그러하도다 그러므로 세상이 우리를 알지 못함은 그를 알지 못함이니라"},{"r":"요일4:9,10","t":"하나님의 사랑이 우리에게 이렇게 나타난 바 되었으니 하나님이 자기의 독생자를 세상에 보내심은 저로 말미암아 우리를 살리려 하심이니라"},{"r":"롬8:32","t":"자기 아들을 아끼지 아니하시고 우리 모든 사람을 위하여 내어 주신 이가 어찌 그 아들과 함께 모든 것을 우리에게 은사로 주지 아니하시겠느뇨"},{"r":"요10:28","t":"내가 저희에게 영생을 주노니 영원히 멸망치 아니할 터이요 또 저희를 내 손에서 빼앗을 자가 없느니라"}],"요3:3":[{"r":"고후5:17","t":"그런즉 누구든지 그리스도 안에 있으면 새로운 피조물이라 이전 것은 지나갔으니 보라  새것이 되었도다"},{"r":"갈6:15","t":"할례나 무할례가 아무 것도 아니로되 오직 새로 지으심을 받은 자뿐이니라"},{"r":"벧전1:3","t":"찬송하리로다 우리 주 예수 그리스도의 아버지 하나님이 그 많으신 긍휼대로 예수 그리스도의 죽은 자 가운데서 복활하심으로 말미암아 우리를 거듭나게 하사 산 소망이 있게 하시며"},{"r":"벧전1:23","t":"너희가 거듭난 것이 썩어질 씨로 된 것이 아니요 썩지 아니할 씨로 된 것이니 하나님의 살아 있고 항상 있는 말씀으로 되었느니라"},{"r":"약1:17","t":"각양 좋은 은사와 온전한 선물이 다 위로부터 빛들의 아버지께로서 내려오나니 그는 변함도 없으시고 회전하는 그림자도 없으시니라"},{"r":"약3:15","t":"이러한 지혜는 위로부터 내려온 것이 아니요 세상적이요 정욕적이요 마귀적이니"},{"r":"약3:17","t":"오직 위로부터 난 지혜는 첫째 성결하고 다음에 화평하고 관용하고 량순하며 긍휼과 선한 열매가 가득하고 편벽과 거짓이 없나니"},{"r":"요1:13","t":"이는 혈통으로나 육정으로나 사람의 뜻으로 나지 아니하고 오직 하나님께로서 난 자들이니라"},{"r":"요3:36","t":"아들을 맏는 자는 영생이 있고 아들을 순종치 아니하는 자는 영생을 보지 못하고 도리어 하나님의 진노가 그 위에 머물러 있느니라"}],"요3:36":[{"r":"요3:15,16","t":"이는 저를 믿는 자마다 영생을 얻게 하려 하심이니라"},{"r":"요5:24","t":"내가 진실로 진실로 너희에게 이르노니 내 말을 듣고 또 나 보내신 이를 믿는 자는 영생을 얻었고 심판에 이르지 아니하나니 사망에서 생명으로 옮겼느니라"},{"r":"요6:40","t":"내 아버지의 뜻은 아들을 보고 믿는 자마다 영생을 얻는 이것이니 마지막 날에 내가 이를 다시 살리리라 하시니라"},{"r":"요6:47","t":"진실로 진실로 너희에게 이르노니 믿는 자는 영생을 가졌나니"},{"r":"요6:54","t":"내 살을 먹고 내 피를 마시는 자는 영생을 가졌고 마지막 날에 내가 그를 다시 살리리니"},{"r":"요일5:12,13","t":"아들이 있는 자에게는 생명이 있고 하나님의 아들이 없는 자에게는 생명이 없느니라"},{"r":"요11:25,26","t":"예수께서 가라사대 나는 복활이요 생명이니 나를 믿는 자는 죽어도 살겠고"},{"r":"요20:31","t":"오직 이것을 기록함은 너희로 예수께서 하나님의 아들 그리스도이심을 믿게 하려 함이요 또 너희로 믿고 그 이름을 힘입어 생명을 얻게 하려 함이니라"},{"r":"마19:16","t":"어떤 사람이 주께 와서 가로되 선생님이여 내가 무슨 선한 일을 하여야 영생을 얻으리이까"},{"r":"요6:53","t":"예수께서 이르시되 내가 진실로 진실로 너희에게 이르노니 인자의 살을 먹지 아니하고 인자의 피를 마시지 아니하면 너희 속에 생명이 없느니라"},{"r":"막16:16","t":"믿고 세례를 받는 사람은 구원을 얻을 것이요 믿지 않는 사람은 정죄를 받으리라"},{"r":"요일5:12","t":"아들이 있는 자에게는 생명이 있고 하나님의 아들이 없는 자에게는 생명이 없느니라"},{"r":"롬2:8","t":"오직 당을 지어 진리를 좇지 아니하고 부의를 좇는 자에게는 노와 분으로 하시리라"},{"r":"엡5:6","t":"누구든지 헛된 말로 너희를 속이지 못하게 하라 이를 인하여 하나님의 진노가 부순종의 아들들에게 임하나니"},{"r":"골3:6","t":"이것들을 인하여 하나님의 진노가 임하느니라"},{"r":"요3:3","t":"예수께서 대답하여 가라사대 진실로 진실로 네게 이르노니 사람이 거듭나지 아니하면 하나님 나라를 볼 수 없느니라"}],"요3:5":[{"r":"겔36:25~27","t":"맑은 물로 너희에게 뿌려서 너희로 정결케 하되 곧 너희 모든 더러운 것에서와 모든 우상을 섬김에서 너희를 정결케 할 것이며"},{"r":"(막16:16)","t":"믿고 세례를 받는 사람은 구원을 얻을 것이요 믿지 않는 사람은 정죄를 받으리라"},{"r":"행2:38","t":"베드로가 가로되 너희가 회개하여 각각 예수 그리스도의 이름으로 세례를 받고 죄 사함을 얻으라 그리하면 성령을 선물로 받으리니"},{"r":"엡5:26","t":"이는 곧 물로 씻어 말씀으로 깨끗하게 하사 거룩하게 하시고"},{"r":"딛3:5","t":"우리를 구원하시되 우리의 행한 바 의로운 행위로 말미암지 아니하고 오직 그의 긍휼하심을 좇아 중생의 씻음과 성령의 새롭게 하심으로 하셨나니"},{"r":"히10:22","t":"우리가 마음에 뿌림을 받아 량심의 악을 깨닫고 몸을 맑은 물로 씻었으니 참 마음과 온전한 믿음으로 하나님께 나아가자"}],"요3:6":[{"r":"고전15:50","t":"형제들아 내가 이것을 말하노니 혈과 육은 하나님 나라를 유업으로 받을 수 없고 또한 썩은 것은 썩지 아니한 것을 유업으로 받지 못하느니라"},{"r":"요6:63","t":"살리는 것은 영이니 육은 무익하니라 내가 너희에게 이른 말이 영이요 생명이라"},{"r":"요4:24","t":"하나님은 영이시니 예배하는 자가 신령과 진정으로 예배할지니라"}],"요3:7":[{"r":"요3:3","t":"예수께서 대답하여 가라사대 진실로 진실로 네게 이르노니 사람이 거듭나지 아니하면 하나님 나라를 볼 수 없느니라"},{"r":"요5:28","t":"이를 기이히 여기지 말라 무덤 속에 있는 자가 다 그의 음성을 들을 때가 오나니"}],"요5:39":[{"r":"행17:11","t":"베뢰아 사람은 데살로니가에 있는 사람보다 더 신사적이어서 간절한 마음으로 말씀을 받고 이것이 그러한가 하여 날마다 성경을 상고하므로"},{"r":"딤후3:15","t":"또 네가 어려서부터 성경을 알았나니 성경은 능히 너로 하여금 그리스도 예수 안에 있는 믿음으로 말미암아 구원에 이르는 지혜가 있게 하느니라"},{"r":"눅24:27","t":"이에 모세와 및 모든 선지자의 글로 시작하여 모든 성경에 쓴바 자기에 관한 것을 자세히 설명하시니라"}],"요6:35":[{"r":"요6:41","t":"자기가 하늘로서 내려온 떡이라 하시므로 유대인들이 예수께 대하여 수군거려"},{"r":"요6:48","t":"내가 곧 생명의 떡이로다"},{"r":"요6:51","t":"나는 하늘로서 내려온 산 떡이니 사람이 이 떡을 먹으면 영생하리라 나의 줄 떡은 곧 세상의 생명을 위한 내 살이로라 하시니라"},{"r":"요6:58","t":"이것은 하늘로서 내려온 떡이니 조상들이 먹고도 죽은 그것과 같지 아니하여 이 떡을 먹는 자는 영원히 살리라"},{"r":"요4:14","t":"내가 주는 물을 먹는 자는 영원히 목마르지 아니하리니 나의 주는 물은 그 속에서 영생하도록 솟아나는 샘물이 되리라"},{"r":"요7:37","t":"명절 끝날 곧 큰날에 예수께서 서서 외쳐 가라사대 누구든지 목마르거든 내게로 와서 마시라"},{"r":"요5:40","t":"그러나 너희가 영생을 얻기 위하여 내게 오기를 원하지 아니하는도다"},{"r":"마11:28","t":"수고하고 무거운 짐진 자들아  다 내게로 오라 내가 너희를 쉬게 하리라"},{"r":"계7:16","t":"저희가 다시 주리지도 아니하며 목마르지도 아니하고 해나 아무 뜨거운 기운에 상하지 아니할지니"}],"요6:36":[{"r":"요6:26?","t":"예수께서 대답하여 가라사대 내가 진실로 진실로 너희에게 이르노니 너희가 나를 찾는 것은 표적을 본 까닭이 아니요 떡을 먹고 배부른 까닭이로다"}],"요6:53":[{"r":"요6:27","t":"썩는 량식을 위하여 일하지 말고 영생하도록 있는 량식을 위하여 하라 이 량식은 인자가 너희에게 주리니 인자는 아버지 하나님의 인치신 자니라"},{"r":"요20:31","t":"오직 이것을 기록함은 너희로 예수께서 하나님의 아들 그리스도이심을 믿게 하려 함이요 또 너희로 믿고 그 이름을 힘입어 생명을 얻게 하려 함이니라"}],"요6:54":[{"r":"요6:40","t":"내 아버지의 뜻은 아들을 보고 믿는 자마다 영생을 얻는 이것이니 마지막 날에 내가 이를 다시 살리리라 하시니라"},{"r":"요6:39","t":"나를 보내신 이의 뜻을 행하려 함이니라 나를 보내신 이의 뜻은 내게 주신 자 중에 내가 하나도 잃어 버리지 아니하고 마지막 날에 다시 살리는 이것이니라"}],"요6:56":[{"r":"요15:4,5","t":"내 안에 거하라 나도 너희 안에 거하리라 가지가 포도나무에 붙어 있지 아니하면 절로 과실을 맺을 수 없음 같이 너희도 내 안에 있지 아니하면 그러하리라"},{"r":"요일3:24","t":"그의 계명들을 지키는 자는 주 안에 거하고 주는 저 안에 거하시나니 우리에게 주신 성령으로 말미암아 그가 우리 안에 거하시는 줄을 우리가 아느니라"},{"r":"요일4:13","t":"그의 성령을 우리에게 주시므로 우리가 그 안에 거하고 그가 우리 안에 거하시는 줄을 아느니라"},{"r":"요일4:15,16","t":"누구든지 예수를 하나님의 아들이라 시인하면 하나님이 저 안에 거하시고 저도 하나님 안에 거하느니라"}],"요6:57":[{"r":"요5:26","t":"아버지께서 자기 속에 생명이 있음같이 아들에게도 생명을 주어 그 속에 있게 하셨고"},{"r":"마16:16","t":"시몬 베드로가 대답하여 가로되 주는 그리스도시요  살아계신 하나님의 아들이시니이다"},{"r":"요3:17","t":"하나님이 그 아들을 세상에 보내신 것은 세상을 심판하려 하심이 아니요 저로 말미암아 세상이 구원을 받게 하려 하심이라"},{"r":"요11:25","t":"예수께서 가라사대 나는 복활이요 생명이니 나를 믿는 자는 죽어도 살겠고"},{"r":"계1:18","t":"곧 산 자라 내가 전에 죽었었노라 볼지어다 이제 세세토록 살아 있어 사망과 음부의 열쇠를 가졌노니"}],"요6:63":[{"r":"고전15:45","t":"기록된 바 첫 사람 아담은 산 영이 되었다 함과 같이 마지막 아담은 살려 주는 영이 되었나니"},{"r":"고후3:6","t":"저가 또 우리로 새 언약의 일군 되기에 만족케 하셨으니 의문으로 하지 아니하고 오직 영으로 함이니 의문은 죽이는 것이요 영은 살리는 것임이니라"},{"r":"요3:6","t":"육으로 난 것은 육이요 성령으로 난 것은 영이니"},{"r":"요6:68","t":"시몬 베드로가 대답하여 주여, 영생의 말씀이 계시매 우리가 뉘게로 가오리이까"}],"요7:17":[{"r":"요8:31,32","t":"그러므로 예수께서 자기를 믿은 유대인들에게 이르시되 너희가 내 말에 거하면 참 내 제자가 되고"},{"r":"요14:21","t":"나의 계명을 가지고 지키는 자라야 나를 사랑하는 자니 나를 사랑하는 자는 내 아버지께 사랑을 받을 것이요 나도 그를 사랑하여 그에게 나를 나타내리라"},{"r":"요14:23","t":"예수께서 대답하여 가라사대 사람이 나를 사랑하면 내 말을 지키리니 내 아버지께서 저를 사랑하실 것이요 우리가 저에게 와서 거처를 저와 함께 하리라"},{"r":"요8:43","t":"어찌하여 내 말을 깨닫지 못하느냐  이는 내 말을 들을 줄 알지 못함이로다"},{"r":"시25:9","t":"온유한 자를 공의로 지도하심이여 온유한 자에게 그 도를 가르치시리로다"},{"r":"단12:10","t":"많은 사람이 연단을 받아 스스로 정결케 하며 희게 할 것이나 악한 사람은 악을 행하리니 악한 자는 아무도 깨닫지 못하되 오직 지혜있는 자는 깨달으리라"},{"r":"빌3:15","t":"그러므로 누구든지 우리 온전히 이룬 자들은 이렇게 생각할지니 만일 무슨 일에 너희가 달리 생각하면 하나님이 이것도 너희에게 나타내시리라"},{"r":"요5:30","t":"내가 아무 것도 스스로 할 수 없노라 듣는대로 심판하노니 나는 나의 원대로 하려 하지않고 나를 보내신 이의 원대로 하려는고로 내 심판은 의로우니라"}],"요8:29":[{"r":"요8:16","t":"만일 내가 판단하여도 내 판단이 참되니 이는 내가 혼자 있는 것이 아니요 나를 보내신 이가 나와 함께 계심이라"},{"r":"요16:32","t":"보라 너희가 다 각각 제 곳으로 흩어지고 나를 혼자 둘 때가 오나니 벌써 왔도다 그러나 내가 혼자 있는 것이 아니라 아버지께서 나와 함께 계시느니라"},{"r":"행10:38","t":"하나님이 나사렛 예수에게 성령과 능력을 기름붓듯 하셨으매 저가 두루 다니시며 착한 일을 행하시고 마귀에게 눌린 모든 자를 고치셨으니 이는 하나님이 함께 하셨음이라"},{"r":"요10:38","t":"내가 행하거든 나를 믿지 아니할지라도 그 일은 믿으라  그러면 너희가 아버지께서 내 안에 계시고 내가 아버지 안에 있음을 깨달아 알리라 하신대"},{"r":"요4:34","t":"예수께서 이르시되 나의 량식은 나를 보내신 이의 뜻을 행하며 그의 일을 온전히 이루는 이것이니라"},{"r":"요5:30","t":"내가 아무 것도 스스로 할 수 없노라 듣는대로 심판하노니 나는 나의 원대로 하려 하지않고 나를 보내신 이의 원대로 하려는고로 내 심판은 의로우니라"},{"r":"요6:38","t":"내가 하늘로서 내려온 것은 내 뜻을 행하려 함이 아니요"},{"r":"요일3:22","t":"무엇이든지 구하는 바를 그에게 받나니 이는 우리가 그의 계명들을 지키고 그 앞에서 기뻐하시는 것을 행함이라"}],"요8:44":[{"r":"요일3:8","t":"죄를 짓는 자는 마귀에게 속하나니 마귀는 처음부터 범죄함이니라 하나님의 아들이 나타나신 것은 마귀의 일을 멸하려 하심이니라"},{"r":"요일3:12","t":"가인같이 하지 말라 저는 악한 자에게 속하여 그 아우를 죽였으니 어찐 연고로 죽였느뇨 자기의 행위는 악하고 그 아우의 행위는 의로움이니라"},{"r":"요8:23","t":"예수께서 가라사대 너희는 아래서 났고 나는 위에서 났으며 너희는 이 세상에 속하였고 나는 이 세상에 속하지 아니하였느니라"},{"r":"마13:38","t":"밭은 세상이요 좋은 씨는 천국의 아들들이요 가라지는 악한 자의 아들들이요"},{"r":"창4:8,9","t":"가인이 그 아우 아벨에게 고하니라 그 후 그들이 들에 있을때에 가인이 그 아우 아벨을 쳐 죽이니라"},{"r":"요일3:12","t":"가인같이 하지 말라 저는 악한 자에게 속하여 그 아우를 죽였으니 어찐 연고로 죽였느뇨 자기의 행위는 악하고 그 아우의 행위는 의로움이니라"},{"r":"요일3:15","t":"그 형제를 미워하는 자마다 살인하는 자니 살인하는 자마다 영생이 그 속에 거하지 아니하는 것을 너희가 아는 바라"},{"r":"롬5:12","t":"이러므로 한 사람으로 말미암아 죄가 세상에 들어오고 죄로 말미암아 사망이 왔나니 이와 같이 모든 사람이 죄를 지었으므로 사망이 모든 사람에게 이르렀느니라"},{"r":"요일2:4","t":"저를 아노라 하고 그의 계명을 지키지 아니하는 자는 거짓말하는 자요 진리가 그 속에 있지 아니하되"},{"r":"창3:4","t":"뱀이 녀자에게 이르되 너희가 결코 죽지 아니하리라"},{"r":"고후11:3","t":"뱀이 그 간계로 이와를 미혹케 한 것같이 너희 마음이 그리스도를 향하는 진실함과 깨끗함에서 떠나 부패할까 두려워하노라"},{"r":"계12:9","t":"큰 용이 내어쫓기니 옛 뱀 곧 마귀라고도 하고 사단이라고도 하는 온 천하를 꾀는 자라 땅으로 내어쫓기니 그의 사자들도 저와 함께 내어 쫓기니라"}],"요일1:9":[{"r":"시32:5","t":"내가 이르기를 내 허물을 여호와께 자복하리라 하고 주께 내 죄를 아뢰고 내 죄악을 숨기지 아니하였더니 곧 주께서 내 죄의 악을 사하셨나이다 셀라"},{"r":"시51:3","t":"대저 나는 내 죄과를 아오니 내 죄가 항상 내 앞에 있나이다"},{"r":"잠28:13","t":"자기의 죄를 숨기는 자는 형통치 못하나 죄를 자복하고 버리는 자는 불쌍히 여김을 받으리라"},{"r":"시143:1","t":"(다윗의 시) 여호와여, 내 기도를 들으시며 내 간구에 귀를 기울이시고 주의 진실과 의로 내게 응답하소서"},{"r":"롬3:26","t":"곧 이 때에 자기의 의로우심을 나타내사 자기도 의로우시며 또한 예수 믿는 자를 의롭다 하려 하심이니라"}],"요일2:1":[{"r":"롬8:34","t":"누가 정죄하리요 죽으실 뿐 아니라 다시 살아나신 이는 그리스도 예수시니 그는 하나님 우편에 계신 자요 우리를 위하여 간구하시는 자시니라"},{"r":"딤전2:5","t":"하나님은 한 분이시요 또 하나님과 사람 사이에 중보도 한 분이시니 곧 사람이신 그리스도 예수라"},{"r":"히7:25","t":"그러므로 자기를 힘입어 하나님께 나아가는 자들을 온전히 구원하실 수 있으니 이는 그가 항상 살아서 저희를 위하여 간구하심이니라"},{"r":"요14:16","t":"내가 아버지께 구하겠으니 그가 또 다른 보혜사를 너희에게 주사 영원토록 너희와 함께 있게 하시리니"}],"요일2:2":[{"r":"요일4:10","t":"사랑은 여기 있으니 우리가 하나님을 사랑한 것이 아니요 오직 하나님이 우리를 사랑하사 우리 죄를 위하여 화목제로 그 아들을 보내셨음이니라"},{"r":"롬3:25","t":"이 예수를 하나님이 그의 피로 인하여 믿음으로 말미암는 화목 제물로 세우셨으니 이는 하나님께서 길이 참으시는 중에 전에 지은 죄를 간과하심으로 자기의 의로우심을 나타내려 하심이니"},{"r":"고후5:18,19","t":"모든 것이 하나님께로 났나니 저가 그리스도로 말미암아 우리를 자기와 화목하게 하시고 또 우리에게 화목하게 하는 직책을 주셨으니"},{"r":"골1:20","t":"그의 십자가의 피로 화평을 이루사 만물 곧 땅에 있는 것들이나 하늘에 있는 것들을 그로 말미암아 자기와 화목케 되기를 기뻐하심이라"},{"r":"요일4:14","t":"아버지가 아들을 세상의 구주로 보내신 것을 우리가 보았고 또 증거하노니"},{"r":"요1:29","t":"이튿날 요한이 예수께서 자기에게 나아오심을 보고 가로되 보라  세상 죄를 지고 가는 하나님의 어린 양이로다"},{"r":"요4:42","t":"그 녀자에게 말하되 이제 우리가 믿는 것은 네 말을 인함이 아니니 이는 우리가 친히 듣고 그가 참으로 세상의 구주신 줄 앎이니라 하였더라"},{"r":"요11:51,52","t":"이 말은 스스로 함이 아니요 그 해에 대제사장이므로 예수께서 그 민족을 위하시고"},{"r":"요12:32","t":"내가 땅에서 들리면 모든 사람을 내게로 이끌겠노라 하시니"}],"요일2:3":[{"r":"요14:15","t":"너희가 나를 사랑하면 나의 계명을 지키리라"},{"r":"요15:10","t":"내가 아버지의 계명을 지켜 그의 사랑 안에 거하는 것같이 너희도 내 계명을 지키면 내 사랑 안에 거하리라"},{"r":"계12:17","t":"용이 녀자에게 분노하여 돌아가서 그 녀자의 남은 자손 곧 하나님의 계명을 지키며 예수의 증거를 가진 자들로 더불어 싸우려고 바다 모래 위에 섰더라"},{"r":"계14:12","t":"성도들의 인내가 여기 있나니 저희는 하나님의 계명과 예수 믿음을 지키는 자니라"}],"요일2:4":[{"r":"요일1:8","t":"만일 우리가 죄 없다 하면 스스로 속이고 또 진리가 우리 속에 있지 아니할 것이요"},{"r":"요8:44","t":"너희는 너희 아비 마귀에게서 났으니 너희 아비의 욕심을 너희도 행하고자 하느니라 저는 처음부터 살인한 자요 진리가 그 속에 없으므로 진리에 서지 못하고 거짓을 말할 때마다 제 것으로 말하나니 이는 저가 거짓말장이요 거짓의 아비가 되었음이니라"}],"요일2:5":[{"r":"요일5:3","t":"하나님을 사랑하는 것은 이것이니 우리가 그의 계명들을 지키는 것이라 그의 계명들은 무거운 것이 아니로다"},{"r":"요14:23","t":"예수께서 대답하여 가라사대 사람이 나를 사랑하면 내 말을 지키리니 내 아버지께서 저를 사랑하실 것이요 우리가 저에게 와서 거처를 저와 함께 하리라"},{"r":"요일4:12","t":"어느 때나 하나님을 본 사람이 없으되 만일 우리가 서로 사랑하면 하나님이 우리 안에 거하시고 그의 사랑이 우리 안에 온전히 이루느니라"},{"r":"요일3:24","t":"그의 계명들을 지키는 자는 주 안에 거하고 주는 저 안에 거하시나니 우리에게 주신 성령으로 말미암아 그가 우리 안에 거하시는 줄을 우리가 아느니라"},{"r":"요일4:13","t":"그의 성령을 우리에게 주시므로 우리가 그 안에 거하고 그가 우리 안에 거하시는 줄을 아느니라"},{"r":"요일5:2","t":"우리가 하나님을 사랑하고 그의 계명들을 지킬 때에 이로써 우리가 하나님의 자녀 사랑하는 줄을 아느니라"}],"요일2:6":[{"r":"요15:4,5","t":"내 안에 거하라 나도 너희 안에 거하리라 가지가 포도나무에 붙어 있지 아니하면 절로 과실을 맺을 수 없음 같이 너희도 내 안에 있지 아니하면 그러하리라"},{"r":"요15:7","t":"너희가 내 안에 거하고 내 말이 너희 안에 거하면 무엇이든지 원하는 대로 구하라 그리하면 이루리라"},{"r":"마11:29","t":"나는 마음이 온유하고 겸손하니 나의 멍에를 메고 내게 배우라 그러면 너희 마음이 쉼을 얻으리니"}],"요일3:2":[{"r":"롬8:15","t":"너희는 다시 무서워하는 종의 영을 받지 아니하였고 양자의 영을 받았으므로 아바 아버지라 부르짖느니라"},{"r":"갈3:26","t":"너희가 다 믿음으로 말미암아 그리스도 예수 안에서 하나님의 아들이 되었으니"},{"r":"엡1:5","t":"그 기쁘신 뜻대로 우리를 예정하사 예수 그리스도로 말미암아 자기의 아들들이 되게 하셨으니"},{"r":"롬8:18","t":"생각건대 현재의 고난은 장차 우리에게 나타날 영광과 족히 비교할 수 없도다"},{"r":"고후4:17","t":"우리의 잠시 받는 환난의 경한 것이 지극히 크고 영원한 영광의 중한 것을 우리에게 이루게 함이니"},{"r":"요일2:28","t":"자녀들아 이제 그 안에 거하라 이는 주께서 나타내신 바 되면 그의 강림하실 때에 우리로 담대함을 얻어 그 앞에서 부끄럽지 않게 하려 함이라"},{"r":"롬8:29","t":"하나님이 미리 아신 자들로 또한 그 아들의 형상을 본받게 하기 위하여 미리 정하셨으니 이는 그로 많은 형제 중에서 맏아들이 되게 하려 하심이니라"},{"r":"고후3:18","t":"우리가 다 수건을 벗은 얼굴로 거울을 보는것 같이 주의 영광을 보매 저와 같은 형상으로 화하여 영광으로 영광에 이르니 곧 주의 영으로 말미암음이니라"},{"r":"고후4:11","t":"우리 산 자가 항상 예수를 위하여 죽음에 넘기움은 예수의 생명이 또한 우리 죽을 육체에 나타나게 하려 함이니라"},{"r":"빌3:21","t":"그가 만물을 자기에게 복종케 하실 수 있는 자의 역사로 우리의 낮은 몸을 자기 영광의 몸의 형체와 같이 변케 하시리라"},{"r":"벧후1:4","t":"이로써 그 보배롭고 지극히 큰 약속을 우리에게 주사 이 약속으로 말미암아 너희로 정욕을 인하여 세상에서 썩어질 것을 피하여 신의 성품에 참여하는 자가 되게 하려 하셨으니"},{"r":"요17:24","t":"아버지여 내게 주신 자도 나 있는 곳에 나와 함께 있어 아버지께서 창세 전부터 나를 사랑하시므로 내게 주신 나의 영광을 저희로 보게 하시기를 원하옵니다"},{"r":"고전13:12","t":"우리가 이제는 거울로 보는 것같이 희미하나 그 때에는 얼굴과 얼굴을 대하여 볼 것이요 이제는 내가 부분적으로 아나 그 때에는 주께서 나를 아신 것같이 내가 온전히 알리라"},{"r":"계22:4","t":"그의 얼굴을 볼 터이요 그의 이름도 저희 이마에 있으리라"}],"요일3:4":[{"r":"요일5:17","t":"모든 부의가 죄로되 사망에 이르지 아니하는 죄도 있도다"},{"r":"롬4:15","t":"률법은 진노를 이루게 하나니 률법이 없는 곳에는 범함도 없느니라"}],"요일3:8":[{"r":"마13:38","t":"밭은 세상이요 좋은 씨는 천국의 아들들이요 가라지는 악한 자의 아들들이요"},{"r":"요8:44","t":"너희는 너희 아비 마귀에게서 났으니 너희 아비의 욕심을 너희도 행하고자 하느니라 저는 처음부터 살인한 자요 진리가 그 속에 없으므로 진리에 서지 못하고 거짓을 말할 때마다 제 것으로 말하나니 이는 저가 거짓말장이요 거짓의 아비가 되었음이니라"},{"r":"히2:14","t":"자녀들은 혈육에 함께 속하였으매 그도 또한 한 모양으로 혈육에 함께 속하심은 사망으로 말미암아 사망의 세력을 잡은 자 곧 마귀를 없이 하시며"},{"r":"창3:15","t":"내가 너로 녀자와 원수가 되게 하고 너의 후손도 녀자의 후손과 원수가 되게 하리니 녀자의 후손은 네 머리를 상하게 할 것이요 너는 그의 발꿈치를 상하게 할 것이니라 하시고"},{"r":"눅10:18","t":"예수께서 이르시되 사단이 하늘로서 번개같이 떨어지는 것을 내가 보았노라"},{"r":"요16:11","t":"심판에 대하여라 함은 이 세상 임금이 심판을 받았음이니라"}],"요일4:1":[{"r":"렘29:8","t":"만군의 여호와 이스라엘의 하나님이 이같이 말하노라 너희 중 선지자들에게와 복술에게 혹하지 말며 너희가 꾼 바 꿈도 신청하지 말라"},{"r":"살전5:21","t":"범사에 헤아려 좋은 것을 취하고"},{"r":"고전12:10","t":"어떤 이에게는 능력 행함을, 어떤 이에게는 예언함을, 어떤 이에게는 영들 분별함을, 다른 이에게는 각종 방언 말함을, 어떤 이에게는 방언들 통역함을 주시나니"},{"r":"고전14:29","t":"예언하는 자는 둘이나 셋이나 말하고 다른 이들은 분변할 것이요"},{"r":"계2:2","t":"내가 네 행위와 수고와 네 인내를 알고 또 악한 자들을 용납지 아니한 것과 자칭 사도라 하되 아닌 자들을 시험하여 그 거짓된 것을 네가 드러낸 것과"},{"r":"요일2:18","t":"아이들아 이것이 마지막 때라 적그리스도가 이르겠다 함을 너희가 들은 것과 같이 지금도 많은 적그리스도가 일어났으니 이러므로 우리가 마지막 때인 줄 아노라"},{"r":"벧후2:1","t":"그러나 민간에 또한 거짓 선지자들이 일어났었나니 이와 같이 너희 중에도 거짓 선생들이 있으리라 저희는 멸망케 할 이단을 가만히 끌어들여 자기들을 사신 주를 부인하고 임박한 멸망을 스스로 취하는 자들이라"},{"r":"요이1:7","t":"미혹하는 자가 많이 세상에 나왔나니 이는 예수 그리스도께서 육체로 임하심을 부인하는 자라 이것이 미혹하는 자요 적그리스도니"}],"요일5:17":[{"r":"요일3:4","t":"죄를 짓는 자마다 부법을 행하나니 죄는 부법이라"}],"욜2:28":[{"r":"욜2:28~32","t":"그 후에 내가 내 신을 만민에게 부어 주리니 너희 자녀들이 장래일을 말할 것이며 너희 늙은이는 꿈을 꾸며 너희 젊은이는 이상을 볼 것이며"},{"r":"행2:17~21","t":"하나님이 가라사대 말세에 내가 내 영으로 모든 육체에게 부어 주리니 너희의 자녀들은 예언할 것이요 너희의 젊은이들은 환상을 보고 너희의 늙은이들은 꿈을 꾸리라"},{"r":"사32:15","t":"필경은 위에서부터 성신을 우리에게 부어주시리니 광야가 아름다운 밭이 되며 아름다운 밭을 삼림으로 여기게 되리라"},{"r":"겔39:29","t":"내가 다시는 내 얼굴을 그들에게 가리우지 아니하리니 이는 내가 내 신을 이스라엘 족속에게 쏟았음이니라 나 주 여호와의 말이니라"},{"r":"슥12:10","t":"내가 다윗의 집과 예루살렘 거민에게 은총과 간구하는 심령을 부어 주리니 그들이 그 찌른바 그를 바라보고 그를 위하여 애통하기를 독자를 위하여 애통하듯 하며 그를 위하여 통곡하기를 장자를 위하여 통곡하듯 하리로다"},{"r":"요7:39","t":"이는 그를 믿는 자의 받을 성령을 가리켜 말씀하신 것이라 예수께서 아직 영광을 받지 못하신고로 성령이 아직 저희에게 계시지 아니하시더라"},{"r":"행10:45","t":"베드로와 함께 온 할례받은 신자들이 이방인들에게도 성령 부어 주심을 인하여 놀라니"},{"r":"행2:39","t":"이 약속은 너희와 너희 자녀와 모든 먼 데 사람 곧 주 우리 하나님이 얼마든지 부르시는 자들에게 하신 것이라 하고"},{"r":"행21:9","t":"그에게 딸 넷이 있으니 처녀로 예언하는 자라"}],"욜2:29":[{"r":"고전12:13","t":"우리가 유대인이나 헬라인이나 종이나 자유자나 다 한 성령으로 세례를 받아 한 몸이 되었고 또 다 한 성령을 마시게 하셨느니라"}],"욥11:7":[{"r":"욥5:9","t":"하나님은 크고 측량할 수 없는 일을 행하시며 기이한 일을 셀 수 없이 행하시나니"},{"r":"전3:11","t":"하나님이 모든 것을 지으시되 때를 따라 아름답게 하셨고 또 사람에게 영원을 사모하는 마음을 주셨느니라 그러나 하나님의 하시는 일의 시종을 사람으로 측량할 수 없게 하셨도다"},{"r":"전8:17","t":"하나님의 모든 행사를 살펴보니 해 아래서 하시는 일을 사람이 능히 깨달을 수 없도다 사람이 아무리 애써 궁구할지라도 능히 깨닫지 못하나니 비록 지혜자가 아노라 할지라도 능히 깨닫지 못하리로다"},{"r":"시145:3","t":"여호와는 광대하시니 크게 찬양할 것이라 그의 광대하심을 측량치 못하리로다"},{"r":"롬11:33","t":"깊도다, 하나님의 지혜와 지식의 부요함이여 그의 판단은 측량치 못할 것이며 그의 길은 찾지 못할 것이로다"}],"욥11:8":[{"r":"욥22:12","t":"하나님이 높은 하늘에 계시지 아니하냐  보라, 별의 높음이 얼마나 높은가"},{"r":"시139:8","t":"내가 하늘에 올라갈지라도 거기 계시며 음부에 내 자리를 펼지라도 거기 계시니이다"}],"욥14:10":[{"r":"욥20:7","t":"자기의 똥처럼 영원히 망할 것이라 그를 본 자가 이르기를 그가 어디 있느냐  하리라"}],"욥14:11":[{"r":"사19:5","t":"바닷물이 없어지겠고 강이 잦아서 마르겠고"}],"욥14:12":[{"r":"신11:21","t":"그리하면 여호와께서 너희 열조에게 주리라고 맹서하신 땅에서 너희의 날과 너희 자녀의 날이 많아서 하늘이 땅을 덮는 날의 장구함 같으리라"},{"r":"시89:29","t":"또 그 후손을 영구케 하여 그 위를 하늘의 날과 같게 하리로다"},{"r":"시72:5","t":"저희가 해가 있을 동안에 주를 두려워하며 달이 있을 동안에 대대로 그리하리로다"},{"r":"마5:18","t":"진실로 너희에게 이르노니 천지가 없어지기 전에는 률법의 일점 일획이라도 반드시 없어지지 아니하고 다 이루리라"},{"r":"요11:11","t":"이 말씀을 하신 후에 또 가라사대 우리 친구 나사로가 잠들었도다 그러나 내가 깨우러 가노라"}],"욥7:10":[{"r":"욥10:21","t":"내가 돌아오지 못할 땅 곧 어둡고 죽음의 그늘진 땅으로 가기 전에 그리하옵소서"},{"r":"삼하12:23","t":"시방은 죽었으니 어찌 금식하랴 내가 다시 돌아오게 할 수 있느냐  나는 저에게로 가려니와 저는 내게로 돌아오지 아니하리라"},{"r":"욥20:9","t":"그를 본 눈이 다시 그를 보지 못할 것이요 그의 처소도 다시 그를 보지 못할 것이며"},{"r":"시103:16","t":"그것은 바람이 지나면 없어지나니 그곳이 다시 알지 못하거니와"},{"r":"욥8:18","t":"그곳에서 뽑히면 그 자리도 모르는 체하고 이르기를 내가 너를 보지 못하였다 하리니"}],"욥7:21":[{"r":"단12:2","t":"땅의 티끌 가운데서 자는 자 중에 많이 깨어 영생을 얻는 자도 있겠고 수욕을 받아서 무궁히 부끄러움을 입을 자도 있을 것이며"},{"r":"욥8:5","t":"네가 만일 하나님을 부지런히 구하며 전능하신 이에게 빌고"},{"r":"욥24:5","t":"그들은 거친 땅의 들나귀 같아서 나가서 일하며 먹을 것을 부지런히 구하니 광야가 그 자식을 위하여 그에게 식물을 내는구나"},{"r":"잠1:28","t":"그 때에 너희가 나를 부르리라 그래도 내가 대답지 아니하겠고 부지런히 나를 찾으리라 그래도 나를 만나지 못하리니"},{"r":"욥7:8","t":"나를 본 자의 눈이 다시는 나를 보지 못할 것이고 주의 눈이 나를 향하실지라도 내가 있지 아니하리이다"}],"욥7:9":[{"r":"욥30:15","t":"놀람이 내게 임하는구나 그들이 내 영광을 바람 같이 모니 내 복록이 구름 같이 지나갔구나"},{"r":"욥21:13","t":"그날을 형통하게 지내다가 경각간에 음부에 내려가느니라"}],"유1:7":[{"r":"창19:24","t":"여호와께서 하늘 곧 여호와에게로서 류황과 불을 비같이 소돔과 고모라에 내리사"},{"r":"신29:23","t":"그 온 땅이 류황이 되며 소금이 되며 또 불에 타서 심지도 못하며 결실함도 없으며 거기 아무 풀도 나지 아니함이 옛적에 여호와께서 진노와 분한으로 훼멸하신 소돔과 고모라와 아드마와 스보임의 무너짐과 같음을 보고 말할 것이요"},{"r":"호11:8","t":"에브라임이여 내가 어찌 너를 놓겠느냐  이스라엘이여 내가 어찌 너를 버리겠느냐  내가 어찌 아드마같이 놓겠느냐  어찌 너를 스보임같이 두겠느냐  내 마음이 내 속에서 돌아서 나의 긍휼이 온전히 불붙듯 하도다"},{"r":"벧후2:10","t":"육체를 따라 더러운 정욕 가운데서 행하며 주관하는 이를 멸시하는 자들에게 특별히 형벌하실 줄을 아시느니라 이들은 담대하고 고집하여 떨지 않고 영광 있는 자를 훼방하거니와"}],"잠2:1":[{"r":"잠1:8","t":"내 아들아, 네 아비의 훈계를 들으며 네 어미의 법을 떠나지 말라"},{"r":"잠4:1","t":"아들들아, 아비의 훈계를 들으며 명철을 얻기에 주의하라"},{"r":"잠4:10","t":"내 아들아, 들으라 내 말을 받으라 그리하면 네 생명의 해가 길리라"},{"r":"잠4:20","t":"내 아들아, 내 말에 주의하며 나의 이르는 것에 네 귀를 기울이라"},{"r":"잠7:1","t":"내 아들아, 내 말을 지키며 내 명령을 네게 간직하라"}],"잠2:3":[{"r":"잠4:1","t":"아들들아, 아비의 훈계를 들으며 명철을 얻기에 주의하라"},{"r":"잠4:5","t":"지혜를 얻으며 명철을 얻으라 내 입의 말을 잊지 말며 어기지 말라"},{"r":"잠4:7","t":"지혜가 제일이니 지혜를 얻으라  무릇 너의 얻은 것을 가져 명철을 얻을지니라"}],"잠2:4":[{"r":"잠3:14","t":"이는 지혜를 얻는 것이 은을 얻는 것보다 낫고 그 리익이 정김보다 나음이니라"},{"r":"욥3:21","t":"이러한 자는 죽기를 바라도 오지 아니하니 그것을 구하기를 땅을 파고 숨긴 보배를 찾음보다 더하다가"},{"r":"마13:44","t":"천국은 마치 밭에 감추인 보화와 같으니 사람이 이를 발견한 후 숨겨두고 기뻐하여 돌아가서 자기의 소유를 다 팔아 그 밭을 샀느니라"}],"잠2:5":[{"r":"시25:14","t":"여호와의 친밀함이 경외하는 자에게 있음이여 그 언약을 저희에게 보이시리로다"},{"r":"요7:17","t":"사람이 하나님의 뜻을 행하려 하면 이 교훈이 하나님께로서 왔는지 내가 스스로 말함인지 알리라"},{"r":"요14:21","t":"나의 계명을 가지고 지키는 자라야 나를 사랑하는 자니 나를 사랑하는 자는 내 아버지께 사랑을 받을 것이요 나도 그를 사랑하여 그에게 나를 나타내리라"}],"전12:1":[{"r":"애3:27","t":"사람이 젊었을 때에 멍에를 메는 것이 좋으니"},{"r":"전11:8","t":"사람이 여러 해를 살면 항상 즐거워할지로다 그러나 캄캄한 날이 많으리니 그 날을 생각할지로다 장래 일은 다 헛되도다"},{"r":"삼하19:35","t":"내 나이 이제 팔십세라 어떻게 좋고 흉한 것을 분간할 수 있사오며 음식의 맛을 알 수 있사오리이까  어떻게 다시 노래하는 남자나 녀인의 소리를 알아 들을 수 있사오리이까  어찌하여 종이 내 주 왕께 오히려 누를 끼치리이까"}],"전12:13":[{"r":"전5:7","t":"꿈이 많으면 헛된 것이 많고 말이 많아도 그러하니 오직 너는 하나님을 경외할지니라"},{"r":"신6:2","t":"곧 너와 네 아들과 네 손자로 평생에 네 하나님 여호와를 경외하며 내가 너희에게 명한 그 모든 규례와 명령을 지키게 하기 위한 것이며 또 네 날을 장구케 하기 위한 것이라"},{"r":"신10:12","t":"이스라엘아, 네 하나님 여호와께서 네게 요구하시는 것이 무엇이냐  곧 네 하나님 여호와를 경외하여 그 모든 도를 행하고 그를 사랑하며 마음을 다하고 성품을 다하여 네 하나님 여호와를 섬기고"}],"전12:14":[{"r":"전11:9","t":"청년이여 네 어린 때를 즐거워 하며 네 청년의 날을 마음에 기뻐하여 마음에 원하는 길과 네 눈이 보는대로 좇아 행하라 그러나 하나님이 이 모든 일로 인하여 너를 심판하실 줄 알라"},{"r":"욥19:29","t":"너희는 칼을 두려워할지니라 분노는 칼의 형벌을 부르나니 너희가 심판이 있는 줄을 알게 되리라"},{"r":"마12:36","t":"내가 너희에게 이르노니 사람이 무슨 무익한 말을 하든지 심판 날에 이에 대하여 심문을 받으리니"},{"r":"행17:31","t":"이는 정하신 사람으로 하여금 천하를 공의로 심판할 날을 작정하시고 이에 저를 죽은 자 가운데서 다시 살리신 것으로 모든 사람에게 믿을 만한 증거를 주셨음이니라 하니라"},{"r":"롬2:16","t":"곧 내 복음에 이른 바와 같이 하나님이 예수 그리스도로 말미암아 사람들의 은밀한 것을 심판하시는 그날이라"},{"r":"롬14:10","t":"네가 어찌하여 네 형제를 판단하느뇨 어찌하여 네 형제를 업신여기느뇨 우리가 다 하나님의 심판대 앞에 서리라"},{"r":"롬14:12","t":"이러므로 우리 각인이 자기 일을 하나님께 직고하리라"},{"r":"고전4:5","t":"그러므로 때가 이르기 전 곧 주께서 오시기까지 아무 것도 판단치 말라 그가 어두움에 감추인 것들을 드러내고 마음의 뜻을 나타내시리니 그때에 각 사람에게 하나님께로부터 칭찬이 있으리라"},{"r":"전3:15","t":"이제 있는 것이 옛적에 있었고 장래에 있을 것도 옛적에 있었나니 하나님은 이미 지난 것을 다시 찾으시느니라"},{"r":"전3:17","t":"내가 심중에 이르기를 의인과 악인을 하나님이 심판하시리니 이는 모든 목적과 모든 일이 이룰 때가 있음이라 하였으며"},{"r":"창18:25","t":"주께서 이같이 하사 의인을 악인과 함께 죽이심은 부가하오며 의인과 악인을 균등히 하심도 부가하니이다 세상을 심판하시는 이가 공의를 행하실 것이 아니니이까"},{"r":"시58:11","t":"때에 사람의 말이 진실로 의인에게 갚음이 있고 진실로 땅에서 판단하시는 하나님이 계시다 하리로다"}],"전9:5":[{"r":"욥14:21","t":"그 아들이 존귀하나 그가 알지 못하며 비천하나 그가 깨닫지 못하나이다"},{"r":"전1:11","t":"이전 세대를 기억함이 없으니 장래 세대도 그 후 세대가 기억함이 없으리라"},{"r":"전8:10","t":"내가 본즉 악인은 장사 지낸 바 되어 무덤에 들어 갔고 선을 행한 자는 거룩한 곳에서 떠나 성읍 사람의 잊어버린 바 되었으니 이것도 헛되도다"},{"r":"시31:12","t":"내가 잊어버린바 됨이 사망한 자를 마음에 두지 아니함 같고 파기와 같으니이다"},{"r":"시88:5","t":"사망자 중에 던지운 바 되었으며 살륙을 당하여 무덤에 누운 자 같으니이다 주께서 저희를 다시 기억지 아니하시니 저희는 주의 손에서 끊어진 자니이다"},{"r":"시88:12","t":"흑암 중에서 주의 기사와, 잊음의 땅에서 주의 의를 알 수 있으리이까"},{"r":"사26:14","t":"그들은 죽었은즉 다시 살지 못하겠고 사망하였은즉 일어나지 못할 것이니 이는 주께서 벌하여 멸하사 그 모든 기억을 멸절하였음이니이다"}],"창15:4":[{"r":"창17:16","t":"내가 그에게 복을 주어 그로 네게 아들을 낳아 주게 하며 내가 그에게 복을 주어 그로 렬국의 어미가 되게 하리니 민족의 열왕이 그에게서 나리라"}],"창15:5":[{"r":"시147:4","t":"저가 별의 수효를 계수하시고 저희를 다 이름대로 부르시는도다"},{"r":"창22:17","t":"내가 네게 큰 복을 주고 네 씨로 크게 성하여 하늘의 별과 같고 바닷가의 모래와 같게 하리니 네 씨가 그 대적의 문을 얻으리라"},{"r":"창26:4","t":"네 자손을 하늘의 별과 같이 번성케 하며 이 모든 땅을 네 자손에게 주리니 네 자손을 인하여 천하 만민이 복을 받으리라"},{"r":"출32:13","t":"주의 종 아브라함과 이삭과 이스라엘을 기억하소서  주께서 주를 가리켜 그들에게 맹서하여 이르시기를 내가 너희 자손을 하늘의 별처럼 많게 하고 나의 허락한 이 온 땅을 너희의 자손에게 주어 영원한 기업이 되게 하리라 하셨나이다"},{"r":"신1:10","t":"너희 하나님 여호와께서 너희를 번성케 하셨으므로 너희가 오늘날 하늘의 별 같이 많거니와"},{"r":"신10:22","t":"애굽에 내려간 네 열조가 겨우 칠십인이었으나 이제는 네 하나님 여호와께서 너를 하늘의 별같이 많게 하셨느니라"},{"r":"대상27:23","t":"이스라엘 사람의 이십세 이하의 수효는 다윗이 조사하지 아니하였으니 이는 여호와께서 전에 말씀하시기를 이스라엘 사람을 하늘의 별같이 많게 하리라 하셨음이라"},{"r":"히11:12","t":"이러므로 죽은 자와 방불한 한 사람으로 말미암아 하늘에 허다한 별과 또 해변의 무수한 모래와 같이 많이 생육하였느니라"},{"r":"롬4:18","t":"아브라함이 바랄 수 없는 중에 바라고 믿었으니 이는 네 후손이 이같으리라 하신 말씀대로 많은 민족의 조상이 되게 하려 하심을 인함이라"}],"창15:6":[{"r":"롬4:9","t":"그런즉 이 행복이 할례자에게뇨 혹 무할례자에게도뇨 대저 우리가 말하기를 아브라함에게는 그 믿음을 의로 여기셨다 하노라"},{"r":"롬4:22","t":"그러므로 이것을 저에게 의로 여기셨느니라"},{"r":"갈3:6","t":"아브라함이 하나님을 믿으매 이것을 그에게 의로 정하셨다 함과 같으니라"},{"r":"약2:23","t":"이에 경에 이른 바 아브라함이 하나님을 믿으니 이것을 의로 여기셨다는 말씀이 응하였고 그는 하나님의 벗이라 칭함을 받았나니"},{"r":"롬4:3","t":"성경이 무엇을 말하느뇨 아브라함이 하나님을 믿으매 이것이 저에게 의로 여기신바 되었느니라"},{"r":"시106:13","t":"저희가 미구에 그 행사를 잊어버리며 그 가르침을 기다리지 아니하고"}],"창1:2":[{"r":"렘4:23","t":"내가 땅을 본즉 혼돈하고 공허하며 하늘들을 우러른즉 거기 빛이 없으며"}],"창1:26":[{"r":"창3:22","t":"여호와 하나님이 가라사대 보라, 이 사람이 선악을 아는 일에 우리 중 하나같이 되었으니 그가 그 손을 들어 생명나무 실과도 먹고 영생할까 하노라 하시고"},{"r":"창11:7","t":"자, 우리가 내려가서 거기서 그들의 언어를 혼잡케 하여 그들로 서로 알아듣지 못하게 하자 하시고"},{"r":"사6:8","t":"내가 또 주의 목소리를 들은즉 이르시되 내가 누구를 보내며 누가 우리를 위하여 갈꼬 그 때에 내가 가로되 내가 여기 있나이다 나를 보내소서"},{"r":"창5:1","t":"아담 자손의 계보가 이러하니라 하나님이 사람을 창조하실 때에 하나님의 형상대로 지으시되"},{"r":"창9:6","t":"무릇 사람의 피를 흘리면 사람이 그 피를 흘릴 것이니 이는 하나님이 자기 형상대로 사람을 지었음이니라"},{"r":"고전11:7","t":"남자는 하나님의 형상과 영광이니 그 머리에 마땅히 쓰지 않거니와 녀자는 남자의 영광이니라"},{"r":"엡4:24","t":"하나님을 따라 의와 진리의 거룩함으로 지으심을 받은 새 사람을 입으라"},{"r":"골3:10","t":"새 사람을 입었으니 이는 자기를 창조하신 자의 형상을 좇아 지식에까지 새롭게 하심을 받는 자니라"},{"r":"약3:9","t":"이것으로 우리가 주 아버지를 찬송하고 또 이것으로 하나님의 형상대로 지음을 받은 사람을 저주하나니"},{"r":"창9:2","t":"땅의 모든 짐승과 공중의 모든 새와 땅에 기는 모든 것과 바다의 모든 고기가 너희를 두려워하며 너희를 무서워하리니 이들은 너희 손에 붙이웠음이라"},{"r":"시8:6~8","t":"주의 손으로 만드신 것을 다스리게 하시고 만물을 그 발 아래 두셨으니"},{"r":"약3:7","t":"여러 종류의 짐승과 새며 벌레와 해물은 다 길들므로 사람에게 길들었거니와"}],"창1:29":[{"r":"창9:3","t":"무릇 산 동물은 너희의 식물이 될지라 채소같이 내가 이것을 다 너희에게 주노라"},{"r":"시104:14,15","t":"저가 가축을 위한 풀과 사람의 소용을 위한 채소를 자라게 하시며 땅에서 식물이 나게 하시고"},{"r":"시145:15,16","t":"중생의 눈이 주를 앙망하오니 주는 때를 따라 저희에게 식물을 주시며"}],"창1:31":[{"r":"전7:29","t":"나의 깨달은 것이 이것이라 곧 하나님이 사람을 정직하게 지으셨으나 사람은 많은 꾀를 낸 것이니라"},{"r":"딤전4:4","t":"하나님의 지으신 모든 것이 선하매 감사함으로 받으면 버릴 것이 없나니"}],"창2:1":[{"r":"신4:19","t":"또 두렵건대 네가 하늘을 향하여 눈을 들어 일월 성신 하늘 위의 군중 곧 너희 하나님 여호와께서 천하 만민을 위하여 분정하신 것을 보고 미혹하여 그것에 경배하며 섬길까 하노라"},{"r":"시33:6","t":"여호와의 말씀으로 하늘이 지음이 되었으며 그 만상이 그 입기운으로 이루었도다"}],"창2:17":[{"r":"창3:1~3","t":"여호와 하나님의 지으신 들짐승 중에 뱀이 가장 간교하더라 뱀이 녀자에게 물어 가로되 하나님이 참으로 너희더러 동산 모든 나무의 실과를 먹지 말라 하시더냐"},{"r":"창3:11","t":"가라사대 누가 너의 벗었음을 네게 고하였느냐  내가 너더러 먹지 말라 명한 그 나무 실과를 네가 먹었느냐"},{"r":"창3:17","t":"아담에게 이르시되 네가 네 아내의 말을 듣고 내가 너더러 먹지 말라 한 나무 실과를 먹었은즉 땅은 너로 인하여 저주를 받고 너는 종신토록 수고하여야 그 소산을 먹으리라"},{"r":"롬6:23","t":"죄의 삯은 사망이요 하나님의 은사는 그리스도 예수 우리 주 안에 있는 영생이니라"},{"r":"약1:15","t":"욕심이 잉태한즉 죄를 낳고 죄가 장성한즉 사망을 낳느니라"}],"창2:2":[{"r":"출20:8~11","t":"안식일을 기억하여 거룩히 지키라"},{"r":"출31:17","t":"이는 나와 이스라엘 자손 사이에 영원한 표징이며 나 여호와가 엿새 동안에 천지를 창조하고 제 칠일에 쉬어 평안하였음이니라 하라"},{"r":"신5:12~14","t":"여호와 너의 하나님이 네게 명한대로 안식일을 지켜 거룩하게 하라"},{"r":"히4:4","t":"제 칠일에 관하여는 어디 이렇게 일렀으되 하나님은 제 칠일에 그의 모든 일을 쉬셨다 하였으며"}],"창2:7":[{"r":"창3:19","t":"네가 얼굴에 땀이 흘러야 식물을 먹고 필경은 흙으로 돌아가리니 그 속에서 네가 취함을 입었음이라 너는 흙이니 흙으로 돌아 갈 것이니라 하시니라"},{"r":"창3:23","t":"여호와 하나님이 에덴 동산에서 그 사람을 내어 보내어 그의 근본된 토지를 갈게 하시니라"},{"r":"창18:27","t":"아브라함이 말씀하여 가로되 티끌과 같은 나라도 감히 주께 고하나이다"},{"r":"시103:14","t":"이는 저가 우리의 체질을 아시며 우리가 진토임을 기억하심이로다"},{"r":"전12:7","t":"흙은 여전히 땅으로 돌아가고 신은 그 주신 하나님께로 돌아가기 전에 기억하라"},{"r":"고전15:47","t":"첫 사람은 땅에서 났으니 흙에 속한 자이거니와 둘째 사람은 하늘에서 나셨느니라"},{"r":"욥27:3","t":"나의 생명이 아직 내 속에 완전히 있고 하나님의 기운이 오히려 내 코에 있느니라"},{"r":"창7:22","t":"륙지에 있어 코로 생물의 기식을 호흡하는 것은 다 죽었더라"},{"r":"욥33:4","t":"하나님의 신이 나를 지으셨고 전능자의 기운이 나를 살리시느니라"},{"r":"사2:22","t":"너희는 인생을 의지하지 말라 그의 호흡은 코에 있나니 수에 칠 가치가 어디 있느뇨"}],"창3:17":[{"r":"창2:17","t":"선악을 알게하는 나무의 실과는 먹지 말라, 네가 먹는 날에는 정녕 죽으리라  하시니라"},{"r":"창5:29","t":"이름을 노아라 하여 가로되 여호와께서 땅을 저주하시므로 수고로이 일하는 우리를 이 아들이 안위하리라 하였더라"},{"r":"전2:22,23","t":"사람이 해 아래서 수고하는 모든 수고와 마음에 애쓰는 것으로 소득이 무엇이랴"}],"창3:19":[{"r":"시90:3","t":"주께서 사람을 티끌로 돌아가게 하시고 말씀하시기를 너희 인생들은 돌아가라 하셨사오니"},{"r":"창2:7","t":"여호와 하나님이 흙으로 사람을 지으시고 생기를 그 코에 불어 넣으시니 사람이 생령이 된지라"},{"r":"시103:14","t":"이는 저가 우리의 체질을 아시며 우리가 진토임을 기억하심이로다"},{"r":"욥34:15","t":"모든 혈기 있는 자가 일체로 망하고 사람도 진토로 돌아가리라"},{"r":"시104:29","t":"주께서 낯을 숨기신즉 저희가 떨고 주께서 저희 호흡을 취하신즉 저희가 죽어 본 흙으로 돌아가나이다"},{"r":"전3:20","t":"다 흙으로 말미암았으므로 다 흙으로 돌아가나니 다 한 곳으로 가거니와"},{"r":"전12:7","t":"흙은 여전히 땅으로 돌아가고 신은 그 주신 하나님께로 돌아가기 전에 기억하라"},{"r":"롬5:12","t":"이러므로 한 사람으로 말미암아 죄가 세상에 들어오고 죄로 말미암아 사망이 왔나니 이와 같이 모든 사람이 죄를 지었으므로 사망이 모든 사람에게 이르렀느니라"}],"창40:8":[{"r":"창41:15","t":"바로가 요셉에게 이르되 내가 한 꿈을 꾸었으나 그것을 해석하는 자가 없더니 들은즉 너는 꿈을 들으면 능히 푼다더라"},{"r":"창41:16","t":"요셉이 바로에게 대답하여 가로되 이는 내게 있는 것이 아니라 하나님이 바로에게 평안한 대답을 하시리이다"},{"r":"단2:28","t":"오직 은밀한 것을 나타내실 자는 하늘에 계신 하나님이시라 그가 느부갓네살왕에게 후일에 될 일을 알게 하셨나이다 왕의 꿈 곧 왕이 침상에서 뇌 속으로 받은 이상은 이러하니이다"},{"r":"단2:47","t":"왕이 대답하여 다니엘에게 이르되 너희 하나님은 참으로 모든 신의 신이시요 모든 왕의 주재시로다 네가 능히 이 은밀한 것을 나타내었으니 네 하나님은 또 은밀한 것을 나타내시는 자시로다"}],"창9:3":[{"r":"신12:15","t":"그러나 네 하나님 여호와께서 네게 주신 복을 따라 각 성에서 네 마음에 즐기는 대로 생축을 잡아 그 고기를 먹을 수 있나니 곧 정한 자나 불정한 자를 무론하고 노루나 사슴을 먹음과 같이 먹으려니와"},{"r":"딤전4:3,4","t":"혼인을 금하고 식물을 폐하라 할 터이나 식물은 하나님이 지으신 바니 믿는 자들과 진리를 아는 자들이 감사함으로 받을 것이니라"},{"r":"창1:29","t":"하나님이 가라사대 내가 온 지면의 씨 맺는 모든 채소와 씨 가진 열매 맺는 모든 나무를 너희에게 주노니 너희 식물이 되리라"}],"창9:4":[{"r":"레17:10","t":"무릇 이스라엘 집 사람이나 그들 중에 우거하는 타국인 중에 어떤 피든지 먹는 자가 있으면 내가 그 피 먹는 사람에게 진노하여 그를 백성 중에서 끊으리니"},{"r":"레17:11","t":"육체의 생명은 피에 있음이라 내가 이 피를 너희에게 주어 단에 뿌려 너희의 생명을 위하여 속하게 하였나니 생명이 피에 있으므로 피가 죄를 속하느니라"},{"r":"레17:14","t":"모든 생물은 그 피가 생명과 일체라 그러므로 내가 이스라엘 자손에게 이르기를 너희는 어느 육체의 피든지 먹지 말라 하였나니 모든 육체의 생명은 그 피인즉 무릇 피를 먹는 자는 끊쳐지리라"},{"r":"신12:16","t":"오직 그 피는 먹지 말고 물 같이 땅에 쏟을 것이며"},{"r":"신12:23","t":"오직 크게 삼가서 그 피는 먹지 말라 피는 그 생명인즉 네가 그 생명을 고기와 아울러 먹지 못하리니"},{"r":"삼상14:33","t":"무리가 사울에게 고하여 가로되 보소서, 백성이 고기를 피채 먹어 여호와께 범죄하였나이다 사울이 가로되 너희가 무신하게 행하였도다 이제 큰 돌을 내게로 굴려오라 하고"},{"r":"행15:20","t":"다만 우상의 더러운 것과 음행과 목매어 죽인 것과 피를 멀리하라고 편지하는 것이 가하니"},{"r":"행15:29","t":"우상의 제물과 피와 목매어 죽인 것과 음행을 멀리 할지니라 이에 스스로 삼가면 잘되리라 평안함을 원하노라 하였더라"}],"출15:26":[{"r":"레26:3~13","t":"너희가 나의 규례와 계명을 준행하면"},{"r":"신7:12~15","t":"너희가 이 모든 법도를 듣고 지켜 행하면 네 하나님 여호와께서 네 열조에게 맹서하신 언약을 지켜 네게 인애를 베푸실 것이라"},{"r":"신28:27","t":"여호와께서 애굽의 종기와, 치질과, 괴혈병과, 개창으로 너를 치시리니 네가 치료함을 얻지 못할 것이며"},{"r":"신28:60","t":"여호와께서 네가 두려워하던 애굽의 모든 질병을 네게로 가져다가 네 몸에 들어붓게 하실 것이며"},{"r":"출23:25","t":"너의 하나님 여호와를 섬기라  그리하면 여호와가 너희의 량식과 물에 복을 내리고 너희 중에 병을 제하리니"},{"r":"시103:3","t":"저가 네 모든 죄악을 사하시며 네 모든 병을 고치시며"},{"r":"시147:3","t":"상심한 자를 고치시며 저희 상처를 싸매시는도다"},{"r":"호6:1","t":"오라, 우리가 여호와께로 돌아가자 여호와께서 우리를 찢으셨으나 도로 낫게 하실 것이요 우리를 치셨으나 싸매어 주실 것임이라"}],"출16:4":[{"r":"느9:15","t":"저희의 주림을 인하여 하늘에서 량식을 주시며 저희의 목마름을 인하여 반석에서 물을 내시고 또 주께서 옛적에 손을 들어 맹서하시고 주마 하신 땅을 들어가서 차지하라 명하셨사오나"},{"r":"시78:24,25","t":"저희에게 {만나}를 비같이 내려 먹이시며 하늘 량식으로 주셨나니"},{"r":"시105:40","t":"그들이 구한즉 메추라기로 오게 하시며 또 하늘 량식으로 그들을 만족케 하셨도다"},{"r":"요6:31,32","t":"기록된 바 하늘에서 저희에게 떡을 주어 먹게 하였다 함과 같이 우리 조상들은 광야에서 만나를 먹었나이다"},{"r":"고전10:3","t":"다 같은 신령한 식물을 먹으며"},{"r":"출15:25","t":"모세가 여호와께 부르짖었더니 여호와께서 그에게 한 나무를 지시하시니 그가 물에 던지매 물이 달아졌더라 거기서 여호와께서 그들을 위하여 법도와 율례를 정하시고 그들을 시험하실쌔"}],"출16:5":[{"r":"출16:22","t":"제 육일에는 각 사람이 갑절의 식물 곧 하나에 두 오멜씩 거둔지라 회중의 모든 두목이 와서 모세에게 고하매"}],"출20:10":[{"r":"출16:26","t":"육일 동안은 너희가 그것을 거두되 제 칠일은 안식일인즉 그날에는 없으리라 하였으나"},{"r":"출31:15","t":"엿새 동안은 일할 것이나 제 칠일은 큰 안식일이니 여호와께 거룩한 것이라 무릇 안식일에 일하는 자를 반드시 죽일지니라"},{"r":"창2:2,3","t":"하나님의 지으시던 일이 일곱째 날이 이를 때에 마치니 그 지으시던 일이 다하므로 일곱째 날에 안식하시니라"},{"r":"겔20:12","t":"또 나는 그들을 거룩하게 하는 여호와인 줄 알게 하려하여 내가 내 안식일을 주어 그들과 나 사이에 표징을 삼았었노라"},{"r":"민15:32~36","t":"이스라엘 자손이 광야에 거할 때에 안식일에 어떤 사람이 나무하는 것을 발견한지라"},{"r":"느13:16~19","t":"또 두로 사람이 예루살렘에 거하며 물고기와 각양 물건을 가져다가 안식일에 유다 자손에게 예루살렘에서도 팔기로"}],"출20:11":[{"r":"창1장","t":"태초에 하나님이 천지를 창조하시니라"},{"r":"창2:1~3","t":"천지와 만물이 다 이루니라"}],"출20:8":[{"r":"레19:3","t":"너희 각 사람은 부모를 경외하고 나의 안식일을 지키라  나는 너희 하나님 여호와니라"},{"r":"레19:30","t":"내 안식일을 지키고 내 성소를 공경하라 나는 여호와니라"},{"r":"레26:2","t":"너희는 나의 안식일을 지키며 나의 성소를 공경하라 나는 여호와니라"},{"r":"출31:13~17","t":"너는 이스라엘 자손에게 고하여 이르기를 너희는 나의 안식일을 지키라  이는 나와 너희 사이에 너희 대대의 표징이니 나는 너희를 거룩하게 하는 여호와인 줄 너희로 알게 함이라"}],"출20:9":[{"r":"출23:12","t":"너는 육일 동안에 네 일을 하고 제 칠일에는 쉬라 네 소와 나귀가 쉴 것이며 네 계집 종의 자식과 나그네가 숨을 돌리리라"},{"r":"출34:21","t":"너는 엿새동안 일하고 제 칠일에는 쉴지니 밭 갈 때에나 거둘 때에도 쉴지며"},{"r":"출35:2","t":"엿새 동안은 일하고 제 칠일은 너희에게 성일이니 여호와께 특별한 안식일이라 무릇 이날에 일하는 자를 죽일지니"},{"r":"레23:3","t":"엿새 동안은 일할 것이요 일곱째 날은 쉴 안식일이니 성회라 너희는 무슨 일이든지 하지 말라 이는 너희 거하는 각처에서 지킬 여호와의 안식일이니라"},{"r":"눅13:14","t":"회당장이 예수께서 안식일에 병고치시는 것을 분내어 무리에게 이르되 일할 날이 엿새가 있으니 그 동안에 와서 고침을 받을 것이요 안식일에는 말 것이니라 하거늘"}],"출32:1":[{"r":"출24:18","t":"모세는 구름 속으로 들어가서 산 위에 올랐으며 사십일 사십야를 산에 있으니라"},{"r":"신9:9","t":"그 때에 내가 돌판들 곧 여호와께서 너희와 세우신 언약의 돌판들을 받으려고 산에 올라가서 사십 주야를 산에 거하며 떡도 먹지 아니하고 물도 마시지 아니하였더니"},{"r":"출13:21","t":"여호와께서 그들 앞에 행하사 낮에는 구름 기둥으로 그들의 길을 인도하시고 밤에는 불기둥으로 그들에게 비취사 주야로 진행하게 하시니"},{"r":"출32:23","t":"그들이 내게 말하기를 우리를 위하여 우리를 인도할 신을 만들라 이 모세 곧 우리를 애굽 땅에서 인도하여 낸 사람은 어찌 되었는지 알 수 없노라 하기에"},{"r":"행7:40","t":"아론더러 이르되 우리를 인도할 신들을 우리를 위하여 만들라 애굽 땅에서 우리를 인도하던 이 모세는 어떻게 되었는지 알지 못하노라 하고"}],"출32:2":[{"r":"출12:35,36","t":"이스라엘 자손이 모세의 말대로 하여 애굽 사람에게 은,김 패물과 의복을 구하매"},{"r":"삿8:24~27","t":"기드온이 또 그들에게 이르되 내가 너희에게 한 일을 청구하노니 너희는 각기 탈취한 귀고리를 내게 줄지니라 하니 그 대적은 이스마엘 사람이므로 김 귀고리가 있었음이라"}],"출32:4":[{"r":"신9:16","t":"내가 본즉 너희가 너희 하나님 여호와께 범죄하여 자기를 위하여 송아지를 부어 만들어서 급속히 여호와의 명하신 도를 떠났기로"},{"r":"느9:18","t":"또 저희가 송아지를 부어 만들고 이르기를 이는 곧 너희를 인도하여 애굽에서 나오게 하신 하나님이라 하여 크게 설만하게 하였사오나"},{"r":"시106:19","t":"저희가 호렙에서 송아지를 만들고 부어 만든 우상을 숭배하여"},{"r":"행7:41","t":"그 때에 저희가 송아지를 만들어 그 우상 앞에 제사하며 자기 손으로 만든 것을 기뻐하더니"},{"r":"삿17:3,4","t":"미가가 은 일천 일백을 그 어미에게 도로 주매 어미가 가로되 내가 내 아들을 위하여 한 신상을 새기며 한 신상을 부어만들 차로 내 손에서 이 은을 여호와께 거룩히 드리노라 그러므로 내가 이제 이 은을 네게 도로 돌리리라"},{"r":"왕상12:28","t":"이에 계획하고 두 김송아지를 만들고 무리에게 말하기를 너희가 다시는 예루살렘에 올라갈 것이 없도다 이스라엘아, 이는 너희를 애굽 땅에서 인도하여 올린 너희 신이라 하고"}],"출32:5":[{"r":"왕하10:20","t":"예후가 바알을 위하는 대회를 거룩히 열라 하매 드디어 공포하였더라"}],"출32:6":[{"r":"고전10:7","t":"저희 중에 어떤 이들과 같이 너희는 우상 숭배하는 자가 되지 말라 기록된 바 백성이 앉아서 먹고 마시며 일어나서 뛰논다 함과 같으니라"},{"r":"창26:8","t":"이삭이 거기 오래 거하였더니 이삭이 그 아내 리브가를 껴안은 것을 블레셋 왕 아비멜렉이 창으로 내다본지라"},{"r":"삿21:21","t":"보다가 실로의 녀자들이 무도하러 나오거든 너희는 포도원에서 나와서 실로의 딸 중에서 각각 그 아내로 붙들어 가지고 베냐민 땅으로 돌아가라"}],"출32:7":[{"r":"신9:12","t":"내게 이르시되 일어나 여기서 속히 내려가라 네가 애굽에서 인도하여 낸 내 백성이 스스로 부패하여 내가 그들에게 명한 도를 속히 떠나 자기를 위하여 우상을 부어 만들었느니라"},{"r":"신4:16","t":"두렵건대 스스로 부패하여 자기를 위하여 아무 형상대로든지 우상을 새겨 만들되 남자의 형상이라든지, 녀자의 형상이라든지,"},{"r":"신32:5","t":"그들이 여호와를 향하여 악을 행하니 하나님의 자녀가 아니요 흠이 있는 사곡한 종류로다"},{"r":"삿2:19","t":"그 사사가 죽은 후에는 그들이 돌이켜 그 열조보다 더욱 패괴하여 다른 신들을 좇아 섬겨 그들에게 절하고 그 행위와 패역한 길을 그치지 아니하였으므로"},{"r":"호9:9","t":"저희는 기브아의 시대와 같이 심히 패괴한지라 여호와께서 그 악을 기억하시고 그 죄를 벌하시리라"}],"출32:8":[{"r":"출20:3,4","t":"너는 나 외에는 다른 신들을 네게 있게 말지니라"},{"r":"출20:23","t":"너희는 나를 비겨서 은으로 신상이나 김으로 신상을 너희를 위하여 만들지 말고"},{"r":"신9:16","t":"내가 본즉 너희가 너희 하나님 여호와께 범죄하여 자기를 위하여 송아지를 부어 만들어서 급속히 여호와의 명하신 도를 떠났기로"}],"출3:14":[{"r":"출6:3","t":"내가 아브라함과 이삭과 야곱에게 전능의 하나님으로 나타났으나 나의 이름을 여호와로는 그들에게 알리지 아니하였고"},{"r":"시68:4","t":"하나님께 노래하며 그 이름을 찬양하라 타고 광야에 행하시던 자를 위하여 대로를 수축하라 그 이름은 여호와시니 그 앞에서 뛰놀지어다"},{"r":"요8:58","t":"예수께서 가라사대 진실로 진실로 너희에게 이르노니 아브라함이 나기 전부터 내가 있느니라 하시니"},{"r":"히13:8","t":"예수 그리스도는 어제나 오늘이나 영원토록 동일하시니라"},{"r":"계1:4","t":"요한은 아시아에 있는 일곱 교회에 편지하노니 이제도 계시고 전에도 계시고 장차 오실 이와 그 보좌 앞에 일곱 영과"},{"r":"계4:8","t":"네 생물이 각각 여섯 날개가 있고 그 안과 주위에 눈이 가득하더라 그들이 밤낮 쉬지 않고 이르기를 거룩하다, 거룩하다, 거룩하다, 주 하나님 곧 전능하신 이여, 전에도 계셨고 이제도 계시고 장차 오실 자라 하고"}],"출3:15":[{"r":"출3:6","t":"또 이르시되 나는 네 조상의 하나님이니 아브라함의 하나님, 이삭의 하나님, 야곱의 하나님이니라 모세가 하나님 뵈옵기를 두려워 하여 얼굴을 가리우매"},{"r":"호12:5","t":"저는 만군의 하나님 여호와시라 여호와는 그의 기념 칭호니라"},{"r":"시135:13","t":"여호와여, 주의 이름이 영원하시니이다 여호와여, 주의 기념이 대대에 이르리이다"}],"행13:10":[{"r":"행18:14","t":"바울이 입을 열고자 할 때에 갈리오가 유대인들에게 이르되 너희 유대인들아 만일 무슨 불정한 일이나 괴악한 행동이었으면 내가 너희 말을 들어주는 것이 가하거니와"},{"r":"마13:38","t":"밭은 세상이요 좋은 씨는 천국의 아들들이요 가라지는 악한 자의 아들들이요"},{"r":"호14:9","t":"누가 지혜가 있어 이런 일을 깨달으며 누가 총명이 있어 이런 일을 알겠느냐  여호와의 도는 정직하니 의인이라야 그 도에 행하리라 그러나 죄인은 그 도에 거쳐 넘어지리라"},{"r":"벧후2:15","t":"저희가 바른 길을 떠나 미혹하여 브올의 아들 발람의 길을 좇는도다 그는 부의의 삯을 사랑하다가"},{"r":"행18:25,26","t":"그가 일찍 주의 도를 배워 열심으로 예수에 관한 것을 자세히 말하며 가르치나 요한의 세례만 알 따름이라"},{"r":"미3:9","t":"야곱 족속의 두령과 이스라엘 족속의 치리자 곧 공의를 미워하고 정직한 것을 굽게 하는 자들아 청컨대 이 말을 들을지어다"}],"행13:8":[{"r":"출7:11","t":"바로도 박사와 박수를 부르매 그 애굽 술객들도 그 술법으로 그와 같이 행하되"},{"r":"딤후3:8","t":"얀네와 얌브레가 모세를 대적한 것같이 저희도 진리를 대적하니 이 사람들은 그 마음이 부패한 자요 믿음에 관하여는 버리운 자들이라"},{"r":"행13:7","t":"그가 총독 서기오 바울과 함께 있으니 서기오 바울은 지혜 있는 사람이라 바나바와 사울을 불러 하나님 말씀을 듣고자 하더라"},{"r":"행13:12","t":"이에 총독이 그렇게 된 것을 보고 믿으며 주의 가르치심을 기이히 여기니라"}],"행13:9":[{"r":"행4:8","t":"이에 베드로가 성령이 충만하여 가로되 백성의 관원과 장로들아"}],"행16:12":[{"r":"빌1:1","t":"그리스도 예수의 종 바울과 디모데는 그리스도 예수 안에서 빌립보에 사는 모든 성도와 또는 감독들과 집사들에게 편지하노니"},{"r":"살전2:2","t":"너희 아는 바와 같이 우리가 먼저 빌립보에서 고난과 릉욕을 당하였으나 우리 하나님을 힘입어 많은 싸움 중에 하나님의 복음을 너희에게 말하였노라"},{"r":"행16:21","t":"로마 사람인 우리가 받지도 못하고 행치도 못할 풍속을 전한다 하거늘"}],"행16:13":[{"r":"행13:14","t":"저희는 버가로부터 지나 비시디아 안디옥에 이르러 안식일에 회당에 들어가 앉으니라"},{"r":"스8:15","t":"내가 무리를 아하와로 흐르는 강가에 모으고 거기서 삼일 동안 장막에 유하며 백성과 제사장들을 살핀즉 그 중에 레위 자손이 하나도 없는지라"},{"r":"스8:21","t":"때에 내가 아하와강 가에서 금식을 선포하고 우리 하나님 앞에서 스스로 겸비하여 우리와 우리 어린 것과 모든 소유를 위하여 평탄한 길을 그에게 간구하였으니"},{"r":"시137:1","t":"우리가 바벨론의 여러 강변 거기 앉아서 시온을 기억하며 울었도다"},{"r":"마5:1","t":"예수께서 무리를 보시고 산에 올라가 앉으시니 제자들이 나아온지라"}],"행17:11":[{"r":"사34:16","t":"너희는 여호와의 책을 자세히 읽어보라 이것들이 하나도 빠진 것이 없고 하나도 그 짝이 없는 것이 없으리니 이는 여호와의 입이 이를 명하셨고 그의 신이 이것들을 모으셨음이라"},{"r":"요5:39","t":"너희가 성경에서 영생을 얻는 줄 생각하고 성경을 상고하거니와 이 성경이 곧 내게 대하여 증거하는 것이로다"}],"행17:12":[{"r":"행17:4","t":"그 중에 어떤 사람 곧 경건한 헬라인의 큰 무리와 적지 않은 귀부인도 권함을 받고 바울과 실라를 좇으나"},{"r":"행13:50","t":"이에 유대인들이 경건한 귀부인들과 그 성내 유력자들을 선동하여 바울과 바나바를 핍박케 하여 그 지경에서 쫓아내니"}],"행17:31":[{"r":"시9:8","t":"공의로 세계를 심판하심이여 정직으로 만민에게 판단을 행하시리로다"},{"r":"시96:13","t":"저가 임하시되 땅을 판단하려 임하실 것임이라 저가 의로 세계를 판단하시며 그의 진실하심으로 백성을 판단하시리로다"},{"r":"시98:9","t":"저가 땅을 판단하려 임하실 것임이로다 저가 의로 세계를 판단하시며 공평으로 그 백성을 판단하시리로다"},{"r":"벧전2:23","t":"욕을 받으시되 대신 욕하지 아니하시고 고난을 받으시되 위협하지 아니하시고 오직 공의로 심판하시는 자에게 부탁하시며"},{"r":"롬3:6","t":"결코 그렇지 아니하니라 만일 그러하면 하나님께서 어찌 세상을 심판하시리요"},{"r":"딤후4:8","t":"이제 후로는 나를 위하여 의의 면류관이 예비되었으므로 주 곧 의로우신 재판장이 그 날에 내게 주실 것이니 내게만 아니라 주의 나타나심을 사모하는 모든 자에게니라"},{"r":"행10:42","t":"우리를 명하사 백성에게 전도하되 하나님이 산 자와 죽은 자의 재판장으로 정하신 자가 곧 이 사람인 것을 증거하게 하셨고"},{"r":"마12:36","t":"내가 너희에게 이르노니 사람이 무슨 무익한 말을 하든지 심판 날에 이에 대하여 심문을 받으리니"},{"r":"롬2:16","t":"곧 내 복음에 이른 바와 같이 하나님이 예수 그리스도로 말미암아 사람들의 은밀한 것을 심판하시는 그날이라"},{"r":"고전3:13","t":"각각 공력이 나타날 터인데 그 날이 공력을 밝히리니 이는 불로 나타내고 그 불이 각 사람의 공력이 어떠한 것을 시험할 것임이니라"},{"r":"벧후2:9","t":"주께서 경건한 자는 시험에서 건지시고 부의한 자는 형벌 아래 두어 심판 날까지 지키시며"},{"r":"요일4:17","t":"이로써 사랑이 우리에게 온전히 이룬 것은 우리로 심판 날에 담대함을 가지게 하려 함이니 주의 어떠하심과 같이 우리도 세상에서 그러하니라"},{"r":"유1:6","t":"또 자기 지위를 지키지 아니하고 자기 처소를 떠난 천사들을 큰 날의 심판까지 영원한 결박으로 흑암에 가두셨으며"},{"r":"사2:12","t":"대저 만군의 여호와의 한 날이 모든 교만자와 거만자와 자고한 자에게 임하여 그들로 낮아지게 하고"},{"r":"행2:24","t":"하나님께서 사망의 고통을 풀어 살리셨으니 이는 그가 사망에게 매여 있을 수 없었음이라"},{"r":"요16:10,11","t":"의에 대하여라 함은 내가 아버지께로 가니 너희가 다시 나를 보지 못함이요"},{"r":"롬1:4","t":"성결의 영으로는 죽은 가운데서 복활하여 능력으로 하나님의 아들로 인정되셨으니 곧 우리 주 예수 그리스도시니라"}],"행18:10":[{"r":"눅21:18","t":"너희 머리털 하나도 상치 아니하리라"},{"r":"살후3:3","t":"주는 미쁘사 너희를 굳게 하시고 악한 자에게서 지키시리라"},{"r":"요10:16","t":"또 이 우리에 들지 아니한 다른 양들이 내게 있어 내가 인도하여야 할 터이니 저희도 내 음성을 듣고 한 무리가 되어 한 목자에게 있으리라"}],"행18:9":[{"r":"행23:11","t":"그날 밤에 주께서 바울 곁에 서서 이르시되 담대하라 네가 예루살렘에서 나의 일을 증거한 것같이 로마에서도 증거하여야 하리라 하시니라"},{"r":"행27:33","t":"날이 새어 가매 바울이 여러 사람을 음식 먹으라 권하여 가로되 너희가 기다리고 기다리며 먹지 못하고 주린 지가 오늘까지 열 나흘인즉"},{"r":"행26:16","t":"일어나 네 발로 서라 내가 네게 나타난 것은 곧 네가 나를 본 일과 장차 내가 네게 나타날 일에 너로 사환과 증인을 삼으려 함이니"},{"r":"고후12:1~4","t":"무익하나마 내가 불득부 자랑하노니 주의 환상과 계시를 말하리라"},{"r":"행27:24","t":"바울아 두려워 말라 네가 가이사 앞에 서야 하겠고 또 하나님께서 너와 함께 행선하는 자를 다 네게 주셨다 하였으니"},{"r":"수1:5,6","t":"너의 평생에 너를 능히 당할 자 없으리니 내가 모세와 함께 있던 것 같이 너의 함께 있을 것임이라 내가 너를 떠나지 아니하며 버리지 아니하리니"},{"r":"렘1:8","t":"너는 그들을 인하여 두려워 말라  내가 너와 함께 하여 너를 구원하리라 나 여호와의 말이니라 하시고"},{"r":"고전2:3","t":"내가 너희 가운데 거할 때에 약하며 두려워하며 심히 떨었노라"}],"행1:1":[{"r":"눅1:3","t":"그 모든 일을 근원부터 자세히 미루어 살핀 나도 데오빌로 각하에게 차례대로 써 보내는 것이 좋은 줄 알았노니"},{"r":"눅24:19","t":"가라사대 무슨 일이뇨  가로되 나사렛 예수의 일이니 그는 하나님과 모든 백성 앞에서 말과 일에 능하신 선지자여늘"}],"행1:10":[{"r":"마28:3","t":"그 형상이 번개 같고 그 옷은 눈같이 희거늘"},{"r":"막16:5","t":"무덤에 들어가서 흰 옷을 입은 한 청년이 우편에 앉은 것을 보고 놀라매"},{"r":"요20:12","t":"흰 옷 입은 두 천사가 예수의 시체 뉘었던 곳에 하나는 머리 편에 하나는 발 편에 앉았더라"},{"r":"눅24:4","t":"이를 인하여 근심할 때에 문득 찬란한 옷을 입은 두 사람이 곁에 섰는지라"},{"r":"수5:13","t":"여호수아가 여리고에 가까왔을 때에 눈을 들어 본즉 한 사람이 칼을 빼어 손에 들고 마주 섰는지라 여호수아가 나아가서 그에게 묻되 너는 우리를 위하느냐  우리의 대적을 위하느냐"},{"r":"단9:21","t":"곧 내가 말하여 기도할 때에 이전 이상 중에 본 그 사람 가브리엘이 빨리 날아서 저녁 제사를 드릴 때 즈음에 내게 이르더니"},{"r":"단10:5","t":"그 때에 내가 눈을 들어 바라본즉 한 사람이 세마포 옷을 입었고 허리에는 우바스 정김 띠를 띠었고"},{"r":"단12:6,7","t":"그 중에 하나가 세마포 옷을 입은 자 곧 강물 위에 있는 자에게 이르되 이 기사의 끝이 어느 때까지냐 하기로"},{"r":"슥1:8~11","t":"내가 밤에 보니 사람이 홍마를 타고 골짜기 속 화석류나무 사이에 섰고 그 뒤에는 홍마와, 자마와, 백마가 있기로"}],"행1:11":[{"r":"행2:7","t":"다 놀라 기이히 여겨 이르되 보라 이 말하는 사람이 다 갈릴리 사람이 아니냐"},{"r":"행13:31","t":"갈릴리로부터 예루살렘에 함께 올라간 사람들에게 여러 날 보이셨으니 저희가 이제 백성 앞에 그의 증인이라"},{"r":"빌3:20","t":"오직 우리의 시민권은 하늘에 있는지라 거기로서 구원하는 자 곧 주 예수 그리스도를 기다리노니"},{"r":"살전1:10","t":"또 죽은 자들 가운데서 다시 살리신 그의 아들이 하늘로부터 강림하심을 기다린다고 말하니 이는 장래 노하심에서 우리를 건지시는 예수시니라"},{"r":"마16:27","t":"인자가 아버지의 영광으로 그 천사들과 함께 오리니 그 때에 각 사람의 행한 대로 갚으리라"},{"r":"살후1:10","t":"그 날에 강림하사 그의 성도들에게서 영광을 얻으시고 모든 믿는 자에게서 기이히 여김을 얻으시리라우리의 증거가 너희에게 믿어졌음이라"}],"행1:2":[{"r":"행10:38","t":"하나님이 나사렛 예수에게 성령과 능력을 기름붓듯 하셨으매 저가 두루 다니시며 착한 일을 행하시고 마귀에게 눌린 모든 자를 고치셨으니 이는 하나님이 함께 하셨음이라"},{"r":"눅4:1","t":"예수께서 성령의 충만함을 입어 요단강에서 돌아오사 광야에서 사십일 동안 성령에게 이끌리시며"},{"r":"눅4:18","t":"주의 성령이 내게 임하셨으니 이는 가난한 자에게 복음을 전하게 하시려고 내게 기름을 부으시고 나를 보내사 포로된 자에게 자유를 눈먼 자에게 다시보게 함을 전파하며 눌린 자를 자유케 하고"},{"r":"요20:22","t":"이 말씀을 하시고 저희를 향하사 숨을 내쉬며 가라사대 성령을 받으라"},{"r":"행10:42","t":"우리를 명하사 백성에게 전도하되 하나님이 산 자와 죽은 자의 재판장으로 정하신 자가 곧 이 사람인 것을 증거하게 하셨고"},{"r":"마28:19,20","t":"그러므로 너희는 가서 모든 족속으로 제자를 삼아 아버지와 아들과 성령의 이름으로 세례를 주고"},{"r":"막16:15","t":"또 가라사대 너희는 온 천하에 다니며 만민에게 복음을 전파하라"},{"r":"눅24:47","t":"또 그의 이름으로 죄 사함을 얻게 하는 회개가 예루살렘으로부터 시작하여 모든 족속에게 전파될 것이 기록되었으니"},{"r":"요20:21","t":"예수께서 또 가라사대 너희에게 평강이 있을지어다  아버지께서 나를 보내신 것같이 나도 너희를 보내노라"},{"r":"막16:19","t":"주 예수께서 말씀을 마치신 후에 하늘로 올리우사 하나님 우편에 앉으시니라"}],"행1:3":[{"r":"행10:40,41","t":"하나님이 사흘만에 다시 살리사 나타내시되"},{"r":"행13:31","t":"갈릴리로부터 예루살렘에 함께 올라간 사람들에게 여러 날 보이셨으니 저희가 이제 백성 앞에 그의 증인이라"},{"r":"마28:17","t":"예수를 뵈옵고 경배하나 오히려 의심하는 자도 있더라"},{"r":"막16:14","t":"그 후에 열 한 제자가 음식 먹을 때에 예수께서 저희에게 나타나사 저희의 믿음 없는 것과 마음이 완악한 것을 꾸짖으시니 이는 자기의 살아난 것을 본 자들의 말을 믿지 아니함일러라"},{"r":"눅24:34","t":"말하기를 주께서 과연 살아나시고 시몬에게 나타나셨다 하는지라"},{"r":"눅24:36~51","t":"이 말을 할 때에 예수께서 친히 그 가운데 서서 가라사대 너희에게 평강이 있을지어다  하시니"},{"r":"요20:19~29","t":"이날 곧 안식 후 첫날 저녁때에 제자들이 유대인들을 두려워하여 모인 곳에 문들을 닫았더니 예수께서 오사 가운데 서서 가라사대 너희에게 평강이 있을찌어다"},{"r":"요21장","t":"그 후에 예수께서 디베랴 바다에서 또 제자들에게 자기를 나타내셨으니 나타내신 일이 이러하니라"},{"r":"고전15:5~7","t":"게바에게 보이시고 후에 열 두 제자에게와"}],"행1:8":[{"r":"행1:5","t":"요한은 물로 세례를 베풀었으나 너희는 몇 날이 못 되어 성령으로 세례를 받으리라 하셨느니라"},{"r":"행4:33","t":"사도들이 큰 권능으로 주 예수의 복활을 증거하니 무리가 큰 은혜를 얻어"},{"r":"눅24:49","t":"볼지어다 내가 내 아버지의 약속하신 것을 너희에게 보내리니 너희는 위로부터 능력을 입히울 때까지 이 성에 유하라 하시니라"},{"r":"살전1:5","t":"이는 우리 복음이 말로만 너희에게 이른 것이 아니라 오직 능력과 성령과 큰 확신으로 된 것이니 우리가 너희 가운데서 너희를 위하여 어떠한 사람이 된 것은 너희 아는 바와 같으니라"},{"r":"딤후1:7","t":"하나님이 우리에게 주신 것은 두려워하는 마음이 아니요 오직 능력과 사랑과 근신하는 마음이니"},{"r":"행10:38","t":"하나님이 나사렛 예수에게 성령과 능력을 기름붓듯 하셨으매 저가 두루 다니시며 착한 일을 행하시고 마귀에게 눌린 모든 자를 고치셨으니 이는 하나님이 함께 하셨음이라"},{"r":"눅4:14","t":"예수께서 성령의 권능으로 갈릴리에 돌아가시니 그 소문이 사방에 퍼졌고"},{"r":"행8:1","t":"사울이 그의 죽임 당함을 마땅히 여기더라 그 날에 예루살렘에 있는 교회에 큰 핍박이 나서 사도 외에는 다 유대와 사마리아 모든 땅으로 흩어지니라"},{"r":"행8:14","t":"예루살렘에 있는 사도들이 사마리아도 하나님의 말씀을 받았다 함을 듣고 베드로와 요한을 보내매"},{"r":"마10:5","t":"예수께서 이 열 둘을 내어 보내시며 명하여 가라사대 이방인의 길로도 가지 말고 사마리아인의 고을에도 들어가지 말고"},{"r":"행13:47","t":"주께서 이같이 우리를 명하시되 내가 너를 이방의 빛을 삼아 너로 땅 끝까지 구원하게 하리라 하셨느니라 하니"},{"r":"막16:15","t":"또 가라사대 너희는 온 천하에 다니며 만민에게 복음을 전파하라"},{"r":"골1:23","t":"만일 너희가 믿음에 거하고 터 위에 굳게 서서 너희 들은 바 복음의 소망에서 흔들리지 아니하면 그리하리라 이 복음은 천하 만민에게 전파된 바요 나 바울은 이 복음의 일군이 되었노라"},{"r":"행2:32","t":"이 예수를 하나님이 살리신지라 우리가 다 이 일에 증인이로다"},{"r":"행13:31","t":"갈릴리로부터 예루살렘에 함께 올라간 사람들에게 여러 날 보이셨으니 저희가 이제 백성 앞에 그의 증인이라"},{"r":"사43:12","t":"내가 고하였으며 구원하였으며 보였고 너희 중에 다른 신이 없었나니 그러므로 너희는 나의 증인이요 나는 하나님이니라 여호와의 말이니라"},{"r":"행1:22","t":"항상 우리와 함께 다니던 사람 중에 하나를 세워 우리로 더불어 예수의 복활하심을 증거할 사람이 되게 하여야 하리라 하거늘"},{"r":"눅24:48","t":"너희는 이 모든 일의 증인이라"}],"행1:9":[{"r":"행1:1","t":"데오빌로여 내가 먼저 쓴 글에는 무릇 예수의 행하시며 가르치시기를 시작하심부터"},{"r":"살전4:17","t":"그 후에 우리 살아 남은 자도 저희와 함께 구름 속으로 끌어올려 공중에서 주를 영접하게 하시리니 그리하여 우리가 항상 주와 함께 있으리라"}],"행20:10":[{"r":"왕상17:21","t":"그 아이 위에 몸을 세번 펴서 엎드리고 여호와께 부르짖어 가로되 나의 하나님 여호와여  원컨대 이 아이의 혼으로 그 몸에 돌아오게 하옵소서 하니"},{"r":"왕하4:34","t":"아이의 위에 올라 엎드려 자기 입을, 그 입에 자기 눈을, 그 눈에 자기 손을, 그 손에 대고 그 몸에 엎드리니 아이의 살이 차차 따뜻하더라"},{"r":"마9:23,24","t":"예수께서 그 직원의 집에 가사 피리 부는 자들과 훤화하는 무리를 보시고"},{"r":"막5:39","t":"들어가서 저희에게 이르시되 너희가 어찌하여 훤화하며 우느냐  이 아이가 죽은 것이 아니라 잔다 하시니"}],"행20:11":[{"r":"행20:7","t":"안식 후 첫날에 우리가 떡을 떼려 하여 모였더니 바울이 이튿날 떠나고자 하여 저희에게 강론할 새 말을 밤중까지 계속하매"}],"행20:28":[{"r":"딤전4:16","t":"네가 네 자신과 가르침을 삼가 이 일을 계속하라 이것을 행함으로 네 자신과 네게 듣는 자를 구원하리라"},{"r":"행20:29","t":"내가 떠난 후에 흉악한 이리가 너희에게 들어와서 그 양떼를 아끼지 아니하며"},{"r":"엡4:11","t":"그가 혹은 사도로, 혹은 선지자로, 혹은 복음 전하는 자로, 혹은 목사와 교사로 주셨으니"},{"r":"눅12:32","t":"적은 무리여 무서워 말라 너희 아버지께서 그 나라를 너희에게 주시기를 기뻐하시느니라"},{"r":"행13:2","t":"주를 섬겨 금식할 때에 성령이 가라사대 내가 불러 시키는 일을 위하여 바나바와 사울을 따로 세우라 하시니"},{"r":"고전12:8~11","t":"어떤 이에게는 성령으로 말미암아 지혜의 말씀을, 어떤 이에게는 같은 성령을 따라 지식의 말씀을,"},{"r":"빌1:1","t":"그리스도 예수의 종 바울과 디모데는 그리스도 예수 안에서 빌립보에 사는 모든 성도와 또는 감독들과 집사들에게 편지하노니"},{"r":"딤전3:2","t":"그러므로 감독은 책망할 것이 없으며 한 아내의 남편이 되며, 절제하며, 근신하며, 아담하며, 나그네를 대접하며, 가르치기를 잘하며,"},{"r":"딛1:7","t":"감독은 하나님의 청지기로서 책망할 것이 없고 제 고집대로 하지 아니하며 급히 분내지 아니하며 술을 즐기지 아니하며 구타하지 아니하며 더러운 이를 탐하지 아니하며"},{"r":"벧전2:25","t":"너희가 전에는 양과 같이 길을 잃었더니 이제는 너희 령혼의 목자와 감독 되신 이에게 돌아왔느니라"},{"r":"행20:17","t":"바울이 밀레도에서 사람을 에베소로 보내어 교회 장로들을 청하니"},{"r":"마16:18","t":"또 내가 네게 이르노니 너는 베드로라 내가 이 반석 위에 내 교회를 세우리니 음부의 권세가 이기지 못하리라"},{"r":"롬16:16","t":"너희가 거룩하게 입맞춤으로 서로 문안하라 그리스도의 모든 교회가 다 너희에게 문안하느니라"},{"r":"히9:12","t":"염소와 송아지의 피로 아니하고 오직 자기 피로 영원한 속죄를 이루사 단번에 성소에 들어가셨느니라"},{"r":"히9:14","t":"하물며 영원하신 성령으로 말미암아 흠 없는 자기를 하나님께 드린 그리스도의 피가 어찌 너희 량심으로 죽은 행실에서 깨끗하게하고 살아계신 하나님을 섬기게 못하겠느뇨"},{"r":"엡1:7","t":"우리가 그리스도 안에서 그의 은혜의 풍성함을 따라 그의 피로 말미암아 구속 곧 죄 사함을 받았으니"},{"r":"요일1:7","t":"저가 빛 가운데 계신 것같이 우리도 빛 가운데 행하면 우리가 서로 사귐이 있고 그 아들 예수의 피가 우리를 모든 죄에서 깨끗하게 하실 것이요"},{"r":"벧전1:18,19","t":"너희가 알거니와 너희 조상의 유전한 망령된 행실에서 구속된 것은 은이나 김같이 없어질 것으로 한 것이 아니요"},{"r":"계5:9","t":"새 노래를 노래하여 가로되 책을 가지시고 그 인봉을 떼기에 합당하시도다 일찍 죽임을 당하사 각 족속과 방언과 백성과 나라 가운데서 사람들을 피로 사서 하나님께 드리시고"},{"r":"벧후2:1","t":"그러나 민간에 또한 거짓 선지자들이 일어났었나니 이와 같이 너희 중에도 거짓 선생들이 있으리라 저희는 멸망케 할 이단을 가만히 끌어들여 자기들을 사신 주를 부인하고 임박한 멸망을 스스로 취하는 자들이라"},{"r":"고전1:2","t":"고린도에 있는 하나님의 교회 곧 그리스도 예수 안에서 거룩하여지고 성도라 부르심을 입은 자들과 또 각처에서 우리의 주 곧 저희와 우리의 주 되신 예수 그리스도의 이름을 부르는 모든 자들에게"},{"r":"고전10:32","t":"유대인에게나 헬라인에게나 하나님의 교회에나 거치는 자가 되지 말고"},{"r":"고전11:16","t":"변론하려는 태도를 가진 자가 있을지라도 우리에게나 하나님의 모든 교회에는 이런 규례가 없느니라"},{"r":"고전15:9","t":"나는 사도 중에 지극히 작은 자라 내가 하나님의 교회를 핍박하였으므로 사도라 칭함을 받기에 감당치 못할 자로라"},{"r":"갈1:13","t":"내가 이전에 유대교에 있을 때에 행한 일을 너희가 들었거니와 하나님의 교회를 심히 핍박하여 잔해하고"},{"r":"요21:16","t":"또 두번째 가라사대 요한의 아들 시몬아, 네가 나를 사랑하느냐  하시니 가로되 주여, 그러하외다 내가 주를 사랑하는 줄 주께서 아시나이다 가라사대 내 양을 치라 하시고"}],"행20:29":[{"r":"마7:15","t":"거짓 선지자들을 삼가라 양의 옷을 입고 너희에게 나아오나 속에는 노략질하는 이리라"},{"r":"요10:12","t":"삯군은 목자도 아니요 양도 제 양이 아니라 이리가 오는 것을 보면 양을 버리고 달아나나니 이리가 양을 늑탈하고 또 헤치느니라"},{"r":"골2:8","t":"누가 철학과 헛된 속임수로 너희를 노략할까 주의하라 이것이 사람의 유전과 세상의 초등 학문을 좇음이요 그리스도를 좇음이 아니니라"}],"행20:30":[{"r":"고전11:19","t":"너희 중에 편당이 있어야 너희 중에 옳다 인정함을 받은 자들이 나타나게 되리라"},{"r":"고후11:13","t":"저런 사람들은 거짓 사도요 궤휼의 역군이니 자기를 그리스도의 사도로 가장하는 자들이니라"},{"r":"딤전1:19,20","t":"믿음과 착한 량심을 가지라 어떤 이들이 이 량심을 버렸고 그 믿음에 관하여는 파선하였느니라"},{"r":"요일2:18,19","t":"아이들아 이것이 마지막 때라 적그리스도가 이르겠다 함을 너희가 들은 것과 같이 지금도 많은 적그리스도가 일어났으니 이러므로 우리가 마지막 때인 줄 아노라"}],"행20:6":[{"r":"행12:3","t":"유대인들이 이 일을 기뻐하는 것을 보고 베드로도 잡으려 할새 때는 무효절일이라"},{"r":"출12:14,15","t":"너희는 이 날을 기념하여 여호와의 절기를 삼아 영원한 규례로 대대에 지킬지니라"},{"r":"출23:15","t":"너는 무효병의 절기를 지키라 내가 네게 명한대로 아빕월의 정한 때에 칠일동안 무효병을 먹을지니 이는 그 달에 네가 애굽에서 나왔음이라 빈 손으로 내게 보이지 말지니라"}],"행20:7":[{"r":"고전16:2","t":"매주일 첫날에 너희 각 사람이 이를 얻은 대로 저축하여 두어서 내가 갈 때에 연보를 하지 않게 하라"},{"r":"막16:9","t":"예수께서 안식 후 첫날 이른 아침에 살아나신 후 전에 일곱 귀신을 쫓아 내어 주신 막달라 마리아에게 먼저 보이시니"},{"r":"요20:19","t":"이날 곧 안식 후 첫날 저녁때에 제자들이 유대인들을 두려워하여 모인 곳에 문들을 닫았더니 예수께서 오사 가운데 서서 가라사대 너희에게 평강이 있을찌어다"},{"r":"계1:10","t":"주의 날에 내가 성령에 감동하여 내 뒤에서 나는 나팔소리 같은 큰 음성을 들으니"},{"r":"행20:11","t":"올라가 떡을 떼어 먹고 오래 동안 곧 날이 새기까지 이야기하고 떠나니라"},{"r":"고전10:16","t":"우리가 축복하는 바 축복의 잔은 그리스도의 피에 참여함이 아니며 우리가 떼는 떡은 그리스도의 몸에 참여함이 아니냐"},{"r":"고전11:23,24","t":"내가 너희에게 전한 것은 주께 받은 것이니 곧 주 예수께서 잡히시던 밤에 떡을 가지사"},{"r":"행2:42","t":"저희가 사도의 가르침을 받아 서로 교제하며 떡을 떼며 기도하기를 전혀 힘쓰니라"}],"행20:8":[{"r":"행1:13","t":"들어가 저희 유하는 다락에 올라 가니 베드로 요한 야고보 안드레와 빌립 도마와 바돌로매 마태와 및 알패오의 아들 야고보 셀롯인 시몬 야고보의 아들 유다가 다 거기 있어"},{"r":"행9:37","t":"그 때에 병들어 죽으매 시체를 씻어 다락에 뉘우니라"},{"r":"행9:39","t":"베드로가 일어나 저희와 함께 가서 이르매 저희가 데리고 다락에 올라가니 모든 과부가 베드로의 곁에 서서 울며 도르가가 저희와 함께 있을 때에 지은 속옷과 겉옷을 다 내어 보이거늘"}],"행20:9":[{"r":"왕하1:2","t":"아하시야가 사마리아에 있는 그 다락 란간에서 떨어져 병들매 사자를 보내며 저희더러 이르되 가서 에그론의 신 바알세붑에게 이 병이 낫겠나 물어 보라 하니라"}],"호12:10":[{"r":"왕하17:13","t":"여호와께서 각 선지자와 각 선견자로 이스라엘과 유다를 경계하여 이르시기를 너희는 돌이켜 너희 악한 길에서 떠나 나의 명령과 율례를 지키되 내가 너희 열조에게 명하고 또 나의 종 선지자들로 너희에게 전한 모든 률법대로 행하라 하셨으나"},{"r":"욜2:28","t":"그 후에 내가 내 신을 만민에게 부어 주리니 너희 자녀들이 장래일을 말할 것이며 너희 늙은이는 꿈을 꾸며 너희 젊은이는 이상을 볼 것이며"}],"호6:3":[{"r":"호4:6","t":"내 백성이 지식이 없으므로 망하는도다 네가 지식을 버렸으니 나도 너를 버려 내 제사장이 되지 못하게 할 것이요 네가 네 하나님의 률법을 잊었으니 나도 네 자녀들을 잊어버리리라"},{"r":"미5:2","t":"베들레헴 에브라다야, 너는 유다 족속 중에 작을지라도 이스라엘을 다스릴 자가 네게서 내게로 나올 것이라 그의 근본은 상고에 태초에니라"},{"r":"호14:5","t":"내가 이스라엘에게 이슬과 같으리니 저가 백합화같이 피겠고 레바논 백향목같이 뿌리가 박힐것이라"},{"r":"욜2:20","t":"내가 북편 군대를 너희에게서 멀리 떠나게 하여 메마르고 적막한 땅으로 쫓아내리니 그 전군은 동해로 그 후군은 서해로 들어갈 것이라 상한 냄새가 일어나고 악취가 오르리니 이는 큰 일을 행하였음이니라 하시리라"}],"히10:16":[{"r":"히8:10","t":"또 주께서 가라사대 그 날 후에 내가 이스라엘 집으로 세울 언약이 이것이니 내 법을 저희 생각에 두고 저희 마음에 이것을 기록하리라 나는 저희에게 하나님이 되고 저희는 내게 백성이 되리라"},{"r":"롬11:27","t":"내가 저희 죄를 없이 할 때에 저희에게 이루어질 내 언약이 이것이라 함과 같으니라"},{"r":"렘31:33","t":"나 여호와가 말하노라 그러나 그날 후에 내가 이스라엘 집에 세울 언약은 이러하니 곧 내가 나의 법을 그들의 속에 두며 그 마음에 기록하여 나는 그들의 하나님이 되고 그들은 내 백성이 될 것이라"}],"히10:17":[{"r":"히8:12","t":"내가 저희 부의를 긍휼히 여기고 저희 죄를 다시 기억하지 아니하리라 하셨느니라"},{"r":"렘31:34","t":"그들이 다시는 각기 이웃과 형제를 가리켜 이르기를 너는 여호와를 알라 하지 아니하리니 이는 작은 자로부터 큰 자까지 다 나를 앎이니라 내가 그들의 죄악을 사하고 다시는 그 죄를 기억지 아니하리라 여호와의 말이니라"}],"히11:1":[{"r":"롬8:24","t":"우리가 소망으로 구원을 얻었으매 보이는 소망이 소망이 아니니 보는 것을 누가 바라리요"},{"r":"고후4:18","t":"우리의 돌아보는 것은 보이는 것이 아니요, 보이지 않는 것이니 보이는 것은 잠간이요, 보이지 않는 것은 영원함이니라"},{"r":"고후5:7","t":"이는 우리가 믿음으로 행하고 보는 것으로 하지 아니함이로라"},{"r":"벧전1:8","t":"예수를 너희가 보지 못하였으나 사랑하는도다 이제도 보지 못하나 믿고 말할 수 없는 영광스러운 즐거움으로 기뻐하니"}],"히11:10":[{"r":"계21:2","t":"또 내가 보매 거룩한 성 새 예루살렘이 하나님께로부터 하늘에서 내려오니 그 예비한 것이 신부가 남편을 위하여 단장한 것 같더라"},{"r":"계21:10","t":"성령으로 나를 데리고 크고 높은 산으로 올라가 하나님께로부터 하늘에서 내려오는 거룩한 성 예루살렘을 보이니"},{"r":"시87:1","t":"(고라 자손의 시. 곧 노래) 그 기지가 성산에 있음이여"},{"r":"계21:14","t":"그 성에 성곽은 열 두 기초석이 있고 그 위에 어린 양의 십 이 사도의 열 두 이름이 있더라"},{"r":"히12:22","t":"그러나 너희가 이른 곳은 시온산과 살아계신 하나님의 도성인 하늘의 예루살렘과 천만 천사와"},{"r":"히13:14","t":"우리가 여기는 영구한 도성이 없고 오직 장차 올 것을 찾나니"}],"히11:6":[{"r":"대상28:9","t":"내 아들 솔로몬아 너는 네 아비의 하나님을 알고 온전한 마음과 기쁜 뜻으로 섬길지어다 여호와께서는 뭇 마음을 감찰하사 모든 사상을 아시나니 네가 저를 찾으면 만날 것이요 버리면 저가 너를 영원히 버리시리라"},{"r":"렘29:12~14","t":"너희는 내게 부르짖으며 와서 내게 기도하면 내가 너희를 들을 것이요"},{"r":"요4:24","t":"하나님은 영이시니 예배하는 자가 신령과 진정으로 예배할지니라"}],"히11:8":[{"r":"창12:1~4","t":"여호와께서 아브람에게 이르시되 너는 너의 본토 친척 아비 집을 떠나 내가 네게 지시할 땅으로 가라"},{"r":"행7:2~4","t":"스데반이 가로되 여러분 부형들이여 들으소서 우리 조상 아브라함이 하란에 있기 전 메소보다미아에 있을 때에 영광의 하나님이 그에게 보여"},{"r":"창12:7","t":"여호와께서 아브람에게 나타나 가라사대 내가 이 땅을 네 자손에게 주리라 하신지라 그가 자기에게 나타나신 여호와를 위하여 그곳에 단을 쌓고"}],"히12:2":[{"r":"히2:10","t":"만물이 인하고 만물이 말미암은 자에게는 많은 아들을 이끌어 영광에 들어가게 하시는 일에 저희 구원의 주를 고난으로 말미암아 온전케 하심이 합당하도다"},{"r":"눅24:26","t":"그리스도가 이런 고난을 받고 자기의 영광에 들어가야 할 것이 아니냐  하시고"},{"r":"빌2:8","t":"사람의 모양으로 나타나셨으매 자기를 낮추시고 죽기까지 복종하셨으니 곧 십자가에 죽으심이라"},{"r":"사53:11","t":"가라사대 그가 자기 령혼의 수고한 것을 보고 만족히 여길 것이라 나의 의로운 종이 자기 지식으로 많은 사람을 의롭게 하며 또 그들의 죄악을 친히 담당하리라"},{"r":"시22:6,7","t":"나는 벌레요 사람이 아니라 사람의 훼방거리요 백성의 조롱거리니이다"},{"r":"시69:19","t":"주께서 나의 훼방과 수치와 릉욕을 아시나이다 내 대적이 다 주의 앞에 있나이다"},{"r":"사53:3","t":"그는 멸시를 받아서 사람에게 싫어버린 바 되었으며 간고를 많이 겪었으며 질고를 아는 자라 마치 사람들에게 얼굴을 가리우고 보지않음을 받는 자 같아서 멸시를 당하였고 우리도 그를 귀히 여기지 아니하였도다"},{"r":"히1:3","t":"이는 하나님의 영광의 광채시요 그 본체의 형상이시라 그의 능력의 말씀으로 만물을 붙드시며 죄를 정결케 하는 일을 하시고 높은 곳에 계신 위엄의 우편에 앉으셨느니라"}],"히1:1":[{"r":"민12:6","t":"이르시되 내 말을 들으라 너희 중에 선지자가 있으면 나 여호와가 이상으로 나를 그에게 알리기도 하고 꿈으로 그와 말하기도 하거니와"},{"r":"민12:8","t":"그와는 내가 대면하여 명백히 말하고 은밀한 말로 아니하며 그는 또 여호와의 형상을 보겠거늘 너희가 어찌하여 내 종 모세 비방하기를 두려워 아니하느냐"},{"r":"욜2:28","t":"그 후에 내가 내 신을 만민에게 부어 주리니 너희 자녀들이 장래일을 말할 것이며 너희 늙은이는 꿈을 꾸며 너희 젊은이는 이상을 볼 것이며"}],"히1:14":[{"r":"마25:34","t":"그 때에 임금이 그 오른편에 있는 자들에게 이르시되 내 아버지께 복 받을 자들이여  나아와 창세로부터 너희를 위하여 예비된 나라를 상속하라"},{"r":"창19:16","t":"그러나 롯이 지체하매 그 사람들이 롯의 손과, 그 아내의 손과, 두 딸의 손을 잡아 인도하여 성밖에 두니 여호와께서 그에게 인자를 더하심이었더라"},{"r":"창28:12","t":"꿈에 본즉 사닥다리가 땅 위에 섰는데 그 꼭대기가 하늘에 닿았고 또 본즉 하나님의 사자가 그 위에서 오르락 내리락하고"},{"r":"창32:1,2","t":"야곱이 그 길을 진행하더니 하나님의 사자들이 그를 만난지라"},{"r":"삿6:11","t":"여호와의 사자가 아비에셀 사람 요아스에게 속한 오브라에 이르러 상수리나무 아래 앉으니라 마침 요아스의 아들 기드온이 미디안 사람에게 알리지 아니하려 하여 밀을 포도주 틀에서 타작하더니"},{"r":"삿13:3","t":"여호와의 사자가 그 녀인에게 나타나시고 그에게 이르시되 보라, 네가 본래 잉태하지 못하므로 생산치 못하였으나 이제 잉태하여 아들을 낳으리니"},{"r":"시34:7","t":"여호와의 사자가 주를 경외하는 자를 둘러 진치고 저희를 건지시는도다"},{"r":"시91:11","t":"저가 너를 위하여 그 사자들을 명하사 네 모든 길에 너를 지키게 하심이라"},{"r":"시103:20,21","t":"능력이 있어 여호와의 말씀을 이루며 그 말씀의 소리를 듣는 너희 천사여 여호와를 송축하라"},{"r":"단3:28","t":"느부갓네살이 말하여 가로되 사드락과 메삭과 아벳느고의 하나님을 찬송할지로다 그가 그 사자를 보내사 자기를 의뢰하고 그 몸을 버려서 왕의 명을 거역하고 그 하나님 밖에는 다른 신을 섬기지 아니하며 그에게 절하지 아니한 종들을 구원하셨도다"},{"r":"단6:22","t":"나의 하나님이 이미 그 천사를 보내어 사자들의 입을 봉하셨으므로 사자들이 나를 상해치 아니하였사오니 이는 나의 무죄함이 그 앞에 명백함이오며 또 왕이여 나는 왕의 앞에도 해를 끼치지 아니하였나이다"},{"r":"단10:11","t":"내게 이르되 은총을 크게 받은 사람 다니엘아 내가 네게 이르는 말을 깨닫고 일어서라 내가 네게 보내심을 받았느니라 그가 내게 이 말을 한 후에 내가 떨며 일어서매"},{"r":"마18:11","t":"없 음"},{"r":"행12:7","t":"홀연히 주의 사자가 곁에 서매 옥중에 광채가 조요하며 또 베드로의 옆구리를 쳐 깨워 가로되 급히 일어나라 하니 쇠사슬이 그 손에서 벗어지더라"},{"r":"행12:15","t":"저희가 말하되 네가 미쳤다 하나 계집아이는 힘써 말하되 참말이라 하니 저희가 말하되 그러면 그의 천사라 하더라"}],"히1:2":[{"r":"벧전1:20","t":"그는 창세 전부터 미리 알리신 바 된 자나 이 말세에 너희를 위하여 나타내신 바 되었으니"},{"r":"히9:26","t":"그리하면 그가 세상을 창조할 때부터 자주 고난을 받았어야 할 것이로되 이제 자기를 단번에 제사로 드려 죄를 없게 하시려고 세상 끝에 나타나셨느니라"},{"r":"행2:17","t":"하나님이 가라사대 말세에 내가 내 영으로 모든 육체에게 부어 주리니 너희의 자녀들은 예언할 것이요 너희의 젊은이들은 환상을 보고 너희의 늙은이들은 꿈을 꾸리라"},{"r":"히3:6","t":"그리스도는 그의 집 맡은 아들로 충성하였으니 우리가 소망의 담대함과 자랑을 끝까지 견고히 잡으면 그의 집이라"},{"r":"히4:14","t":"그러므로 우리에게 큰 대제사장이 있으니 승천하신 자 곧 하나님 아들 예수시라 우리가 믿는 도리를 굳게 잡을지어다"},{"r":"히5:8","t":"그가 아들이시라도 받으신 고난으로 순종함을 배워서"},{"r":"마14:33","t":"배에 있는 사람들이 예수께 절하며 가로되 진실로 하나님의 아들이로소이다 하더라"},{"r":"히2:3","t":"우리가 이같이 큰 구원을 등한히 여기면 어찌 피하리요 이 구원은 처음에 주로 말씀하신 바요 들은 자들이 우리에게 확증한 바니"},{"r":"시2:8","t":"내게 구하라 내가 열방을 유업으로 주리니 네 소유가 땅끝까지 이르리로다"},{"r":"마21:38","t":"농부들이 그 아들을 보고 서로 말하되 이는 상속자니 자, 죽이고 그의 유업을 차지하자 하고"},{"r":"마28:18","t":"예수께서 나아와 일러 가라사대 하늘과 땅의 모든 권세를 내게 주셨으니"},{"r":"히3:3","t":"저는 모세보다 더욱 영광을 받을 만한 것이 마치 집 지은 자가 그 집보다 더욱 존귀함 같으니라"},{"r":"요1:3","t":"만물이 그로 말미암아 지은 바 되었으니 지은 것이 하나도 그가 없이는 된 것이 없느니라"},{"r":"히11:3","t":"믿음으로 모든 세계가 하나님의 말씀으로 지어진 줄을 우리가 아나니 보이는 것은 나타난 것으로 말미암아 된 것이 아니니라"}],"히1:3":[{"r":"고후4:4","t":"그 중에 이 세상 신이 믿지 아니하는 자들의 마음을 혼미케하여 그리스도의 영광의 복음의 광채를 비취지 못하게 함이니 그리스도는 하나님의 형상이니라"},{"r":"히11:3","t":"믿음으로 모든 세계가 하나님의 말씀으로 지어진 줄을 우리가 아나니 보이는 것은 나타난 것으로 말미암아 된 것이 아니니라"},{"r":"골1:17","t":"또한 그가 만물보다 먼저 계시고 만물이 그 안에 함께 섰느니라"},{"r":"히9:14","t":"하물며 영원하신 성령으로 말미암아 흠 없는 자기를 하나님께 드린 그리스도의 피가 어찌 너희 량심으로 죽은 행실에서 깨끗하게하고 살아계신 하나님을 섬기게 못하겠느뇨"},{"r":"눅22:69","t":"그러나 이제 후로는 인자가 하나님의 권능의 우편에 앉아 있으리라 하시니"},{"r":"막16:19","t":"주 예수께서 말씀을 마치신 후에 하늘로 올리우사 하나님 우편에 앉으시니라"}],"히1:4":[{"r":"엡1:21","t":"모든 정사와 권세와 능력과 주관하는 자와 이 세상 뿐 아니라 오는 세상에 일컫는 모든 이름 위에 뛰어나게 하시고"},{"r":"빌2:9","t":"이러므로 하나님이 그를 지극히 높여 모든 이름 위에 뛰어난 이름을 주사"}],"히4:10":[{"r":"계14:13","t":"또 내가 들으니 하늘에서 음성이 나서 가로되 기록하라 자금 이후로 주 안에서 죽는 자들은 복이 있도다 하시매 성령이 가라사대 그러하다 저희 수고를 그치고 쉬리니 이는 저희의 행한 일이 따름이라 하시더라"}],"히4:11":[{"r":"히3:12","t":"형제들아 너희가 삼가 혹 너희 중에 누가 믿지 아니하는 악심을 품고 살아 계신 하나님에게서 떨어질까 념려할 것이요"}],"히4:12":[{"r":"벧전1:23","t":"너희가 거듭난 것이 썩어질 씨로 된 것이 아니요 썩지 아니할 씨로 된 것이니 하나님의 살아 있고 항상 있는 말씀으로 되었느니라"},{"r":"렘23:29","t":"나 여호와가 말하노라 내 말이 불 같지 아니하냐  반석을 쳐서 부스러뜨리는 방망이 같지 아니하냐"},{"r":"살전2:13","t":"이러므로 우리가 하나님께 쉬지 않고 감사함은 너희가 우리에게 들은 바 하나님의 말씀을 받을 때에 사람의 말로 아니하고 하나님의 말씀으로 받음이니 진실로 그러하다 이 말씀이 또한 너희 믿는 자 속에서 역사하느니라"},{"r":"잠5:4","t":"나중은 쑥 같이 쓰고 두 날 가진 칼같이 날카로우며"},{"r":"계1:16","t":"그 오른손에 일곱 별이 있고 그 입에서 좌우에 날선 검이 나오고 그 얼굴은 해가 힘있게 비취는 것 같더라"},{"r":"계2:12","t":"버가모 교회의 사자에게 편지하기를 좌우에 날선 검을 가진 이가 가라사대"},{"r":"사49:2","t":"내 입을 날카로운 칼 같이 만드시고 나를 그 손 그늘에 숨기시며 나로 마광한 살을 만드사 그 전통에 감추시고"},{"r":"엡6:17","t":"구원의 투구와 성령의 검 곧 하나님의 말씀을 가지라"},{"r":"고전14:24,25","t":"그러나 다 예언을 하면 믿지 아니하는 자들이나 무식한 자들이 들어와서 모든 사람에게 책망을 들으며 모든 사람에게 판단을 받고"}],"히6:13":[{"r":"창22:16","t":"가라사대 여호와께서 이르시기를 내가 나를 가리켜 맹서하노니 네가 이같이 행하여 네 아들 네 독자를 아끼지 아니하였은즉"}],"히6:16":[{"r":"출22:11","t":"두 사람 사이에 맡은 자가 이웃의 것에 손을 대지 아니하였다고 여호와로 맹서할 것이요 그 임자는 그대로 믿을 것이며 그 사람은 배상하지 아니하려니와"}],"히6:17":[{"r":"히11:9","t":"믿음으로 저가 외방에 있는 것같이 약속하신 땅에 우거하여 동일한 약속을 유업으로 함께 받은 이삭과 야곱으로 더불어 장막에 거하였으니"},{"r":"히6:18","t":"이는 하나님이 거짓말을 하실 수 없는 이 두 가지 변치 못할 사실을 인하여 앞에 있는 소망을 얻으려고 피하여 가는 우리로 큰 안위를 받게 하려 하심이라"},{"r":"시110:4","t":"여호와는 맹서하고 변치 아니하시리라 이르시기를 너는 멜기세덱의 반차를 좇아 영원한 제사장이라 하셨도다"},{"r":"잠19:21","t":"사람의 마음에는 많은 계획이 있어도 오직 여호와의 뜻이 완전히 서리라"},{"r":"갈3:20","t":"중보는 한 편만 위한 자가 아니나 오직 하나님은 하나이시니라"}],"히6:18":[{"r":"딛1:2","t":"영생의 소망을 인함이라 이 영생은 거짓이 없으신 하나님이 영원한 때 전부터 약속하신 것인데"},{"r":"히12:1,2","t":"이러므로 우리에게 구름같이 둘러싼 허다한 증인들이 있으니 모든 무거운 것과 얽매이기 쉬운 죄를 벗어 버리고 인내로써 우리 앞에 당한 경주를 경주하며"}],"히8:1":[{"r":"막16:19","t":"주 예수께서 말씀을 마치신 후에 하늘로 올리우사 하나님 우편에 앉으시니라"}],"히8:2":[{"r":"히9:24","t":"그리스도께서는 참 것의 그림자인 손으로 만든 성소에 들어가지 아니하시고 오직 참 하늘에 들어가사 이제 우리를 위하여 하나님앞에 나타나시고"},{"r":"히9:11","t":"그리스도께서 장래 좋은 일의 대제사장으로 오사 손으로 짓지 아니한 곧 이 창조에 속하지 아니한 더 크고 온전한 장막으로 말미암아"},{"r":"출33:7","t":"모세가 항상 장막을 취하여 진 밖에 쳐서 진과 멀리 떠나게 하고 회막이라 이름하니 여호와를 앙모하는 자는 다 진 바깥 회막으로 나아가며"}],"히8:3":[{"r":"히5:1","t":"대제사장마다 사람 가운데서 취한 자이므로 하나님께 속한 일에 사람을 위하여 예물과 속죄하는 제사를 드리게 하나니"},{"r":"히9:12~14","t":"염소와 송아지의 피로 아니하고 오직 자기 피로 영원한 속죄를 이루사 단번에 성소에 들어가셨느니라"},{"r":"히10:9~12","t":"그 후에 말씀하시기를 보시옵소서 내가 하나님의 뜻을 행하러 왔나이다 하셨으니 그 첫 것을 폐하심은 둘째 것을 세우려 하심이니라"},{"r":"엡5:2","t":"그리스도께서 너희를 사랑하신 것같이 너희도 사랑 가운데서 행하라 그는 우리를 위하여 자신을 버리사 향기로운 제물과 생축으로 하나님께 드리셨느니라"}],"히8:5":[{"r":"히9:23","t":"그러므로 하늘에 있는 것들의 모형은 이런 것들로써 정결케 할 필요가 있었으나 하늘에 있는 그것들은 이런 것들보다 더 좋은 제물로 할지니라"},{"r":"히10:1","t":"률법은 장차 오는 좋은 일의 그림자요 참 형상이 아니므로 해마다 늘 드리는 바 같은 제사로는 나아오는 자들을 언제든지 온전케 할 수 없느니라"},{"r":"골2:17","t":"이것들은 장래 일의 그림자이나 몸은 그리스도의 것이니라"},{"r":"출25:40","t":"너는 삼가 이 산에서 네게 보인 식양대로 할지니라"}],"히9:1":[{"r":"출25:8","t":"내가 그들 중에 거할 성소를 그들을 시켜 나를 위하여 짓되"}],"히9:2":[{"r":"출26:1","t":"너는 성막을 만들되 앙장 열 폭을 가늘게 꼰 베실과, 청색, 자색, 홍색실로 그룹을 공교히 수 놓아 만들지니"},{"r":"출25:31~39","t":"너는 정김으로 등대를 쳐서 만들되 그 밑판과, 줄기와, 잔과, 꽃받침과, 꽃을 한 덩이로 연하게 하고"},{"r":"출26:35","t":"그 장 바깥 북편에 상을 놓고 남편에 등대를 놓아 상과 대하게 할지며"},{"r":"출40:4","t":"또 상을 들여 놓고 그 위에 물품을 진설하고 등대를 들여 놓고 불을 켜고"},{"r":"출25:23~29","t":"너는 조각목으로 상을 만들되 장이 이 규빗, 광이 일 규빗, 고가 일 규빗 반이 되게 하고"},{"r":"출25:30","t":"상 위에 진설병을 두어 항상 내 앞에 있게 할지니라"},{"r":"레24:5~8","t":"너는 고운 가루를 취하여 떡 열 둘을 굽되 매 덩이를 에바 십분 이로 하여"}],"히9:22":[{"r":"레17:11","t":"육체의 생명은 피에 있음이라 내가 이 피를 너희에게 주어 단에 뿌려 너희의 생명을 위하여 속하게 하였나니 생명이 피에 있으므로 피가 죄를 속하느니라"}],"히9:23":[{"r":"히8:5","t":"저희가 섬기는 것은 하늘에 있는 것의 모형과 그림자라 모세가 장막을 지으려 할 때에 지시하심을 얻음과 같으니 가라사대 삼가 모든 것을 산에서 네게 보이던 본을 좇아 지으라 하셨느니라"}],"히9:24":[{"r":"히8:2","t":"성소와 참 장막에 부리는 자라 이 장막은 주께서 베푸신 것이요 사람이 한 것이 아니니라"},{"r":"히9:11","t":"그리스도께서 장래 좋은 일의 대제사장으로 오사 손으로 짓지 아니한 곧 이 창조에 속하지 아니한 더 크고 온전한 장막으로 말미암아"},{"r":"히7:25","t":"그러므로 자기를 힘입어 하나님께 나아가는 자들을 온전히 구원하실 수 있으니 이는 그가 항상 살아서 저희를 위하여 간구하심이니라"},{"r":"롬8:34","t":"누가 정죄하리요 죽으실 뿐 아니라 다시 살아나신 이는 그리스도 예수시니 그는 하나님 우편에 계신 자요 우리를 위하여 간구하시는 자시니라"}],"히9:28":[{"r":"마20:28","t":"인자가 온 것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라"},{"r":"마26:28","t":"이것은 죄 사함을 얻게 하려고 많은 사람을 위하여 흘리는 바 나의 피 곧 언약의 피니라"},{"r":"막10:45","t":"인자의 온 것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라"},{"r":"계5:9","t":"새 노래를 노래하여 가로되 책을 가지시고 그 인봉을 떼기에 합당하시도다 일찍 죽임을 당하사 각 족속과 방언과 백성과 나라 가운데서 사람들을 피로 사서 하나님께 드리시고"},{"r":"사53:12","t":"이러므로 내가 그로 존귀한 자와 함께 분깃을 얻게 하며 강한 자와 함께 탈취한 것을 나누게 하리니 이는 그가 자기 령혼을 버려 사망에 이르게 하며 범죄자 중 하나로 헤아림을 입었음이라 그러나 실상은 그가 많은 사람의 죄를 지며 범죄자를 위하여 기도하였느니라 하시니라"},{"r":"벧전2:24","t":"친히 나무에 달려 그 몸으로 우리 죄를 담당하셨으니 이는 우리로 죄에 대하여 죽고 의에 대하여 살게 하려 하심이라 저가 채찍에 맞음으로 너희는 나음을 얻었나니"},{"r":"벧전3:18","t":"그리스도께서도 한번 죄를 위하여 죽으사 의인으로서 부의한 자를 대신하셨으니 이는 우리를 하나님 앞으로 인도하려 하심이라 육체로는 죽임을 당하시고 영으로는 살리심을 받으셨으니"},{"r":"히4:15","t":"우리에게 있는 대제사장은 우리 연약함을 체휼하지 아니하는 자가 아니요 모든 일에 우리와 한결같이 시험을 받은 자로되 죄는 없으시니라"},{"r":"딛2:13","t":"복스러운 소망과 우리의 크신 하나님 구주 예수 그리스도의 영광이 나타나심을 기다리게 하셨으니"},{"r":"사25:9","t":"그 날에 말하기를 이는 우리의 하나님이시라 우리가 그를 기다렸으니 그가 우리를 구원하시리로다 이는 여호와시라 우리가 그를 기다렸으니 우리는 그 구원을 기뻐하며 즐거워하리라 할 것이며"},{"r":"행1:11","t":"가로되 갈릴리 사람들아 어찌하여 서서 하늘을 쳐다보느냐  너희 가운데서 하늘로 올리우신 이 예수는 하늘로 가심을 본 그대로 오시리라 하였느니라"}],"히9:3":[{"r":"출26:31~33","t":"너는 청색, 자색, 홍색실과 가늘게 꼰 베실로 짜서 장을 만들고 그 위에 그룹들을 공교히 수 놓아서"},{"r":"출40:3","t":"또 증거궤를 들여 놓고 또 장으로 그 궤를 가리우고"},{"r":"출40:21","t":"또 그 궤를 성막에 들여 놓고 장을 드리워서 그 증거궤를 가리우니 여호와께서 모세에게 명하신 대로 되니라"}],"히9:4":[{"r":"레16:12,13","t":"향로를 취하여 여호와 앞 단 위에서 피운 불을 그것에 채우고 또 두손에 곱게 간 향기로운 향을 채워 가지고 장 안에 들어가서"},{"r":"출30:1","t":"너는 분향할 단을 만들지니 곧 조각목으로 만들되"},{"r":"왕상6:22","t":"온 전을 김으로 입히기를 마치고 내소에 속한 단의 전부를 김으로 입혔더라"},{"r":"출25:10","t":"그들은 조각목으로 궤를 짓되 장이 이 규빗 반, 광이 일 규빗 반, 고가 일 규빗 반이 되게 하고"},{"r":"출26:33","t":"그 장을 갈고리 아래 드리운 후에 증거궤를 그 장 안에 들여 놓으라 그 장이 너희를 위하여 성소와 지성소를 구별하리라"},{"r":"출40:3","t":"또 증거궤를 들여 놓고 또 장으로 그 궤를 가리우고"},{"r":"출40:21","t":"또 그 궤를 성막에 들여 놓고 장을 드리워서 그 증거궤를 가리우니 여호와께서 모세에게 명하신 대로 되니라"},{"r":"계11:19","t":"이에 하늘에 있는 하나님의 성전이 열리니 성전 안에 하나님의 언약궤가 보이며 또 번개와 음성들과 뢰성과 지진과 큰 우박이 있더라"},{"r":"출16:33,34","t":"또 아론에게 이르되 항아리를 가져다가 그 속에 {만나} 한 오멜을 담아 여호와 앞에 두어 너희 대대로 간수하라"},{"r":"민17:10","t":"여호와께서 또 모세에게 이르시되 아론의 지팡이는 증거궤 앞으로 도로 가져다가 거기 간직하여 패역한 자에 대한 표징이 되게 하여 그들로 내게 대한 원망을 그치고 죽지 않게 할지니라"},{"r":"출25:16","t":"내가 네게 줄 증거판을 궤 속에 둘지며"},{"r":"출40:20","t":"그가 또 증거판을 궤 속에 넣고 채를 궤에 꿰고 속죄소를 궤 위에 두고"},{"r":"신10:2","t":"네가 깨뜨린 처음 판에 쓴 말을 내가 그 판에 쓰리니 너는 그것을 그 궤에 넣으라 하시기로"},{"r":"신10:5","t":"내가 돌이켜 산에서 내려와서 여호와께서 내게 명하신 대로 그 판을 내가 만든 궤에 넣었더니 지금까지 있느니라"},{"r":"왕상8:9","t":"궤 안에는 두 돌판 외에 아무것도 없으니 이것은 이스라엘 자손이 애굽 땅에서 나온 후 여호와께서 저희와 언약을 세우실 때에 모세가 호렙에서 그 안에 넣은 것이더라"},{"r":"왕상8:21","t":"내가 또 그곳에 우리 열조를 애굽 땅에서 인도하여 내실 때에 저희와 세우신 바 여호와의 언약 넣은 궤를 위하여 한 처소를 설치하였노라"},{"r":"대하5:10","t":"궤 안에는 두 돌판 외에 아무 것도 없으니 이것은 이스라엘 자손이 애굽에서 나온 후 여호와께서 저희와 언약을 세우실 때에 모세가 호렙에서 그 안에 넣은 것이더라"}],"히9:5":[{"r":"레16:2","t":"여호와께서 모세에게 이르시되 네 형 아론에게 이르라 성소의 장 안 법궤 위 속죄소 앞에 무시로 들어오지 말아서 사망을 면하라 내가 구름 가운데서 속죄소 위에 나타남이니라"},{"r":"출25:18~22","t":"김으로 그룹 둘을 속죄소 두 끝에 쳐서 만들되"},{"r":"왕상8:6,7","t":"제사장들이 여호와의 언약궤를 그 처소로 메어 들였으니 곧 내전 지성소 그룹들의 날개 아래라"}]};
